-- LEAP baseline schema (public) — generated from production catalog
SET check_function_bodies = off;
SET client_min_messages = warning;


DO $do$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname='customer') THEN CREATE ROLE customer; END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname='external_partner') THEN CREATE ROLE external_partner; END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname='internal_staff') THEN CREATE ROLE internal_staff; END IF;
END
$do$;


CREATE EXTENSION IF NOT EXISTS http WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS pg_cron WITH SCHEMA pg_catalog;
CREATE EXTENSION IF NOT EXISTS pg_net WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS pg_stat_statements WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS pg_trgm WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS pgcrypto WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS postgis WITH SCHEMA public;
CREATE EXTENSION IF NOT EXISTS supabase_vault WITH SCHEMA vault;
CREATE EXTENSION IF NOT EXISTS "uuid-ossp" WITH SCHEMA extensions;


