CREATE OR REPLACE FUNCTION public._automation_action_create_task(p_rule automation_rules, p_record_id uuid, OUT v_outcome text, OUT v_message text, OUT v_created_id uuid)
 RETURNS record
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_task_name text;
  v_assigned_role text;
  v_assigned_user uuid;
  v_due_days integer;
BEGIN
  v_task_name := p_rule.action_config ->> 'task_name';
  v_assigned_role := p_rule.action_config ->> 'assigned_role';
  v_due_days := COALESCE((p_rule.action_config ->> 'due_days')::integer, 1);
  v_assigned_user := _automation_resolve_role_user(v_assigned_role);
  IF v_assigned_user IS NULL THEN
    v_outcome := 'skipped';
    v_message := format('No user with role "%s"', v_assigned_role);
    v_created_id := NULL;
    RETURN;
  END IF;
  INSERT INTO public.tasks
    (subject, description, status, priority, due_date,
     owner_id, related_object, related_id,
     is_automated, automation_rule)
  VALUES
    (v_task_name,
     format('Auto-created by rule: %s', p_rule.name),
     'Open', 'Normal',
     (now() + (v_due_days || ' days')::interval)::date,
     v_assigned_user,
     p_rule.trigger_object, p_record_id,
     true, p_rule.name)
  RETURNING id INTO v_created_id;
  v_outcome := 'success';
  v_message := format('Created task "%s" assigned to %s (due in %s days)',
    v_task_name, v_assigned_role, v_due_days);
END; $function$
;

CREATE OR REPLACE FUNCTION public._automation_action_create_work_order(p_rule automation_rules, p_record_id uuid, OUT v_outcome text, OUT v_message text, OUT v_created_id uuid)
 RETURNS record
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_work_type_name text;
  v_assigned_role  text;
  v_name           text;

  v_work_type_id   uuid;
  v_assignee_id    uuid;

  v_project_id     uuid;
  v_opp_id         uuid;
  v_property_id    uuid;
  v_building_id    uuid;
  v_unit_id        uuid;

  v_status_id      uuid;
BEGIN
  v_work_type_name := p_rule.action_config ->> 'work_type';
  v_assigned_role  := p_rule.action_config ->> 'assigned_role';
  v_name           := p_rule.action_config ->> 'name';
  v_created_id     := NULL;

  IF v_work_type_name IS NULL THEN
    v_outcome := 'error';
    v_message := 'create_work_order: action_config.work_type required';
    RETURN;
  END IF;

  SELECT id INTO v_work_type_id
    FROM public.work_types
   WHERE work_type_name = v_work_type_name AND NOT work_type_is_deleted
   LIMIT 1;
  IF v_work_type_id IS NULL THEN
    v_outcome := 'error';
    v_message := format('No active work_type named "%s"', v_work_type_name);
    RETURN;
  END IF;

  IF v_assigned_role IS NOT NULL THEN
    v_assignee_id := _automation_resolve_role_user(v_assigned_role);
    IF v_assignee_id IS NULL THEN
      v_outcome := 'error';
      v_message := format('No user found with role "%s"', v_assigned_role);
      RETURN;
    END IF;
  ELSE
    v_outcome := 'error';
    v_message := 'create_work_order: action_config.assigned_role required (owner is NOT NULL)';
    RETURN;
  END IF;

  IF p_rule.trigger_object = 'opportunities' THEN
    v_opp_id := p_record_id;
    SELECT property_id, building_id INTO v_property_id, v_building_id
      FROM public.opportunities WHERE id = v_opp_id;
    SELECT id INTO v_project_id
      FROM public.projects
     WHERE opportunity_id = v_opp_id AND NOT project_is_deleted
     ORDER BY project_created_at DESC NULLS LAST
     LIMIT 1;
    IF v_project_id IS NULL THEN
      v_outcome := 'skipped';
      v_message := format(
        'No live project exists for opportunity %s yet — create the project first, then the WO rule can fire',
        v_opp_id);
      RETURN;
    END IF;
  ELSIF p_rule.trigger_object = 'projects' THEN
    v_project_id := p_record_id;
    SELECT opportunity_id, property_id, building_id
      INTO v_opp_id, v_property_id, v_building_id
      FROM public.projects WHERE id = v_project_id;
  ELSIF p_rule.trigger_object = 'work_orders' THEN
    SELECT project_id, opportunity_id, property_id, building_id, unit_id
      INTO v_project_id, v_opp_id, v_property_id, v_building_id, v_unit_id
      FROM public.work_orders WHERE id = p_record_id;
  ELSE
    v_outcome := 'error';
    v_message := format('create_work_order: unsupported trigger_object "%s"', p_rule.trigger_object);
    RETURN;
  END IF;

  -- FIX: live picklist value is bare 'To Be Scheduled', not 'Work Order To Be Scheduled'.
  SELECT id INTO v_status_id
    FROM public.picklist_values
   WHERE picklist_object='work_orders' AND picklist_field='work_order_status'
     AND picklist_value='To Be Scheduled' AND picklist_is_active
   LIMIT 1;

  -- Hardening: never birth a statusless WO. Fall back to lowest sort_order active status.
  IF v_status_id IS NULL THEN
    SELECT id INTO v_status_id
      FROM public.picklist_values
     WHERE picklist_object='work_orders' AND picklist_field='work_order_status'
       AND picklist_is_active
     ORDER BY picklist_sort_order
     LIMIT 1;
    RAISE NOTICE 'create_work_order: "To Be Scheduled" not found; fell back to lowest-sort active status %', v_status_id;
  END IF;

  IF v_name IS NULL OR length(trim(v_name)) = 0 THEN
    v_name := v_work_type_name;
  END IF;

  INSERT INTO public.work_orders (
    work_order_record_number,
    work_order_name,
    work_order_status,
    work_type_id,
    work_order_owner,
    work_order_created_by,
    project_id, opportunity_id, property_id, building_id, unit_id,
    is_seed_data, work_order_is_deleted
  ) VALUES (
    '',
    v_name,
    v_status_id,
    v_work_type_id,
    v_assignee_id,
    v_assignee_id,
    v_project_id, v_opp_id, v_property_id, v_building_id, v_unit_id,
    false, false
  ) RETURNING id INTO v_created_id;

  v_outcome := 'success';
  v_message := format('Created work_order/%s ("%s") on project/%s', v_created_id, v_name, v_project_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public._automation_action_send_email(p_rule automation_rules, p_record_id uuid, OUT v_outcome text, OUT v_message text, OUT v_created_id uuid)
 RETURNS record
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_template_name text;
  v_recipient_role text;
  v_recipient_user uuid;
BEGIN
  v_template_name := p_rule.action_config ->> 'template';
  v_recipient_role := p_rule.action_config ->> 'recipient_role';
  v_recipient_user := _automation_resolve_role_user(v_recipient_role);
  IF v_recipient_user IS NULL THEN
    v_outcome := 'skipped';
    v_message := format('No user with role "%s"', v_recipient_role);
    v_created_id := NULL;
    RETURN;
  END IF;
  -- Log the intended send. Actual delivery is the responsibility of the
  -- email send path once Microsoft Graph is fully wired. Right now we capture
  -- the intent so it shows up in the run log + the user's notification list.
  INSERT INTO public.notification_logs
    (nl_record_number, nl_trigger_event, nl_channel, nl_subject, nl_status, nl_provider)
  VALUES
    ('', 'automation_rule', 'email',
     format('Automation: %s', v_template_name),
     'queued', 'pending')
  RETURNING id INTO v_created_id;
  v_outcome := 'success';
  v_message := format('Queued email "%s" to role %s (user %s)',
    v_template_name, v_recipient_role, v_recipient_user);
END; $function$
;

CREATE OR REPLACE FUNCTION public._automation_action_update_record(p_rule automation_rules, p_record_id uuid, OUT v_outcome text, OUT v_message text, OUT v_created_id uuid)
 RETURNS record
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_target      text;
  v_condition   text;
  v_new_status  text;
  v_set_field   text;
  v_set_value   text;

  v_parent_name   text;
  v_target_object text;
  v_target_id     uuid;

  v_status_col    text;
  v_new_status_id uuid;
  v_current_status_id uuid;

  v_all_verified  boolean;
BEGIN
  v_target     := p_rule.action_config ->> 'target';
  v_condition  := p_rule.action_config ->> 'condition';
  v_new_status := p_rule.action_config ->> 'new_status';
  v_set_field  := p_rule.action_config ->> 'set_field';
  v_set_value  := p_rule.action_config ->> 'set_value';
  v_created_id := NULL;

  IF v_target = 'self' THEN
    v_target_object := p_rule.trigger_object;
    v_target_id     := p_record_id;
  ELSIF v_target LIKE 'parent_%' THEN
    v_parent_name := substring(v_target FROM 'parent_(.+)');
    v_target_object := CASE v_parent_name
      WHEN 'project'        THEN 'projects'
      WHEN 'projects'       THEN 'projects'
      WHEN 'opportunity'    THEN 'opportunities'
      WHEN 'opportunities'  THEN 'opportunities'
      WHEN 'account'        THEN 'accounts'
      WHEN 'accounts'       THEN 'accounts'
      WHEN 'assessment'     THEN 'assessments'
      WHEN 'assessments'    THEN 'assessments'
      WHEN 'building'       THEN 'buildings'
      WHEN 'buildings'      THEN 'buildings'
      WHEN 'property'       THEN 'properties'
      WHEN 'properties'     THEN 'properties'
      ELSE NULL
    END;
    IF v_target_object IS NULL THEN
      v_outcome := 'error';
      v_message := format('Unknown parent type: %s', v_parent_name);
      RETURN;
    END IF;
    SELECT _automation_resolve_parent_record(p_rule.trigger_object, p_record_id, v_target_object)
      INTO v_target_id;
    IF v_target_id IS NULL THEN
      v_outcome := 'skipped';
      v_message := format('No %s found for %s/%s',
        v_target_object, p_rule.trigger_object, p_record_id);
      RETURN;
    END IF;
  ELSE
    v_outcome := 'skipped';
    v_message := format('Unsupported target: %s', v_target);
    RETURN;
  END IF;

  IF v_condition IS NOT NULL AND v_condition <> 'always' THEN
    IF v_condition = 'all_work_orders_verified'
       AND p_rule.trigger_object = 'work_orders'
       AND v_target_object = 'projects' THEN
      SELECT NOT EXISTS (
        SELECT 1 FROM public.work_orders w
          LEFT JOIN public.picklist_values pv ON pv.id = w.work_order_status
         WHERE w.project_id = v_target_id
           AND NOT w.work_order_is_deleted
           AND COALESCE(pv.picklist_value,'') NOT LIKE '%Verified%'
      ) INTO v_all_verified;
      IF NOT v_all_verified THEN
        v_outcome := 'skipped';
        v_message := 'Not all work orders on this project are verified yet';
        RETURN;
      END IF;
    ELSE
      v_outcome := 'skipped';
      v_message := format('Unsupported condition: %s on target %s', v_condition, v_target);
      RETURN;
    END IF;
  END IF;

  IF v_new_status IS NOT NULL THEN
    v_status_col := _automation_status_column_for(v_target_object);
    IF v_status_col IS NULL THEN
      v_outcome := 'error';
      v_message := format('No status column registered for %s', v_target_object);
      RETURN;
    END IF;
    SELECT id INTO v_new_status_id
      FROM public.picklist_values
     WHERE picklist_object = v_target_object
       AND picklist_field  = v_status_col
       AND picklist_value  = v_new_status
       AND picklist_is_active
     LIMIT 1;
    IF v_new_status_id IS NULL THEN
      v_outcome := 'error';
      v_message := format('No active %s picklist value "%s"', v_status_col, v_new_status);
      RETURN;
    END IF;
    EXECUTE format('SELECT %I FROM public.%I WHERE id = $1', v_status_col, v_target_object)
      INTO v_current_status_id
      USING v_target_id;
    IF v_current_status_id = v_new_status_id THEN
      v_outcome := 'skipped';
      v_message := format('%s already at "%s"', v_target_object, v_new_status);
      RETURN;
    END IF;
    EXECUTE format('UPDATE public.%I SET %I = $1 WHERE id = $2',
                   v_target_object, v_status_col)
      USING v_new_status_id, v_target_id;
    v_created_id := v_target_id;
    v_outcome := 'success';
    v_message := format('Set %s/%s.%s to "%s"',
      v_target_object, v_target_id, v_status_col, v_new_status);
    RETURN;
  END IF;

  IF v_set_field IS NOT NULL THEN
    IF NOT EXISTS (
      SELECT 1 FROM information_schema.columns
       WHERE table_schema='public' AND table_name=v_target_object AND column_name=v_set_field
    ) THEN
      v_outcome := 'error';
      v_message := format('Column %s.%s does not exist', v_target_object, v_set_field);
      RETURN;
    END IF;
    EXECUTE format('UPDATE public.%I SET %I = $1 WHERE id = $2',
                   v_target_object, v_set_field)
      USING v_set_value, v_target_id;
    v_created_id := v_target_id;
    v_outcome := 'success';
    v_message := format('Set %s/%s.%s', v_target_object, v_target_id, v_set_field);
    RETURN;
  END IF;

  v_outcome := 'skipped';
  v_message := 'update_record: neither new_status nor set_field provided in action_config';
END;
$function$
;

CREATE OR REPLACE FUNCTION public._automation_resolve_parent_record(p_source_object text, p_source_id uuid, p_parent_object text, OUT v_parent_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  v_parent_id := NULL;
  IF p_source_id IS NULL OR p_parent_object IS NULL THEN RETURN; END IF;

  IF p_parent_object = 'projects' THEN
    IF p_source_object = 'work_orders' THEN
      SELECT project_id INTO v_parent_id FROM public.work_orders WHERE id = p_source_id;
    END IF;
  ELSIF p_parent_object = 'opportunities' THEN
    IF p_source_object = 'projects' THEN
      SELECT opportunity_id INTO v_parent_id FROM public.projects WHERE id = p_source_id;
    ELSIF p_source_object = 'work_orders' THEN
      SELECT opportunity_id INTO v_parent_id FROM public.work_orders WHERE id = p_source_id;
    ELSIF p_source_object = 'incentive_applications' THEN
      SELECT opportunity_id INTO v_parent_id FROM public.incentive_applications WHERE id = p_source_id;
    ELSIF p_source_object = 'assessments' THEN
      SELECT opportunity_id INTO v_parent_id FROM public.assessments WHERE id = p_source_id;
    END IF;
  ELSIF p_parent_object = 'accounts' THEN
    IF p_source_object = 'opportunities' THEN
      SELECT opportunity_account_id INTO v_parent_id FROM public.opportunities WHERE id = p_source_id;
    ELSIF p_source_object = 'properties' THEN
      SELECT property_account_id INTO v_parent_id FROM public.properties WHERE id = p_source_id;
    END IF;
  END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public._automation_resolve_role_user(p_role_name text)
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT u.id
    FROM public.users u
    JOIN public.roles r ON r.id = u.role_id
   WHERE r.role_name = p_role_name
   ORDER BY u.id
   LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public._automation_status_column_for(p_object text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN CASE p_object
    WHEN 'accounts'               THEN 'account_status'
    WHEN 'assessments'            THEN 'assessment_status'
    WHEN 'incentive_applications' THEN 'ia_status'
    WHEN 'opportunities'          THEN 'opportunity_status'
    WHEN 'projects'               THEN 'project_status'
    WHEN 'work_orders'            THEN 'work_order_status'
    ELSE NULL
  END;
END;
$function$
;

CREATE OR REPLACE FUNCTION public._current_app_user_id()
 RETURNS uuid
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_id uuid;
BEGIN
  SELECT id INTO v_id FROM public.users WHERE auth_user_id = auth.uid() LIMIT 1;
  RETURN v_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public._dt_status_value(p_status_id uuid)
 RETURNS text
 LANGUAGE sql
