CREATE OR REPLACE FUNCTION public._et_status_value(p_status_id uuid)
 RETURNS text
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT picklist_value FROM public.picklist_values
  WHERE id = p_status_id
    AND picklist_object='email_templates'
    AND picklist_field ='status'
