$function$
;

CREATE OR REPLACE FUNCTION public._flow_eval_condition(p_cond jsonb, p_object text, p_record_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_field text := p_cond->>'field';
  v_op    text := COALESCE(p_cond->>'op','eq');
  v_val   text := p_cond->>'value';
  v_actual text;
BEGIN
  IF v_field IS NULL THEN RETURN false; END IF;
  EXECUTE format('SELECT (%I)::text FROM public.%I WHERE id = $1', v_field, p_object)
    INTO v_actual USING p_record_id;
  RETURN CASE v_op
    WHEN 'eq'       THEN v_actual IS NOT DISTINCT FROM v_val
    WHEN 'neq'      THEN v_actual IS DISTINCT FROM v_val
    WHEN 'is_null'  THEN v_actual IS NULL
    WHEN 'not_null' THEN v_actual IS NOT NULL
    ELSE false END;
EXCEPTION WHEN OTHERS THEN RETURN false;
END; $function$
;

CREATE OR REPLACE FUNCTION public._humanize_column(p_col text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_name text := p_col;
  v_prefixes text[] := ARRAY[
    'property_owner_', 'property_management_company_', 'pmc_',
    'property_', 'opportunity_', 'work_order_', 'work_plan_template_',
    'work_step_template_', 'work_type_', 'project_payment_request_',
    'project_', 'building_', 'unit_', 'assessment_', 'vehicle_',
    'vehicle_activity_', 'va_', 'technician_', 'product_item_', 'product_',
    'equipment_', 'incentive_application_', 'ia_', 'ppr_', 'wpt_', 'wst_',
    'wpte_', 'user_', 'program_', 'partner_org_', 'role_', 'page_layout_',
    'picklist_', 'portal_user_', 'contact_'
  ];
  v_p text;
BEGIN
  FOREACH v_p IN ARRAY v_prefixes LOOP
    IF v_name LIKE v_p || '%' THEN
      v_name := substring(v_name FROM length(v_p) + 1);
      EXIT;
    END IF;
  END LOOP;
  IF v_name LIKE '%_id' THEN
    v_name := substring(v_name FROM 1 FOR length(v_name) - 3);
  END IF;
  v_name := replace(v_name, '_', ' ');
  v_name := initcap(v_name);
  IF v_name IS NULL OR v_name = '' THEN
    RETURN initcap(replace(p_col, '_', ' '));
  END IF;
  RETURN v_name;
END;
$function$
;

CREATE OR REPLACE FUNCTION public._pick_ees_display_column(p_target_table text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_col text;
BEGIN
  IF p_target_table IS NULL THEN RETURN NULL; END IF;

  -- 1. Unprefixed canonical display column
  SELECT column_name INTO v_col
  FROM information_schema.columns
  WHERE table_schema = 'public' AND table_name = p_target_table
    AND column_name IN ('name', 'title', 'display_name', 'label')
  ORDER BY
    CASE column_name
      WHEN 'name'         THEN 1
      WHEN 'title'        THEN 2
      WHEN 'display_name' THEN 3
      WHEN 'label'        THEN 4
    END
  LIMIT 1;
  IF v_col IS NOT NULL THEN RETURN v_col; END IF;

  -- 2. Prefixed *_name — shortest (most canonical) wins, excluding first/last
  SELECT column_name INTO v_col
  FROM information_schema.columns
  WHERE table_schema = 'public' AND table_name = p_target_table
    AND column_name LIKE '%\_name' ESCAPE '\'
    AND column_name NOT LIKE '%\_first\_name' ESCAPE '\'
    AND column_name NOT LIKE '%\_last\_name' ESCAPE '\'
  ORDER BY length(column_name) ASC
  LIMIT 1;
  IF v_col IS NOT NULL THEN RETURN v_col; END IF;

  -- 3. Record number as an identifier of last resort
  SELECT column_name INTO v_col
  FROM information_schema.columns
  WHERE table_schema = 'public' AND table_name = p_target_table
    AND column_name LIKE '%\_record\_number' ESCAPE '\'
  LIMIT 1;
  IF v_col IS NOT NULL THEN RETURN v_col; END IF;

  RETURN 'id';
END;
$function$
;

CREATE OR REPLACE FUNCTION public._pick_ees_field_type(p_col text, p_data_type text, p_is_fk boolean)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF p_is_fk AND p_data_type = 'uuid' THEN RETURN 'lookup'; END IF;
  IF p_data_type = 'date' THEN RETURN 'date'; END IF;
  IF p_data_type IN ('timestamp with time zone', 'timestamp without time zone') THEN RETURN 'datetime'; END IF;
  IF p_data_type = 'boolean' THEN RETURN 'boolean'; END IF;
  IF p_data_type IN ('integer', 'bigint', 'smallint', 'numeric', 'real', 'double precision') THEN RETURN 'number'; END IF;
  IF p_col ~ '(_notes|_description|_content|_message|_body|_instructions|_guidance)$'
     OR p_col IN ('notes', 'description', 'comments', 'instructions', 'guidance')
  THEN RETURN 'textarea'; END IF;
  RETURN 'text';
END;
$function$
;

