CREATE OR REPLACE FUNCTION public._work_step_evidence_gap(p_step work_steps)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_etype       text;
  v_photo_total integer := 0;
  v_before_n    integer := 0;
  v_after_n     integer := 0;
  v_doc_n       integer := 0;
  v_req_count   integer := COALESCE(p_step.work_step_photos_required_count, 0);
BEGIN
  SELECT picklist_value INTO v_etype
    FROM public.picklist_values WHERE id = p_step.work_step_required_evidence_type_id;

  -- Photo tallies (apply to any step that declares photo requirements).
  SELECT
    count(*),
    count(*) FILTER (WHERE lower(coalesce(photo_type,'')) = 'before'),
    count(*) FILTER (WHERE lower(coalesce(photo_type,'')) = 'after')
  INTO v_photo_total, v_before_n, v_after_n
  FROM public.photos
  WHERE work_step_id = p_step.id AND is_deleted = false;

  IF v_req_count > 0 AND v_photo_total < v_req_count THEN
    RETURN format('Step "%s" requires %s photo(s); %s captured. Capture the remaining photo(s) before completing.',
                  p_step.work_step_name, v_req_count, v_photo_total);
  END IF;

  IF p_step.work_step_photo_before_required AND v_before_n < 1 THEN
    RETURN format('Step "%s" requires a BEFORE photo; none captured. Capture a before photo before completing.',
                  p_step.work_step_name);
  END IF;

  IF p_step.work_step_photo_after_required AND v_after_n < 1 THEN
    RETURN format('Step "%s" requires an AFTER photo; none captured. Capture an after photo before completing.',
                  p_step.work_step_name);
  END IF;

  -- Document Upload steps need at least one document artifact on the step.
  IF v_etype = 'Document Upload' THEN
    SELECT count(*) INTO v_doc_n
    FROM public.documents
    WHERE related_object = 'work_steps' AND related_id = p_step.id AND is_deleted = false;
    IF v_doc_n < 1 THEN
      RETURN format('Step "%s" requires a document upload; none attached. Upload the required document before completing.',
                    p_step.work_step_name);
    END IF;
  END IF;

  RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.add_module_object_section(p_module_id text, p_object_table text, p_label text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user uuid;
  v_next int;
  v_id   uuid;
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Editing module sections is admin-only' USING ERRCODE='insufficient_privilege';
  END IF;
  SELECT id INTO v_user FROM public.users WHERE auth_user_id = auth.uid();

  -- Reuse an existing (even soft-deleted) row for this module+object.
  SELECT id INTO v_id
  FROM public.module_sections
  WHERE ms_module_id = p_module_id AND ms_section_id = p_object_table
  LIMIT 1;

  SELECT COALESCE(max(ms_sort_order), 0) + 1 INTO v_next
  FROM public.module_sections
  WHERE ms_module_id = p_module_id AND ms_is_deleted = false;

  IF v_id IS NOT NULL THEN
    UPDATE public.module_sections
       SET ms_is_deleted = false, ms_is_visible = true,
           ms_label = COALESCE(p_label, ms_label),
           ms_object_table = p_object_table,
           ms_updated_by = v_user
     WHERE id = v_id;
  ELSE
    INSERT INTO public.module_sections
      (ms_module_id, ms_section_id, ms_label, ms_sort_order, ms_is_visible,
       ms_is_system, ms_object_table, ms_created_by, ms_updated_by)
    VALUES
      (p_module_id, p_object_table, COALESCE(p_label, initcap(replace(p_object_table,'_',' '))),
       v_next, true, false, p_object_table, v_user, v_user)
    RETURNING id INTO v_id;
  END IF;

  RETURN jsonb_build_object('ok', true, 'id', v_id);
END; $function$
;

CREATE OR REPLACE FUNCTION public.admin_add_custom_field(p_object text, p_column text, p_label text, p_data_type text, p_help_text text DEFAULT NULL::text, p_description text DEFAULT NULL::text, p_example_value text DEFAULT NULL::text, p_financial_tier integer DEFAULT 1, p_track_history boolean DEFAULT false, p_fk_table text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user uuid;
  v_pgtype text;
  v_col text;
  v_sql text;
  v_exists boolean;
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Adding fields is admin-only' USING ERRCODE='insufficient_privilege';
  END IF;

  -- Validate object is a real, writable public base table.
  SELECT EXISTS (
    SELECT 1 FROM pg_catalog.pg_class c
    JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public' AND c.relname = p_object AND c.relkind = 'r'
  ) INTO v_exists;
  IF NOT v_exists THEN
    RAISE EXCEPTION 'Unknown object: %', p_object USING ERRCODE='invalid_parameter_value';
  END IF;
  IF p_object IN ('field_metadata','audit_log','field_history','seed_data_records','schema_migrations') THEN
    RAISE EXCEPTION 'Cannot add fields to system table %', p_object USING ERRCODE='insufficient_privilege';
  END IF;

  -- Validate/normalize column name: lower snake_case, must start with a letter,
  -- 2..58 chars, letters/digits/underscore only.
  v_col := lower(btrim(p_column));
  IF v_col !~ '^[a-z][a-z0-9_]{1,57}$' THEN
    RAISE EXCEPTION 'Invalid column name: % (use lower snake_case, letters/digits/underscore, start with a letter)', p_column USING ERRCODE='invalid_parameter_value';
  END IF;

  -- Reject if column already exists on the table.
  SELECT EXISTS (
    SELECT 1 FROM pg_catalog.pg_attribute a
    JOIN pg_catalog.pg_class c ON c.oid = a.attrelid
    JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname='public' AND c.relname=p_object AND a.attname=v_col AND a.attnum>0 AND NOT a.attisdropped
  ) INTO v_exists;
  IF v_exists THEN
    RAISE EXCEPTION 'Column % already exists on %', v_col, p_object USING ERRCODE='duplicate_column';
  END IF;

  -- Map logical type to a safe Postgres type.
  v_pgtype := CASE p_data_type
    WHEN 'text'      THEN 'text'
    WHEN 'number'    THEN 'numeric'
    WHEN 'integer'   THEN 'integer'
    WHEN 'date'      THEN 'date'
    WHEN 'timestamp' THEN 'timestamptz'
    WHEN 'boolean'   THEN 'boolean'
    WHEN 'uuid'      THEN 'uuid'
    WHEN 'picklist'  THEN 'text'   -- values live in picklist_values, added via the picklist editor
    WHEN 'lookup'    THEN 'uuid'
    ELSE NULL
  END;
  IF v_pgtype IS NULL THEN
    RAISE EXCEPTION 'Unsupported data type: %', p_data_type USING ERRCODE='invalid_parameter_value';
  END IF;

  IF p_financial_tier NOT IN (1,2,3) THEN
    RAISE EXCEPTION 'financial_tier must be 1, 2, or 3' USING ERRCODE='invalid_parameter_value';
  END IF;

  -- Build and run the ALTER. Identifiers are validated above; use format/%I.
  IF p_data_type = 'lookup' THEN
    IF p_fk_table IS NULL THEN
      RAISE EXCEPTION 'lookup field requires p_fk_table' USING ERRCODE='invalid_parameter_value';
    END IF;
    SELECT EXISTS (
      SELECT 1 FROM pg_catalog.pg_class c
      JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
      WHERE n.nspname='public' AND c.relname=p_fk_table AND c.relkind='r'
    ) INTO v_exists;
    IF NOT v_exists THEN
      RAISE EXCEPTION 'Unknown lookup target table: %', p_fk_table USING ERRCODE='invalid_parameter_value';
    END IF;
    v_sql := format('ALTER TABLE public.%I ADD COLUMN %I uuid REFERENCES public.%I(id)', p_object, v_col, p_fk_table);
  ELSE
    v_sql := format('ALTER TABLE public.%I ADD COLUMN %I %s', p_object, v_col, v_pgtype);
  END IF;
  EXECUTE v_sql;

  SELECT id INTO v_user FROM public.users WHERE auth_user_id = auth.uid();

  INSERT INTO public.field_metadata (
    fm_record_number, fm_object, fm_column, fm_label, fm_help_text, fm_description,
    fm_example_value, fm_financial_tier, fm_track_history, fm_data_type, fm_is_custom,
    fm_created_by, fm_updated_by
  ) VALUES (
    '', p_object, v_col, COALESCE(NULLIF(btrim(p_label),''), v_col), p_help_text, p_description,
    p_example_value, p_financial_tier, p_track_history, p_data_type, true,
    v_user, v_user
  );

  RETURN jsonb_build_object('ok', true, 'object', p_object, 'column', v_col, 'pg_type', v_pgtype, 'data_type', p_data_type);
END; $function$
;

CREATE OR REPLACE FUNCTION public.admin_disable_record_create_dispatch(p_object text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_trig text := format('zz_flow_record_create_%s', p_object);
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Admin only' USING ERRCODE='insufficient_privilege';
  END IF;
  EXECUTE format('DROP TRIGGER IF EXISTS %I ON public.%I', v_trig, p_object);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_empty_recycle_bin()
 RETURNS TABLE(purged_total bigint, passes integer, blocked_remaining bigint)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_is_admin boolean := public.app_is_admin();
  r record;
  v_flag text;
  v_id uuid;
  v_purged bigint := 0;
  v_pass int := 0;
  v_changed bigint;
  v_remaining bigint := 0;
BEGIN
  IF NOT v_is_admin THEN
    RAISE EXCEPTION 'admin_empty_recycle_bin: admin role required' USING ERRCODE='42501';
  END IF;

  -- up to 12 passes; each pass purges every currently-purgeable soft-deleted row.
  -- rows blocked by a not-yet-purged child clear on a later pass once the child goes.
  FOR v_pass IN 1..12 LOOP
    v_changed := 0;
    FOR r IN
      SELECT c.table_name AS tn, c.column_name AS cc
      FROM information_schema.columns c
      JOIN information_schema.tables t
        ON t.table_schema=c.table_schema AND t.table_name=c.table_name AND t.table_type='BASE TABLE'
      WHERE c.table_schema='public' AND c.column_name LIKE '%is_deleted'
    LOOP
      FOR v_id IN
        EXECUTE format('SELECT id FROM public.%I WHERE %I IS TRUE', r.tn, r.cc)
      LOOP
        BEGIN
          PERFORM public.purge_record(r.tn, v_id);
          v_purged := v_purged + 1;
          v_changed := v_changed + 1;
        EXCEPTION
          WHEN foreign_key_violation THEN NULL;  -- still has a child; next pass
          WHEN others THEN NULL;                  -- table not metadata-registered etc.; skip
        END;
      END LOOP;
    END LOOP;
    EXIT WHEN v_changed = 0;
  END LOOP;

  -- count anything still soft-deleted (genuinely blocked)
  FOR r IN
    SELECT c.table_name AS tn, c.column_name AS cc
    FROM information_schema.columns c
    JOIN information_schema.tables t
      ON t.table_schema=c.table_schema AND t.table_name=c.table_name AND t.table_type='BASE TABLE'
    WHERE c.table_schema='public' AND c.column_name LIKE '%is_deleted'
  LOOP
    EXECUTE format('SELECT count(*) FROM public.%I WHERE %I IS TRUE', r.tn, r.cc) INTO v_changed;
    v_remaining := v_remaining + v_changed;
  END LOOP;

  purged_total := v_purged; passes := v_pass; blocked_remaining := v_remaining;
  RETURN NEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_enable_record_create_dispatch(p_object text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_trig text := format('zz_flow_record_create_%s', p_object);
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Admin only' USING ERRCODE='insufficient_privilege';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.tables
                 WHERE table_schema='public' AND table_name=p_object) THEN
    RAISE EXCEPTION 'Unknown table %', p_object;
  END IF;
  IF NOT EXISTS (
    SELECT 1 FROM pg_trigger t JOIN pg_class c ON c.oid=t.tgrelid
    WHERE c.relname=p_object AND t.tgname=v_trig
  ) THEN
    EXECUTE format(
      'CREATE TRIGGER %I AFTER INSERT ON public.%I FOR EACH ROW EXECUTE FUNCTION public.trg_dispatch_record_create()',
      v_trig, p_object);
  END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_health_summary()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller          uuid := public.current_app_user_id();
  v_audit_24h       integer;
  v_recycle_total   integer;
  v_active_users    integer;
  v_perm_sets       integer;
  v_last_dispatch   timestamptz;
  v_dispatch_errs   integer;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'admin_health_summary: must be authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT count(*) INTO v_audit_24h FROM public.audit_log
  WHERE al_performed_at > now() - interval '24 hours';

  -- Curated recycle-bin total: matches RECYCLE_BIN_TABLES in
  -- src/modules/admin/SetupHome.jsx (29 tables).
  v_recycle_total := COALESCE((
    SELECT sum(c) FROM (
      -- Primary business objects
      SELECT count(*) AS c FROM public.projects                WHERE project_is_deleted UNION ALL
      SELECT count(*)      FROM public.opportunities           WHERE opportunity_is_deleted UNION ALL
      SELECT count(*)      FROM public.work_orders             WHERE work_order_is_deleted UNION ALL
      SELECT count(*)      FROM public.properties              WHERE property_is_deleted UNION ALL
      SELECT count(*)      FROM public.buildings               WHERE building_is_deleted UNION ALL
      SELECT count(*)      FROM public.units                   WHERE unit_is_deleted UNION ALL
      SELECT count(*)      FROM public.accounts                WHERE account_is_deleted UNION ALL
      SELECT count(*)      FROM public.contacts                WHERE contact_is_deleted UNION ALL
      SELECT count(*)      FROM public.assessments             WHERE assessment_is_deleted UNION ALL
      SELECT count(*)      FROM public.incentive_applications  WHERE ia_is_deleted UNION ALL
      SELECT count(*)      FROM public.incentives              WHERE incentive_is_deleted UNION ALL
      SELECT count(*)      FROM public.project_payment_requests WHERE is_deleted UNION ALL
      SELECT count(*)      FROM public.payment_receipts        WHERE is_deleted UNION ALL
      SELECT count(*)      FROM public.documents               WHERE is_deleted UNION ALL
      -- Configuration / builder objects
      SELECT count(*)      FROM public.work_types              WHERE work_type_is_deleted UNION ALL
      SELECT count(*)      FROM public.work_plan_templates     WHERE wpt_is_deleted UNION ALL
      SELECT count(*)      FROM public.work_step_templates     WHERE wst_is_deleted UNION ALL
      SELECT count(*)      FROM public.programs                WHERE is_deleted UNION ALL
      SELECT count(*)      FROM public.price_books             WHERE price_book_is_deleted UNION ALL
      SELECT count(*)      FROM public.products                WHERE product_is_deleted UNION ALL
      SELECT count(*)      FROM public.document_templates      WHERE is_deleted UNION ALL
      SELECT count(*)      FROM public.email_templates         WHERE is_deleted UNION ALL
      SELECT count(*)      FROM public.project_report_templates WHERE prt_is_deleted UNION ALL
      -- Reports module
      SELECT count(*)      FROM public.reports                 WHERE is_deleted UNION ALL
      SELECT count(*)      FROM public.dashboards              WHERE is_deleted UNION ALL
      SELECT count(*)      FROM public.scheduled_reports       WHERE is_deleted UNION ALL
      -- Permission Builder
      SELECT count(*)      FROM public.permission_sets         WHERE ps_is_deleted UNION ALL
      -- Field operations
      SELECT count(*)      FROM public.vehicles                WHERE vehicle_is_deleted UNION ALL
      SELECT count(*)      FROM public.equipment               WHERE equipment_is_deleted UNION ALL
      SELECT count(*)      FROM public.job_kits                WHERE is_deleted
    ) s
  ), 0)::integer;

  SELECT count(*) INTO v_active_users FROM public.users WHERE NOT user_is_deleted;
  SELECT count(*) INTO v_perm_sets    FROM public.permission_sets
    WHERE NOT ps_is_deleted AND ps_is_active;

  SELECT max(srr_started_at) INTO v_last_dispatch
    FROM public.scheduled_report_runs;
  SELECT count(*) INTO v_dispatch_errs FROM public.scheduled_report_runs
    WHERE srr_started_at > now() - interval '24 hours'
      AND srr_status = 'error';

  RETURN jsonb_build_object(
    'audit_24h',           v_audit_24h,
    'recycle_bin_total',   v_recycle_total,
    'active_users',        v_active_users,
    'permission_sets',     v_perm_sets,
    'last_dispatch',       v_last_dispatch,
    'dispatch_errors_24h', v_dispatch_errs,
    'generated_at',        now()
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.admin_upsert_field_metadata(p_object text, p_column text, p_label text, p_help_text text DEFAULT NULL::text, p_description text DEFAULT NULL::text, p_example_value text DEFAULT NULL::text, p_financial_tier integer DEFAULT 1, p_track_history boolean DEFAULT false)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user uuid;
  v_exists boolean;
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Editing field metadata is admin-only' USING ERRCODE='insufficient_privilege';
  END IF;
  IF p_financial_tier NOT IN (1,2,3) THEN
    RAISE EXCEPTION 'financial_tier must be 1, 2, or 3' USING ERRCODE='invalid_parameter_value';
  END IF;
  -- Confirm the column actually exists on the object.
  SELECT EXISTS (
    SELECT 1 FROM pg_catalog.pg_attribute a
    JOIN pg_catalog.pg_class c ON c.oid = a.attrelid
    JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname='public' AND c.relname=p_object AND a.attname=p_column AND a.attnum>0 AND NOT a.attisdropped
  ) INTO v_exists;
  IF NOT v_exists THEN
    RAISE EXCEPTION 'Column % does not exist on %', p_column, p_object USING ERRCODE='invalid_parameter_value';
  END IF;

  SELECT id INTO v_user FROM public.users WHERE auth_user_id = auth.uid();

  INSERT INTO public.field_metadata (
    fm_record_number, fm_object, fm_column, fm_label, fm_help_text, fm_description,
    fm_example_value, fm_financial_tier, fm_track_history, fm_created_by, fm_updated_by
  ) VALUES (
    '', p_object, p_column, COALESCE(NULLIF(btrim(p_label),''), p_column), p_help_text, p_description,
    p_example_value, p_financial_tier, p_track_history, v_user, v_user
  )
  ON CONFLICT (fm_object, fm_column) DO UPDATE SET
    fm_label         = COALESCE(NULLIF(btrim(EXCLUDED.fm_label),''), field_metadata.fm_label),
    fm_help_text     = EXCLUDED.fm_help_text,
    fm_description   = EXCLUDED.fm_description,
    fm_example_value = EXCLUDED.fm_example_value,
    fm_financial_tier= EXCLUDED.fm_financial_tier,
    fm_track_history = EXCLUDED.fm_track_history,
    fm_updated_by    = v_user,
    fm_updated_at    = now();

  RETURN jsonb_build_object('ok', true, 'object', p_object, 'column', p_column);
END; $function$
;

CREATE OR REPLACE FUNCTION public.app_can_see_work_order(p_wo_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT public.app_is_office_side()
      OR EXISTS (
        SELECT 1 FROM public.work_orders wo
        WHERE wo.id = p_wo_id
          AND wo.assigned_technician_id = public.current_app_user_id()
      )
      OR EXISTS (
        SELECT 1
        FROM public.service_appointments sa
        JOIN public.service_appointment_assignments saa
          ON saa.service_appointment_id = sa.id
        WHERE sa.work_order_id = p_wo_id
          AND saa.saa_user_id = public.current_app_user_id()
          AND COALESCE(saa.saa_is_deleted, false) = false
      );
$function$
;

CREATE OR REPLACE FUNCTION public.app_current_contact_id()
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT c.id
  FROM public.contacts c
  JOIN public.users u ON u.id = c.contact_user_id
  WHERE u.auth_user_id = auth.uid()
    AND u.user_is_active = true
    AND COALESCE(c.contact_is_deleted, false) = false
  LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.app_current_role_name()
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT r.role_name
  FROM public.users u
  JOIN public.roles r ON r.id = u.role_id
  WHERE u.auth_user_id = auth.uid()
    AND u.user_is_active = true
  LIMIT 1;
$function$
;

