CREATE OR REPLACE FUNCTION public.app_user_can(p_object text, p_action text)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id uuid;
  v_role_id uuid;
  v_role_name text;
  v_has boolean;
BEGIN
  IF p_action NOT IN ('read','create','update','delete') THEN
    RETURN false;
  END IF;

  SELECT u.id, u.role_id, r.role_name
    INTO v_user_id, v_role_id, v_role_name
  FROM public.users u
  LEFT JOIN public.roles r ON r.id = u.role_id
  WHERE u.auth_user_id = auth.uid();

  IF v_user_id IS NULL THEN RETURN false; END IF;

  -- Admin always wins, regardless of seeded rows
  IF v_role_name = 'Admin' THEN RETURN true; END IF;

  -- Role baseline
  EXECUTE format(
    'SELECT %I FROM public.role_object_access WHERE roa_role_id = $1 AND roa_object_name = $2',
    'roa_' || p_action
  ) INTO v_has USING v_role_id, p_object;
  IF COALESCE(v_has, false) THEN RETURN true; END IF;

  -- Permission set additive grants
  EXECUTE format(
    'SELECT bool_or(%I)
       FROM public.permission_set_object_access psoa
       JOIN public.user_permission_sets ups
         ON ups.ups_permission_set_id = psoa.psoa_permission_set_id
      WHERE ups.ups_user_id = $1 AND psoa.psoa_object_name = $2',
    'psoa_' || p_action
  ) INTO v_has USING v_user_id, p_object;

  RETURN COALESCE(v_has, false);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.app_user_dashboard_folder_access(p_folder_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id     uuid;
  v_role_id     uuid;
  v_role_name   text;
  v_level_rank  int := 0;
  v_best        text;
  v_levels      text[] := ARRAY['viewer','editor','manager'];
  v_check_rank  int;
BEGIN
  SELECT u.id, u.role_id, r.role_name
    INTO v_user_id, v_role_id, v_role_name
  FROM public.users u
  LEFT JOIN public.roles r ON r.id = u.role_id
  WHERE u.auth_user_id = auth.uid();

  IF v_user_id IS NULL THEN RETURN NULL; END IF;
  IF v_role_name = 'Admin' THEN RETURN 'manager'; END IF;

  IF EXISTS (SELECT 1 FROM public.dashboard_folders
             WHERE id = p_folder_id AND df_owner_user_id = v_user_id AND is_deleted = false) THEN
    RETURN 'manager';
  END IF;

  IF EXISTS (SELECT 1 FROM public.dashboard_folders
             WHERE id = p_folder_id AND df_is_public = true AND is_deleted = false) THEN
    v_best := 'viewer';
    v_level_rank := 1;
  END IF;

  SELECT dfus_access_level INTO v_best
  FROM public.dashboard_folder_user_shares
  WHERE dfus_folder_id = p_folder_id AND dfus_user_id = v_user_id AND is_deleted = false
  ORDER BY array_position(v_levels, dfus_access_level) DESC
  LIMIT 1;
  IF v_best IS NOT NULL THEN
    v_check_rank := array_position(v_levels, v_best);
    IF v_check_rank > v_level_rank THEN v_level_rank := v_check_rank; END IF;
  END IF;

  SELECT dfrs_access_level INTO v_best
  FROM public.dashboard_folder_role_shares
  WHERE dfrs_folder_id = p_folder_id AND dfrs_role_id = v_role_id AND is_deleted = false
  ORDER BY array_position(v_levels, dfrs_access_level) DESC
  LIMIT 1;
  IF v_best IS NOT NULL THEN
    v_check_rank := array_position(v_levels, v_best);
    IF v_check_rank > v_level_rank THEN v_level_rank := v_check_rank; END IF;
  END IF;

  IF v_level_rank = 0 THEN RETURN NULL; END IF;
  RETURN v_levels[v_level_rank];
END;
$function$
;

CREATE OR REPLACE FUNCTION public.app_user_field_editable(p_object text, p_field text)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id uuid;
  v_role_id uuid;
  v_role_name text;
  v_role_editable boolean;
  v_pset_editable boolean;
BEGIN
  SELECT u.id, u.role_id, r.role_name
    INTO v_user_id, v_role_id, v_role_name
  FROM public.users u
  LEFT JOIN public.roles r ON r.id = u.role_id
  WHERE u.auth_user_id = auth.uid();

  IF v_user_id IS NULL THEN RETURN false; END IF;
  IF v_role_name = 'Admin' THEN RETURN true; END IF;

  SELECT fp_editable INTO v_role_editable
  FROM public.field_permissions
  WHERE fp_role_id = v_role_id AND fp_object = p_object AND fp_field = p_field;

  SELECT bool_and(psfp.psfp_editable) INTO v_pset_editable
  FROM public.permission_set_field_permissions psfp
  JOIN public.user_permission_sets ups
    ON ups.ups_permission_set_id = psfp.psfp_permission_set_id
  WHERE ups.ups_user_id = v_user_id
    AND psfp.psfp_object = p_object
    AND psfp.psfp_field = p_field;

  IF v_pset_editable IS NOT NULL THEN
    RETURN v_pset_editable;
  END IF;

  -- A field that isn't visible cannot be editable; if visible default and no row, allow edit
  RETURN COALESCE(v_role_editable, true);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.app_user_field_permissions(p_object text, p_fields text[])
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id uuid;
  v_role_id uuid;
  v_role_name text;
  v_result jsonb := '{}'::jsonb;
  v_field text;
  v_role_visible boolean;
  v_role_editable boolean;
  v_pset_visible boolean;
  v_pset_editable boolean;
  v_visible boolean;
  v_editable boolean;
BEGIN
  IF p_fields IS NULL OR array_length(p_fields, 1) IS NULL THEN
    RETURN '{}'::jsonb;
  END IF;

  SELECT u.id, u.role_id, r.role_name
    INTO v_user_id, v_role_id, v_role_name
  FROM public.users u
  LEFT JOIN public.roles r ON r.id = u.role_id
  WHERE u.auth_user_id = auth.uid();

  -- No app-level user row → return empty (caller should treat as fully hidden).
  IF v_user_id IS NULL THEN
    RETURN '{}'::jsonb;
  END IF;

  -- Admin short-circuit: every requested field is visible + editable.
  IF v_role_name = 'Admin' THEN
    FOREACH v_field IN ARRAY p_fields LOOP
      v_result := v_result || jsonb_build_object(
        v_field, jsonb_build_object('visible', true, 'editable', true)
      );
    END LOOP;
    RETURN v_result;
  END IF;

  FOREACH v_field IN ARRAY p_fields LOOP
    -- Role baseline (NULL when no row exists)
    SELECT fp_visible, fp_editable
      INTO v_role_visible, v_role_editable
    FROM public.field_permissions
    WHERE fp_role_id = v_role_id
      AND fp_object = p_object
      AND fp_field  = v_field;

    -- Pset overrides — if any rows exist, most restrictive wins
    SELECT bool_and(psfp.psfp_visible), bool_and(psfp.psfp_editable)
      INTO v_pset_visible, v_pset_editable
    FROM public.permission_set_field_permissions psfp
    JOIN public.user_permission_sets ups
      ON ups.ups_permission_set_id = psfp.psfp_permission_set_id
    WHERE ups.ups_user_id = v_user_id
      AND psfp.psfp_object = p_object
      AND psfp.psfp_field  = v_field;

    -- Visibility: pset override wins if present, else role, else default true
    IF v_pset_visible IS NOT NULL THEN
      v_visible := v_pset_visible;
    ELSE
      v_visible := COALESCE(v_role_visible, true);
    END IF;

    -- Editability: pset override wins if present, else role, else default true.
    -- Hidden fields are not editable regardless.
    IF v_pset_editable IS NOT NULL THEN
      v_editable := v_pset_editable;
    ELSE
      v_editable := COALESCE(v_role_editable, true);
    END IF;
    IF NOT v_visible THEN v_editable := false; END IF;

    v_result := v_result || jsonb_build_object(
      v_field, jsonb_build_object('visible', v_visible, 'editable', v_editable)
    );
  END LOOP;

  RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.app_user_field_visible(p_object text, p_field text)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id uuid;
  v_role_id uuid;
  v_role_name text;
  v_role_visible boolean;
  v_pset_visible boolean;
BEGIN
  SELECT u.id, u.role_id, r.role_name
    INTO v_user_id, v_role_id, v_role_name
  FROM public.users u
  LEFT JOIN public.roles r ON r.id = u.role_id
  WHERE u.auth_user_id = auth.uid();

  IF v_user_id IS NULL THEN RETURN false; END IF;
  IF v_role_name = 'Admin' THEN RETURN true; END IF;

  -- Role baseline (NULL when no row exists)
  SELECT fp_visible INTO v_role_visible
  FROM public.field_permissions
  WHERE fp_role_id = v_role_id AND fp_object = p_object AND fp_field = p_field;

  -- Permission set overrides — if any exist, most restrictive wins
  SELECT bool_and(psfp.psfp_visible) INTO v_pset_visible
  FROM public.permission_set_field_permissions psfp
  JOIN public.user_permission_sets ups
    ON ups.ups_permission_set_id = psfp.psfp_permission_set_id
  WHERE ups.ups_user_id = v_user_id
    AND psfp.psfp_object = p_object
    AND psfp.psfp_field = p_field;

  IF v_pset_visible IS NOT NULL THEN
    RETURN v_pset_visible;
  END IF;

  -- No pset override; fall back to role; default visible if no rows anywhere
  RETURN COALESCE(v_role_visible, true);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.app_user_folder_access(p_folder_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id     uuid;
  v_role_id     uuid;
  v_role_name   text;
  v_level_rank  int := 0;
  v_best        text;
  v_levels      text[] := ARRAY['viewer','editor','manager'];
  v_check_rank  int;
BEGIN
  SELECT u.id, u.role_id, r.role_name
    INTO v_user_id, v_role_id, v_role_name
  FROM public.users u
  LEFT JOIN public.roles r ON r.id = u.role_id
  WHERE u.auth_user_id = auth.uid();

  IF v_user_id IS NULL THEN RETURN NULL; END IF;
  IF v_role_name = 'Admin' THEN RETURN 'manager'; END IF;

  -- Owner check
  IF EXISTS (SELECT 1 FROM public.report_folders
             WHERE id = p_folder_id AND rf_owner_user_id = v_user_id AND is_deleted = false) THEN
    RETURN 'manager';
  END IF;

  -- Public flag → at least viewer
  IF EXISTS (SELECT 1 FROM public.report_folders
             WHERE id = p_folder_id AND rf_is_public = true AND is_deleted = false) THEN
    v_best := 'viewer';
    v_level_rank := 1;
  END IF;

  -- User shares
  SELECT rfus_access_level INTO v_best
  FROM public.report_folder_user_shares
  WHERE rfus_folder_id = p_folder_id AND rfus_user_id = v_user_id AND is_deleted = false
  ORDER BY array_position(v_levels, rfus_access_level) DESC
  LIMIT 1;
  IF v_best IS NOT NULL THEN
    v_check_rank := array_position(v_levels, v_best);
    IF v_check_rank > v_level_rank THEN v_level_rank := v_check_rank; END IF;
  END IF;

  -- Role shares — pick the highest level granted to any of the user's roles.
  -- (Future: when permission_set-based role membership lands, expand this.)
  SELECT rfrs_access_level INTO v_best
  FROM public.report_folder_role_shares
  WHERE rfrs_folder_id = p_folder_id AND rfrs_role_id = v_role_id AND is_deleted = false
  ORDER BY array_position(v_levels, rfrs_access_level) DESC
  LIMIT 1;
  IF v_best IS NOT NULL THEN
    v_check_rank := array_position(v_levels, v_best);
    IF v_check_rank > v_level_rank THEN v_level_rank := v_check_rank; END IF;
  END IF;

  IF v_level_rank = 0 THEN RETURN NULL; END IF;
  RETURN v_levels[v_level_rank];
END;
$function$
;

CREATE OR REPLACE FUNCTION public.app_user_in_scope(p_object text, p_record_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id      uuid;
  v_role_id      uuid;
  v_role_name    text;
  v_is_portal    boolean;
  v_account_ids  uuid[];
  v_property_ids uuid[];
  v_program_ids  uuid[];
  v_match        boolean;
BEGIN
  SELECT u.id, u.role_id, r.role_name
    INTO v_user_id, v_role_id, v_role_name
  FROM public.users u
  LEFT JOIN public.roles r ON r.id = u.role_id
  WHERE u.auth_user_id = auth.uid();

  IF v_user_id IS NULL THEN RETURN false; END IF;
  IF v_role_name = 'Admin' THEN RETURN true; END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.portal_role_assignments
    WHERE pra_role_id = v_role_id AND is_deleted = false
  ) INTO v_is_portal;

  -- Internal staff bypass scope checks
  IF NOT v_is_portal THEN RETURN true; END IF;

  SELECT array_agg(DISTINCT uas_account_id)
    INTO v_account_ids
  FROM public.user_account_scopes
  WHERE uas_user_id = v_user_id AND is_deleted = false;

  SELECT array_agg(DISTINCT uas_property_id)
    INTO v_property_ids
  FROM public.user_account_scopes
  WHERE uas_user_id = v_user_id AND is_deleted = false
    AND uas_property_id IS NOT NULL;

  SELECT array_agg(DISTINCT ups_program_id)
    INTO v_program_ids
  FROM public.user_program_scopes
  WHERE ups_user_id = v_user_id AND is_deleted = false;

  CASE p_object

    WHEN 'accounts' THEN
      RETURN p_record_id = ANY(COALESCE(v_account_ids, ARRAY[]::uuid[]));

    WHEN 'contacts' THEN
      SELECT EXISTS (
        SELECT 1 FROM public.contacts c
        WHERE c.id = p_record_id
          AND c.contact_account_id = ANY(COALESCE(v_account_ids, ARRAY[]::uuid[]))
      ) INTO v_match;
      RETURN COALESCE(v_match, false);

    WHEN 'properties' THEN
      -- Match if: property is explicitly scoped, OR its account is scoped
      -- account-wide (no property narrowing on that scope row).
      SELECT EXISTS (
        SELECT 1 FROM public.properties p
        WHERE p.id = p_record_id
          AND (
            p.id = ANY(COALESCE(v_property_ids, ARRAY[]::uuid[]))
            OR EXISTS (
              SELECT 1 FROM public.user_account_scopes uas
              WHERE uas.uas_user_id = v_user_id
                AND uas.is_deleted = false
                AND uas.uas_property_id IS NULL
                AND uas.uas_account_id = p.property_account_id
            )
          )
      ) INTO v_match;
      RETURN COALESCE(v_match, false);

    WHEN 'buildings' THEN
      -- buildings.property_id → properties
      SELECT EXISTS (
        SELECT 1 FROM public.buildings b
        WHERE b.id = p_record_id
          AND public.app_user_in_scope('properties', b.property_id)
      ) INTO v_match;
      RETURN COALESCE(v_match, false);

    WHEN 'units' THEN
      -- units.building_id → buildings.property_id → properties
      SELECT EXISTS (
        SELECT 1 FROM public.units u
        JOIN public.buildings b ON b.id = u.building_id
        WHERE u.id = p_record_id
          AND public.app_user_in_scope('properties', b.property_id)
      ) INTO v_match;
      RETURN COALESCE(v_match, false);

    WHEN 'projects' THEN
      -- projects.property_id → properties (also has account_id, but property is the canonical path)
      SELECT EXISTS (
        SELECT 1 FROM public.projects pr
        WHERE pr.id = p_record_id
          AND pr.property_id IS NOT NULL
          AND public.app_user_in_scope('properties', pr.property_id)
      ) INTO v_match;
      RETURN COALESCE(v_match, false);

    WHEN 'work_orders' THEN
      -- Direct property_id on work_orders — short-circuit, no project recursion needed
      SELECT EXISTS (
        SELECT 1 FROM public.work_orders wo
        WHERE wo.id = p_record_id
          AND wo.property_id IS NOT NULL
          AND public.app_user_in_scope('properties', wo.property_id)
      ) INTO v_match;
      RETURN COALESCE(v_match, false);

    WHEN 'incentive_applications' THEN
      -- Direct property_id on incentive_applications too
      SELECT EXISTS (
        SELECT 1 FROM public.incentive_applications ia
        WHERE ia.id = p_record_id
          AND ia.property_id IS NOT NULL
          AND public.app_user_in_scope('properties', ia.property_id)
      ) INTO v_match;
      RETURN COALESCE(v_match, false);

    WHEN 'programs' THEN
      RETURN p_record_id = ANY(COALESCE(v_program_ids, ARRAY[]::uuid[]));

    ELSE
      -- Object not yet taught: fail closed for portal users
      RETURN false;

  END CASE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.apply_sql_from_url(p_url text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  resp      record;
  body_text text;
  sess      text := session_user;
begin
  -- Allow if the calling SESSION is a trusted backend role (Supabase
  -- MCP, edge functions, service_role JWT). Otherwise require the
  -- JWT-presenting caller to resolve to an admin user. Anon and
  -- non-admin authenticated callers fail both checks.
  if sess not in ('postgres', 'service_role') and not (select is_admin()) then
    raise exception 'apply_sql_from_url: admin only (session=%)', sess;
  end if;

  select * into resp from extensions.http_get(p_url);
  if resp.status <> 200 then
    raise exception 'apply_sql_from_url: HTTP % fetching %', resp.status, p_url;
  end if;
  body_text := resp.content;
  execute body_text;
  return format('applied %s bytes from %s', length(body_text), p_url);
end;
$function$
;

CREATE OR REPLACE FUNCTION public.appointments_for_resource_in_window(p_contact_id uuid, p_window_start timestamp with time zone, p_window_end timestamp with time zone)
 RETURNS TABLE(start_iso text, end_iso text, address_street text, address_city text, address_state text, address_zip text)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT sa.sa_scheduled_start_time::text AS start_iso,
         sa.sa_scheduled_end_time::text   AS end_iso,
         NULL::text AS address_street,
         NULL::text AS address_city,
         NULL::text AS address_state,
         NULL::text AS address_zip
  FROM service_appointments sa
  JOIN service_appointment_assignments saa
       ON saa.service_appointment_id = sa.id
      AND saa.contact_id              = p_contact_id
      AND saa.saa_is_deleted          = false
  LEFT JOIN picklist_values pv ON pv.id = sa.sa_status
  WHERE sa.sa_is_deleted = false
    AND sa.sa_scheduled_start_time IS NOT NULL
    AND sa.sa_scheduled_end_time   IS NOT NULL
    AND sa.sa_scheduled_start_time <  p_window_end
    AND sa.sa_scheduled_end_time   >  p_window_start
    AND (pv.picklist_value IS NULL OR pv.picklist_value NOT IN ('canceled','no_show'))
  ORDER BY sa.sa_scheduled_start_time;
$function$
;

CREATE OR REPLACE FUNCTION public.archive_document_template(p_document_template_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller      uuid := public.current_app_user_id();
  v_current     text;
  v_archived_id uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'archive_document_template: must be authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT public._dt_status_value(status) INTO v_current
  FROM public.document_templates WHERE id = p_document_template_id AND NOT is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'archive_document_template: template not found';
  END IF;
  IF v_current = 'Archived' THEN
    RAISE EXCEPTION 'archive_document_template: template is already Archived';
  END IF;

  SELECT id INTO v_archived_id FROM public.picklist_values
  WHERE picklist_object='document_templates' AND picklist_field='status'
    AND picklist_value='Archived' AND picklist_is_active=true LIMIT 1;

  UPDATE public.document_templates
  SET status = v_archived_id, updated_by = v_caller, updated_at = now()
  WHERE id = p_document_template_id;

  RETURN jsonb_build_object('ok', true, 'document_template_id', p_document_template_id, 'new_status', 'Archived');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.archive_email_template(p_email_template_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller      uuid := public.current_app_user_id();
  v_current     text;
  v_archived_id uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'archive_email_template: must be authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT public._et_status_value(status) INTO v_current
  FROM public.email_templates WHERE id = p_email_template_id AND NOT is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'archive_email_template: template not found';
  END IF;
  IF v_current = 'Archived' THEN
    RAISE EXCEPTION 'archive_email_template: template is already Archived';
  END IF;

  SELECT id INTO v_archived_id FROM public.picklist_values
  WHERE picklist_object='email_templates' AND picklist_field='status'
    AND picklist_value='Archived' AND picklist_is_active=true LIMIT 1;

  UPDATE public.email_templates
  SET status = v_archived_id, updated_by = v_caller, updated_at = now()
  WHERE id = p_email_template_id;

  RETURN jsonb_build_object('ok', true, 'email_template_id', p_email_template_id, 'new_status', 'Archived');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.archive_flow(p_flow_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF NOT app_user_can('flows','update') THEN RAISE EXCEPTION 'No update permission on flows'; END IF;
  UPDATE public.flows SET flow_status='archived', updated_by=current_app_user_id()
   WHERE id=p_flow_id AND is_deleted=false;
  RETURN jsonb_build_object('ok',true);
END; $function$
;

CREATE OR REPLACE FUNCTION public.archive_project_report_template(p_prt_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller uuid := public.current_app_user_id();
  v_current text;
  v_archived_id uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'archive: must be authenticated as a registered user' USING ERRCODE = '42501';
  END IF;

  SELECT _prt_status_value(prt_status) INTO v_current
  FROM project_report_templates
  WHERE id = p_prt_id AND NOT prt_is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'archive: template not found';
  END IF;
  IF v_current = 'Archived' THEN
    RAISE EXCEPTION 'archive: template is already Archived';
  END IF;

  SELECT id INTO v_archived_id
  FROM picklist_values
  WHERE picklist_object='project_report_templates'
    AND picklist_field='prt_status'
    AND picklist_value='Archived'
    AND picklist_is_active=true
  LIMIT 1;
  IF v_archived_id IS NULL THEN
    RAISE EXCEPTION 'archive: Archived status not configured';
  END IF;

  UPDATE project_report_templates SET
    prt_status = v_archived_id,
    prt_is_default_for_unmapped = false,
    prt_updated_by = v_caller,
    prt_updated_at = now()
  WHERE id = p_prt_id;

  RETURN jsonb_build_object('ok', true, 'prt_id', p_prt_id, 'new_status', 'Archived');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.attach_lifecycle_dispatcher(p_object text, p_status_field text)
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_trigger_name text := format('trg_lifecycle_dispatch_%s', p_status_field);
BEGIN
  EXECUTE format('DROP TRIGGER IF EXISTS %I ON public.%I', v_trigger_name, p_object);
  EXECUTE format(
    'CREATE TRIGGER %I BEFORE UPDATE ON public.%I
       FOR EACH ROW EXECUTE FUNCTION public.lifecycle_field_dispatcher(%L)',
    v_trigger_name, p_object, p_status_field
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.audit_page_layout_fields()
 RETURNS TABLE(object_name text, page_layout_name text, widget_title text, widget_type text, field_name text, declared_type text, db_type text, child_table text, child_column text, issue text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  -- ─── 1. field_group widget audit (preserved exactly) ──────────────────
  with field_expand as (
    select
      pl.page_layout_object as object_name,
      pl.page_layout_name,
      plw.widget_title,
      'field_group'::text as widget_type,
      (fld->>'name')      as field_name,
      (fld->>'type')      as declared_type,
      coalesce(fld->>'lookup_table','') as lookup_table
    from public.page_layouts pl
    join public.page_layout_widgets plw on plw.page_layout_id = pl.id
    cross join lateral jsonb_array_elements(plw.widget_config->'fields') fld
    where plw.widget_type = 'field_group'
      and coalesce(pl.is_deleted, false)  = false
      and coalesce(plw.is_deleted, false) = false
  ),
  field_group_issues as (
    select
      f.object_name, f.page_layout_name, f.widget_title, f.widget_type,
      f.field_name, f.declared_type,
      c.data_type as db_type,
      null::text  as child_table,
      null::text  as child_column,
      case
        when f.field_name is null                                               then 'NULL_FIELD_NAME'
        when c.data_type is null                                                then 'COLUMN_NOT_FOUND'
        when f.declared_type = 'lookup' and (f.lookup_table is null or f.lookup_table = '')
                                                                                then 'LOOKUP_MISSING_TABLE'
        when f.declared_type = 'picklist' and c.data_type <> 'uuid'             then 'PICKLIST_BUT_DB_IS_' || upper(c.data_type)
        when f.declared_type not in ('datetime','date') and c.data_type like 'timestamp%'
                                                                                then 'NON_DATETIME_BUT_DB_IS_TIMESTAMP'
        when f.declared_type <> 'boolean' and c.data_type = 'boolean'           then 'NON_BOOLEAN_BUT_DB_IS_BOOLEAN'
        when f.declared_type in ('text','email','phone','textarea') and c.data_type = 'uuid'
                                                                                then 'TEXT_BUT_DB_IS_UUID'
        else null
      end as issue
    from field_expand f
    left join information_schema.columns c
      on c.table_schema='public'
     and c.table_name=f.object_name
     and c.column_name=f.field_name
  ),
  -- ─── 2. related_list widget audit (new) ──────────────────────────────
  rl as (
    select pl.page_layout_object as parent_table,
           pl.page_layout_name   as page_layout_name,
           plw.widget_title,
           plw.widget_config->>'table' as child_table,
           plw.widget_config->>'fk'    as fk_column,
           plw.widget_config->'columns' as cols
    from public.page_layouts pl
    join public.page_layout_widgets plw on plw.page_layout_id = pl.id
    where plw.widget_type = 'related_list'
      and coalesce(pl.is_deleted, false)  = false
      and coalesce(plw.is_deleted, false) = false
  ),
  rl_table_issues as (
    select
      rl.parent_table       as object_name,
      rl.page_layout_name,
      rl.widget_title,
      'related_list'::text  as widget_type,
      null::text            as field_name,
      null::text            as declared_type,
      null::text            as db_type,
      rl.child_table,
      null::text            as child_column,
      'RELATED_LIST_TABLE_MISSING'::text as issue
    from rl
    left join information_schema.tables t
      on t.table_schema='public' and t.table_name = rl.child_table
    where t.table_name is null and rl.child_table is not null
  ),
  rl_fk_issues as (
    select
      rl.parent_table       as object_name,
      rl.page_layout_name,
      rl.widget_title,
      'related_list'::text  as widget_type,
      rl.fk_column          as field_name,
      null::text            as declared_type,
      null::text            as db_type,
      rl.child_table,
      rl.fk_column          as child_column,
      'RELATED_LIST_FK_MISSING'::text as issue
    from rl
    join information_schema.tables t
      on t.table_schema='public' and t.table_name = rl.child_table
    left join information_schema.columns c
      on c.table_schema='public' and c.table_name = rl.child_table and c.column_name = rl.fk_column
    where c.column_name is null and rl.fk_column is not null and rl.fk_column <> ''
  ),
  rl_col_issues as (
    select
      rl.parent_table       as object_name,
      rl.page_layout_name,
      rl.widget_title,
      'related_list'::text  as widget_type,
      (col_spec->>'name')   as field_name,
      null::text            as declared_type,
      null::text            as db_type,
      rl.child_table,
      (col_spec->>'name')   as child_column,
      'RELATED_LIST_COLUMN_MISSING'::text as issue
    from rl
    join information_schema.tables t
      on t.table_schema='public' and t.table_name = rl.child_table
    cross join lateral jsonb_array_elements(coalesce(rl.cols,'[]'::jsonb)) col_spec
    left join information_schema.columns c
      on c.table_schema='public' and c.table_name = rl.child_table and c.column_name = (col_spec->>'name')
    where c.column_name is null
      and (col_spec->>'name') is not null
      and (col_spec->>'name') <> ''
  )
  select * from field_group_issues where issue is not null
  union all
  select * from rl_table_issues
  union all
  select * from rl_fk_issues
  union all
  select * from rl_col_issues
$function$
;

CREATE OR REPLACE FUNCTION public.audit_rls_unhoisted_function_calls()
 RETURNS TABLE(table_name text, policy_name text, cmd text, clause text, unhoisted_call text, expr_snippet text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  with bad_policies as (
    select
      c.relname  as table_name,
      p.polname  as policy_name,
      case p.polcmd
        when 'r' then 'SELECT' when 'a' then 'INSERT'
        when 'w' then 'UPDATE' when 'd' then 'DELETE'
        when '*' then 'ALL'
      end                                      as cmd,
      pg_get_expr(p.polqual,      p.polrelid)  as using_expr,
      pg_get_expr(p.polwithcheck, p.polrelid)  as check_expr
    from pg_policy p
    join pg_class     c on c.oid = p.polrelid
    join pg_namespace n on n.oid = c.relnamespace
    where n.nspname = 'public'
  ),
  -- Per-function detector. Match the function name preceded by something
  -- that's NOT `.` or alphanumeric (so we don't match `m.is_admin` or
  -- `someother_is_admin` as a column accessor). The bare-call pattern
  -- requires the function call NOT to be preceded by `SELECT `.
  function_names(fn_name) as (
    values
      ('app_user_can'),
      ('current_app_user_id'),
      ('is_admin'),
      ('has_communications_view_all')
  ),
  -- For auth.uid we have to special-case since it has a `.` namespace.
  using_violations as (
    select bp.table_name, bp.policy_name, bp.cmd, 'USING'::text as clause,
           fn.fn_name as unhoisted_call,
           substring(bp.using_expr for 200) as expr_snippet
    from bad_policies bp
    cross join function_names fn
    where bp.using_expr is not null
      and bp.using_expr ~ ('(^|[^.a-zA-Z_])' || fn.fn_name || '\(')
      and bp.using_expr !~ ('SELECT ' || fn.fn_name || '\(')
    union all
    select bp.table_name, bp.policy_name, bp.cmd, 'USING'::text as clause,
           'auth.uid' as unhoisted_call,
           substring(bp.using_expr for 200) as expr_snippet
    from bad_policies bp
    where bp.using_expr is not null
      and bp.using_expr ~ 'auth\.uid\(\)'
      and bp.using_expr !~ 'SELECT auth\.uid\(\)'
  ),
  check_violations as (
    select bp.table_name, bp.policy_name, bp.cmd, 'WITH CHECK'::text as clause,
           fn.fn_name as unhoisted_call,
           substring(bp.check_expr for 200) as expr_snippet
    from bad_policies bp
    cross join function_names fn
    where bp.check_expr is not null
      and bp.check_expr ~ ('(^|[^.a-zA-Z_])' || fn.fn_name || '\(')
      and bp.check_expr !~ ('SELECT ' || fn.fn_name || '\(')
    union all
    select bp.table_name, bp.policy_name, bp.cmd, 'WITH CHECK'::text as clause,
           'auth.uid' as unhoisted_call,
           substring(bp.check_expr for 200) as expr_snippet
    from bad_policies bp
    where bp.check_expr is not null
      and bp.check_expr ~ 'auth\.uid\(\)'
      and bp.check_expr !~ 'SELECT auth\.uid\(\)'
  )
  select * from using_violations
  union all
  select * from check_violations
$function$
;

CREATE OR REPLACE FUNCTION public.audit_soft_delete_audit_gaps()
 RETURNS TABLE(table_name text, record_id uuid, has_deleted_at boolean, has_deleted_by boolean, deletion_reason text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  select 'properties'::text, id,
         property_deleted_at is not null, property_deleted_by is not null,
         property_deletion_reason
  from public.properties
  where property_is_deleted = true
    and (property_deleted_at is null or property_deleted_by is null)
  union all
  select 'opportunities', id,
         opportunity_deleted_at is not null, opportunity_deleted_by is not null,
         opportunity_deletion_reason
  from public.opportunities
  where opportunity_is_deleted = true
    and (opportunity_deleted_at is null or opportunity_deleted_by is null)
  union all
  select 'contacts', id,
         contact_deleted_at is not null, contact_deleted_by is not null,
         contact_deletion_reason
  from public.contacts
  where contact_is_deleted = true
    and (contact_deleted_at is null or contact_deleted_by is null)
  union all
  select 'projects', id,
         project_deleted_at is not null, project_deleted_by is not null,
         project_deletion_reason
  from public.projects
  where project_is_deleted = true
    and (project_deleted_at is null or project_deleted_by is null)
  union all
  select 'work_orders', id,
         work_order_deleted_at is not null, work_order_deleted_by is not null,
         work_order_deletion_reason
  from public.work_orders
  where work_order_is_deleted = true
    and (work_order_deleted_at is null or work_order_deleted_by is null)
  union all
  select 'accounts', id,
         account_deleted_at is not null, account_deleted_by is not null,
         account_deletion_reason
  from public.accounts
  where account_is_deleted = true
    and (account_deleted_at is null or account_deleted_by is null)
  union all
  select 'units', id,
         unit_deleted_at is not null, unit_deleted_by is not null,
         unit_deletion_reason
  from public.units
  where unit_is_deleted = true
    and (unit_deleted_at is null or unit_deleted_by is null)
  union all
  select 'buildings', id,
         building_deleted_at is not null, building_deleted_by is not null,
         building_deletion_reason
  from public.buildings
  where building_is_deleted = true
    and (building_deleted_at is null or building_deleted_by is null)
$function$
;

CREATE OR REPLACE FUNCTION public.block_hard_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  -- Allow hard delete when purge_seed_data() has set the bypass flag
  -- for the current session.
  IF current_setting('leap.allow_hard_delete', true) = 'seed_purge' THEN
    RETURN OLD;
  END IF;
  RAISE EXCEPTION 'Hard deletes are not permitted in LEAP. Use soft delete (set is_deleted = true with a deletion_reason). Record: % on table: %', OLD.id, TG_TABLE_NAME;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.bulk_reschedule_work_orders(p_project_id uuid, p_work_order_ids uuid[], p_team_lead_contact_id uuid, p_start_date date, p_end_date date, p_daily_start_time time without time zone, p_daily_end_time time without time zone, p_lunch_start time without time zone, p_lunch_end time without time zone, p_inter_wo_buffer_minutes integer, p_timezone text, p_commit boolean, p_pinned_placements jsonb, p_inter_property_buffer_minutes integer, p_team_lead_user_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(work_order_id uuid, work_order_record_number text, work_order_name text, work_type_name text, building_name text, unit_name text, duration_minutes numeric, scheduled boolean, scheduled_start text, scheduled_end text, service_appointment_id uuid, service_appointment_record_number text, placement_error text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_sa_scheduled_id  uuid;
  v_blocking_count   integer;
  v_blocking_sample  text;
  v_caller_id        uuid;
BEGIN
  IF p_project_id IS NULL THEN
    RAISE EXCEPTION 'p_project_id is required' USING ERRCODE='22023';
  END IF;
  IF p_work_order_ids IS NULL OR array_length(p_work_order_ids,1) IS NULL THEN
    RAISE EXCEPTION 'p_work_order_ids must contain at least one work order' USING ERRCODE='22023';
  END IF;

  v_caller_id := public.current_app_user_id();
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'caller not mapped to a public.users row' USING ERRCODE='28000';
  END IF;

  SELECT id INTO v_sa_scheduled_id FROM picklist_values
   WHERE picklist_object='service_appointments'
     AND picklist_field='sa_status'
     AND picklist_value='Scheduled'
     AND picklist_is_active=true;
  IF v_sa_scheduled_id IS NULL THEN
    RAISE EXCEPTION 'picklist value service_appointments.sa_status=Scheduled missing' USING ERRCODE='P0001';
  END IF;

  -- Refuse to touch WOs with active SAs past the Scheduled state.
  SELECT count(*),
         string_agg(DISTINCT wo.work_order_record_number, ', ' ORDER BY wo.work_order_record_number)
    INTO v_blocking_count, v_blocking_sample
    FROM service_appointments sa
    JOIN work_orders wo ON wo.id = sa.work_order_id
   WHERE sa.work_order_id = ANY (p_work_order_ids)
     AND coalesce(sa.sa_is_deleted, false) = false
     AND (sa.sa_status IS NULL OR sa.sa_status <> v_sa_scheduled_id);

  IF v_blocking_count > 0 THEN
    RAISE EXCEPTION 'cannot reschedule — % work order(s) have appointments past the Scheduled state: %',
      v_blocking_count, v_blocking_sample
      USING ERRCODE='P0001';
  END IF;

  -- Only mutate when committing; a dry run (p_commit=false) should not cancel
  -- the existing schedule.
  IF p_commit THEN
    UPDATE service_appointment_assignments saa
       SET saa_is_deleted      = true,
           saa_deleted_at      = now(),
           saa_deleted_by      = v_caller_id,
           saa_deletion_reason = 'rescheduled',
           saa_updated_at      = now(),
           saa_updated_by      = v_caller_id
      FROM service_appointments sa
     WHERE saa.service_appointment_id = sa.id
       AND coalesce(saa.saa_is_deleted, false) = false
       AND sa.work_order_id = ANY (p_work_order_ids)
       AND coalesce(sa.sa_is_deleted, false) = false
       AND sa.sa_status = v_sa_scheduled_id;

    UPDATE service_appointments
       SET sa_is_deleted      = true,
           sa_deleted_at      = now(),
           sa_deleted_by      = v_caller_id,
           sa_deletion_reason = 'rescheduled',
           sa_updated_at      = now(),
           sa_updated_by      = v_caller_id
     WHERE work_order_id = ANY (p_work_order_ids)
       AND coalesce(sa_is_deleted, false) = false
       AND sa_status = v_sa_scheduled_id;

    UPDATE work_orders
       SET work_order_status = (SELECT id FROM picklist_values
                                WHERE picklist_object='work_orders'
                                  AND picklist_field='work_order_status'
                                  AND picklist_value='To Be Scheduled'
                                  AND picklist_is_active=true),
           work_order_updated_at = now(),
           work_order_updated_by = v_caller_id
     WHERE id = ANY (p_work_order_ids)
       AND coalesce(work_order_is_deleted, false) = false;
  END IF;

  RETURN QUERY
    SELECT * FROM public.bulk_schedule_work_orders(
      p_project_id                    => p_project_id,
      p_work_order_ids                => p_work_order_ids,
      p_team_lead_contact_id          => p_team_lead_contact_id,
      p_start_date                    => p_start_date,
      p_end_date                      => p_end_date,
      p_daily_start_time              => p_daily_start_time,
      p_daily_end_time                => p_daily_end_time,
      p_lunch_start                   => p_lunch_start,
      p_lunch_end                     => p_lunch_end,
      p_inter_wo_buffer_minutes       => p_inter_wo_buffer_minutes,
      p_timezone                      => p_timezone,
      p_commit                        => p_commit,
      p_pinned_placements             => p_pinned_placements,
      p_inter_property_buffer_minutes => p_inter_property_buffer_minutes,
      p_team_lead_user_id             => p_team_lead_user_id
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.bulk_schedule_work_orders(p_project_id uuid, p_work_order_ids uuid[], p_team_lead_contact_id uuid, p_start_date date, p_end_date date, p_daily_start_time time without time zone, p_daily_end_time time without time zone, p_lunch_start time without time zone, p_lunch_end time without time zone, p_inter_wo_buffer_minutes integer, p_timezone text, p_commit boolean, p_pinned_placements jsonb, p_inter_property_buffer_minutes integer, p_team_lead_user_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(work_order_id uuid, work_order_record_number text, work_order_name text, work_type_name text, building_name text, unit_name text, duration_minutes numeric, scheduled boolean, scheduled_start text, scheduled_end text, service_appointment_id uuid, service_appointment_record_number text, placement_error text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller_id              uuid;
  v_lead_title             text;
  v_lead_is_user           boolean;
  v_lock_key               text;
  v_sa_scheduled_id        uuid;
  v_sa_canceled_id         uuid;
  v_wo_scheduled_id        uuid;
  v_wo_to_be_scheduled_id  uuid;
  v_day                    date;
  v_period_starts          timestamptz[];
  v_period_ends            timestamptz[];
  v_placed_starts          timestamptz[];
  v_placed_ends            timestamptz[];
  v_placed_sa_ids          uuid[];
  v_placed_sa_record_nums  text[];
  v_placement_errors       text[];
  v_wo_unit_ids            uuid[];
  v_wo_property_ids        uuid[];
  v_wo_post_buffers        integer[];
  v_wo_count               integer;
  v_wo_is_pinned           boolean[];
  v_wo_pin_forced          boolean[];
  v_pin                    record;
  v_pin_idx                integer;
  v_pin_start              timestamptz;
  v_pin_end                timestamptz;
  v_pin_duration           numeric;
  v_pin_day_local          date;
  v_pin_local_start        time;
  v_pin_local_end          time;
  v_pin_overlaps           boolean;
  v_other_idx              integer;
  i                        integer;
  m                        integer;
  v_duration               numeric;
  v_duration_interval      interval;
  v_buffer_after_interval  interval;
  v_buffer_after_minutes   integer;
  v_next_unit_id           uuid;
  v_next_property_id       uuid;
  v_property_drive_minutes integer;
  v_fit_idx                integer;
  v_placement_start        timestamptz;
  v_placement_end          timestamptz;
  v_period_count           integer;
  k                        integer;
  v_conflict               record;
  v_new_starts             timestamptz[];
  v_new_ends               timestamptz[];
  j                        integer;
  v_ps                     timestamptz;
  v_pe                     timestamptz;
  v_new_sa_id              uuid;
  v_new_sa_rn              text;
  v_wo_row                 record;
  v_sa_name                text;
  v_missing_certs          text;
BEGIN
  v_caller_id := public.current_app_user_id();
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'bulk_schedule_work_orders: caller not authenticated' USING ERRCODE = '28000';
  END IF;

  SELECT id INTO v_sa_scheduled_id FROM picklist_values
   WHERE picklist_object='service_appointments' AND picklist_field='sa_status'
     AND picklist_value='Scheduled' AND picklist_is_active=true;
  SELECT id INTO v_sa_canceled_id FROM picklist_values
   WHERE picklist_object='service_appointments' AND picklist_field='sa_status'
     AND picklist_value='Canceled' AND picklist_is_active=true;
  SELECT id INTO v_wo_scheduled_id FROM picklist_values
   WHERE picklist_object='work_orders' AND picklist_field='work_order_status'
     AND picklist_value='Scheduled' AND picklist_is_active=true;
  SELECT id INTO v_wo_to_be_scheduled_id FROM picklist_values
   WHERE picklist_object='work_orders' AND picklist_field='work_order_status'
     AND picklist_value='To Be Scheduled' AND picklist_is_active=true;

  IF v_sa_scheduled_id IS NULL OR v_wo_scheduled_id IS NULL OR v_wo_to_be_scheduled_id IS NULL THEN
    RAISE EXCEPTION 'required picklist value(s) missing' USING ERRCODE = 'P0001';
  END IF;
  IF p_project_id IS NULL THEN RAISE EXCEPTION 'p_project_id is required' USING ERRCODE='22023'; END IF;
  IF p_work_order_ids IS NULL OR array_length(p_work_order_ids,1) IS NULL THEN
    RAISE EXCEPTION 'p_work_order_ids must contain at least one work order' USING ERRCODE='22023';
  END IF;

  -- Exactly one lead resource (contact OR user).
  IF (p_team_lead_contact_id IS NOT NULL AND p_team_lead_user_id IS NOT NULL)
     OR (p_team_lead_contact_id IS NULL AND p_team_lead_user_id IS NULL) THEN
    RAISE EXCEPTION 'exactly one of p_team_lead_contact_id or p_team_lead_user_id is required' USING ERRCODE='22023';
  END IF;
  v_lead_is_user := (p_team_lead_user_id IS NOT NULL);

  IF p_start_date IS NULL OR p_end_date IS NULL OR p_start_date > p_end_date THEN
    RAISE EXCEPTION 'p_start_date must be <= p_end_date' USING ERRCODE='22023';
  END IF;
  IF p_daily_start_time >= p_lunch_start OR p_lunch_start > p_lunch_end OR p_lunch_end >= p_daily_end_time THEN
    RAISE EXCEPTION 'daily/lunch boundary order invalid' USING ERRCODE='22023';
  END IF;
  IF p_inter_wo_buffer_minutes < 0 THEN RAISE EXCEPTION 'p_inter_wo_buffer_minutes must be >= 0' USING ERRCODE='22023'; END IF;
  IF p_inter_property_buffer_minutes < 0 THEN RAISE EXCEPTION 'p_inter_property_buffer_minutes must be >= 0' USING ERRCODE='22023'; END IF;

  PERFORM 1 FROM projects WHERE id=p_project_id AND project_is_deleted=false;
  IF NOT FOUND THEN RAISE EXCEPTION 'project % not found or deleted', p_project_id USING ERRCODE='P0002'; END IF;

  -- Validate the lead exists + is a Team Lead, from whichever source.
  IF v_lead_is_user THEN
    SELECT u.user_title INTO v_lead_title
      FROM users u
      JOIN roles r ON r.id = u.role_id
     WHERE u.id = p_team_lead_user_id AND u.user_is_deleted = false AND u.user_is_active = true
       AND r.role_name = 'Team Lead';
    IF NOT FOUND THEN
      RAISE EXCEPTION 'team lead user % not found, inactive, or not in the Team Lead role', p_team_lead_user_id USING ERRCODE='P0002';
    END IF;
    v_lock_key := 'user:' || p_team_lead_user_id::text;
  ELSE
    SELECT contact_title INTO v_lead_title FROM contacts
     WHERE id=p_team_lead_contact_id AND contact_is_deleted=false;
    IF NOT FOUND THEN RAISE EXCEPTION 'team lead contact % not found or deleted', p_team_lead_contact_id USING ERRCODE='P0002'; END IF;
    IF v_lead_title IS NULL OR v_lead_title NOT ILIKE '%team lead%' THEN
      RAISE EXCEPTION 'contact % is not a Team Lead (title: %)', p_team_lead_contact_id, COALESCE(v_lead_title,'(null)') USING ERRCODE='P0001';
    END IF;
    v_lock_key := 'contact:' || p_team_lead_contact_id::text;
  END IF;

  -- SKILLS / CERT GATE — only for contact leads. User-resource certifications
  -- are not tracked in contact_certifications yet, so we explicitly skip the
  -- gate for user leads rather than silently treating them as qualified.
  IF NOT v_lead_is_user THEN
    SELECT string_agg(DISTINCT cert.certification_name, ', ' ORDER BY cert.certification_name)
      INTO v_missing_certs
      FROM unnest(p_work_order_ids) AS uw(wo_id)
      JOIN work_orders wo ON wo.id = uw.wo_id
      JOIN work_type_required_certifications wtrc
        ON wtrc.work_type_id = wo.work_type_id AND wtrc.wtrc_is_deleted = false
      JOIN certifications cert
        ON cert.id = wtrc.certification_id
       AND COALESCE(cert.certification_is_active, true) = true
       AND COALESCE(cert.certification_is_deleted, false) = false
      WHERE NOT EXISTS (
        SELECT 1 FROM contact_certifications cc
         WHERE cc.contact_id = p_team_lead_contact_id
           AND cc.certification_id = cert.id
           AND COALESCE(cc.cc_is_deleted, false) = false
           AND (cc.cc_expires_date IS NULL OR cc.cc_expires_date >= p_start_date)
      );
    IF v_missing_certs IS NOT NULL AND v_missing_certs <> '' THEN
      RAISE EXCEPTION 'team lead is missing required certification(s) for one or more work types in this batch: %', v_missing_certs
        USING ERRCODE='P0001';
    END IF;
  END IF;

  PERFORM 1 FROM unnest(p_work_order_ids) AS x(id)
    WHERE NOT EXISTS (
      SELECT 1 FROM work_orders wo
       WHERE wo.id = x.id AND wo.project_id = p_project_id
         AND wo.work_order_is_deleted = false
         AND wo.work_order_status = v_wo_to_be_scheduled_id
    );
  IF FOUND THEN
    RAISE EXCEPTION 'one or more work orders are missing, deleted, on a different project, or not in ''To Be Scheduled'' status' USING ERRCODE='P0001';
  END IF;

  v_wo_count := array_length(p_work_order_ids, 1);
  v_placed_starts         := array_fill(NULL::timestamptz, ARRAY[v_wo_count]);
  v_placed_ends           := array_fill(NULL::timestamptz, ARRAY[v_wo_count]);
  v_placed_sa_ids         := array_fill(NULL::uuid,        ARRAY[v_wo_count]);
  v_placed_sa_record_nums := array_fill(NULL::text,        ARRAY[v_wo_count]);
  v_placement_errors      := array_fill(NULL::text,        ARRAY[v_wo_count]);
  v_wo_is_pinned          := array_fill(false,             ARRAY[v_wo_count]);
  v_wo_pin_forced         := array_fill(false,             ARRAY[v_wo_count]);

  SELECT array_agg(unit_id     ORDER BY idx),
         array_agg(property_id ORDER BY idx),
         array_agg(pb           ORDER BY idx)
    INTO v_wo_unit_ids, v_wo_property_ids, v_wo_post_buffers
    FROM (
      SELECT gs.idx, wo.unit_id, b.property_id,
             COALESCE(wt.work_type_post_buffer_minutes, p_inter_wo_buffer_minutes) AS pb
        FROM generate_subscripts(p_work_order_ids, 1) AS gs(idx)
        JOIN work_orders wo ON wo.id = p_work_order_ids[gs.idx]
        JOIN buildings   b  ON b.id  = wo.building_id
        JOIN work_types  wt ON wt.id = wo.work_type_id
    ) s;

  IF jsonb_array_length(p_pinned_placements) > 0 THEN
    FOR v_pin IN
      SELECT (pin->>'work_order_id')::uuid AS wo_id,
             (pin->>'start_ts')::timestamptz AS start_ts,
             COALESCE((pin->>'force')::boolean, false) AS forced
        FROM jsonb_array_elements(p_pinned_placements) AS pin
    LOOP
      v_pin_idx := NULL;
      FOR i IN 1..v_wo_count LOOP
        IF p_work_order_ids[i] = v_pin.wo_id THEN v_pin_idx := i; EXIT; END IF;
      END LOOP;
      IF v_pin_idx IS NULL THEN CONTINUE; END IF;

      SELECT COALESCE(wo.work_order_duration_minutes, wt.work_type_duration_minutes)
        INTO v_pin_duration
        FROM work_orders wo JOIN work_types wt ON wt.id = wo.work_type_id
       WHERE wo.id = v_pin.wo_id;
      IF v_pin_duration IS NULL OR v_pin_duration <= 0 THEN
        v_placement_errors[v_pin_idx] := 'duration_not_set';
        v_wo_is_pinned[v_pin_idx] := true; CONTINUE;
      END IF;

      v_pin_start := v_pin.start_ts;
      v_pin_end   := v_pin_start + make_interval(mins => v_pin_duration::integer);
      v_pin_day_local := (v_pin_start AT TIME ZONE p_timezone)::date;
      v_pin_local_start := (v_pin_start AT TIME ZONE p_timezone)::time;
      v_pin_local_end   := (v_pin_end   AT TIME ZONE p_timezone)::time;

      IF NOT v_pin.forced THEN
        IF v_pin_day_local < p_start_date OR v_pin_day_local > p_end_date
           OR EXTRACT(DOW FROM v_pin_day_local) IN (0, 6)
           OR v_pin_local_start < p_daily_start_time
           OR v_pin_local_end   > p_daily_end_time
           OR (v_pin_local_start < p_lunch_end AND v_pin_local_end > p_lunch_start)
           OR (v_pin_start AT TIME ZONE p_timezone)::date <> ((v_pin_end - interval '1 second') AT TIME ZONE p_timezone)::date
        THEN
          v_placement_errors[v_pin_idx] := 'pin_outside_working_hours';
          v_wo_is_pinned[v_pin_idx] := true; CONTINUE;
        END IF;
      END IF;

      v_pin_overlaps := false;
      FOR v_other_idx IN 1..v_wo_count LOOP
        IF v_wo_is_pinned[v_other_idx] AND v_placed_starts[v_other_idx] IS NOT NULL
           AND v_placed_ends[v_other_idx] > v_pin_start AND v_placed_starts[v_other_idx] < v_pin_end
        THEN v_pin_overlaps := true; EXIT; END IF;
      END LOOP;
      IF v_pin_overlaps THEN
        v_placement_errors[v_pin_idx] := 'pin_overlaps_existing';
        v_wo_is_pinned[v_pin_idx] := true; CONTINUE;
      END IF;

      v_placed_starts[v_pin_idx] := v_pin_start;
      v_placed_ends[v_pin_idx]   := v_pin_end;
      v_wo_is_pinned[v_pin_idx]  := true;
      v_wo_pin_forced[v_pin_idx] := v_pin.forced;
    END LOOP;
  END IF;

  IF p_commit THEN PERFORM pg_advisory_xact_lock(hashtextextended(v_lock_key, 0)); END IF;

  v_day := p_start_date;
  WHILE v_day <= p_end_date LOOP
    IF EXTRACT(DOW FROM v_day) NOT IN (0, 6) THEN
      v_period_starts := ARRAY[
        (v_day::text || ' ' || p_daily_start_time::text)::timestamp AT TIME ZONE p_timezone,
        (v_day::text || ' ' || p_lunch_end::text)::timestamp        AT TIME ZONE p_timezone
      ];
      v_period_ends := ARRAY[
        (v_day::text || ' ' || p_lunch_start::text)::timestamp      AT TIME ZONE p_timezone,
        (v_day::text || ' ' || p_daily_end_time::text)::timestamp   AT TIME ZONE p_timezone
      ];

      FOR v_conflict IN
        SELECT sa.sa_scheduled_start_time AS conflict_start, sa.sa_scheduled_end_time AS conflict_end
          FROM service_appointments sa
          JOIN service_appointment_assignments saa
            ON saa.service_appointment_id = sa.id AND saa.saa_is_deleted = false
         WHERE ((v_lead_is_user AND saa.saa_user_id = p_team_lead_user_id)
                OR (NOT v_lead_is_user AND saa.contact_id = p_team_lead_contact_id))
           AND sa.sa_is_deleted = false
           AND sa.sa_scheduled_start_time IS NOT NULL
           AND sa.sa_scheduled_end_time   IS NOT NULL
           AND sa.sa_scheduled_end_time   > v_period_starts[1]
           AND sa.sa_scheduled_start_time < v_period_ends[2]
           AND (v_sa_canceled_id IS NULL OR sa.sa_status IS DISTINCT FROM v_sa_canceled_id)
        UNION ALL
        SELECT ra.ra_start_datetime, ra.ra_end_datetime
          FROM resource_absences ra
         WHERE ((v_lead_is_user AND ra.ra_user_id = p_team_lead_user_id)
                OR (NOT v_lead_is_user AND ra.contact_id = p_team_lead_contact_id))
           AND COALESCE(ra.ra_is_deleted, false) = false
           AND ra.ra_end_datetime   > v_period_starts[1]
           AND ra.ra_start_datetime < v_period_ends[2]
        UNION ALL
        SELECT v_placed_starts[gs.i], v_placed_ends[gs.i]
          FROM generate_subscripts(v_placed_starts, 1) AS gs(i)
         WHERE v_wo_is_pinned[gs.i] = true
           AND v_placed_starts[gs.i] IS NOT NULL
           AND v_placed_ends[gs.i]   > v_period_starts[1]
           AND v_placed_starts[gs.i] < v_period_ends[2]
        ORDER BY 1
      LOOP
        v_new_starts := ARRAY[]::timestamptz[];
        v_new_ends   := ARRAY[]::timestamptz[];
        FOR j IN 1..COALESCE(array_length(v_period_starts,1),0) LOOP
          v_ps := v_period_starts[j]; v_pe := v_period_ends[j];
          IF v_conflict.conflict_end <= v_ps OR v_conflict.conflict_start >= v_pe THEN
            v_new_starts := v_new_starts || v_ps; v_new_ends := v_new_ends || v_pe;
          ELSE
            IF v_conflict.conflict_start > v_ps THEN
              v_new_starts := v_new_starts || v_ps; v_new_ends := v_new_ends || v_conflict.conflict_start;
            END IF;
            IF v_conflict.conflict_end < v_pe THEN
              v_new_starts := v_new_starts || v_conflict.conflict_end; v_new_ends := v_new_ends || v_pe;
            END IF;
          END IF;
        END LOOP;
        v_period_starts := v_new_starts; v_period_ends := v_new_ends;
        EXIT WHEN COALESCE(array_length(v_period_starts,1),0) = 0;
      END LOOP;

      FOR i IN 1..v_wo_count LOOP
        CONTINUE WHEN v_placed_starts[i]    IS NOT NULL;
        CONTINUE WHEN v_placement_errors[i] IS NOT NULL;

        SELECT COALESCE(wo.work_order_duration_minutes, wt.work_type_duration_minutes)
          INTO v_duration
          FROM work_orders wo JOIN work_types wt ON wt.id = wo.work_type_id
         WHERE wo.id = p_work_order_ids[i];
        IF v_duration IS NULL OR v_duration <= 0 THEN
          v_placement_errors[i] := 'duration_not_set'; CONTINUE;
        END IF;
        v_duration_interval := make_interval(mins => v_duration::integer);

        v_fit_idx := NULL;
        v_period_count := COALESCE(array_length(v_period_starts,1), 0);
        FOR k IN 1..v_period_count LOOP
          IF (v_period_ends[k] - v_period_starts[k]) >= v_duration_interval THEN
            v_fit_idx := k; EXIT;
          END IF;
        END LOOP;

        IF v_fit_idx IS NOT NULL THEN
          v_placement_start := v_period_starts[v_fit_idx];
          v_placement_end   := v_placement_start + v_duration_interval;
          v_placed_starts[i] := v_placement_start;
          v_placed_ends[i]   := v_placement_end;

          v_next_unit_id := NULL;
          v_next_property_id := NULL;
          FOR m IN i+1..v_wo_count LOOP
            IF v_placed_starts[m] IS NULL AND v_placement_errors[m] IS NULL AND NOT v_wo_is_pinned[m] THEN
              v_next_unit_id := v_wo_unit_ids[m];
              v_next_property_id := v_wo_property_ids[m];
              EXIT;
            END IF;
          END LOOP;

          IF v_next_unit_id IS NULL THEN
            v_buffer_after_minutes := 0;
          ELSIF v_next_unit_id = v_wo_unit_ids[i] THEN
            v_buffer_after_minutes := 0;
          ELSIF v_next_property_id IS NOT NULL
                AND v_wo_property_ids[i] IS NOT NULL
                AND v_next_property_id <> v_wo_property_ids[i] THEN
            v_property_drive_minutes := NULL;
            SELECT pd_drive_minutes INTO v_property_drive_minutes
              FROM property_distances
             WHERE origin_property_id = v_wo_property_ids[i]
               AND destination_property_id = v_next_property_id
               AND pd_is_deleted = false
             LIMIT 1;
            v_buffer_after_minutes := COALESCE(v_property_drive_minutes, p_inter_property_buffer_minutes);
          ELSE
            v_buffer_after_minutes := COALESCE(v_wo_post_buffers[i], p_inter_wo_buffer_minutes);
          END IF;
          v_buffer_after_interval := make_interval(mins => v_buffer_after_minutes);

          v_period_starts[v_fit_idx] := v_placement_end + v_buffer_after_interval;
          IF v_period_starts[v_fit_idx] >= v_period_ends[v_fit_idx] THEN
            v_period_starts := v_period_starts[1:v_fit_idx-1] || v_period_starts[v_fit_idx+1:array_length(v_period_starts,1)];
            v_period_ends   := v_period_ends[1:v_fit_idx-1]   || v_period_ends[v_fit_idx+1:array_length(v_period_ends,1)];
          END IF;
        END IF;
      END LOOP;
    END IF;
    v_day := v_day + 1;
  END LOOP;

  FOR i IN 1..v_wo_count LOOP
    IF v_placed_starts[i] IS NULL AND v_placement_errors[i] IS NULL THEN
      v_placement_errors[i] := 'no_capacity_in_window';
    END IF;
  END LOOP;

  IF p_commit THEN
    FOR i IN 1..v_wo_count LOOP
      CONTINUE WHEN v_placed_starts[i] IS NULL;
      CONTINUE WHEN v_placement_errors[i] IS NOT NULL;
      SELECT wo.id AS wo_id, wo.opportunity_id, wo.work_type_id AS wt_id,
             wt.work_type_name AS wt_name, b.building_name AS b_name, u.unit_name AS u_name
        INTO v_wo_row
        FROM work_orders wo
        JOIN work_types wt ON wt.id = wo.work_type_id
        JOIN buildings  b  ON b.id  = wo.building_id
        JOIN units      u  ON u.id  = wo.unit_id
       WHERE wo.id = p_work_order_ids[i];

      v_sa_name := COALESCE(v_wo_row.wt_name,'Work') || ' — ' || COALESCE(v_wo_row.b_name,'') ||
                   CASE WHEN v_wo_row.u_name IS NOT NULL THEN ' / ' || v_wo_row.u_name ELSE '' END;

      INSERT INTO service_appointments (
        sa_record_number, sa_name, sa_owner, sa_created_by,
        work_order_id, work_type_id, opportunity_id, project_id,
        sa_status, sa_scheduled_start_time, sa_scheduled_end_time, sa_duration_minutes
      ) VALUES (
        '', v_sa_name, v_caller_id, v_caller_id,
        p_work_order_ids[i], v_wo_row.wt_id, v_wo_row.opportunity_id, p_project_id,
        v_sa_scheduled_id, v_placed_starts[i], v_placed_ends[i],
        EXTRACT(EPOCH FROM (v_placed_ends[i] - v_placed_starts[i])) / 60.0
      )
      RETURNING id, sa_record_number INTO v_new_sa_id, v_new_sa_rn;

      INSERT INTO service_appointment_assignments (
        saa_record_number, saa_name, saa_created_by, service_appointment_id,
        contact_id, saa_user_id
      ) VALUES (
        '', v_sa_name || ' — Team Lead', v_caller_id, v_new_sa_id,
        CASE WHEN v_lead_is_user THEN NULL ELSE p_team_lead_contact_id END,
        CASE WHEN v_lead_is_user THEN p_team_lead_user_id ELSE NULL END
      );

      UPDATE work_orders SET
        work_order_status = v_wo_scheduled_id,
        work_order_scheduled_start_date = (v_placed_starts[i] AT TIME ZONE p_timezone)::date,
        work_order_scheduled_start_time = (v_placed_starts[i] AT TIME ZONE p_timezone)::time,
        work_order_updated_by = v_caller_id, work_order_updated_at = now()
       WHERE id = p_work_order_ids[i];

      v_placed_sa_ids[i]         := v_new_sa_id;
      v_placed_sa_record_nums[i] := v_new_sa_rn;
    END LOOP;
  END IF;

  RETURN QUERY
    SELECT p_work_order_ids[gs.idx], wo.work_order_record_number, wo.work_order_name,
           wt.work_type_name, b.building_name, u.unit_name,
           COALESCE(wo.work_order_duration_minutes, wt.work_type_duration_minutes),
           (v_placed_starts[gs.idx] IS NOT NULL AND v_placement_errors[gs.idx] IS NULL),
           CASE WHEN v_placed_starts[gs.idx] IS NOT NULL AND v_placement_errors[gs.idx] IS NULL
                THEN to_char(v_placed_starts[gs.idx] AT TIME ZONE p_timezone, 'YYYY-MM-DD"T"HH24:MI:SS') END,
           CASE WHEN v_placed_ends[gs.idx] IS NOT NULL AND v_placement_errors[gs.idx] IS NULL
                THEN to_char(v_placed_ends[gs.idx]   AT TIME ZONE p_timezone, 'YYYY-MM-DD"T"HH24:MI:SS') END,
           v_placed_sa_ids[gs.idx], v_placed_sa_record_nums[gs.idx], v_placement_errors[gs.idx]
      FROM generate_subscripts(p_work_order_ids, 1) AS gs(idx)
      JOIN work_orders wo ON wo.id = p_work_order_ids[gs.idx]
      JOIN work_types  wt ON wt.id = wo.work_type_id
      JOIN buildings   b  ON b.id  = wo.building_id
      JOIN units       u  ON u.id  = wo.unit_id
     ORDER BY gs.idx;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.bulk_soft_delete_properties(p_state text DEFAULT NULL::text)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE n integer;
BEGIN
  UPDATE public.properties
  SET property_is_deleted = true,
      property_updated_by = 'c5a01ec8-960f-42ab-8a9e-a49822de89af',
      property_updated_at = now()
  WHERE property_is_deleted IS NOT TRUE
    AND (p_state IS NULL OR property_state = p_state);
  GET DIAGNOSTICS n = ROW_COUNT;
  RETURN n;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.bulk_update_records(p_table text, p_record_ids uuid[], p_updates jsonb, p_actor_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_total        int := COALESCE(array_length(p_record_ids, 1), 0);
  v_updated      int := 0;
  v_errored      int := 0;
  v_errors       jsonb := '[]'::jsonb;
  v_record_id    uuid;
  v_prefix       text;
  v_set_clause   text := '';
  v_key          text;
  v_col_exists   boolean;
  v_update_sql   text;
  v_error_msg    text;
  v_audit_updater_col text;
  v_audit_at_col text;
BEGIN
  IF p_table IS NULL OR p_table = '' THEN
    RAISE EXCEPTION 'p_table is required';
  END IF;
  IF v_total = 0 THEN
    RAISE EXCEPTION 'p_record_ids must contain at least one UUID';
  END IF;
  IF p_updates IS NULL OR jsonb_typeof(p_updates) <> 'object' THEN
    RAISE EXCEPTION 'p_updates must be a JSON object';
  END IF;
  IF jsonb_object_keys_count(p_updates) IS NOT NULL AND
     (SELECT COUNT(*) FROM jsonb_object_keys(p_updates)) = 0 THEN
    RAISE EXCEPTION 'p_updates must contain at least one column';
  END IF;
  IF p_actor_id IS NULL THEN
    RAISE EXCEPTION 'p_actor_id is required';
  END IF;

  -- Table allowlist — entity tables LEAP manages directly. Excludes
  -- system tables, auth, audit_log, and picklist_* metadata writes.
  IF p_table NOT IN (
    'properties','accounts','contacts','opportunities','opportunity_contact_roles',
    'buildings','units','property_programs',
    'work_orders','service_appointments','service_appointment_assignments',
    'projects','project_payment_requests',
    'incentive_applications','assessments',
    'equipment_activities','vehicle_activities','diagnostic_tests',
    'mechanical_equipment','products','efr_reports',
    'tasks','documents',
    'property_source_data','property_disaster_exposure','property_import_batches',
    'service_territory_members','resource_absences'
  ) THEN
    RAISE EXCEPTION 'Bulk update not allowed on table %', p_table;
  END IF;

  v_prefix := CASE
    WHEN p_table = 'properties' THEN 'property'
    WHEN p_table = 'accounts'   THEN 'account'
    WHEN p_table = 'contacts'   THEN 'contact'
    WHEN p_table = 'opportunities' THEN 'opportunity'
    WHEN p_table = 'opportunity_contact_roles' THEN 'ocr'
    WHEN p_table = 'buildings'  THEN 'building'
    WHEN p_table = 'units'      THEN 'unit'
    WHEN p_table = 'property_programs' THEN 'pp'
    WHEN p_table = 'work_orders' THEN 'work_order'
    WHEN p_table = 'service_appointments' THEN 'sa'
    WHEN p_table = 'service_appointment_assignments' THEN 'saa'
    WHEN p_table = 'projects'   THEN 'project'
    WHEN p_table = 'project_payment_requests' THEN 'ppr'
    WHEN p_table = 'incentive_applications' THEN 'ia'
    WHEN p_table = 'assessments' THEN 'assessment'
    WHEN p_table = 'equipment_activities' THEN 'ea'
    WHEN p_table = 'vehicle_activities' THEN 'va'
    WHEN p_table = 'diagnostic_tests' THEN 'dt'
    WHEN p_table = 'mechanical_equipment' THEN 'me'
    WHEN p_table = 'products'   THEN 'product'
    WHEN p_table = 'efr_reports' THEN 'efr'
    WHEN p_table = 'tasks'      THEN 'task'
    WHEN p_table = 'documents'  THEN 'doc'
    WHEN p_table = 'property_source_data' THEN 'psd'
    WHEN p_table = 'property_disaster_exposure' THEN 'pde'
    WHEN p_table = 'property_import_batches' THEN 'pib'
    WHEN p_table = 'service_territory_members' THEN 'stm'
    WHEN p_table = 'resource_absences' THEN 'ra'
  END;

  IF EXISTS (
    SELECT 1 FROM information_schema.columns
     WHERE table_schema='public' AND table_name=p_table
       AND column_name = v_prefix || '_updated_by'
  ) THEN
    v_audit_updater_col := v_prefix || '_updated_by';
    v_audit_at_col      := v_prefix || '_updated_at';
  ELSE
    v_audit_updater_col := 'updated_by';
    v_audit_at_col      := 'updated_at';
  END IF;

  FOR v_key IN SELECT jsonb_object_keys(p_updates) LOOP
    IF v_key = 'id'
       OR v_key LIKE '%_record_number'
       OR v_key LIKE '%_created_at' OR v_key LIKE '%_created_by'
       OR v_key LIKE '%_updated_at' OR v_key LIKE '%_updated_by'
       OR v_key LIKE '%_deleted_at' OR v_key LIKE '%_deleted_by'
       OR v_key LIKE '%_is_deleted' OR v_key LIKE '%_deletion_reason'
       OR v_key IN ('created_at','created_by','updated_at','updated_by',
                    'deleted_at','deleted_by','is_deleted','deletion_reason')
    THEN
      RAISE EXCEPTION 'Column % is system-managed and not user-editable', v_key;
    END IF;

    SELECT EXISTS (
      SELECT 1 FROM information_schema.columns
       WHERE table_schema='public' AND table_name=p_table AND column_name=v_key
    ) INTO v_col_exists;
    IF NOT v_col_exists THEN
      RAISE EXCEPTION 'Column % does not exist on table %', v_key, p_table;
    END IF;
  END LOOP;

  SELECT string_agg(
           quote_ident(k) || ' = ' ||
           CASE
             WHEN jsonb_typeof(p_updates -> k) = 'null'
               THEN 'NULL'
             ELSE '(' || quote_literal(p_updates ->> k) || ')::' ||
                  (SELECT data_type FROM information_schema.columns
                    WHERE table_schema='public' AND table_name=p_table AND column_name=k)
           END,
           ', '
         )
    INTO v_set_clause
    FROM jsonb_object_keys(p_updates) k;

  v_set_clause := v_set_clause
    || ', ' || quote_ident(v_audit_updater_col) || ' = ' || quote_literal(p_actor_id::text) || '::uuid'
    || ', ' || quote_ident(v_audit_at_col)      || ' = now()';

  FOREACH v_record_id IN ARRAY p_record_ids LOOP
    BEGIN
      v_update_sql := 'UPDATE ' || quote_ident(p_table) ||
                      ' SET '  || v_set_clause ||
                      ' WHERE id = ' || quote_literal(v_record_id::text) || '::uuid';
      EXECUTE v_update_sql;
      IF FOUND THEN
        v_updated := v_updated + 1;
      ELSE
        v_errored := v_errored + 1;
        v_errors := v_errors || jsonb_build_object(
          'record_id', v_record_id,
          'error', 'Record not found or RLS denied update'
        );
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_errored := v_errored + 1;
      GET STACKED DIAGNOSTICS v_error_msg = MESSAGE_TEXT;
      v_errors := v_errors || jsonb_build_object(
        'record_id', v_record_id,
        'error',     v_error_msg
      );
    END;
  END LOOP;

  RETURN jsonb_build_object(
    'records_total',   v_total,
    'records_updated', v_updated,
    'records_errored', v_errored,
    'errors',          v_errors
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.can_use_view_as()
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_role_id uuid;
BEGIN
  IF app_is_admin() THEN RETURN true; END IF;
  SELECT role_id INTO v_role_id FROM public.users WHERE id = current_app_user_id();
  IF v_role_id IS NULL THEN RETURN false; END IF;
  RETURN EXISTS (
    SELECT 1 FROM public.role_view_as_grants
    WHERE rvag_role_id = v_role_id AND is_deleted = false
  );
END; $function$
;

CREATE OR REPLACE FUNCTION public.cancel_appointment(p_token text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_sat         service_appointment_tokens%rowtype;
  v_sa          service_appointments%rowtype;
  v_canceled_id uuid;
  v_admin_id    uuid := 'c5a01ec8-960f-42ab-8a9e-a49822de89af';
BEGIN
  IF p_token IS NULL OR length(p_token) != 32 THEN
    RETURN jsonb_build_object('status', 'invalid_token');
  END IF;

  SELECT * INTO v_sat FROM service_appointment_tokens WHERE sat_token = p_token;
  IF v_sat.id IS NULL THEN
    RETURN jsonb_build_object('status', 'invalid_token');
  END IF;
  IF v_sat.sat_expires_at < now() THEN
    RETURN jsonb_build_object('status', 'expired_token');
  END IF;
  IF v_sat.sat_consumed_at IS NOT NULL THEN
    RETURN jsonb_build_object('status', 'already_consumed',
                              'message', 'This appointment has already been canceled.');
  END IF;

  SELECT * INTO v_sa FROM service_appointments
   WHERE id = v_sat.service_appointment_id AND sa_is_deleted = false;
  IF v_sa.id IS NULL THEN
    RETURN jsonb_build_object('status', 'appointment_not_found');
  END IF;

  IF v_sa.sa_scheduled_start_time < now() THEN
    RETURN jsonb_build_object(
      'status', 'too_late',
      'message', 'Cannot cancel an appointment that has already started or passed. Contact Energy Efficiency Services for assistance.'
    );
  END IF;

  SELECT id INTO v_canceled_id
    FROM picklist_values
   WHERE picklist_object = 'service_appointments'
     AND picklist_field  = 'status'
     AND picklist_value  = 'canceled'
     AND picklist_is_active = true
   LIMIT 1;
  IF v_canceled_id IS NULL THEN
    RETURN jsonb_build_object('status', 'error', 'message', 'Cancel status not configured.');
  END IF;

  UPDATE service_appointments
     SET sa_status     = v_canceled_id,
         sa_updated_at = now(),
         sa_updated_by = v_admin_id
   WHERE id = v_sa.id;

  UPDATE service_appointment_tokens
     SET sat_consumed_at = now()
   WHERE id = v_sat.id;

  RETURN jsonb_build_object('status', 'ok',
                            'service_appointment_id', v_sa.id,
                            'sa_record_number',       v_sa.sa_record_number);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cascade_building_name_to_children()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF NEW.building_name IS DISTINCT FROM OLD.building_name THEN
    UPDATE units SET building_id = building_id
      WHERE building_id = NEW.id AND unit_is_deleted = false;
    UPDATE opportunities SET building_id = building_id
      WHERE building_id = NEW.id AND opportunity_is_deleted = false;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cascade_building_soft_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
    IF NEW.building_is_deleted = true AND OLD.building_is_deleted = false THEN
        UPDATE units SET
            unit_is_deleted = true,
            unit_deleted_at = now(),
            unit_deleted_by = NEW.building_deleted_by,
            unit_deletion_reason = 'Parent building soft-deleted: ' || NEW.building_deletion_reason
        WHERE building_id = NEW.id AND unit_is_deleted = false;
    END IF;
    IF NEW.building_is_deleted = false AND OLD.building_is_deleted = true THEN
        UPDATE units SET
            unit_is_deleted = false,
            unit_deleted_at = NULL,
            unit_deleted_by = NULL,
            unit_deletion_reason = NULL
        WHERE building_id = NEW.id;
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cascade_opportunity_name_to_projects()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF NEW.opportunity_name IS DISTINCT FROM OLD.opportunity_name THEN
    UPDATE projects SET opportunity_id = opportunity_id
      WHERE opportunity_id = NEW.id AND project_is_deleted = false;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cascade_property_name_to_children()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF NEW.property_name IS DISTINCT FROM OLD.property_name THEN
    -- No-op write fires trg_building_name on each child building.
    UPDATE buildings SET property_id = property_id
      WHERE property_id = NEW.id AND building_is_deleted = false;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cascade_property_soft_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
    IF NEW.property_is_deleted = true AND OLD.property_is_deleted = false THEN
        UPDATE buildings SET
            building_is_deleted = true,
            building_deleted_at = now(),
            building_deleted_by = NEW.property_deleted_by,
            building_deletion_reason = 'Parent property soft-deleted: ' || NEW.property_deletion_reason
        WHERE property_id = NEW.id AND building_is_deleted = false;
    END IF;
    IF NEW.property_is_deleted = false AND OLD.property_is_deleted = true THEN
        UPDATE buildings SET
            building_is_deleted = false,
            building_deleted_at = NULL,
            building_deleted_by = NULL,
            building_deletion_reason = NULL
        WHERE property_id = NEW.id;
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cascade_work_order_soft_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
    IF NEW.work_order_is_deleted = true AND OLD.work_order_is_deleted = false THEN
        UPDATE work_plans SET
            work_plan_is_deleted = true,
            work_plan_deleted_at = now(),
            work_plan_deleted_by = NEW.work_order_deleted_by,
            work_plan_deletion_reason = 'Parent work order soft-deleted: ' || NEW.work_order_deletion_reason
        WHERE work_order_id = NEW.id AND work_plan_is_deleted = false;

        UPDATE work_steps SET
            work_step_is_deleted = true,
            work_step_deleted_at = now(),
            work_step_deleted_by = NEW.work_order_deleted_by,
            work_step_deletion_reason = 'Parent work order soft-deleted: ' || NEW.work_order_deletion_reason
        WHERE work_order_id = NEW.id AND work_step_is_deleted = false;
    END IF;
    RETURN NEW;
END;
$function$
;

