CREATE OR REPLACE FUNCTION public.change_record_status(p_object text, p_record_id uuid, p_status_field text, p_to_status_id uuid, p_note text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user_id        uuid;
  v_updated_by_col text;
  v_updated_at_col text;
  v_table_prefix   text;
  v_current_status uuid;
  v_transition_id  uuid;
  v_transition_label text;
  v_pv_object      text;
  v_pv_field       text;
  v_pv_value       text;
  v_sql            text;
  v_event_id       uuid;
BEGIN
  SELECT id INTO v_user_id FROM public.users WHERE auth_user_id = auth.uid();
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated' USING ERRCODE = 'insufficient_privilege';
  END IF;

  IF NOT public.app_user_can(p_object, 'update') THEN
    RAISE EXCEPTION 'User does not have update permission on %', p_object
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  SELECT picklist_object, picklist_field, picklist_value
    INTO v_pv_object, v_pv_field, v_pv_value
  FROM public.picklist_values WHERE id = p_to_status_id;
  IF v_pv_object IS NULL THEN
    RAISE EXCEPTION 'p_to_status_id does not reference an existing picklist value';
  END IF;
  IF v_pv_object <> p_object OR v_pv_field <> p_status_field THEN
    RAISE EXCEPTION 'p_to_status_id (% on %.%) does not match transition scope %.%',
      v_pv_value, v_pv_object, v_pv_field, p_object, p_status_field;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema='public' AND table_name=p_object AND column_name=p_status_field
  ) THEN
    RAISE EXCEPTION 'Column %.% does not exist', p_object, p_status_field;
  END IF;

  v_table_prefix := regexp_replace(p_object, 's$', '');

  IF EXISTS (SELECT 1 FROM information_schema.columns
             WHERE table_schema='public' AND table_name=p_object
               AND column_name = v_table_prefix || '_updated_by') THEN
    v_updated_by_col := v_table_prefix || '_updated_by';
    v_updated_at_col := v_table_prefix || '_updated_at';
  ELSIF EXISTS (SELECT 1 FROM information_schema.columns
                WHERE table_schema='public' AND table_name=p_object
                  AND column_name = 'updated_by') THEN
    v_updated_by_col := 'updated_by';
    v_updated_at_col := 'updated_at';
  ELSE
    v_updated_by_col := NULL;
    v_updated_at_col := NULL;
  END IF;

  EXECUTE format('SELECT %I FROM public.%I WHERE id = $1', p_status_field, p_object)
    INTO v_current_status USING p_record_id;

  SELECT id, st_transition_label INTO v_transition_id, v_transition_label
  FROM public.status_transitions
  WHERE st_object         = p_object
    AND st_status_field   = p_status_field
    AND st_to_status_id   = p_to_status_id
    AND st_from_status_id IS NOT DISTINCT FROM v_current_status
    AND st_is_active      = true
    AND st_is_deleted     = false
  LIMIT 1;

  IF v_transition_id IS NULL THEN
    RAISE EXCEPTION 'No active transition exists for %.% from % to %',
      p_object, p_status_field,
      COALESCE(v_current_status::text, '(initial creation)'),
      p_to_status_id::text
      USING ERRCODE = 'check_violation';
  END IF;

  IF v_updated_by_col IS NOT NULL THEN
    v_sql := format(
      'UPDATE public.%I SET %I = $1, %I = $2, %I = now() WHERE id = $3',
      p_object, p_status_field, v_updated_by_col, v_updated_at_col
    );
    EXECUTE v_sql USING p_to_status_id, v_user_id, p_record_id;
  ELSE
    v_sql := format('UPDATE public.%I SET %I = $1 WHERE id = $2', p_object, p_status_field);
    EXECUTE v_sql USING p_to_status_id, p_record_id;
  END IF;

  INSERT INTO public.status_change_events (
    sce_record_number, sce_object, sce_record_id, sce_transition_id,
    sce_from_status_id, sce_to_status_id, sce_note, sce_created_by
  ) VALUES (
    '', p_object, p_record_id, v_transition_id,
    v_current_status, p_to_status_id,
    NULLIF(btrim(p_note), ''),
    v_user_id
  )
  RETURNING id INTO v_event_id;

  -- Single automation engine: silent flows only. A flow error is logged to
  -- flow_runs/flow_run_steps and cannot roll back the status change.
  BEGIN
    PERFORM public.execute_flows_for(p_object, p_record_id, 'status_change', v_pv_value);
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;

  RETURN jsonb_build_object(
    'ok',                true,
    'transition_id',     v_transition_id,
    'transition_label',  v_transition_label,
    'from_status_id',    v_current_status,
    'to_status_id',      p_to_status_id,
    'event_id',          v_event_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.clock_in_work_order(p_wo_id uuid, p_latitude numeric DEFAULT NULL::numeric, p_longitude numeric DEFAULT NULL::numeric, p_odometer numeric DEFAULT NULL::numeric, p_sa_id uuid DEFAULT NULL::uuid, p_clock_in_at timestamp with time zone DEFAULT now())
 RETURNS TABLE(wte_id uuid, wte_record_number text, outcome text, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_uid uuid := public.current_app_user_id();
  v_open uuid;
  v_new  public.work_order_time_entries;
BEGIN
  IF v_uid IS NULL THEN
    RETURN QUERY SELECT NULL::uuid, NULL::text, 'error', 'Not authenticated.'; RETURN;
  END IF;

  -- Reject a second open session for the same technician + work order.
  SELECT id INTO v_open
  FROM public.work_order_time_entries
  WHERE work_order_id = p_wo_id
    AND wte_technician_user_id = v_uid
    AND wte_clock_out_at IS NULL
    AND wte_is_deleted IS NOT TRUE
  LIMIT 1;

  IF v_open IS NOT NULL THEN
    RETURN QUERY SELECT v_open, NULL::text, 'error',
      'An open clock session already exists for this work order. Clock out before clocking in again.'; RETURN;
  END IF;

  INSERT INTO public.work_order_time_entries (
    wte_record_number, work_order_id, wte_technician_user_id, service_appointment_id,
    wte_clock_in_at, wte_clock_in_latitude, wte_clock_in_longitude, wte_clock_in_odometer,
    wte_owner, wte_created_by, wte_updated_by, wte_updated_at
  ) VALUES (
    '', p_wo_id, v_uid, p_sa_id,
    p_clock_in_at, p_latitude, p_longitude, p_odometer,
    v_uid, v_uid, v_uid, now()
  ) RETURNING * INTO v_new;

  RETURN QUERY SELECT v_new.id, v_new.wte_record_number, 'ok', 'Clocked in.';
END; $function$
;

CREATE OR REPLACE FUNCTION public.clock_out_work_order(p_wo_id uuid, p_latitude numeric DEFAULT NULL::numeric, p_longitude numeric DEFAULT NULL::numeric, p_odometer numeric DEFAULT NULL::numeric, p_clock_out_at timestamp with time zone DEFAULT now())
 RETURNS TABLE(wte_id uuid, wte_record_number text, wte_duration_minutes numeric, outcome text, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_uid uuid := public.current_app_user_id();
  v_row public.work_order_time_entries;
  v_dur numeric;
BEGIN
  IF v_uid IS NULL THEN
    RETURN QUERY SELECT NULL::uuid, NULL::text, NULL::numeric, 'error', 'Not authenticated.'; RETURN;
  END IF;

  SELECT * INTO v_row
  FROM public.work_order_time_entries
  WHERE work_order_id = p_wo_id
    AND wte_technician_user_id = v_uid
    AND wte_clock_out_at IS NULL
    AND wte_is_deleted IS NOT TRUE
  ORDER BY wte_clock_in_at DESC NULLS LAST
  LIMIT 1;

  IF v_row.id IS NULL THEN
    RETURN QUERY SELECT NULL::uuid, NULL::text, NULL::numeric, 'error',
      'No open clock session found for this work order.'; RETURN;
  END IF;

  v_dur := round(EXTRACT(EPOCH FROM (p_clock_out_at - v_row.wte_clock_in_at)) / 60.0, 2);

  UPDATE public.work_order_time_entries
  SET wte_clock_out_at        = p_clock_out_at,
      wte_clock_out_latitude  = p_latitude,
      wte_clock_out_longitude = p_longitude,
      wte_clock_out_odometer  = p_odometer,
      wte_duration_minutes    = v_dur,
      wte_updated_by          = v_uid,
      wte_updated_at          = now()
  WHERE id = v_row.id;

  RETURN QUERY SELECT v_row.id, v_row.wte_record_number, v_dur, 'ok', 'Clocked out.';
END; $function$
;

CREATE OR REPLACE FUNCTION public.clone_dashboard(p_source_dashboard_id uuid, p_new_name text DEFAULT NULL::text, p_new_folder_id uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller   uuid := public.current_app_user_id();
  v_src      public.dashboards%ROWTYPE;
  v_new_id   uuid;
  v_name     text;
  v_folder   uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'clone_dashboard: must be authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT * INTO v_src FROM public.dashboards
  WHERE id = p_source_dashboard_id AND NOT is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'clone_dashboard: source dashboard % not found or deleted', p_source_dashboard_id
      USING ERRCODE = '02000';
  END IF;

  v_name   := COALESCE(NULLIF(trim(p_new_name), ''), v_src.dash_name || ' (Clone)');
  v_folder := COALESCE(p_new_folder_id, v_src.dash_folder_id);

  -- Clone the dashboard row itself.
  INSERT INTO public.dashboards (
    dash_record_number, dash_name, dash_description, dash_folder_id,
    dash_layout, dash_columns, dash_owner_user_id,
    created_by, updated_by
  ) VALUES (
    '', v_name, v_src.dash_description, v_folder,
    v_src.dash_layout, v_src.dash_columns, v_caller,
    v_caller, v_caller
  )
  RETURNING id INTO v_new_id;

  -- Clone non-deleted widget rows
  INSERT INTO public.dashboard_widgets (
    dw_dashboard_id, dw_report_id, dw_title, dw_widget_type,
    dw_position_row, dw_position_col, dw_width, dw_height,
    dw_widget_config,
    created_by, updated_by
  )
  SELECT
    v_new_id, dw_report_id, dw_title, dw_widget_type,
    dw_position_row, dw_position_col, dw_width, dw_height,
    dw_widget_config,
    v_caller, v_caller
  FROM public.dashboard_widgets
  WHERE dw_dashboard_id = p_source_dashboard_id AND NOT is_deleted;

  -- Clone non-deleted filter rows
  INSERT INTO public.dashboard_filters (
    dfilt_dashboard_id, dfilt_label, dfilt_field_name, dfilt_operator,
    dfilt_default_value, dfilt_options, dfilt_display_order,
    created_by, updated_by
  )
  SELECT
    v_new_id, dfilt_label, dfilt_field_name, dfilt_operator,
    dfilt_default_value, dfilt_options, dfilt_display_order,
    v_caller, v_caller
  FROM public.dashboard_filters
  WHERE dfilt_dashboard_id = p_source_dashboard_id AND NOT is_deleted;

  RETURN v_new_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.clone_document_template(p_source_document_template_id uuid, p_new_name text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller uuid := public.current_app_user_id();
  v_src    public.document_templates%ROWTYPE;
  v_new_id uuid;
  v_draft  uuid;
  v_name   text;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'clone_document_template: must be authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT * INTO v_src FROM public.document_templates
  WHERE id = p_source_document_template_id AND NOT is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'clone_document_template: source % not found or deleted', p_source_document_template_id;
  END IF;

  SELECT id INTO v_draft FROM public.picklist_values
  WHERE picklist_object='document_templates' AND picklist_field='status'
    AND picklist_value='Draft' AND picklist_is_active=true LIMIT 1;
  IF v_draft IS NULL THEN
    v_draft := v_src.status;
  END IF;

  v_name := COALESCE(p_new_name, v_src.name || ' (Clone)');

  INSERT INTO public.document_templates (
    dt_record_number, name, description, template_type, body_html,
    program_id, state, related_object, record_type,
    requires_signature, signer_role, trigger_status,
    is_manual, is_automated,
    status, owner_id, created_by, updated_by, version,
    dt_authoring_mode, dt_template_asset_path
  ) VALUES (
    '', v_name, v_src.description, v_src.template_type, v_src.body_html,
    v_src.program_id, v_src.state, v_src.related_object, v_src.record_type,
    v_src.requires_signature, v_src.signer_role, v_src.trigger_status,
    v_src.is_manual, v_src.is_automated,
    v_draft, v_caller, v_caller, v_caller, 1,
    v_src.dt_authoring_mode, NULL
  )
  RETURNING id INTO v_new_id;

  RETURN v_new_id;
END;
$function$
;

