CREATE OR REPLACE FUNCTION public.clone_flow(p_flow_id uuid, p_new_name text)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_user uuid; v_src public.flows%ROWTYPE; v_new_id uuid; v_map jsonb := '{}'::jsonb; v_el public.flow_elements%ROWTYPE; v_new_el uuid;
BEGIN
  v_user := current_app_user_id();
  IF NOT app_user_can('flows','create') THEN RAISE EXCEPTION 'No create permission on flows'; END IF;
  SELECT * INTO v_src FROM public.flows WHERE id=p_flow_id AND is_deleted=false;
  IF NOT FOUND THEN RAISE EXCEPTION 'Flow not found'; END IF;

  INSERT INTO public.flows
    (flow_record_number, flow_name, flow_description, flow_type, flow_launch_contexts,
     flow_launch_object, flow_trigger_object, flow_trigger_event, flow_trigger_status,
     flow_trigger_field, flow_trigger_field_value, flow_status, flow_current_version,
     owner_id, created_by)
  VALUES
    ('', p_new_name, v_src.flow_description, v_src.flow_type, v_src.flow_launch_contexts,
     v_src.flow_launch_object, v_src.flow_trigger_object, v_src.flow_trigger_event, v_src.flow_trigger_status,
     v_src.flow_trigger_field, v_src.flow_trigger_field_value, 'inactive', 1,
     v_user, v_user)
  RETURNING id INTO v_new_id;

  -- first pass: clone elements, build old→new id map
  FOR v_el IN SELECT * FROM public.flow_elements WHERE fe_flow_id=p_flow_id AND is_deleted=false ORDER BY fe_order LOOP
    INSERT INTO public.flow_elements
      (fe_record_number, fe_flow_id, fe_element_type, fe_order, fe_label, fe_api_name, fe_config, owner_id, created_by)
    VALUES
      ('', v_new_id, v_el.fe_element_type, v_el.fe_order, v_el.fe_label, v_el.fe_api_name, v_el.fe_config, v_user, v_user)
    RETURNING id INTO v_new_el;
    v_map := v_map || jsonb_build_object(v_el.id::text, v_new_el::text);
  END LOOP;

  -- second pass: rewrite next/parent/branch references through the map
  UPDATE public.flow_elements ne
     SET fe_next_element_id = NULLIF(v_map->>(oe.fe_next_element_id::text),'')::uuid,
         fe_parent_element_id = NULLIF(v_map->>(oe.fe_parent_element_id::text),'')::uuid,
         fe_decision_branches = oe.fe_decision_branches
    FROM public.flow_elements oe
   WHERE oe.fe_flow_id=p_flow_id AND oe.is_deleted=false
     AND ne.fe_flow_id=v_new_id
     AND ne.fe_order=oe.fe_order AND ne.fe_element_type=oe.fe_element_type
     AND ne.fe_label IS NOT DISTINCT FROM oe.fe_label;

  RETURN v_new_id;
END; $function$
;

CREATE OR REPLACE FUNCTION public.clone_page_layout(p_source_layout_id uuid, p_new_name text, p_new_description text DEFAULT NULL::text, p_new_role_id uuid DEFAULT NULL::uuid, p_new_record_type_id uuid DEFAULT NULL::uuid, p_new_is_default boolean DEFAULT false, p_owner uuid DEFAULT NULL::uuid, p_created_by uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_source_layout  public.page_layouts%ROWTYPE;
  v_new_layout_id  uuid;
  v_section_map    jsonb := '{}'::jsonb;
  v_old_sec_id     uuid;
  v_new_sec_id     uuid;
  v_sec_row        public.page_layout_sections%ROWTYPE;
  v_owner          uuid;
  v_created_by     uuid;
BEGIN
  -- Load source layout; error cleanly if it doesn't exist or was deleted.
  SELECT * INTO v_source_layout
  FROM public.page_layouts
  WHERE id = p_source_layout_id AND is_deleted = false;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'clone_page_layout: source layout % not found or deleted', p_source_layout_id;
  END IF;

  -- Resolve owner / created_by — fall back to source layout values if caller
  -- didn't pass them. page_layout_owner and page_layout_created_by are NOT NULL.
  v_owner      := COALESCE(p_owner,      v_source_layout.page_layout_owner);
  v_created_by := COALESCE(p_created_by, v_source_layout.page_layout_created_by);

  -- 1. Insert the new layout header.
  --    page_layout_record_number='' -> BEFORE INSERT trigger overwrites it.
  INSERT INTO public.page_layouts (
    page_layout_record_number,
    page_layout_name,
    page_layout_object,
    page_layout_type,
    role_id,
    record_type_id,
    page_layout_is_default,
    page_layout_description,
    page_layout_owner,
    page_layout_created_by
  )
  VALUES (
    '',
    p_new_name,
    v_source_layout.page_layout_object,
    v_source_layout.page_layout_type,
    p_new_role_id,
    p_new_record_type_id,
    COALESCE(p_new_is_default, false),
    COALESCE(p_new_description, v_source_layout.page_layout_description),
    v_owner,
    v_created_by
  )
  RETURNING id INTO v_new_layout_id;

  -- 2. Copy sections. For each live source section, insert a new row under
  --    the new layout and record old_id -> new_id in a jsonb mapping.
  FOR v_sec_row IN
    SELECT *
    FROM public.page_layout_sections
    WHERE page_layout_id = p_source_layout_id AND is_deleted = false
    ORDER BY section_order
  LOOP
    INSERT INTO public.page_layout_sections (
      page_layout_id,
      section_order,
      section_label,
      section_columns,
      section_is_collapsible,
      section_is_collapsed_by_default,
      section_tab
    )
    VALUES (
      v_new_layout_id,
      v_sec_row.section_order,
      v_sec_row.section_label,
      v_sec_row.section_columns,
      v_sec_row.section_is_collapsible,
      v_sec_row.section_is_collapsed_by_default,
      v_sec_row.section_tab
    )
    RETURNING id INTO v_new_sec_id;

    v_section_map := v_section_map || jsonb_build_object(v_sec_row.id::text, v_new_sec_id::text);
  END LOOP;

  -- 3. Copy widgets. Re-anchor to the new section via the mapping.
  --    page_layout_widget_record_number='' -> trigger fills it in.
  INSERT INTO public.page_layout_widgets (
    page_layout_widget_record_number,
    page_layout_id,
    section_id,
    widget_type,
    widget_title,
    widget_column,
    widget_position,
    widget_size,
    widget_config,
    widget_is_user_customizable,
    widget_is_required
  )
  SELECT
    '',
    v_new_layout_id,
    (v_section_map ->> w.section_id::text)::uuid,
    w.widget_type,
    w.widget_title,
    w.widget_column,
    w.widget_position,
    w.widget_size,
    w.widget_config,
    w.widget_is_user_customizable,
    w.widget_is_required
  FROM public.page_layout_widgets w
  WHERE w.page_layout_id = p_source_layout_id
    AND w.is_deleted = false
    AND (v_section_map ? w.section_id::text);

  RETURN v_new_layout_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.clone_permission_set(p_source_permission_set_id uuid, p_new_name text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller   uuid := public.current_app_user_id();
  v_src      public.permission_sets%ROWTYPE;
  v_new_id   uuid;
  v_name     text;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'clone_permission_set: must be authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT * INTO v_src FROM public.permission_sets
  WHERE id = p_source_permission_set_id AND NOT ps_is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'clone_permission_set: source permission set % not found or deleted', p_source_permission_set_id
      USING ERRCODE = '02000';
  END IF;

  v_name := COALESCE(NULLIF(trim(p_new_name), ''), v_src.ps_name || ' (Clone)');

  INSERT INTO public.permission_sets (
    ps_name, ps_description, ps_is_active,
    ps_created_by, ps_updated_by
  ) VALUES (
    v_name, v_src.ps_description, false,    -- always inactive on clone
    v_caller, v_caller
  )
  RETURNING id INTO v_new_id;

  -- Clone object-access grants
  INSERT INTO public.permission_set_object_access (
    psoa_permission_set_id, psoa_object_name,
    psoa_read, psoa_create, psoa_update, psoa_delete,
    psoa_created_by, psoa_updated_by
  )
  SELECT
    v_new_id, psoa_object_name,
    psoa_read, psoa_create, psoa_update, psoa_delete,
    v_caller, v_caller
  FROM public.permission_set_object_access
  WHERE psoa_permission_set_id = p_source_permission_set_id;

  -- Clone field-visibility overrides
  INSERT INTO public.permission_set_field_permissions (
    psfp_permission_set_id, psfp_object, psfp_field,
    psfp_visible, psfp_editable, psfp_financial_tier,
    psfp_created_by, psfp_updated_by
  )
  SELECT
    v_new_id, psfp_object, psfp_field,
    psfp_visible, psfp_editable, psfp_financial_tier,
    v_caller, v_caller
  FROM public.permission_set_field_permissions
  WHERE psfp_permission_set_id = p_source_permission_set_id;

  RETURN v_new_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.clone_project_report_template(p_source_prt_id uuid, p_new_name text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller uuid := public.current_app_user_id();  -- public.users.id, not auth.uid()
  v_src project_report_templates%ROWTYPE;
  v_new_id uuid;
  v_status_draft uuid;
  v_clone_name text;
  v_section project_report_template_sections%ROWTYPE;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'clone_project_report_template: must be authenticated as a registered user';
  END IF;

  SELECT * INTO v_src
  FROM project_report_templates
  WHERE id = p_source_prt_id AND NOT prt_is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'clone_project_report_template: source % not found or deleted', p_source_prt_id;
  END IF;

  -- Resolve Draft status uuid (fall back to original source status if Draft is missing)
  SELECT id INTO v_status_draft
  FROM picklist_values
  WHERE picklist_object='project_report_templates'
    AND picklist_field='prt_status'
    AND picklist_value='Draft'
    AND picklist_is_active=true
  LIMIT 1;
  IF v_status_draft IS NULL THEN
    v_status_draft := v_src.prt_status;
  END IF;

  v_clone_name := COALESCE(p_new_name, v_src.prt_name || ' (Clone)');

  -- Insert the new PRT (record_number auto-set by trg_prt_rn)
  INSERT INTO project_report_templates (
    prt_record_number, prt_name, prt_description,
    prt_record_type, prt_status, prt_orientation, prt_paper_size,
    prt_version, prt_is_default_for_unmapped,
    prt_owner, prt_created_by, prt_updated_by
  )
  VALUES (
    '', v_clone_name, v_src.prt_description,
    v_src.prt_record_type, v_status_draft, v_src.prt_orientation, v_src.prt_paper_size,
    1, false,
    v_caller, v_caller, v_caller
  )
  RETURNING id INTO v_new_id;

  -- Copy each non-deleted section
  FOR v_section IN
    SELECT * FROM project_report_template_sections
    WHERE prt_id = p_source_prt_id AND NOT prts_is_deleted
    ORDER BY prts_section_order ASC
  LOOP
    INSERT INTO project_report_template_sections (
      prts_record_number, prt_id, prts_section_order, prts_section_type,
      prts_section_title, prts_body_template, prts_config, prts_filter_config,
      prts_show_if_empty, prts_page_break_after,
      prts_created_by, prts_updated_by
    ) VALUES (
      '', v_new_id, v_section.prts_section_order, v_section.prts_section_type,
      v_section.prts_section_title, v_section.prts_body_template,
      COALESCE(v_section.prts_config, '{}'::jsonb),
      COALESCE(v_section.prts_filter_config, '{}'::jsonb),
      v_section.prts_show_if_empty, v_section.prts_page_break_after,
      v_caller, v_caller
    );
  END LOOP;

  RETURN v_new_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.clone_report(p_source_report_id uuid, p_new_name text DEFAULT NULL::text, p_new_folder_id uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller   uuid := public.current_app_user_id();
  v_src      public.reports%ROWTYPE;
  v_new_id   uuid;
  v_name     text;
  v_folder   uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'clone_report: must be authenticated' USING ERRCODE = '42501';
  END IF;

  -- Source report
  SELECT * INTO v_src FROM public.reports
  WHERE id = p_source_report_id AND NOT is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'clone_report: source report % not found or deleted', p_source_report_id
      USING ERRCODE = '02000';
  END IF;

  v_name   := COALESCE(NULLIF(trim(p_new_name), ''), v_src.rpt_name || ' (Clone)');
  v_folder := COALESCE(p_new_folder_id, v_src.rpt_folder_id);

  -- Clone the report row itself. Empty-string record_number triggers the
  -- BEFORE INSERT auto-numbering trigger.
  INSERT INTO public.reports (
    rpt_record_number, rpt_name, rpt_description, rpt_folder_id,
    rpt_format, rpt_primary_object, rpt_selected_fields,
    rpt_filter_logic, rpt_sort_config, rpt_column_groupings,
    rpt_runtime_prompts, rpt_charts, rpt_owner_user_id,
    created_by, updated_by
  ) VALUES (
    '', v_name, v_src.rpt_description, v_folder,
    v_src.rpt_format, v_src.rpt_primary_object, v_src.rpt_selected_fields,
    v_src.rpt_filter_logic, v_src.rpt_sort_config, v_src.rpt_column_groupings,
    v_src.rpt_runtime_prompts, v_src.rpt_charts, v_caller,
    v_caller, v_caller
  )
  RETURNING id INTO v_new_id;

  -- Clone non-deleted filter rows
  INSERT INTO public.report_filters (
    rfilt_report_id, rfilt_filter_index,
    rfilt_field_name, rfilt_field_table, rfilt_field_via_path,
    rfilt_operator, rfilt_value,
    rfilt_is_cross_filter, rfilt_cross_object, rfilt_cross_match, rfilt_cross_subfilters,
    rfilt_is_runtime_prompt, rfilt_runtime_label,
    rfilt_prompt_input_type, rfilt_prompt_options,
    created_by, updated_by
  )
  SELECT
    v_new_id, rfilt_filter_index,
    rfilt_field_name, rfilt_field_table, rfilt_field_via_path,
    rfilt_operator, rfilt_value,
    rfilt_is_cross_filter, rfilt_cross_object, rfilt_cross_match, rfilt_cross_subfilters,
    rfilt_is_runtime_prompt, rfilt_runtime_label,
    rfilt_prompt_input_type, rfilt_prompt_options,
    v_caller, v_caller
  FROM public.report_filters
  WHERE rfilt_report_id = p_source_report_id AND NOT is_deleted;

  -- Clone non-deleted grouping rows
  INSERT INTO public.report_groupings (
    rgr_report_id, rgr_grouping_level,
    rgr_field_name, rgr_field_table, rgr_field_via_path, rgr_field_label,
    rgr_sort_direction, rgr_sort_by_aggregate, rgr_show_subtotal,
    rgr_date_granularity,
    created_by, updated_by
  )
  SELECT
    v_new_id, rgr_grouping_level,
    rgr_field_name, rgr_field_table, rgr_field_via_path, rgr_field_label,
    rgr_sort_direction, rgr_sort_by_aggregate, rgr_show_subtotal,
    rgr_date_granularity,
    v_caller, v_caller
  FROM public.report_groupings
  WHERE rgr_report_id = p_source_report_id AND NOT is_deleted;

  -- Clone non-deleted calculated-field rows
  INSERT INTO public.report_calculated_fields (
    rcf_report_id, rcf_label, rcf_scope, rcf_expression, rcf_data_type,
    rcf_format_options, rcf_display_order, rcf_grouping_level,
    created_by, updated_by
  )
  SELECT
    v_new_id, rcf_label, rcf_scope, rcf_expression, rcf_data_type,
    rcf_format_options, rcf_display_order, rcf_grouping_level,
    v_caller, v_caller
  FROM public.report_calculated_fields
  WHERE rcf_report_id = p_source_report_id AND NOT is_deleted;

  RETURN v_new_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.clone_scheduled_report(p_source_schedule_id uuid, p_new_name text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller   uuid := public.current_app_user_id();
  v_src      public.scheduled_reports%ROWTYPE;
  v_new_id   uuid;
  v_name     text;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'clone_scheduled_report: must be authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT * INTO v_src FROM public.scheduled_reports
  WHERE id = p_source_schedule_id AND NOT is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'clone_scheduled_report: source schedule % not found or deleted', p_source_schedule_id
      USING ERRCODE = '02000';
  END IF;

  v_name := COALESCE(NULLIF(trim(p_new_name), ''), v_src.sr_name || ' (Clone)');

  INSERT INTO public.scheduled_reports (
    sr_record_number, sr_report_id, sr_name,
    sr_frequency, sr_day_of_week, sr_day_of_month,
    sr_send_time, sr_timezone, sr_format,
    sr_subject_line, sr_message_body,
    sr_recipient_user_ids, sr_recipient_role_ids, sr_recipient_emails,
    sr_is_active,        -- always false on clone, see header
    sr_last_sent_at,     -- always null on clone
    sr_next_send_at,     -- always null on clone
    sr_owner_user_id,
    created_by, updated_by
  ) VALUES (
    '', v_src.sr_report_id, v_name,
    v_src.sr_frequency, v_src.sr_day_of_week, v_src.sr_day_of_month,
    v_src.sr_send_time, v_src.sr_timezone, v_src.sr_format,
    v_src.sr_subject_line, v_src.sr_message_body,
    v_src.sr_recipient_user_ids, v_src.sr_recipient_role_ids, v_src.sr_recipient_emails,
    false,
    NULL,
    NULL,
    v_caller,
    v_caller, v_caller
  )
  RETURNING id INTO v_new_id;

  RETURN v_new_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.commit_screen_flow_run(p_flow_id uuid, p_context jsonb, p_actions jsonb, p_ai_assisted boolean DEFAULT false)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user uuid; v_flow public.flows%ROWTYPE; v_run_id uuid;
  v_action jsonb; v_order integer := 0;
  v_obj text; v_rid uuid; v_vals jsonb; v_type text;
  v_status_field text; v_to_status uuid; v_note text;
  v_cols text; v_set text; v_created uuid; v_results jsonb := '[]'::jsonb;
  v_outcome text; v_message text;
  v_k text; v_blocked text[];
  v_num_col text; v_colrec record;
  v_extra_cols text; v_extra_vals text;
  v_rpc text; v_p jsonb; v_rpc_result jsonb;
  v_refs jsonb := '{}'::jsonb;          -- ref name -> created uuid (this batch)
  v_ref text;                            -- this action's own ref label
  v_action_text text;                    -- serialized action for token substitution
  v_missing text[];                      -- unresolved {{ref:...}} names
  v_m text;
  v_pk text; v_praw text; v_pdigits text;  -- phone normalization scratch
  v_unknown text[];                        -- proposed columns that do not exist
  v_valid_cols text;                       -- comma list of real columns (for the error)
BEGIN
  v_user := current_app_user_id();
  IF v_user IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;
  SELECT * INTO v_flow FROM public.flows WHERE id=p_flow_id AND is_deleted=false;
  IF NOT FOUND THEN RAISE EXCEPTION 'Flow not found'; END IF;

  INSERT INTO public.flow_runs
    (fr_record_number, fr_flow_id, fr_flow_version_id, fr_flow_type,
     fr_status, fr_context, fr_ai_assisted, owner_id, created_by)
  VALUES
    ('', p_flow_id, v_flow.flow_active_version_id, 'screen',
     'in_progress', COALESCE(p_context,'{}'::jsonb), p_ai_assisted, v_user, v_user)
  RETURNING id INTO v_run_id;

  FOR v_action IN SELECT * FROM jsonb_array_elements(COALESCE(p_actions,'[]'::jsonb)) LOOP
    v_order := v_order + 1;
    v_ref := NULLIF(v_action->>'ref','');

    -- ── Resolve {{ref:NAME}} tokens against ids created earlier in this batch.
    v_action_text := v_action::text;
    IF position('{{ref:' in v_action_text) > 0 THEN
      v_missing := ARRAY[]::text[];
      FOR v_m IN
        SELECT DISTINCT (regexp_matches(v_action_text, '\{\{ref:([A-Za-z0-9_\-]+)\}\}', 'g'))[1]
      LOOP
        IF v_refs ? v_m THEN
          v_action_text := replace(v_action_text, '{{ref:' || v_m || '}}', v_refs->>v_m);
        ELSE
          v_missing := array_append(v_missing, v_m);
        END IF;
      END LOOP;
      IF array_length(v_missing,1) IS NOT NULL THEN
        v_outcome := 'error';
        v_message := format('Unresolved reference(s): %s — a referenced record was not created earlier in this batch.', array_to_string(v_missing, ', '));
        INSERT INTO public.flow_run_steps
          (frs_record_number, frs_run_id, frs_element_type, frs_order,
           frs_outcome, frs_outcome_message, frs_input, frs_created_target_id)
        VALUES ('', v_run_id, v_action->>'type', v_order, v_outcome, v_message, v_action, NULL);
        v_results := v_results || jsonb_build_object('order',v_order,'outcome',v_outcome,'message',v_message,'created_id',NULL);
        UPDATE public.flow_runs SET fr_status='error', fr_outcome_message=v_message, fr_completed_at=now() WHERE id=v_run_id;
        RETURN jsonb_build_object('ok',false,'run_id',v_run_id,'results',v_results);
      END IF;
      v_action := v_action_text::jsonb;
    END IF;

    v_type := v_action->>'type';
    v_obj  := v_action->>'object';
    v_rid  := NULLIF(v_action->>'record_id','')::uuid;
    v_vals := v_action->'values';
    v_outcome := 'ok'; v_message := NULL; v_created := NULL;

    -- ── Phone normalization. Any value whose key contains 'phone' is reduced to
    -- bare digits so display-formatted input like "(262) 745-1000" satisfies the
    -- ^\d{10}$ check constraints. A leading US country-code 1 is dropped when that
    -- yields exactly 10 digits. If the stripped result is not 10 digits the original
    -- value is left untouched so the constraint still surfaces the real problem
    -- rather than silently storing mangled input. Applies to create and update.
    IF v_vals IS NOT NULL AND jsonb_typeof(v_vals) = 'object' THEN
      FOR v_pk IN SELECT key FROM jsonb_object_keys(v_vals) AS key LOOP
        IF v_pk ILIKE '%phone%' AND jsonb_typeof(v_vals->v_pk) = 'string' THEN
          v_praw := v_vals->>v_pk;
          IF v_praw IS NOT NULL AND v_praw <> '' THEN
            v_pdigits := regexp_replace(v_praw, '\D', '', 'g');
            IF length(v_pdigits) = 11 AND left(v_pdigits,1) = '1' THEN
              v_pdigits := substr(v_pdigits, 2);
            END IF;
            IF length(v_pdigits) = 10 THEN
              v_vals := jsonb_set(v_vals, ARRAY[v_pk], to_jsonb(v_pdigits));
            END IF;
          END IF;
        END IF;
      END LOOP;
    END IF;

    BEGIN
      -- ── Unknown-column guard. For create/update, every proposed key must be a
      -- real column on the target table. A hallucinated column name (e.g.
      -- contact_work_phone) would otherwise surface as a cryptic 42703. Instead,
      -- fail early with a precise message naming the bad column(s) and listing the
      -- table's actual columns so the caller can self-correct in the same turn.
      IF v_type IN ('record_create','record_update')
         AND v_vals IS NOT NULL AND jsonb_typeof(v_vals) = 'object' THEN
        v_unknown := ARRAY(
          SELECT k FROM jsonb_object_keys(v_vals) AS k
          WHERE NOT EXISTS (
            SELECT 1 FROM pg_attribute a
            JOIN pg_class c ON c.oid=a.attrelid
            JOIN pg_namespace ns ON ns.oid=c.relnamespace
            WHERE ns.nspname='public' AND c.relname=v_obj
              AND a.attnum>0 AND NOT a.attisdropped
              AND a.attname = k
          )
        );
        IF array_length(v_unknown,1) IS NOT NULL THEN
          SELECT string_agg(a.attname, ', ' ORDER BY a.attname)
            INTO v_valid_cols
            FROM pg_attribute a
            JOIN pg_class c ON c.oid=a.attrelid
            JOIN pg_namespace ns ON ns.oid=c.relnamespace
            WHERE ns.nspname='public' AND c.relname=v_obj
              AND a.attnum>0 AND NOT a.attisdropped;
          RAISE EXCEPTION 'Unknown column(s) on %: %. Valid columns are: %',
            v_obj, array_to_string(v_unknown, ', '), v_valid_cols;
        END IF;
      END IF;

      IF v_type='status_change' THEN
        v_status_field := COALESCE(v_action->>'status_field', _automation_status_column_for(v_obj));
        v_to_status    := NULLIF(v_action->>'to_status_id','')::uuid;
        v_note         := v_action->>'note';
        IF v_rid IS NULL THEN RAISE EXCEPTION 'status_change requires record_id'; END IF;
        IF v_status_field IS NULL THEN RAISE EXCEPTION 'status_change requires status_field for %', v_obj; END IF;
        IF v_to_status IS NULL THEN RAISE EXCEPTION 'status_change requires to_status_id'; END IF;
        PERFORM change_record_status(v_obj, v_status_field, v_rid, v_to_status, v_note);
        v_created := v_rid;
        v_message := format('Status changed on %s %s', v_obj, v_rid);

      ELSIF v_type='report_create' THEN
        v_created := create_report(v_action->'report');
        v_message := format('Created report %s', v_created);

      ELSIF v_type='admin_action' THEN
        v_rpc := v_action->>'rpc';
        v_p   := COALESCE(v_action->'params', '{}'::jsonb);
        IF v_rpc IS NULL OR v_rpc = '' THEN
          RAISE EXCEPTION 'admin_action requires an rpc name';
        END IF;
        IF v_rpc ~* '(purge|delete|drop|truncate|hard_delete|destroy)' THEN
          RAISE EXCEPTION 'Refused: % is a destructive operation. Froggy cannot delete or purge data.', v_rpc;
        END IF;

        IF v_rpc = 'admin_add_custom_field' THEN
          SELECT admin_add_custom_field(
            v_p->>'object', v_p->>'column', v_p->>'label', v_p->>'data_type',
            v_p->>'help_text', v_p->>'description', v_p->>'example_value',
            COALESCE((v_p->>'financial_tier')::int, 1),
            COALESCE((v_p->>'track_history')::boolean, false),
            v_p->>'fk_table'
          ) INTO v_rpc_result;
        ELSIF v_rpc = 'admin_upsert_field_metadata' THEN
          SELECT admin_upsert_field_metadata(
            v_p->>'object', v_p->>'column', v_p->>'label',
            v_p->>'help_text', v_p->>'description', v_p->>'example_value',
            COALESCE((v_p->>'financial_tier')::int, 1),
            COALESCE((v_p->>'track_history')::boolean, false)
          ) INTO v_rpc_result;
        ELSIF v_rpc = 'set_record_type_picklist_values' THEN
          SELECT set_record_type_picklist_values(
            (v_p->>'record_type_id')::uuid, v_p->>'object', v_p->>'field',
            ARRAY(SELECT jsonb_array_elements_text(v_p->'value_ids'))::uuid[]
          ) INTO v_rpc_result;
        ELSIF v_rpc = 'set_flow_active' THEN
          SELECT set_flow_active((v_p->>'flow_id')::uuid, (v_p->>'active')::boolean) INTO v_rpc_result;
        ELSIF v_rpc = 'set_module_sections' THEN
          SELECT set_module_sections(v_p->>'module_id', v_p->'sections') INTO v_rpc_result;
        ELSIF v_rpc = 'save_home_page' THEN
          SELECT save_home_page(v_p->'page', v_p->'components') INTO v_rpc_result;
        ELSIF v_rpc = 'bulk_update_records' THEN
          SELECT bulk_update_records(
            v_p->>'table',
            ARRAY(SELECT jsonb_array_elements_text(v_p->'record_ids'))::uuid[],
            v_p->'updates',
            v_user
          ) INTO v_rpc_result;
        ELSIF v_rpc = 'provision_field_technician' THEN
          SELECT provision_field_technician(
            (v_p->>'user_id')::uuid,
            COALESCE(ARRAY(SELECT jsonb_array_elements_text(v_p->'program_ids'))::uuid[], '{}'::uuid[]),
            COALESCE(ARRAY(SELECT jsonb_array_elements_text(v_p->'permission_set_ids'))::uuid[], '{}'::uuid[]),
            NULLIF(v_p->>'service_territory_id','')::uuid
          ) INTO v_rpc_result;
        ELSIF v_rpc = 'recompute_account_rollups' THEN
          PERFORM recompute_account_rollups((v_p->>'account_id')::uuid); v_rpc_result := jsonb_build_object('ok',true);
        ELSIF v_rpc = 'recompute_building_rollups' THEN
          PERFORM recompute_building_rollups((v_p->>'building_id')::uuid); v_rpc_result := jsonb_build_object('ok',true);
        ELSIF v_rpc = 'recompute_opportunity_rollups' THEN
          PERFORM recompute_opportunity_rollups((v_p->>'opportunity_id')::uuid); v_rpc_result := jsonb_build_object('ok',true);
        ELSIF v_rpc = 'recompute_property_rollups' THEN
          PERFORM recompute_property_rollups((v_p->>'property_id')::uuid); v_rpc_result := jsonb_build_object('ok',true);
        ELSIF v_rpc = 'restore_record' THEN
          SELECT restore_record(v_p->>'table', (v_p->>'record_id')::uuid) INTO v_rpc_result;
        ELSIF v_rpc = 'restore_document_template' THEN
          SELECT restore_document_template((v_p->>'document_template_id')::uuid) INTO v_rpc_result;
        ELSIF v_rpc = 'restore_email_template' THEN
          SELECT restore_email_template((v_p->>'email_template_id')::uuid) INTO v_rpc_result;
        ELSIF v_rpc = 'restore_project_report_template' THEN
          SELECT restore_project_report_template((v_p->>'prt_id')::uuid) INTO v_rpc_result;
        ELSIF v_rpc = 'void_envelope' THEN
          SELECT void_envelope((v_p->>'envelope_id')::uuid, v_p->>'reason') INTO v_rpc_result;
        ELSE
          RAISE EXCEPTION 'Refused: % is not an allowed admin action.', v_rpc;
        END IF;

        v_message := format('Ran %s', v_rpc);

      ELSIF v_type='record_create' THEN
        IF NOT app_user_can(v_obj, 'create') THEN
          RAISE EXCEPTION 'No create permission on %', v_obj;
        END IF;
        v_blocked := ARRAY[]::text[];
        FOR v_k IN SELECT key FROM jsonb_object_keys(v_vals) AS key LOOP
          IF NOT app_user_field_editable(v_obj, v_k) THEN
            v_blocked := array_append(v_blocked, v_k);
          END IF;
        END LOOP;
        IF array_length(v_blocked,1) IS NOT NULL THEN
          RAISE EXCEPTION 'Not permitted to set field(s): %', array_to_string(v_blocked, ', ');
        END IF;

        SELECT string_agg(quote_ident(k),','), string_agg(format('%L', val),',')
          INTO v_cols, v_set
          FROM jsonb_each_text(v_vals) AS j(k,val);

        v_extra_cols := NULL; v_extra_vals := NULL;

        FOR v_colrec IN
          SELECT a.attname
          FROM pg_attribute a
          JOIN pg_class c ON c.oid=a.attrelid
          JOIN pg_namespace ns ON ns.oid=c.relnamespace
          LEFT JOIN pg_attrdef d ON d.adrelid=a.attrelid AND d.adnum=a.attnum
          WHERE ns.nspname='public' AND c.relname=v_obj
            AND a.attnum>0 AND NOT a.attisdropped AND a.attnotnull
            AND pg_get_expr(d.adbin,d.adrelid) IS NULL
            AND format_type(a.atttypid,a.atttypmod)='uuid'
            AND ( a.attname LIKE '%\_owner' OR a.attname='owner_id'
               OR a.attname LIKE '%\_created\_by' OR a.attname='created_by'
               OR a.attname LIKE '%\_updated\_by' OR a.attname='updated_by' )
        LOOP
          IF NOT (v_vals ? v_colrec.attname) THEN
            v_extra_cols := concat_ws(',', v_extra_cols, quote_ident(v_colrec.attname));
            v_extra_vals := concat_ws(',', v_extra_vals, format('%L', v_user));
          END IF;
        END LOOP;

        SELECT a.attname INTO v_num_col
          FROM pg_attribute a
          JOIN pg_class c ON c.oid=a.attrelid
          JOIN pg_namespace ns ON ns.oid=c.relnamespace
          WHERE ns.nspname='public' AND c.relname=v_obj
            AND a.attnum>0 AND NOT a.attisdropped
            AND a.attname LIKE '%\_record\_number'
          LIMIT 1;
        IF v_num_col IS NOT NULL AND NOT (v_vals ? v_num_col) THEN
          v_extra_cols := concat_ws(',', v_extra_cols, quote_ident(v_num_col));
          v_extra_vals := concat_ws(',', v_extra_vals, '''''');
        END IF;

        IF v_extra_cols IS NOT NULL THEN
          v_cols := concat_ws(',', v_cols, v_extra_cols);
          v_set  := concat_ws(',', v_set,  v_extra_vals);
        END IF;

        EXECUTE format('INSERT INTO public.%I (%s) VALUES (%s) RETURNING id', v_obj, v_cols, v_set)
          INTO v_created;
        v_message := format('Created %s %s', v_obj, v_created);

      ELSIF v_type='record_update' THEN
        IF v_rid IS NULL THEN RAISE EXCEPTION 'record_update requires record_id'; END IF;
        IF NOT app_user_can(v_obj, 'update') THEN
          RAISE EXCEPTION 'No update permission on %', v_obj;
        END IF;
        IF NOT app_user_in_scope(v_obj, v_rid) THEN
          RAISE EXCEPTION 'Record % on % is not in your scope', v_rid, v_obj;
        END IF;
        v_blocked := ARRAY[]::text[];
        FOR v_k IN SELECT key FROM jsonb_object_keys(v_vals) AS key LOOP
          IF NOT app_user_field_editable(v_obj, v_k) THEN
            v_blocked := array_append(v_blocked, v_k);
          END IF;
        END LOOP;
        IF array_length(v_blocked,1) IS NOT NULL THEN
          RAISE EXCEPTION 'Not permitted to set field(s): %', array_to_string(v_blocked, ', ');
        END IF;
        SELECT string_agg(format('%I = %L', k, val), ', ')
          INTO v_set FROM jsonb_each_text(v_vals) AS j(k,val);
        EXECUTE format('UPDATE public.%I SET %s WHERE id = $1', v_obj, v_set) USING v_rid;
        v_created := v_rid;
        v_message := format('Updated %s %s', v_obj, v_rid);

      ELSE
        v_outcome := 'skipped'; v_message := format('Unknown action type %s', v_type);
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_outcome := 'error'; v_message := format('%s: %s', SQLSTATE, SQLERRM);
    END;

    -- Register this action's created id under its ref so later actions can use it.
    IF v_outcome='ok' AND v_ref IS NOT NULL AND v_created IS NOT NULL THEN
      v_refs := v_refs || jsonb_build_object(v_ref, v_created::text);
    END IF;

    INSERT INTO public.flow_run_steps
      (frs_record_number, frs_run_id, frs_element_type, frs_order,
       frs_outcome, frs_outcome_message, frs_input, frs_created_target_id)
    VALUES
      ('', v_run_id, v_type, v_order, v_outcome, v_message, v_action, v_created);

    v_results := v_results || jsonb_build_object('order',v_order,'outcome',v_outcome,'message',v_message,'created_id',v_created,'object',v_obj,'ref',v_ref);

    IF v_outcome='error' THEN
      UPDATE public.flow_runs SET fr_status='error', fr_outcome_message=v_message, fr_completed_at=now() WHERE id=v_run_id;
      RETURN jsonb_build_object('ok',false,'run_id',v_run_id,'results',v_results);
    END IF;
  END LOOP;

  UPDATE public.flow_runs SET fr_status='completed', fr_completed_at=now() WHERE id=v_run_id;
  RETURN jsonb_build_object('ok',true,'run_id',v_run_id,'results',v_results);
END; $function$
;

CREATE OR REPLACE FUNCTION public.complete_work_step(p_step_id uuid)
 RETURNS TABLE(step_id uuid, status text, outcome text, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_actor     uuid := public.current_app_user_id();
  v_step      public.work_steps;
  v_gap       text;
  v_completed uuid;
  v_cur       text;
BEGIN
  SELECT * INTO v_step FROM public.work_steps WHERE id = p_step_id AND work_step_is_deleted IS NOT TRUE;
  IF v_step.id IS NULL THEN
    RETURN QUERY SELECT p_step_id, NULL::text, 'error', 'Work step not found or deleted'; RETURN;
  END IF;

  v_actor := COALESCE(v_actor, v_step.work_step_owner, v_step.work_step_created_by);

  SELECT picklist_value INTO v_cur FROM public.picklist_values WHERE id = v_step.work_step_status;
  IF v_cur IN ('Completed','Verified') THEN
    RETURN QUERY SELECT p_step_id, v_cur, 'noop', format('Step is already %s', v_cur); RETURN;
  END IF;
  IF v_cur = 'Not Applicable' THEN
    RETURN QUERY SELECT p_step_id, v_cur, 'noop', 'Step is marked Not Applicable'; RETURN;
  END IF;

  v_gap := public._work_step_evidence_gap(v_step);
  IF v_gap IS NOT NULL THEN
    RETURN QUERY SELECT p_step_id, v_cur, 'blocked', v_gap; RETURN;
  END IF;

  SELECT id INTO v_completed FROM public.picklist_values
   WHERE picklist_object='work_steps' AND picklist_field='work_step_status'
     AND picklist_value='Completed' AND picklist_is_active LIMIT 1;

  UPDATE public.work_steps
     SET work_step_status   = v_completed,
         work_step_end_time = COALESCE(work_step_end_time, now()),
         work_step_updated_by = v_actor,
         work_step_updated_at = now()
   WHERE id = p_step_id;

  RETURN QUERY SELECT p_step_id, 'Completed', 'success',
    format('Step "%s" completed', v_step.work_step_name);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compute_next_send_at(p_frequency text, p_day_of_week integer, p_day_of_month integer, p_send_time time without time zone, p_timezone text, p_anchor timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS timestamp with time zone
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_local_anchor   timestamp;       -- naive timestamp in the schedule's TZ
  v_today_local    date;
  v_candidate      timestamp;
  v_month_start    date;
  v_last_day       int;
  v_target_dom     int;
BEGIN
  -- Use now() as the anchor when none supplied
  IF p_anchor IS NULL THEN p_anchor := now(); END IF;

  -- Convert anchor to the schedule's local time
  v_local_anchor := (p_anchor AT TIME ZONE p_timezone);
  v_today_local  := v_local_anchor::date;

  IF p_frequency = 'daily' THEN
    v_candidate := v_today_local + p_send_time;
    IF v_candidate <= v_local_anchor THEN
      v_candidate := v_today_local + 1 + p_send_time;
    END IF;

  ELSIF p_frequency = 'weekly' THEN
    -- ISODOW: 1=Monday, 7=Sunday
    DECLARE v_today_isodow int := EXTRACT(ISODOW FROM v_today_local)::int; v_offset int;
    BEGIN
      v_offset := (p_day_of_week - v_today_isodow);
      IF v_offset < 0 THEN v_offset := v_offset + 7; END IF;
      v_candidate := (v_today_local + v_offset) + p_send_time;
      IF v_candidate <= v_local_anchor THEN
        v_candidate := (v_today_local + v_offset + 7) + p_send_time;
      END IF;
    END;

  ELSIF p_frequency = 'monthly' THEN
    v_month_start := date_trunc('month', v_today_local)::date;
    v_last_day    := EXTRACT(DAY FROM (v_month_start + INTERVAL '1 month - 1 day'))::int;
    v_target_dom  := LEAST(p_day_of_month, v_last_day);
    v_candidate   := (v_month_start + (v_target_dom - 1)) + p_send_time;
    IF v_candidate <= v_local_anchor THEN
      v_month_start := (v_month_start + INTERVAL '1 month')::date;
      v_last_day    := EXTRACT(DAY FROM (v_month_start + INTERVAL '1 month - 1 day'))::int;
      v_target_dom  := LEAST(p_day_of_month, v_last_day);
      v_candidate   := (v_month_start + (v_target_dom - 1)) + p_send_time;
    END IF;

  ELSE
    RAISE EXCEPTION 'Unknown frequency: %', p_frequency;
  END IF;

  RETURN v_candidate AT TIME ZONE p_timezone;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.count_appts_for_resource_in_territory_day(p_contact_id uuid, p_territory_id uuid, p_window_start timestamp with time zone, p_window_end timestamp with time zone)
 RETURNS integer
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT COUNT(*)::integer
  FROM service_appointments sa
  JOIN service_appointment_assignments saa
       ON saa.service_appointment_id = sa.id
      AND saa.contact_id              = p_contact_id
      AND saa.saa_is_deleted          = false
  LEFT JOIN picklist_values pv ON pv.id = sa.sa_status
  WHERE sa.sa_is_deleted = false
    AND sa.service_territory_id = p_territory_id
    AND sa.sa_scheduled_start_time <  p_window_end
    AND sa.sa_scheduled_end_time   >  p_window_start
    AND (pv.picklist_value IS NULL OR pv.picklist_value NOT IN ('canceled','no_show'));
$function$
;

CREATE OR REPLACE FUNCTION public.count_seed_data()
 RETURNS TABLE(table_name text, record_count bigint)
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT sdr_table_name AS table_name, COUNT(*) AS record_count
    FROM seed_data_records
   GROUP BY sdr_table_name
   ORDER BY sdr_table_name;
$function$
;

CREATE OR REPLACE FUNCTION public.create_report(p_report jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user uuid;
  v_report_id uuid;
  v_name text;
  v_primary text;
  v_format text;
  v_row jsonb;
  v_idx integer;
BEGIN
  v_user := current_app_user_id();
  IF v_user IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;
  IF NOT app_user_can('reports', 'create') THEN
    RAISE EXCEPTION 'No create permission on reports';
  END IF;

  v_name := NULLIF(trim(p_report->>'name'), '');
  IF v_name IS NULL THEN RAISE EXCEPTION 'Report name is required'; END IF;
  v_primary := NULLIF(p_report->>'primary_object', '');
  IF v_primary IS NULL THEN RAISE EXCEPTION 'Report primary_object is required'; END IF;
  v_format := COALESCE(NULLIF(p_report->>'format',''), 'tabular');
  IF v_format NOT IN ('tabular','summary','matrix') THEN
    RAISE EXCEPTION 'Report format must be tabular, summary, or matrix (got %)', v_format;
  END IF;

  INSERT INTO public.reports
    (rpt_record_number, rpt_name, rpt_description, rpt_format, rpt_primary_object,
     rpt_selected_fields, rpt_filter_logic, rpt_sort_config, rpt_column_groupings,
     rpt_charts, rpt_owner_user_id, created_by, updated_by)
  VALUES
    ('', v_name, NULLIF(p_report->>'description',''), v_format, v_primary,
     COALESCE(p_report->'selected_fields', '[]'::jsonb),
     COALESCE(NULLIF(p_report->>'filter_logic',''), 'all'),
     COALESCE(p_report->'sort_config', '[]'::jsonb),
     COALESCE(p_report->'column_groupings', '[]'::jsonb),
     COALESCE(p_report->'charts', '[]'::jsonb),
     v_user, v_user, v_user)
  RETURNING id INTO v_report_id;

  -- Filters (with cross-object support).
  v_idx := 0;
  FOR v_row IN SELECT * FROM jsonb_array_elements(COALESCE(p_report->'filters','[]'::jsonb)) LOOP
    v_idx := v_idx + 1;
    INSERT INTO public.report_filters
      (rfilt_report_id, rfilt_filter_index, rfilt_field_name, rfilt_field_table,
       rfilt_field_via_path, rfilt_operator, rfilt_value,
       rfilt_is_cross_filter, rfilt_cross_object, rfilt_cross_match, rfilt_cross_subfilters,
       created_by, updated_by)
    VALUES
      (v_report_id, v_idx,
       NULLIF(v_row->>'field_name',''),
       NULLIF(v_row->>'field_table',''),
       CASE WHEN v_row ? 'field_via_path' THEN v_row->'field_via_path' ELSE NULL END,
       COALESCE(NULLIF(v_row->>'operator',''), 'equals'),
       CASE WHEN v_row ? 'value' THEN v_row->'value' ELSE NULL END,
       COALESCE((v_row->>'is_cross_filter')::boolean, false),
       NULLIF(v_row->>'cross_object',''),
       NULLIF(v_row->>'cross_match',''),
       COALESCE(v_row->'cross_subfilters', '[]'::jsonb),
       v_user, v_user);
  END LOOP;

  -- Row groupings (summary / matrix row axis).
  v_idx := 0;
  FOR v_row IN SELECT * FROM jsonb_array_elements(COALESCE(p_report->'groupings','[]'::jsonb)) LOOP
    v_idx := v_idx + 1;
    IF NULLIF(v_row->>'field_name','') IS NULL THEN
      RAISE EXCEPTION 'Grouping % is missing field_name', v_idx;
    END IF;
    INSERT INTO public.report_groupings
      (rgr_report_id, rgr_grouping_level, rgr_field_name, rgr_field_table,
       rgr_field_via_path, rgr_field_label, rgr_sort_direction, rgr_sort_by_aggregate,
       rgr_show_subtotal, rgr_date_granularity, created_by, updated_by)
    VALUES
      (v_report_id, v_idx,
       v_row->>'field_name',
       NULLIF(v_row->>'field_table',''),
       CASE WHEN v_row ? 'field_via_path' THEN v_row->'field_via_path' ELSE NULL END,
       NULLIF(v_row->>'field_label',''),
       COALESCE(NULLIF(v_row->>'sort_direction',''), 'asc'),
       NULLIF(v_row->>'sort_by_aggregate',''),
       COALESCE((v_row->>'show_subtotal')::boolean, true),
       NULLIF(v_row->>'date_granularity',''),
       v_user, v_user);
  END LOOP;

  -- Calculated fields.
  v_idx := 0;
  FOR v_row IN SELECT * FROM jsonb_array_elements(COALESCE(p_report->'calculated_fields','[]'::jsonb)) LOOP
    IF NULLIF(v_row->>'label','') IS NULL OR NULLIF(v_row->>'expression','') IS NULL THEN
      RAISE EXCEPTION 'Calculated field requires label and expression';
    END IF;
    INSERT INTO public.report_calculated_fields
      (rcf_report_id, rcf_label, rcf_scope, rcf_expression, rcf_data_type,
       rcf_format_options, rcf_display_order, rcf_grouping_level, created_by, updated_by)
    VALUES
      (v_report_id,
       v_row->>'label',
       COALESCE(NULLIF(v_row->>'scope',''), 'row'),
       v_row->>'expression',
       COALESCE(NULLIF(v_row->>'data_type',''), 'number'),
       COALESCE(v_row->'format_options', '{}'::jsonb),
       v_idx,
       NULLIF(v_row->>'grouping_level','')::integer,
       v_user, v_user);
    v_idx := v_idx + 1;
  END LOOP;

  RETURN v_report_id;
END; $function$
;

CREATE OR REPLACE FUNCTION public.create_service_appointment(payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_admin_id     uuid := 'c5a01ec8-960f-42ab-8a9e-a49822de89af';

  v_slug         text;
  v_start_iso    timestamptz;
  v_end_iso      timestamptz;
  v_resource_id  uuid;
  v_first        text;
  v_last         text;
  v_phone_raw    text;
  v_phone        text;
  v_email        text;
  v_street       text;
  v_city         text;
  v_state        text;
  v_zip          text;
  v_intake       jsonb;

  -- NEW v2: bypass flag honored only for authenticated app users.
  v_bypass_territory boolean := false;

  v_work_type_id           uuid;
  v_territory_id           uuid;
  v_duration_minutes       numeric;
  v_account_id             uuid;
  v_contact_id             uuid;
  v_property_id            uuid;
  v_building_id            uuid;
  v_unit_id                uuid;
  v_opportunity_id         uuid;
  v_project_id             uuid;
  v_work_order_id          uuid;
  v_service_appointment_id uuid;
  v_sa_record_number       text;
  v_sat_token              text;
  v_scheduled_status_id    uuid;
  v_lock_key               bigint;
  v_sa_day                 date;
  v_conflict_count         integer;
BEGIN
  v_slug        := payload->>'slug';
  v_start_iso   := (payload->>'start_iso')::timestamptz;
  v_end_iso     := (payload->>'end_iso')::timestamptz;
  v_resource_id := (payload->>'resource_id')::uuid;
  v_first       := payload->>'customer_first_name';
  v_last        := payload->>'customer_last_name';
  v_phone_raw   := payload->>'phone';
  v_email       := lower(payload->>'email');
  v_street      := payload->'address'->>'street';
  v_city        := payload->'address'->>'city';
  v_state       := upper(payload->'address'->>'state');
  v_zip         := substring(payload->'address'->>'zip' from 1 for 5);
  v_intake      := COALESCE(payload->'intake', '{}'::jsonb);

  -- NEW v2: compute bypass eligibility. The COALESCE guards against
  -- nulls; the AND with current_app_user_id() IS NOT NULL ensures only
  -- authenticated callers can activate the bypass. Anon callers via
  -- the service-role edge function path will see current_app_user_id()
  -- return NULL and the flag is silently ignored.
  v_bypass_territory := COALESCE((payload->>'bypass_territory_check')::boolean, false)
                    AND current_app_user_id() IS NOT NULL;

  v_phone := regexp_replace(v_phone_raw, '\D', '', 'g');
  IF length(v_phone) = 11 AND left(v_phone, 1) = '1' THEN
    v_phone := substring(v_phone from 2);
  END IF;
  IF length(v_phone) != 10 THEN
    RETURN jsonb_build_object('status','error','message','Phone must be a 10-digit US number.');
  END IF;
  IF v_zip !~ '^\d{5}$' THEN RETURN jsonb_build_object('status','error','message','ZIP must be 5 digits.'); END IF;
  IF length(v_state) != 2 THEN RETURN jsonb_build_object('status','error','message','State must be a 2-letter code.'); END IF;

  SELECT id INTO v_work_type_id FROM work_types
   WHERE work_type_public_slug = v_slug
     AND work_type_is_publicly_schedulable = true
     AND work_type_is_deleted = false
     AND work_type_is_active = true
   LIMIT 1;
  IF v_work_type_id IS NULL THEN RETURN jsonb_build_object('status','error','message','Invalid work type slug.'); END IF;

  SELECT stz.service_territory_id INTO v_territory_id
    FROM service_territory_zips stz
    JOIN service_territories st ON st.id = stz.service_territory_id
   WHERE stz.stz_zip_code = v_zip AND stz.stz_is_deleted = false
     AND st.service_territory_is_active = true AND st.service_territory_is_deleted = false
   LIMIT 1;
  -- CHANGED v2: territory-not-found is only an error when the caller
  -- has not requested (and been granted) the bypass. With bypass,
  -- v_territory_id stays NULL and the SA is created with NULL territory.
  IF v_territory_id IS NULL AND NOT v_bypass_territory THEN
    RETURN jsonb_build_object('status','error','message','Address is outside our service territory.');
  END IF;

  v_duration_minutes := EXTRACT(EPOCH FROM (v_end_iso - v_start_iso)) / 60;

  v_sa_day   := (v_start_iso AT TIME ZONE 'America/Chicago')::date;
  v_lock_key := hashtextextended(v_resource_id::text || ':' || v_sa_day::text, 0);
  PERFORM pg_advisory_xact_lock(v_lock_key);

  SELECT count(*) INTO v_conflict_count
    FROM service_appointment_assignments saa
    JOIN service_appointments sa ON sa.id = saa.service_appointment_id
   WHERE saa.contact_id = v_resource_id
     AND coalesce(saa.saa_is_deleted, false) = false
     AND coalesce(sa.sa_is_deleted, false)  = false
     AND sa.sa_scheduled_start_time < v_end_iso
     AND sa.sa_scheduled_end_time   > v_start_iso;
  IF v_conflict_count > 0 THEN
    RETURN jsonb_build_object('status','slot_taken','message','That time slot was just taken by another customer. Please pick another.');
  END IF;

  SELECT id INTO v_scheduled_status_id FROM picklist_values
   WHERE picklist_object='service_appointments' AND picklist_field='sa_status' AND picklist_value='Scheduled' AND picklist_is_active=true
   LIMIT 1;

  SELECT id, contact_account_id INTO v_contact_id, v_account_id FROM contacts
   WHERE contact_phone = v_phone AND coalesce(contact_is_deleted,false) = false
   LIMIT 1;

  IF v_contact_id IS NULL THEN
    INSERT INTO accounts (account_record_number, account_name, account_phone, account_email, account_owner,
                          account_created_at, account_created_by, account_updated_at, account_updated_by)
    VALUES ('', trim(v_first || ' ' || v_last), v_phone, v_email, v_admin_id,
            now(), v_admin_id, now(), v_admin_id)
    RETURNING id INTO v_account_id;

    INSERT INTO contacts (contact_record_number, contact_name, contact_first_name, contact_last_name,
                          contact_phone, contact_email, contact_account_id, contact_owner,
                          contact_created_at, contact_created_by, contact_updated_at, contact_updated_by)
    VALUES ('', trim(v_first || ' ' || v_last), v_first, v_last,
            v_phone, v_email, v_account_id, v_admin_id,
            now(), v_admin_id, now(), v_admin_id)
    RETURNING id INTO v_contact_id;
  END IF;

  INSERT INTO properties (property_record_number, property_name, property_street, property_city,
                          property_state, property_zip, property_account_id, property_owner,
                          property_created_at, property_created_by, property_updated_at, property_updated_by)
  VALUES ('', v_street, v_street, v_city, v_state, v_zip, v_account_id, v_admin_id,
          now(), v_admin_id, now(), v_admin_id)
  RETURNING id INTO v_property_id;

  INSERT INTO buildings (building_record_number, building_name, building_number_or_name,
                         property_id, building_owner,
                         building_created_at, building_created_by, building_updated_at, building_updated_by)
  VALUES ('', v_street, 'Main', v_property_id, v_admin_id,
          now(), v_admin_id, now(), v_admin_id)
  RETURNING id INTO v_building_id;

  INSERT INTO units (unit_record_number, unit_name, unit_number, building_id, unit_owner,
                     unit_created_at, unit_created_by, unit_updated_at, unit_updated_by)
  VALUES ('', 'Unit 1', '1', v_building_id, v_admin_id,
          now(), v_admin_id, now(), v_admin_id)
  RETURNING id INTO v_unit_id;

  INSERT INTO opportunities (opportunity_record_number, opportunity_name,
                             opportunity_account_id, property_id, building_id, opportunity_owner,
                             opportunity_created_at, opportunity_created_by, opportunity_updated_at, opportunity_updated_by)
  VALUES ('', trim(v_first || ' ' || v_last) || ' — ' || v_street,
          v_account_id, v_property_id, v_building_id, v_admin_id,
          now(), v_admin_id, now(), v_admin_id)
  RETURNING id INTO v_opportunity_id;

  INSERT INTO projects (project_record_number, project_name,
                        project_account_id, opportunity_id, property_id, building_id, project_owner,
                        project_created_at, project_created_by, project_updated_at, project_updated_by)
  VALUES ('', trim(v_first || ' ' || v_last) || ' — assessment',
          v_account_id, v_opportunity_id, v_property_id, v_building_id, v_admin_id,
          now(), v_admin_id, now(), v_admin_id)
  RETURNING id INTO v_project_id;

  INSERT INTO work_orders (work_order_record_number, work_order_name,
                           work_type_id, property_id, opportunity_id,
                           work_order_account_id, project_id, building_id, unit_id, work_order_owner,
                           work_order_created_at, work_order_created_by, work_order_updated_at, work_order_updated_by)
  VALUES ('', 'WO — assessment',
          v_work_type_id, v_property_id, v_opportunity_id,
          v_account_id, v_project_id, v_building_id, v_unit_id, v_admin_id,
          now(), v_admin_id, now(), v_admin_id)
  RETURNING id INTO v_work_order_id;

  -- service_territory_id can be NULL here in the bypass path. Column is
  -- nullable; FK is ON DELETE SET NULL (verified by schema).
  INSERT INTO service_appointments (sa_record_number, sa_name, work_order_id, sa_owner,
                                    sa_status, sa_scheduled_start_time, sa_scheduled_end_time,
                                    sa_duration_minutes, service_territory_id,
                                    sa_created_at, sa_created_by, sa_updated_at, sa_updated_by)
  VALUES ('', 'SA', v_work_order_id, v_admin_id,
          v_scheduled_status_id, v_start_iso, v_end_iso,
          v_duration_minutes, v_territory_id,
          now(), v_admin_id, now(), v_admin_id)
  RETURNING id, sa_record_number INTO v_service_appointment_id, v_sa_record_number;

  INSERT INTO service_appointment_assignments (saa_record_number, saa_name,
                                               service_appointment_id, contact_id,
                                               saa_created_at, saa_created_by, saa_updated_at, saa_updated_by,
                                               saa_is_deleted)
  VALUES ('', '',
          v_service_appointment_id, v_resource_id,
          now(), v_admin_id, now(), v_admin_id, false);

  v_sat_token := replace(gen_random_uuid()::text, '-', '');
  INSERT INTO service_appointment_tokens (sat_token, service_appointment_id, sat_purpose, sat_expires_at)
  VALUES (v_sat_token, v_service_appointment_id, 'manage', v_start_iso + interval '7 days');

  RETURN jsonb_build_object(
    'status', 'ok',
    'service_appointment_id',    v_service_appointment_id,
    'sa_record_number',          v_sa_record_number,
    'service_appointment_token', v_sat_token,
    -- NEW v2: surface whether the bypass was actually used (true only
    -- when the flag was set, the caller was authenticated, AND the ZIP
    -- didn't match a territory). Useful for analytics and for the
    -- frontend to know it took the bypass path.
    'territory_bypassed',        (v_bypass_territory AND v_territory_id IS NULL)
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('status','error','message',SQLERRM);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_standard_page_layout(p_table text)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_admin_uuid       uuid := 'c5a01ec8-960f-42ab-8a9e-a49822de89af';
  v_existing         uuid;
  v_layout_id        uuid;
  v_record_section   uuid;
  v_system_section   uuid;
  v_business_fields  jsonb := '[]'::jsonb;
  v_system_fields    jsonb := '[]'::jsonb;
  v_pretty_label     text;
  r                  record;
  v_field            jsonb;
  v_is_system        boolean;
  v_is_fk            boolean;
  v_field_type       text;
  v_display_col      text;
  v_label            text;
BEGIN
  SELECT id INTO v_existing
  FROM page_layouts
  WHERE page_layout_object = p_table
    AND page_layout_type = 'record_detail'
    AND page_layout_is_default = true
    AND is_deleted = false
  LIMIT 1;

  IF v_existing IS NOT NULL THEN
    RETURN v_existing;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.tables
    WHERE table_schema = 'public' AND table_name = p_table AND table_type = 'BASE TABLE'
  ) THEN
    RAISE NOTICE 'Table public.% does not exist — skipping', p_table;
    RETURN NULL;
  END IF;

  FOR r IN
    SELECT
      c.column_name,
      c.data_type,
      c.ordinal_position,
      fk.foreign_table_name
    FROM information_schema.columns c
    LEFT JOIN LATERAL (
      SELECT ccu.table_name AS foreign_table_name
      FROM information_schema.table_constraints tc
      JOIN information_schema.key_column_usage kcu
        ON tc.constraint_name = kcu.constraint_name
       AND tc.table_schema    = kcu.table_schema
      JOIN information_schema.constraint_column_usage ccu
        ON ccu.constraint_name = tc.constraint_name
       AND ccu.table_schema    = tc.table_schema
      WHERE tc.constraint_type = 'FOREIGN KEY'
        AND tc.table_schema    = 'public'
        AND tc.table_name      = c.table_name
        AND kcu.column_name    = c.column_name
      LIMIT 1
    ) fk ON true
    WHERE c.table_schema = 'public'
      AND c.table_name   = p_table
    ORDER BY c.ordinal_position
  LOOP
    IF r.column_name = 'id' THEN CONTINUE; END IF;
    IF r.column_name = 'is_deleted' THEN CONTINUE; END IF;
    IF r.column_name LIKE '%\_is\_deleted' ESCAPE '\' THEN CONTINUE; END IF;
    IF r.column_name = 'created_by' OR r.column_name = 'updated_by' THEN CONTINUE; END IF;
    IF r.column_name LIKE '%\_created\_by' ESCAPE '\' THEN CONTINUE; END IF;
    IF r.column_name LIKE '%\_updated\_by' ESCAPE '\' THEN CONTINUE; END IF;
    IF r.data_type IN ('ARRAY', 'jsonb', 'json') THEN CONTINUE; END IF;

    v_is_fk      := r.foreign_table_name IS NOT NULL;
    v_field_type := public._pick_ees_field_type(r.column_name, r.data_type, v_is_fk);
    v_display_col := CASE WHEN v_field_type = 'lookup'
                          THEN public._pick_ees_display_column(r.foreign_table_name)
                          ELSE NULL END;
    v_label := public._humanize_column(r.column_name);

    v_is_system := (
      r.column_name = 'owner_id'
      OR r.column_name = 'created_at'
      OR r.column_name = 'updated_at'
      OR r.column_name LIKE '%\_owner' ESCAPE '\'
      OR r.column_name LIKE '%\_created\_at' ESCAPE '\'
      OR r.column_name LIKE '%\_updated\_at' ESCAPE '\'
    );

    v_field := jsonb_strip_nulls(jsonb_build_object(
      'name',         r.column_name,
      'type',         v_field_type,
      'label',        v_label,
      'lookup_table', CASE WHEN v_field_type = 'lookup' THEN r.foreign_table_name ELSE NULL END,
      'lookup_field', CASE WHEN v_field_type = 'lookup' THEN v_display_col          ELSE NULL END
    ));

    IF v_is_system THEN
      v_system_fields := v_system_fields || v_field;
    ELSE
      v_business_fields := v_business_fields || v_field;
    END IF;
  END LOOP;

  IF jsonb_array_length(v_business_fields) = 0 AND jsonb_array_length(v_system_fields) = 0 THEN
    RAISE NOTICE 'Table public.% has no renderable columns — skipping', p_table;
    RETURN NULL;
  END IF;

  v_pretty_label := initcap(replace(p_table, '_', ' '));

  INSERT INTO page_layouts (
    page_layout_record_number, page_layout_name, page_layout_object, page_layout_type,
    page_layout_is_default, page_layout_description, page_layout_owner, page_layout_created_by
  ) VALUES (
    '', 'Standard ' || v_pretty_label || ' Layout', p_table, 'record_detail',
    true, 'Default layout auto-generated from column metadata. Safe to modify.',
    v_admin_uuid, v_admin_uuid
  ) RETURNING id INTO v_layout_id;

  IF jsonb_array_length(v_business_fields) > 0 THEN
    INSERT INTO page_layout_sections (
      page_layout_id, section_order, section_label, section_tab, section_columns
    ) VALUES (v_layout_id, 1, 'Record', 'Details', 2)
    RETURNING id INTO v_record_section;

    INSERT INTO page_layout_widgets (
      page_layout_widget_record_number, page_layout_id, section_id,
      widget_type, widget_title, widget_column, widget_position, widget_config
    ) VALUES (
      '', v_layout_id, v_record_section,
      'field_group', 'Details', 1, 1,
      jsonb_build_object('fields', v_business_fields)
    );
  END IF;

  IF jsonb_array_length(v_system_fields) > 0 THEN
    INSERT INTO page_layout_sections (
      page_layout_id, section_order, section_label, section_tab, section_columns
    ) VALUES (v_layout_id, 2, 'System Information', 'Details', 2)
    RETURNING id INTO v_system_section;

    INSERT INTO page_layout_widgets (
      page_layout_widget_record_number, page_layout_id, section_id,
      widget_type, widget_title, widget_column, widget_position, widget_config
    ) VALUES (
      '', v_layout_id, v_system_section,
      'field_group', 'System Information', 1, 1,
      jsonb_build_object('fields', v_system_fields)
    );
  END IF;

  RETURN v_layout_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.current_app_user_id()
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT u.id
  FROM public.users u
  WHERE u.auth_user_id = auth.uid()
  LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.dashboard_filter_distinct_values(p_object text, p_field text, p_limit integer DEFAULT 200)
 RETURNS TABLE(value text, n bigint)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_soft_col text;
  v_where    text := ' WHERE true';
  v_sql      text;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM information_schema.tables
                 WHERE table_schema='public' AND table_name=p_object) THEN
    RAISE EXCEPTION 'Unknown object: %', p_object;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                 WHERE table_schema='public' AND table_name=p_object
                   AND column_name=p_field) THEN
    RAISE EXCEPTION 'Unknown column %.%', p_object, p_field;
  END IF;

  SELECT (ees_table_metadata(p_object)->>'is_deleted_column') INTO v_soft_col;
  IF v_soft_col IS NOT NULL THEN
    v_where := v_where || format(' AND t.%I = false', v_soft_col);
  END IF;

  v_where := v_where
    || format(' AND t.%I IS NOT NULL', p_field)
    || format(' AND btrim(t.%I::text) <> ''''', p_field);

  v_sql := format(
    'SELECT t.%I::text AS value, COUNT(*)::bigint AS n FROM %I t%s GROUP BY t.%I ORDER BY n DESC, value ASC LIMIT %s',
    p_field, p_object, v_where, p_field, GREATEST(p_limit, 1)
  );

  RETURN QUERY EXECUTE v_sql;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.derive_building_name()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_property_name text;
  v_number        text;
BEGIN
  SELECT p.property_name INTO v_property_name
    FROM properties p WHERE p.id = NEW.property_id;
  v_number := NULLIF(trim(coalesce(NEW.building_number_or_name, '')), '');

  NEW.building_name := NULLIF(
    trim(both ' -' FROM (
      coalesce(NULLIF(trim(coalesce(v_property_name,'')),''), '')
      || CASE WHEN v_number IS NOT NULL THEN ' - ' || v_number ELSE '' END
    )),
    ''
  );
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.derive_opportunity_name()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_building_name text;
  v_record_label  text;
  v_property_name text;
  v_base          text;
BEGIN
  SELECT b.building_name INTO v_building_name
    FROM buildings b WHERE b.id = NEW.building_id;

  SELECT pv.picklist_label INTO v_record_label
    FROM picklist_values pv WHERE pv.id = NEW.opportunity_record_type;

  -- Base = building name, or property name when no building is linked.
  v_base := NULLIF(trim(coalesce(v_building_name, '')), '');
  IF v_base IS NULL THEN
    SELECT p.property_name INTO v_property_name
      FROM properties p WHERE p.id = NEW.property_id;
    v_base := NULLIF(trim(coalesce(v_property_name, '')), '');
  END IF;

  -- Compose. Trim any trailing " - " when the record type is absent.
  NEW.opportunity_name := NULLIF(
    trim(both ' -' FROM (
      coalesce(v_base, '')
      || CASE WHEN v_record_label IS NOT NULL AND trim(v_record_label) <> ''
              THEN ' - ' || v_record_label ELSE '' END
    )),
    ''
  );

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.derive_project_name()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_opportunity_name text;
  v_record_label     text;
BEGIN
  SELECT o.opportunity_name INTO v_opportunity_name
    FROM opportunities o WHERE o.id = NEW.opportunity_id;

  SELECT pv.picklist_label INTO v_record_label
    FROM picklist_values pv WHERE pv.id = NEW.project_record_type;

  NEW.project_name := NULLIF(
    trim(both ' -' FROM (
      coalesce(NULLIF(trim(coalesce(v_opportunity_name,'')),''), '')
      || CASE WHEN v_record_label IS NOT NULL AND trim(v_record_label) <> ''
              THEN ' - ' || v_record_label ELSE '' END
    )),
    ''
  );
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.derive_unit_name()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
