CREATE OR REPLACE FUNCTION public.describe_object_columns(p_table text)
 RETURNS TABLE(column_name text, data_type text, is_nullable text, column_default text, character_maximum_length integer, numeric_precision integer, numeric_scale integer, ordinal_position integer, is_primary_key boolean, is_foreign_key boolean, references_table text, references_column text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  WITH rel AS (
    SELECT c.oid AS relid
    FROM pg_catalog.pg_class c
    JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public' AND c.relname = p_table AND c.relkind IN ('r','p')
  ),
  pk AS (
    -- Primary key column attnums for the target relation
    SELECT unnest(con.conkey) AS attnum
    FROM pg_catalog.pg_constraint con, rel
    WHERE con.conrelid = rel.relid AND con.contype = 'p'
  ),
  fk AS (
    -- Single-column FKs referencing the target relation's columns.
    -- conkey[1] is the FK column's attnum on the local table; confkey[1]
    -- is the referenced column's attnum on the foreign table.
    SELECT
      con.conkey[1] AS attnum,
      fc.relname    AS ref_table,
      fa.attname    AS ref_column
    FROM pg_catalog.pg_constraint con
    JOIN rel ON con.conrelid = rel.relid
    JOIN pg_catalog.pg_class     fc ON fc.oid = con.confrelid
    JOIN pg_catalog.pg_attribute fa
      ON fa.attrelid = con.confrelid AND fa.attnum = con.confkey[1]
    WHERE con.contype = 'f' AND array_length(con.conkey, 1) = 1
  )
  SELECT
    a.attname::text                        AS column_name,
    CASE
      WHEN a.attndims > 0 THEN 'ARRAY'
      ELSE CASE t.typname
        WHEN 'int2'        THEN 'smallint'
        WHEN 'int4'        THEN 'integer'
        WHEN 'int8'        THEN 'bigint'
        WHEN 'float4'      THEN 'real'
        WHEN 'float8'      THEN 'double precision'
        WHEN 'numeric'     THEN 'numeric'
        WHEN 'varchar'     THEN 'character varying'
        WHEN 'bpchar'      THEN 'character'
        WHEN 'bool'        THEN 'boolean'
        WHEN 'timestamp'   THEN 'timestamp without time zone'
        WHEN 'timestamptz' THEN 'timestamp with time zone'
        WHEN 'time'        THEN 'time without time zone'
        WHEN 'timetz'      THEN 'time with time zone'
        WHEN 'date'        THEN 'date'
        WHEN 'text'        THEN 'text'
        WHEN 'uuid'        THEN 'uuid'
        WHEN 'jsonb'       THEN 'jsonb'
        WHEN 'json'        THEN 'json'
        ELSE t.typname::text
      END
    END                                    AS data_type,
    CASE WHEN a.attnotnull THEN 'NO' ELSE 'YES' END AS is_nullable,
    pg_catalog.pg_get_expr(ad.adbin, ad.adrelid)    AS column_default,
    -- character_maximum_length — varchar(N) / char(N) via atttypmod
    CASE
      WHEN t.typname IN ('varchar','bpchar') AND a.atttypmod > 4
        THEN (a.atttypmod - 4)
      ELSE NULL
    END::int                               AS character_maximum_length,
    -- numeric_precision — stored in upper 16 bits of (atttypmod - 4)
    CASE
      WHEN t.typname = 'numeric' AND a.atttypmod >= 4
        THEN ((a.atttypmod - 4) >> 16) & 65535
      WHEN t.typname = 'int2' THEN 16
      WHEN t.typname = 'int4' THEN 32
      WHEN t.typname = 'int8' THEN 64
      WHEN t.typname = 'float4' THEN 24
      WHEN t.typname = 'float8' THEN 53
      ELSE NULL
    END::int                               AS numeric_precision,
    -- numeric_scale — lower 16 bits of (atttypmod - 4)
    CASE
      WHEN t.typname = 'numeric' AND a.atttypmod >= 4
        THEN (a.atttypmod - 4) & 65535
      WHEN t.typname IN ('int2','int4','int8') THEN 0
      ELSE NULL
    END::int                               AS numeric_scale,
    a.attnum::int                          AS ordinal_position,
    (pk.attnum IS NOT NULL)                AS is_primary_key,
    (fk.attnum IS NOT NULL)                AS is_foreign_key,
    fk.ref_table::text                     AS references_table,
    fk.ref_column::text                    AS references_column
  FROM rel
  JOIN pg_catalog.pg_attribute a ON a.attrelid = rel.relid
  JOIN pg_catalog.pg_type      t ON t.oid      = a.atttypid
  LEFT JOIN pg_catalog.pg_attrdef ad
    ON ad.adrelid = a.attrelid AND ad.adnum = a.attnum
  LEFT JOIN pk ON pk.attnum = a.attnum
  LEFT JOIN fk ON fk.attnum = a.attnum
  WHERE a.attnum > 0 AND NOT a.attisdropped
  ORDER BY a.attnum;
$function$
;

CREATE OR REPLACE FUNCTION public.describe_object_incoming_fks(p_table text)
 RETURNS TABLE(referencing_table text, referencing_column text, referenced_column text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT
    rc.relname::text  AS referencing_table,
    ra.attname::text  AS referencing_column,
    fa.attname::text  AS referenced_column
  FROM pg_catalog.pg_constraint con
  JOIN pg_catalog.pg_class     rc ON rc.oid = con.conrelid
  JOIN pg_catalog.pg_namespace rn ON rn.oid = rc.relnamespace
  JOIN pg_catalog.pg_class     fc ON fc.oid = con.confrelid
  JOIN pg_catalog.pg_namespace fn ON fn.oid = fc.relnamespace
  JOIN pg_catalog.pg_attribute ra
    ON ra.attrelid = con.conrelid AND ra.attnum = con.conkey[1]
  JOIN pg_catalog.pg_attribute fa
    ON fa.attrelid = con.confrelid AND fa.attnum = con.confkey[1]
  WHERE con.contype = 'f'
    AND fn.nspname  = 'public'
    AND fc.relname  = p_table
    AND array_length(con.conkey, 1) = 1
  ORDER BY rc.relname, ra.attname;
$function$
;

CREATE OR REPLACE FUNCTION public.dispatch_date_based_flows()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_flow   public.flows%ROWTYPE;
  v_offset integer;
  v_rec    record;
  v_count  integer := 0;
  v_sql    text;
BEGIN
  FOR v_flow IN
    SELECT * FROM public.flows
    WHERE flow_type='silent' AND flow_status='active' AND is_deleted=false
      AND flow_trigger_event='date_based'
      AND flow_trigger_object IS NOT NULL
      AND flow_trigger_field  IS NOT NULL
  LOOP
    v_offset := COALESCE(NULLIF(v_flow.flow_trigger_field_value,'')::integer, 0);
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                   WHERE table_schema='public' AND table_name=v_flow.flow_trigger_object
                     AND column_name=v_flow.flow_trigger_field) THEN
      CONTINUE;
    END IF;
    -- Records whose (trigger date + offset) = today and not yet fired today.
    v_sql := format($q$
      SELECT r.id AS rid
      FROM public.%I r
      WHERE (r.%I)::date + ($1 * INTERVAL '1 day') = CURRENT_DATE
        AND NOT EXISTS (
          SELECT 1 FROM public.flow_date_fires f
          WHERE f.fdf_flow_id = $2 AND f.fdf_record_id = r.id AND f.fdf_fire_date = CURRENT_DATE
        )
    $q$, v_flow.flow_trigger_object, v_flow.flow_trigger_field);

    FOR v_rec IN EXECUTE v_sql USING v_offset, v_flow.id LOOP
      BEGIN
        PERFORM public.execute_flow(v_flow.id, v_flow.flow_trigger_object, v_rec.rid, 'date_based', NULL);
        INSERT INTO public.flow_date_fires (fdf_flow_id, fdf_object, fdf_record_id, fdf_fire_date)
        VALUES (v_flow.id, v_flow.flow_trigger_object, v_rec.rid, CURRENT_DATE)
        ON CONFLICT DO NOTHING;
        v_count := v_count + 1;
      EXCEPTION WHEN OTHERS THEN
        NULL; -- execute_flow logs its own failure; continue the sweep
      END;
    END LOOP;
  END LOOP;
  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.dispatch_due_reminders()
 RETURNS TABLE(fired_sa_id uuid, fired_template_id uuid, fired_trigger_event text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'net'
AS $function$
declare
  v_lookbehind_min int := 5;   -- cron runs every 5 min; cover one missed tick
  v_lookahead_min  int := 5;
  v_now            timestamptz := now();
  v_chicago_now    timestamp;
  v_chicago_today  date;
  v_terminal_status_ids uuid[];
begin
  -- Resolve terminal status picklist ids once. Reminders never fire for
  -- SAs in these states regardless of timing.
  select array_agg(id) into v_terminal_status_ids
  from picklist_values
  where picklist_object='service_appointments'
    and picklist_field='sa_status'
    and picklist_value in ('Completed', 'Canceled', 'No-Show', 'Cannot Complete');

  -- ─── Offset-based reminders (NT-00003 -2880, NT-00004 -1440) ──────
  for fired_sa_id, fired_template_id, fired_trigger_event in
    with due_pairs as (
      select sa.id as sa_id,
             tpl.id as tpl_id,
             tpl.nt_trigger_event,
             tpl.nt_channel
      from service_appointments sa
      cross join notification_templates tpl
      where tpl.nt_is_deleted = false
        and tpl.nt_is_active = true
        and tpl.nt_send_offset_minutes is not null
        -- Match on work_type when the template carries one; else NULL global
        and (tpl.work_type_id is null or tpl.work_type_id = sa.work_type_id)
        and sa.sa_is_deleted = false
        and sa.contact_id is not null
        and (v_terminal_status_ids is null or not (sa.sa_status = any(v_terminal_status_ids)))
        -- The reminder fires when now() lands inside the offset window.
        -- sa_start + offset_minutes_as_interval bracketed by lookbehind/ahead.
        and v_now >= sa.sa_scheduled_start_time + (tpl.nt_send_offset_minutes * interval '1 minute') - (v_lookbehind_min * interval '1 minute')
        and v_now <  sa.sa_scheduled_start_time + (tpl.nt_send_offset_minutes * interval '1 minute') + (v_lookahead_min  * interval '1 minute')
    ),
    -- Idempotency: exclude pairs already logged in any non-failed state.
    not_already_logged as (
      select dp.* from due_pairs dp
      where not exists (
        select 1 from notification_logs nl
        where nl.service_appointment_id = dp.sa_id
          and nl.notification_template_id = dp.tpl_id
          and nl.nl_status in ('queued', 'sent', 'delivered')
      )
    )
    select sa_id, tpl_id, nt_trigger_event from not_already_logged
  loop
    perform public.enqueue_notification(fired_sa_id, fired_trigger_event, null);
    return next;
  end loop;

  -- ─── Morning-of reminder (NT-00005, NULL offset) ──────────────────
  -- Fire only between 07:55 and 08:05 America/Chicago, only for SAs
  -- whose calendar day (Chicago) matches today.
  v_chicago_now   := (v_now at time zone 'America/Chicago')::timestamp;
  v_chicago_today := v_chicago_now::date;

  if extract(hour from v_chicago_now) = 7  and extract(minute from v_chicago_now) >= 55
     or extract(hour from v_chicago_now) = 8 and extract(minute from v_chicago_now) <  5
  then
    for fired_sa_id, fired_template_id, fired_trigger_event in
      with morning_pairs as (
        select sa.id as sa_id,
               tpl.id as tpl_id,
               tpl.nt_trigger_event
        from service_appointments sa
        cross join notification_templates tpl
        where tpl.nt_is_deleted = false
          and tpl.nt_is_active = true
          and tpl.nt_trigger_event = 'reminder_morning_of'
          and tpl.nt_send_offset_minutes is null
          and (tpl.work_type_id is null or tpl.work_type_id = sa.work_type_id)
          and sa.sa_is_deleted = false
          and sa.contact_id is not null
          and (v_terminal_status_ids is null or not (sa.sa_status = any(v_terminal_status_ids)))
          and (sa.sa_scheduled_start_time at time zone 'America/Chicago')::date = v_chicago_today
      ),
      not_already_logged as (
        select mp.* from morning_pairs mp
        where not exists (
          select 1 from notification_logs nl
          where nl.service_appointment_id = mp.sa_id
            and nl.notification_template_id = mp.tpl_id
            and nl.nl_status in ('queued', 'sent', 'delivered')
        )
      )
      select sa_id, tpl_id, nt_trigger_event from not_already_logged
    loop
      perform public.enqueue_notification(fired_sa_id, fired_trigger_event, null);
      return next;
    end loop;
  end if;

  return;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.dispatch_reschedule_service_appointment(p_sa_id uuid, p_new_start_iso timestamp with time zone, p_new_end_iso timestamp with time zone, p_new_team_lead_contact_id uuid, p_new_team_lead_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_sa                  service_appointments%rowtype;
  v_sa_scheduled_id     uuid;
  v_caller_id           uuid;
  v_current_lead_contact uuid;
  v_current_lead_user    uuid;
  v_resource_ok         boolean;
  v_conflict_count      integer;
  v_sa_day_chi          date;
  v_lock_key            bigint;
  v_is_user             boolean;
  v_lead_changed        boolean;
BEGIN
  IF p_sa_id IS NULL THEN RETURN jsonb_build_object('status','invalid_sa'); END IF;
  IF p_new_start_iso IS NULL OR p_new_end_iso IS NULL OR p_new_start_iso >= p_new_end_iso THEN
    RETURN jsonb_build_object('status','invalid_slot');
  END IF;

  -- Exactly one lead resource.
  IF (p_new_team_lead_contact_id IS NOT NULL AND p_new_team_lead_user_id IS NOT NULL)
     OR (p_new_team_lead_contact_id IS NULL AND p_new_team_lead_user_id IS NULL) THEN
    RETURN jsonb_build_object('status','invalid_resource');
  END IF;
  v_is_user := (p_new_team_lead_user_id IS NOT NULL);

  SELECT id INTO v_caller_id FROM public.users WHERE auth_user_id = auth.uid() LIMIT 1;
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'caller not mapped to a public.users row' USING ERRCODE='28000';
  END IF;

  SELECT * INTO v_sa FROM service_appointments
   WHERE id = p_sa_id AND coalesce(sa_is_deleted,false) = false;
  IF v_sa.id IS NULL THEN
    RETURN jsonb_build_object('status','appointment_not_found');
  END IF;

  SELECT id INTO v_sa_scheduled_id FROM picklist_values
   WHERE picklist_object='service_appointments'
     AND picklist_field='sa_status'
     AND picklist_value='Scheduled'
     AND picklist_is_active=true;

  IF v_sa.sa_status IS NULL OR v_sa.sa_status <> v_sa_scheduled_id THEN
    RETURN jsonb_build_object('status','not_reschedulable',
                              'message','Only appointments in Scheduled status can be rescheduled.');
  END IF;

  -- Validate the resource exists / is appropriate.
  IF v_is_user THEN
    SELECT true INTO v_resource_ok
      FROM users u JOIN roles r ON r.id = u.role_id
     WHERE u.id = p_new_team_lead_user_id
       AND u.user_is_deleted = false AND u.user_is_active = true
       AND r.role_name = 'Team Lead';
  ELSE
    SELECT true INTO v_resource_ok
      FROM contacts
     WHERE id = p_new_team_lead_contact_id
       AND coalesce(contact_is_deleted,false) = false;
  END IF;
  IF v_resource_ok IS NULL THEN
    RETURN jsonb_build_object('status','invalid_resource');
  END IF;

  v_sa_day_chi := (p_new_start_iso AT TIME ZONE 'America/Chicago')::date;
  v_lock_key   := hashtextextended(
                    (CASE WHEN v_is_user THEN 'user:'||p_new_team_lead_user_id::text
                          ELSE 'contact:'||p_new_team_lead_contact_id::text END)
                    || ':' || v_sa_day_chi::text, 0);
  PERFORM pg_advisory_xact_lock(v_lock_key);

  SELECT count(*) INTO v_conflict_count
    FROM service_appointment_assignments saa
    JOIN service_appointments sa2 ON sa2.id = saa.service_appointment_id
   WHERE ((v_is_user AND saa.saa_user_id = p_new_team_lead_user_id)
          OR (NOT v_is_user AND saa.contact_id = p_new_team_lead_contact_id))
     AND coalesce(saa.saa_is_deleted,false) = false
     AND coalesce(sa2.sa_is_deleted,false)  = false
     AND sa2.id != p_sa_id
     AND sa2.sa_scheduled_start_time < p_new_end_iso
     AND sa2.sa_scheduled_end_time   > p_new_start_iso;
  IF v_conflict_count > 0 THEN
    RETURN jsonb_build_object('status','slot_taken',
                              'message','That time conflicts with another appointment for the selected Team Lead.');
  END IF;

  -- Identify the current lead assignment (contact-based via title, or any
  -- user-based assignment).
  SELECT saa.contact_id, saa.saa_user_id
    INTO v_current_lead_contact, v_current_lead_user
    FROM service_appointment_assignments saa
    LEFT JOIN contacts c ON c.id = saa.contact_id
   WHERE saa.service_appointment_id = p_sa_id
     AND coalesce(saa.saa_is_deleted,false) = false
     AND (saa.saa_user_id IS NOT NULL OR coalesce(c.contact_title,'') ILIKE '%team lead%')
   LIMIT 1;

  UPDATE service_appointments
     SET sa_scheduled_start_time = p_new_start_iso,
         sa_scheduled_end_time   = p_new_end_iso,
         sa_updated_at           = now(),
         sa_updated_by           = v_caller_id
   WHERE id = p_sa_id;

  UPDATE work_orders
     SET work_order_scheduled_start_date = (p_new_start_iso AT TIME ZONE 'America/Chicago')::date,
         work_order_updated_at = now(),
         work_order_updated_by = v_caller_id
   WHERE id = v_sa.work_order_id
     AND coalesce(work_order_is_deleted,false) = false;

  v_lead_changed := (v_is_user AND v_current_lead_user IS DISTINCT FROM p_new_team_lead_user_id)
                 OR (NOT v_is_user AND v_current_lead_contact IS DISTINCT FROM p_new_team_lead_contact_id);

  IF v_lead_changed THEN
    -- Soft-delete the existing lead assignment (contact-title based OR user based).
    UPDATE service_appointment_assignments saa
       SET saa_is_deleted      = true,
           saa_deleted_at      = now(),
           saa_deleted_by      = v_caller_id,
           saa_deletion_reason = 'reassigned by dispatcher',
           saa_updated_at      = now(),
           saa_updated_by      = v_caller_id
      FROM ( SELECT saa2.id
               FROM service_appointment_assignments saa2
               LEFT JOIN contacts c ON c.id = saa2.contact_id
              WHERE saa2.service_appointment_id = p_sa_id
                AND coalesce(saa2.saa_is_deleted,false) = false
                AND (saa2.saa_user_id IS NOT NULL OR coalesce(c.contact_title,'') ILIKE '%team lead%')
           ) old
     WHERE saa.id = old.id;

    INSERT INTO service_appointment_assignments
      (saa_record_number, saa_name, service_appointment_id, contact_id, saa_user_id,
       saa_created_by, saa_updated_by)
    VALUES
      ('', '', p_sa_id,
       CASE WHEN v_is_user THEN NULL ELSE p_new_team_lead_contact_id END,
       CASE WHEN v_is_user THEN p_new_team_lead_user_id ELSE NULL END,
       v_caller_id, v_caller_id);
  END IF;

  RETURN jsonb_build_object(
    'status', 'ok',
    'service_appointment_id', p_sa_id,
    'sa_record_number',       v_sa.sa_record_number,
    'sa_scheduled_start_iso', p_new_start_iso,
    'sa_scheduled_end_iso',   p_new_end_iso,
    'lead_changed',           v_lead_changed
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ees_table_metadata(p_table text)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH cols AS (
    SELECT column_name, is_nullable, column_default
    FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = p_table
  )
  SELECT jsonb_build_object(
    'required_fields', (
      SELECT COALESCE(array_agg(column_name ORDER BY column_name), ARRAY[]::text[])
      FROM cols WHERE is_nullable = 'NO' AND column_default IS NULL
    ),
    'is_deleted_column', (
      SELECT column_name FROM cols
      WHERE column_name = 'is_deleted' OR column_name LIKE '%\_is\_deleted' ESCAPE '\'
      ORDER BY (column_name = 'is_deleted') DESC
      LIMIT 1
    ),
    'is_active_column', (
      SELECT column_name FROM cols
      WHERE column_name = 'is_active' OR column_name LIKE '%\_is\_active' ESCAPE '\'
      ORDER BY (column_name = 'is_active') DESC
      LIMIT 1
    )
  );
$function$
;

CREATE OR REPLACE FUNCTION public.enforce_soft_delete_audit()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_prefix      text;
  v_is_deleted_col text;
  v_deleted_at_col text;
  v_deleted_by_col text;
  v_old_is_deleted bool;
  v_new_is_deleted bool;
  v_new_jsonb   jsonb;
  v_actor_id    uuid;
begin
  -- The audit cols are named {prefix}_is_deleted etc., where prefix
  -- matches the table-specific abbreviation. Some tables use a short
  -- prefix (work_order_, ia_, sa_); others use the table name.
  -- We discover the prefix by walking known patterns.
  --
  -- For our supported tables (8 in the backfill), the prefix is
  -- always equal to the singular form of the table name, e.g.
  -- properties -> property_, opportunities -> opportunity_.
  -- We hardcode the mapping to keep this fast and explicit.

  v_prefix := case tg_table_name
    when 'properties'    then 'property'
    when 'opportunities' then 'opportunity'
    when 'contacts'      then 'contact'
    when 'projects'      then 'project'
    when 'work_orders'   then 'work_order'
    when 'accounts'      then 'account'
    when 'units'         then 'unit'
    when 'buildings'     then 'building'
    else null
  end;

  if v_prefix is null then
    return new;
  end if;

  v_is_deleted_col := v_prefix || '_is_deleted';
  v_deleted_at_col := v_prefix || '_deleted_at';
  v_deleted_by_col := v_prefix || '_deleted_by';

  -- Extract is_deleted from OLD and NEW via jsonb. Avoids dynamic SQL
  -- and works generically across the 8 tables.
  v_old_is_deleted := (to_jsonb(old) ->> v_is_deleted_col)::bool;
  v_new_is_deleted := (to_jsonb(new) ->> v_is_deleted_col)::bool;

  -- Only act when is_deleted flips from false to true. Restoring a
  -- record (true -> false) is a separate concern; un-restore doesn't
  -- need to touch deleted_at/by (it leaves them as breadcrumbs).
  if not (coalesce(v_old_is_deleted, false) = false
          and coalesce(v_new_is_deleted, false) = true) then
    return new;
  end if;

  -- Try to resolve current actor. SECURITY DEFINER means auth.uid()
  -- may not be visible here; current_app_user_id() is safer.
  begin
    select public.current_app_user_id() into v_actor_id;
  exception when others then
    v_actor_id := null;
  end;

  -- If deleted_at is null on NEW, set it to now().
  -- If deleted_by is null on NEW, set it to the resolved actor (if any).
  -- We can't simply do `new.{col} := value` since the column names are
  -- dynamic per table — but we CAN reassemble NEW via jsonb_populate_record
  -- after patching the jsonb.
  v_new_jsonb := to_jsonb(new);

  if v_new_jsonb ->> v_deleted_at_col is null then
    v_new_jsonb := jsonb_set(v_new_jsonb, array[v_deleted_at_col], to_jsonb(now()));
  end if;

  if v_new_jsonb ->> v_deleted_by_col is null and v_actor_id is not null then
    v_new_jsonb := jsonb_set(v_new_jsonb, array[v_deleted_by_col], to_jsonb(v_actor_id));
  end if;

  -- Re-hydrate NEW. jsonb_populate_record returns a fresh record of
  -- the same type, so we re-assign each field via NEW.* = ... by
  -- exporting back through EXECUTE for the dynamic column names.
  -- Easier: use the jsonb_populate_record result directly. Postgres
  -- allows `NEW := jsonb_populate_record(NEW, v_new_jsonb)` in plpgsql.
  new := jsonb_populate_record(new, v_new_jsonb);

  return new;
end$function$
;

CREATE OR REPLACE FUNCTION public.enqueue_notification(p_service_appointment_id uuid, p_trigger_event text, p_channel text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'net'
AS $function$
declare
  v_url    text;
  v_body   jsonb;
begin
  -- Allow session-level opt-out for bulk operations.
  if coalesce(current_setting('app.suppress_notifications', true), '') = 'on' then
    return;
  end if;

  -- Hardcoded to this project's functions URL. Self-hosted forks would
  -- override the GUC; for the EES-WI environment this is stable.
  v_url := coalesce(
    nullif(current_setting('app.fire_notification_url', true), ''),
    'https://flyjigrijjjtcsvpgzvk.supabase.co/functions/v1/fire-notification'
  );

  v_body := jsonb_build_object(
    'service_appointment_id', p_service_appointment_id,
    'trigger_event',          p_trigger_event
  );
  if p_channel is not null then
    v_body := v_body || jsonb_build_object('channel', p_channel);
  end if;

  -- Fire-and-forget. net.http_post queues and returns a request_id; we
  -- don't await the response. pg_net stores the result in net._http_response
  -- for debugging if needed.
  perform net.http_post(
    url := v_url,
    body := v_body,
    headers := jsonb_build_object('Content-Type', 'application/json')
  );
end;
$function$
;

CREATE OR REPLACE FUNCTION public.execute_automation_rules(p_object text, p_record_id uuid, p_event text, p_status_label text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_rule public.automation_rules%ROWTYPE;
  v_outcome text;
  v_message text;
  v_created_id uuid;
  v_user_id uuid;
BEGIN
  SELECT id INTO v_user_id FROM public.users WHERE auth_user_id = auth.uid();

  FOR v_rule IN
    SELECT *
      FROM public.automation_rules
     WHERE is_active = true
       AND trigger_object = p_object
       AND trigger_event = p_event
       AND (
         (p_event = 'status_change' AND p_status_label IS NOT NULL
            AND trigger_status = p_status_label)
         OR p_event <> 'status_change'
       )
     ORDER BY execution_order ASC NULLS LAST, created_at ASC
  LOOP
    BEGIN
      IF v_rule.action_type = 'send_email' THEN
        SELECT * INTO v_outcome, v_message, v_created_id
          FROM _automation_action_send_email(v_rule, p_record_id);
      ELSIF v_rule.action_type = 'create_task' THEN
        SELECT * INTO v_outcome, v_message, v_created_id
          FROM _automation_action_create_task(v_rule, p_record_id);
      ELSIF v_rule.action_type = 'update_record' THEN
        SELECT * INTO v_outcome, v_message, v_created_id
          FROM _automation_action_update_record(v_rule, p_record_id);
      ELSIF v_rule.action_type = 'create_work_order' THEN
        SELECT * INTO v_outcome, v_message, v_created_id
          FROM _automation_action_create_work_order(v_rule, p_record_id);
      ELSE
        v_outcome := 'skipped';
        v_message := format('Action type "%s" not implemented yet', v_rule.action_type);
        v_created_id := NULL;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_outcome := 'error';
      v_message := format('%s: %s', SQLSTATE, SQLERRM);
      v_created_id := NULL;
    END;

    INSERT INTO public.automation_run_log
      (arl_record_number, arl_rule_id, arl_rule_name,
       arl_trigger_object, arl_trigger_record_id, arl_trigger_event, arl_trigger_status,
       arl_action_type, arl_outcome, arl_outcome_message, arl_created_target_id, arl_fired_by)
    VALUES
      ('', v_rule.id, v_rule.name,
       p_object, p_record_id, p_event, p_status_label,
       v_rule.action_type, v_outcome, v_message, v_created_id, v_user_id);
  END LOOP;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.execute_flow(p_flow_id uuid, p_trigger_object text, p_record_id uuid, p_event text DEFAULT NULL::text, p_status_label text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_flow            public.flows%ROWTYPE;
  v_run_id          uuid;
  v_user_id         uuid;
  v_el              public.flow_elements%ROWTYPE;
  v_cur             uuid;
  v_guard           integer := 0;
  v_order           integer := 0;
  v_rule            public.automation_rules%ROWTYPE;
  v_outcome         text;
  v_message         text;
  v_created_id      uuid;
  v_branch          jsonb;
  v_next            uuid;
  v_matched         boolean;
BEGIN
  SELECT id INTO v_user_id FROM public.users WHERE auth_user_id = auth.uid();
  SELECT * INTO v_flow FROM public.flows WHERE id = p_flow_id AND flow_status='active' AND is_deleted=false;
  IF NOT FOUND THEN RETURN NULL; END IF;

  INSERT INTO public.flow_runs
    (fr_record_number, fr_flow_id, fr_flow_version_id, fr_flow_type,
     fr_trigger_object, fr_trigger_record_id, fr_trigger_event, fr_status,
     owner_id, created_by)
  VALUES
    ('', p_flow_id, v_flow.flow_active_version_id, v_flow.flow_type,
     p_trigger_object, p_record_id, p_event, 'in_progress',
     COALESCE(v_user_id, v_flow.owner_id), v_user_id)
  RETURNING id INTO v_run_id;

  -- start element
  SELECT fe_next_element_id INTO v_cur
    FROM public.flow_elements
   WHERE fe_flow_id = p_flow_id AND fe_element_type='start' AND is_deleted=false
   ORDER BY fe_order ASC LIMIT 1;

  WHILE v_cur IS NOT NULL AND v_guard < 200 LOOP
    v_guard := v_guard + 1;
    v_order := v_order + 1;
    SELECT * INTO v_el FROM public.flow_elements WHERE id = v_cur AND is_deleted=false;
    IF NOT FOUND THEN EXIT; END IF;

    v_outcome := 'ok'; v_message := NULL; v_created_id := NULL; v_next := v_el.fe_next_element_id;

    IF v_el.fe_element_type IN ('record_create','record_update','action') THEN
      -- synthesize a transient automation_rules rowtype from element config
      v_rule := NULL::public.automation_rules;
      v_rule.id              := v_el.id;
      v_rule.name            := COALESCE(v_el.fe_label, v_el.fe_record_number);
      v_rule.action_type     := COALESCE(v_el.fe_config->>'action_type',
                                  CASE WHEN v_el.fe_element_type='record_update' THEN 'update_record' ELSE 'create_task' END);
      v_rule.action_config   := v_el.fe_config->'action_config';
      v_rule.target_object   := v_el.fe_config->>'target_object';
      v_rule.target_role_id  := NULLIF(v_el.fe_config->>'target_role_id','')::uuid;
      v_rule.email_template_id := NULLIF(v_el.fe_config->>'email_template_id','')::uuid;
      v_rule.document_template_id := NULLIF(v_el.fe_config->>'document_template_id','')::uuid;
      v_rule.trigger_object  := p_trigger_object;

      BEGIN
        IF v_rule.action_type = 'send_email' THEN
          SELECT * INTO v_outcome, v_message, v_created_id FROM _automation_action_send_email(v_rule, p_record_id);
        ELSIF v_rule.action_type = 'create_task' THEN
          SELECT * INTO v_outcome, v_message, v_created_id FROM _automation_action_create_task(v_rule, p_record_id);
        ELSIF v_rule.action_type = 'update_record' THEN
          SELECT * INTO v_outcome, v_message, v_created_id FROM _automation_action_update_record(v_rule, p_record_id);
        ELSIF v_rule.action_type = 'create_work_order' THEN
          SELECT * INTO v_outcome, v_message, v_created_id FROM _automation_action_create_work_order(v_rule, p_record_id);
        ELSE
          v_outcome := 'skipped';
          v_message := format('Action type "%s" not implemented', v_rule.action_type);
        END IF;
      EXCEPTION WHEN OTHERS THEN
        v_outcome := 'error'; v_message := format('%s: %s', SQLSTATE, SQLERRM);
      END;

    ELSIF v_el.fe_element_type = 'decision' THEN
      -- evaluate branches in order; first whose condition jsonb @> context-record match wins.
      -- v1 condition shape: {"field":"<col>","op":"eq|neq|is_null|not_null","value":"<v>"} on trigger record.
      v_matched := false;
      FOR v_branch IN SELECT * FROM jsonb_array_elements(COALESCE(v_el.fe_decision_branches,'[]'::jsonb)) LOOP
        IF public._flow_eval_condition(v_branch->'condition', p_trigger_object, p_record_id) THEN
          v_next := NULLIF(v_branch->>'next_element_id','')::uuid;
          v_matched := true;
          v_message := format('Branch matched: %s', COALESCE(v_branch->>'label','(unnamed)'));
          EXIT;
        END IF;
      END LOOP;
      IF NOT v_matched THEN
        v_message := 'No branch matched; default path';
        v_next := v_el.fe_next_element_id;
      END IF;

    ELSIF v_el.fe_element_type = 'finish' THEN
      v_message := 'Flow finished';
      v_next := NULL;

    ELSE
      -- screen/assignment/screen_field are no-ops in silent execution
      v_outcome := 'skipped';
      v_message := format('%s element skipped in silent run', v_el.fe_element_type);
    END IF;

    INSERT INTO public.flow_run_steps
      (frs_record_number, frs_run_id, frs_element_id, frs_element_type, frs_order,
       frs_outcome, frs_outcome_message, frs_created_target_id)
    VALUES
      ('', v_run_id, v_el.id, v_el.fe_element_type, v_order,
       v_outcome, v_message, v_created_id);

    IF v_outcome = 'error' THEN
      UPDATE public.flow_runs SET fr_status='error', fr_outcome_message=v_message,
             fr_completed_at=now() WHERE id=v_run_id;
      RETURN v_run_id;
    END IF;

    v_cur := v_next;
  END LOOP;

  UPDATE public.flow_runs SET fr_status='completed', fr_completed_at=now() WHERE id=v_run_id;
  RETURN v_run_id;
END; $function$
;

CREATE OR REPLACE FUNCTION public.execute_flows_for(p_object text, p_record_id uuid, p_event text, p_status_label text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_flow public.flows%ROWTYPE;
BEGIN
  FOR v_flow IN
    SELECT * FROM public.flows
     WHERE flow_type='silent' AND flow_status='active' AND is_deleted=false
       AND flow_trigger_object = p_object
       AND flow_trigger_event = p_event
       AND ( (p_event='status_change' AND p_status_label IS NOT NULL AND flow_trigger_status = p_status_label)
             OR p_event <> 'status_change' )
  LOOP
    PERFORM public.execute_flow(v_flow.id, p_object, p_record_id, p_event, p_status_label);
  END LOOP;
END; $function$
;

CREATE OR REPLACE FUNCTION public.fetch_deleted_records(p_table text, p_limit integer DEFAULT 200)
 RETURNS TABLE(id uuid, name text, deletion_reason text, deleted_at timestamp with time zone, deleted_by uuid)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller     uuid := public.current_app_user_id();
  v_meta       jsonb;
  v_deleted    text;
  v_prefix     text;
  v_reason     text;
  v_at         text;
  v_by         text;
  v_name_col   text;
  v_recnum_col text;
  v_display    text;
  v_safe_limit integer;
  v_sql        text;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'fetch_deleted_records: must be authenticated' USING ERRCODE = '42501';
  END IF;
  IF p_table IS NULL THEN
    RAISE EXCEPTION 'fetch_deleted_records: table is required';
  END IF;
  v_safe_limit := LEAST(GREATEST(COALESCE(p_limit, 200), 1), 1000);

  v_meta := public.ees_table_metadata(p_table);
  IF v_meta IS NULL OR v_meta->>'is_deleted_column' IS NULL THEN
    RAISE EXCEPTION 'fetch_deleted_records: table % is not soft-deletable', p_table
      USING ERRCODE = '22023';
  END IF;
  v_deleted := v_meta->>'is_deleted_column';
  v_prefix  := regexp_replace(v_deleted, 'is_deleted$', '');

  -- Audit columns (NULL if missing). The format() expression in the SQL
  -- below uses NULL::<type> when a column doesn't exist so the row shape
  -- is consistent regardless of table.
  SELECT a.attname INTO v_reason
  FROM pg_attribute a
  JOIN pg_class c ON a.attrelid = c.oid
  JOIN pg_namespace n ON c.relnamespace = n.oid
  WHERE n.nspname='public' AND c.relname=p_table
    AND a.attname=v_prefix||'deletion_reason' AND a.attnum>0
  LIMIT 1;
  SELECT a.attname INTO v_at
  FROM pg_attribute a
  JOIN pg_class c ON a.attrelid = c.oid
  JOIN pg_namespace n ON c.relnamespace = n.oid
  WHERE n.nspname='public' AND c.relname=p_table
    AND a.attname=v_prefix||'deleted_at' AND a.attnum>0
  LIMIT 1;
  SELECT a.attname INTO v_by
  FROM pg_attribute a
  JOIN pg_class c ON a.attrelid = c.oid
  JOIN pg_namespace n ON c.relnamespace = n.oid
  WHERE n.nspname='public' AND c.relname=p_table
    AND a.attname=v_prefix||'deleted_by' AND a.attnum>0
  LIMIT 1;

  -- Display name: prefer record_number, fall back to name. Walk through
  -- common candidates (the same shape ees_table_metadata uses for
  -- display elsewhere).
  v_recnum_col := v_prefix || 'record_number';
  IF NOT EXISTS (
    SELECT 1 FROM pg_attribute a JOIN pg_class c ON a.attrelid=c.oid
    JOIN pg_namespace n ON c.relnamespace=n.oid
    WHERE n.nspname='public' AND c.relname=p_table AND a.attname=v_recnum_col AND a.attnum>0
  ) THEN v_recnum_col := NULL; END IF;

  v_name_col := v_prefix || 'name';
  IF NOT EXISTS (
    SELECT 1 FROM pg_attribute a JOIN pg_class c ON a.attrelid=c.oid
    JOIN pg_namespace n ON c.relnamespace=n.oid
    WHERE n.nspname='public' AND c.relname=p_table AND a.attname=v_name_col AND a.attnum>0
  ) THEN v_name_col := NULL; END IF;

  v_display := CASE
    WHEN v_recnum_col IS NOT NULL AND v_name_col IS NOT NULL
      THEN format('COALESCE(%I, %I, id::text)', v_recnum_col, v_name_col)
    WHEN v_recnum_col IS NOT NULL
      THEN format('COALESCE(%I, id::text)', v_recnum_col)
    WHEN v_name_col IS NOT NULL
      THEN format('COALESCE(%I, id::text)', v_name_col)
    ELSE 'id::text'
  END;

  v_sql := format(
    'SELECT id, %s, %s, %s, %s FROM public.%I WHERE %I = true ORDER BY %s DESC NULLS LAST LIMIT %s',
    v_display,
    COALESCE(quote_ident(v_reason), 'NULL::text'),
    COALESCE(quote_ident(v_at),     'NULL::timestamptz'),
    COALESCE(quote_ident(v_by),     'NULL::uuid'),
    p_table,
    v_deleted,
    COALESCE(quote_ident(v_at), 'id'),
    v_safe_limit
  );

  RETURN QUERY EXECUTE v_sql;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.find_or_create_conversation(p_channel text, p_our_address text, p_customer_address text, p_contact_id uuid DEFAULT NULL::uuid, p_account_id uuid DEFAULT NULL::uuid, p_project_id uuid DEFAULT NULL::uuid, p_service_appointment_id uuid DEFAULT NULL::uuid, p_subject text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_conv_id  uuid;
begin
  if p_channel is null or p_channel not in ('sms','email') then
    raise exception 'channel must be sms or email';
  end if;
  if p_our_address is null or p_customer_address is null then
    raise exception 'our_address and customer_address are required';
  end if;

  -- Look up existing open thread for this pair
  select id into v_conv_id
  from public.conversations
  where conv_channel = p_channel
    and conv_our_address = p_our_address
    and conv_customer_address = p_customer_address
    and conv_status = 'open'
    and conv_is_deleted = false
  limit 1;

  if v_conv_id is not null then
    -- Backfill any FKs that weren't known when the thread was created
    update public.conversations
    set
      contact_id             = coalesce(contact_id, p_contact_id),
      account_id             = coalesce(account_id, p_account_id),
      project_id             = coalesce(project_id, p_project_id),
      service_appointment_id = coalesce(service_appointment_id, p_service_appointment_id),
      conv_subject           = coalesce(conv_subject, p_subject),
      conv_updated_at        = now()
    where id = v_conv_id;
    return v_conv_id;
  end if;

  insert into public.conversations (
    conv_record_number, conv_channel, conv_our_address, conv_customer_address,
    conv_status, conv_subject,
    contact_id, account_id, project_id, service_appointment_id
  ) values (
    '', p_channel, p_our_address, p_customer_address,
    'open', p_subject,
    p_contact_id, p_account_id, p_project_id, p_service_appointment_id
  )
  returning id into v_conv_id;

  return v_conv_id;
end $function$
;

CREATE OR REPLACE FUNCTION public.flow_ai_usage_summary(p_since timestamp with time zone DEFAULT (now() - '30 days'::interval), p_until timestamp with time zone DEFAULT now())
 RETURNS TABLE(user_id uuid, user_name text, user_email text, call_count bigint, error_count bigint, total_input_tokens bigint, total_output_tokens bigint, total_cost_usd numeric, last_used_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'AI usage report is restricted to administrators'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  RETURN QUERY
  SELECT
    u.id,
    COALESCE(NULLIF(btrim(COALESCE(u.user_name,'')),''),
             NULLIF(btrim(COALESCE(u.user_first_name,'') || ' ' || COALESCE(u.user_last_name,'')),''),
             '(unknown)') AS user_name,
    u.user_email AS user_email,
    count(*)::bigint AS call_count,
    count(*) FILTER (WHERE f.fau_outcome = 'error')::bigint AS error_count,
    COALESCE(sum(f.fau_input_tokens),0)::bigint AS total_input_tokens,
    COALESCE(sum(f.fau_output_tokens),0)::bigint AS total_output_tokens,
    COALESCE(sum(f.fau_estimated_cost_usd),0)::numeric AS total_cost_usd,
    max(f.fau_created_at) AS last_used_at
  FROM public.flow_ai_usage f
  LEFT JOIN public.users u ON u.id = f.fau_user_id
  WHERE f.fau_is_deleted = false
    AND f.fau_created_at >= p_since
    AND f.fau_created_at <= p_until
  GROUP BY u.id, u.user_name, u.user_first_name, u.user_last_name, u.user_email
  ORDER BY total_cost_usd DESC;
END; $function$
;

CREATE OR REPLACE FUNCTION public.fuzzy_match_records(p_query text, p_object_type text DEFAULT NULL::text, p_threshold real DEFAULT 0.3, p_limit integer DEFAULT 8)
 RETURNS TABLE(object_type text, object_label text, table_name text, id uuid, primary_label text, secondary_label text, record_number text, score real)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'extensions', 'pg_catalog'
AS $function$
  WITH p AS (
    SELECT NULLIF(TRIM(p_query), '') AS q,
           GREATEST(COALESCE(p_threshold, 0.3), 0.05) AS thr,
           LEAST(GREATEST(COALESCE(p_limit, 8), 1), 25) AS lim
  ),
  cand AS (
    -- Accounts
    SELECT 'account'::text AS object_type, 'Accounts'::text AS object_label, 'accounts'::text AS table_name,
           a.id,
           a.account_name AS primary_label,
           COALESCE(a.account_organization_name, a.account_email, a.account_phone) AS secondary_label,
           a.account_record_number AS record_number,
           word_similarity((SELECT q FROM p), a.account_name) AS score
    FROM accounts a
    WHERE a.account_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'account')
      AND a.account_name IS NOT NULL
      AND word_similarity((SELECT q FROM p), a.account_name) >= (SELECT thr FROM p)

    UNION ALL
    -- Contacts (match against the composed display name)
    SELECT 'contact', 'Contacts', 'contacts',
           c.id,
           COALESCE(c.contact_name, NULLIF(TRIM(COALESCE(c.contact_first_name,'') || ' ' || COALESCE(c.contact_last_name,'')), '')) AS primary_label,
           COALESCE(c.contact_email, c.contact_mobile_phone, c.contact_phone),
           c.contact_record_number,
           word_similarity(
             (SELECT q FROM p),
             COALESCE(c.contact_name, NULLIF(TRIM(COALESCE(c.contact_first_name,'') || ' ' || COALESCE(c.contact_last_name,'')), ''), '')
           ) AS score
    FROM contacts c
    WHERE c.contact_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'contact')
      AND word_similarity(
            (SELECT q FROM p),
            COALESCE(c.contact_name, NULLIF(TRIM(COALESCE(c.contact_first_name,'') || ' ' || COALESCE(c.contact_last_name,'')), ''), '')
          ) >= (SELECT thr FROM p)

    UNION ALL
    -- Properties (name + aka)
    SELECT 'property', 'Properties', 'properties',
           p2.id, p2.property_name, p2.property_aka_name, p2.property_record_number,
           GREATEST(
             word_similarity((SELECT q FROM p), COALESCE(p2.property_name,'')),
             word_similarity((SELECT q FROM p), COALESCE(p2.property_aka_name,''))
           ) AS score
    FROM properties p2
    WHERE p2.property_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'property')
      AND GREATEST(
            word_similarity((SELECT q FROM p), COALESCE(p2.property_name,'')),
            word_similarity((SELECT q FROM p), COALESCE(p2.property_aka_name,''))
          ) >= (SELECT thr FROM p)

    UNION ALL
    -- Buildings
    SELECT 'building', 'Buildings', 'buildings',
           b.id,
           COALESCE(b.building_name, b.building_number_or_name) AS primary_label,
           b.building_address, b.building_record_number,
           word_similarity((SELECT q FROM p), COALESCE(b.building_name, b.building_number_or_name, '')) AS score
    FROM buildings b
    WHERE b.building_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'building')
      AND word_similarity((SELECT q FROM p), COALESCE(b.building_name, b.building_number_or_name, '')) >= (SELECT thr FROM p)

    UNION ALL
    -- Opportunities
    SELECT 'opportunity', 'Opportunities', 'opportunities',
           o.id, o.opportunity_name, o.opportunity_subdivision_name, o.opportunity_record_number,
           word_similarity((SELECT q FROM p), COALESCE(o.opportunity_name,'')) AS score
    FROM opportunities o
    WHERE o.opportunity_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'opportunity')
      AND word_similarity((SELECT q FROM p), COALESCE(o.opportunity_name,'')) >= (SELECT thr FROM p)

    UNION ALL
    -- Projects
    SELECT 'project', 'Projects', 'projects',
           pr.id, pr.project_name, pr.project_program_name, pr.project_record_number,
           word_similarity((SELECT q FROM p), COALESCE(pr.project_name,'')) AS score
    FROM projects pr
    WHERE pr.project_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'project')
      AND word_similarity((SELECT q FROM p), COALESCE(pr.project_name,'')) >= (SELECT thr FROM p)

    UNION ALL
    -- Work orders
    SELECT 'work_order', 'Work Orders', 'work_orders',
           wo.id,
           COALESCE(wo.work_order_name, wo.work_order_property_name) AS primary_label,
           wo.work_order_customer_name, wo.work_order_record_number,
           word_similarity((SELECT q FROM p), COALESCE(wo.work_order_name, wo.work_order_property_name, '')) AS score
    FROM work_orders wo
    WHERE wo.work_order_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'work_order')
      AND word_similarity((SELECT q FROM p), COALESCE(wo.work_order_name, wo.work_order_property_name, '')) >= (SELECT thr FROM p)
  )
  SELECT object_type, object_label, table_name, id, primary_label, secondary_label, record_number, score
  FROM cand, p
  WHERE p.q IS NOT NULL AND length(p.q) >= 2
  ORDER BY score DESC, primary_label ASC
  LIMIT (SELECT lim FROM p)
$function$
;

CREATE OR REPLACE FUNCTION public.fuzzy_resolve_picklist(p_object text, p_term text, p_field text DEFAULT NULL::text, p_limit integer DEFAULT 5, p_min_score real DEFAULT 0.20)
 RETURNS TABLE(id uuid, picklist_field text, value text, label text, score real)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'extensions', 'pg_temp'
AS $function$
  select
    pv.id,
    pv.picklist_field,
    pv.picklist_value as value,
    pv.picklist_label as label,
    greatest(
      similarity(coalesce(pv.picklist_label, ''), coalesce(p_term, '')),
      similarity(coalesce(pv.picklist_value, ''), coalesce(p_term, ''))
    ) as score
  from public.picklist_values pv
  where pv.picklist_object = p_object
    and pv.picklist_is_active is true
    and (p_field is null or pv.picklist_field = p_field)
    and (
      coalesce(pv.picklist_label, '') ilike '%' || coalesce(p_term, '') || '%'
      or coalesce(pv.picklist_value, '') ilike '%' || coalesce(p_term, '') || '%'
      or greatest(
           similarity(coalesce(pv.picklist_label, ''), coalesce(p_term, '')),
           similarity(coalesce(pv.picklist_value, ''), coalesce(p_term, ''))
         ) >= p_min_score
    )
  order by score desc, length(coalesce(pv.picklist_label, pv.picklist_value)) asc
  limit greatest(least(coalesce(p_limit, 5), 25), 1);
$function$
;

