CREATE OR REPLACE FUNCTION public.get_assistant_task(p_flow_id uuid)
 RETURNS jsonb
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT v.fv_snapshot
  FROM public.flows f
  JOIN public.flow_versions v ON v.id = f.flow_active_version_id
  WHERE f.id = p_flow_id
    AND f.is_deleted = false
    AND f.flow_status = 'active';
$function$
;

CREATE OR REPLACE FUNCTION public.get_portal_project_tracker()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_portal_user_id uuid;
  v_result jsonb;
BEGIN
  -- Resolve the calling auth user to a portal_users row.
  SELECT pu.id INTO v_portal_user_id
  FROM portal_users pu
  WHERE pu.auth_user_id = auth.uid()
    AND pu.is_deleted = false
    AND pu.status = 'Active'
  LIMIT 1;

  IF v_portal_user_id IS NULL THEN
    RETURN jsonb_build_object('error', 'no_portal_user', 'properties', '[]'::jsonb);
  END IF;

  -- Granted property + building id sets for this portal user.
  WITH granted_properties AS (
    SELECT DISTINCT pug_property_id AS property_id
    FROM portal_user_property_grants
    WHERE pug_portal_user_id = v_portal_user_id
      AND pug_is_deleted = false
      AND pug_property_id IS NOT NULL
  ),
  granted_buildings AS (
    SELECT DISTINCT pug_building_id AS building_id
    FROM portal_user_property_grants
    WHERE pug_portal_user_id = v_portal_user_id
      AND pug_is_deleted = false
      AND pug_building_id IS NOT NULL
  ),
  -- Opportunities in scope: under a granted property OR a granted building.
  scoped_opps AS (
    SELECT o.id, o.opportunity_record_number, o.opportunity_name,
           o.property_id, o.building_id,
           o.opportunity_amount,
           sv.picklist_label     AS stage_label,
           sv.picklist_sort_order AS stage_order,
           rt.picklist_label     AS program_label
    FROM opportunities o
    LEFT JOIN picklist_values sv ON o.opportunity_stage = sv.id
    LEFT JOIN picklist_values rt ON o.opportunity_record_type = rt.id
    WHERE o.opportunity_is_deleted = false
      AND (
        o.property_id IN (SELECT property_id FROM granted_properties)
        OR o.building_id IN (SELECT building_id FROM granted_buildings)
      )
  ),
  -- Buildings to display: every granted building, plus every building under a
  -- granted property. (A building grant alone shows only that building.)
  visible_buildings AS (
    SELECT b.id, b.building_name, b.building_record_number, b.building_address,
           b.building_total_units, b.building_number_of_units, b.property_id
    FROM buildings b
    WHERE b.building_is_deleted = false
      AND (
        b.property_id IN (SELECT property_id FROM granted_properties)
        OR b.id IN (SELECT building_id FROM granted_buildings)
      )
  ),
  -- Properties to display: every granted property, plus the parent property of
  -- any granted building (so a building-only grant still renders its property
  -- header, but only the one granted building beneath it).
  visible_properties AS (
    SELECT DISTINCT p.id, p.property_name, p.property_record_number,
           p.property_city, p.property_state,
           p.property_total_units, p.property_total_buildings
    FROM properties p
    WHERE p.property_is_deleted = false
      AND (
        p.id IN (SELECT property_id FROM granted_properties)
        OR p.id IN (SELECT property_id FROM visible_buildings)
      )
  ),
  -- Assemble opportunities per building.
  opps_by_building AS (
    SELECT so.building_id,
           jsonb_agg(jsonb_build_object(
             'id', so.id,
             'record_number', so.opportunity_record_number,
             'name', so.opportunity_name,
             'program', so.program_label,
             'stage_label', so.stage_label,
             'stage_order', COALESCE(so.stage_order, 0)
           ) ORDER BY so.opportunity_name) AS opps
    FROM scoped_opps so
    WHERE so.building_id IS NOT NULL
    GROUP BY so.building_id
  ),
  buildings_by_property AS (
    SELECT vb.property_id,
           jsonb_agg(jsonb_build_object(
             'id', vb.id,
             'name', vb.building_name,
             'record_number', vb.building_record_number,
             'address', vb.building_address,
             'total_units', COALESCE(vb.building_total_units, vb.building_number_of_units),
             'opportunities', COALESCE(ob.opps, '[]'::jsonb)
           ) ORDER BY vb.building_name) AS buildings
    FROM visible_buildings vb
    LEFT JOIN opps_by_building ob ON ob.building_id = vb.id
    GROUP BY vb.property_id
  )
  SELECT jsonb_build_object(
    'portal_user_id', v_portal_user_id,
    'properties', COALESCE(jsonb_agg(jsonb_build_object(
      'id', vp.id,
      'name', vp.property_name,
      'record_number', vp.property_record_number,
      'city', vp.property_city,
      'state', vp.property_state,
      'total_units', vp.property_total_units,
      'total_buildings', vp.property_total_buildings,
      'buildings', COALESCE(bp.buildings, '[]'::jsonb)
    ) ORDER BY vp.property_name), '[]'::jsonb)
  ) INTO v_result
  FROM visible_properties vp
  LEFT JOIN buildings_by_property bp ON bp.property_id = vp.id;

  RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.global_search(p_query text, p_limit_per_object integer DEFAULT 5, p_object_type text DEFAULT NULL::text)
 RETURNS TABLE(object_type text, object_label text, table_name text, id uuid, primary_label text, secondary_label text, record_number text, match_rank integer)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'extensions', 'pg_catalog'
AS $function$
  WITH p AS (
    SELECT NULLIF(TRIM(p_query), '') AS q
  ),
  pat AS (
    SELECT q,
           '%' || q || '%' AS like_pat,
           q || '%'        AS prefix_pat
    FROM p
    WHERE q IS NOT NULL AND length(q) >= 2
  ),

  q_accounts AS (
    SELECT 'account'::text AS object_type, 'Accounts'::text AS object_label, 'accounts'::text AS table_name,
           a.id, a.account_name AS primary_label,
           COALESCE(a.account_organization_name, a.account_email, a.account_phone) AS secondary_label,
           a.account_record_number AS record_number,
           CASE
             WHEN a.account_record_number    ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN a.account_name             ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN a.account_name             ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3
           END AS match_rank
    FROM accounts a, pat
    WHERE a.account_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'account')
      AND ( a.account_name ILIKE pat.like_pat OR a.account_record_number ILIKE pat.prefix_pat
         OR a.account_organization_name ILIKE pat.like_pat OR a.account_email ILIKE pat.like_pat
         OR a.account_phone ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_contacts AS (
    SELECT 'contact'::text, 'Contacts'::text, 'contacts'::text, c.id,
           COALESCE(c.contact_name, NULLIF(TRIM(COALESCE(c.contact_first_name,'') || ' ' || COALESCE(c.contact_last_name,'')), '')),
           COALESCE(c.contact_email, c.contact_mobile_phone, c.contact_phone), c.contact_record_number,
           CASE
             WHEN c.contact_record_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN c.contact_last_name     ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN c.contact_first_name    ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN c.contact_name          ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN c.contact_name          ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM contacts c, pat
    WHERE c.contact_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'contact')
      AND ( c.contact_name ILIKE pat.like_pat OR c.contact_first_name ILIKE pat.like_pat
         OR c.contact_last_name ILIKE pat.like_pat OR c.contact_record_number ILIKE pat.prefix_pat
         OR c.contact_email ILIKE pat.like_pat OR c.contact_mobile_phone ILIKE pat.like_pat
         OR c.contact_phone ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_properties AS (
    SELECT 'property'::text, 'Properties'::text, 'properties'::text, p2.id,
           p2.property_name, p2.property_aka_name, p2.property_record_number,
           CASE
             WHEN p2.property_record_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN p2.property_name          ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN p2.property_name          ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM properties p2, pat
    WHERE p2.property_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'property')
      AND ( p2.property_name ILIKE pat.like_pat OR p2.property_aka_name ILIKE pat.like_pat
         OR p2.property_record_number ILIKE pat.prefix_pat OR p2.property_subdivision_name ILIKE pat.like_pat
         OR p2.property_hud_property_id ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_buildings AS (
    SELECT 'building'::text, 'Buildings'::text, 'buildings'::text, b.id,
           COALESCE(b.building_name, b.building_number_or_name), b.building_address, b.building_record_number,
           CASE
             WHEN b.building_record_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN b.building_name          ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN b.building_name          ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM buildings b, pat
    WHERE b.building_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'building')
      AND ( b.building_name ILIKE pat.like_pat OR b.building_number_or_name ILIKE pat.like_pat
         OR b.building_record_number ILIKE pat.prefix_pat OR b.building_address ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_units AS (
    SELECT 'unit'::text, 'Units'::text, 'units'::text, u.id,
           COALESCE(u.unit_name, u.unit_number), u.unit_tenant_name, u.unit_record_number,
           CASE
             WHEN u.unit_record_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN u.unit_name          ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN u.unit_number        ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN u.unit_tenant_name   ILIKE (SELECT prefix_pat FROM pat) THEN 1
             ELSE 2 END
    FROM units u, pat
    WHERE u.unit_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'unit')
      AND ( u.unit_name ILIKE pat.like_pat OR u.unit_number ILIKE pat.like_pat
         OR u.unit_record_number ILIKE pat.prefix_pat OR u.unit_tenant_name ILIKE pat.like_pat
         OR u.unit_tenant_email ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_opportunities AS (
    SELECT 'opportunity'::text, 'Opportunities'::text, 'opportunities'::text, o.id,
           o.opportunity_name, o.opportunity_subdivision_name, o.opportunity_record_number,
           CASE
             WHEN o.opportunity_record_number             ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN o.opportunity_external_reference_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN o.opportunity_name                      ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN o.opportunity_name                      ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM opportunities o, pat
    WHERE o.opportunity_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'opportunity')
      AND ( o.opportunity_name ILIKE pat.like_pat OR o.opportunity_record_number ILIKE pat.prefix_pat
         OR o.opportunity_external_reference_number ILIKE pat.prefix_pat OR o.opportunity_subdivision_name ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_projects AS (
    SELECT 'project'::text, 'Projects'::text, 'projects'::text, pr.id,
           pr.project_name, pr.project_program_name, pr.project_record_number,
           CASE
             WHEN pr.project_record_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN pr.project_name          ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN pr.project_name          ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM projects pr, pat
    WHERE pr.project_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'project')
      AND ( pr.project_name ILIKE pat.like_pat OR pr.project_record_number ILIKE pat.prefix_pat
         OR pr.project_program_name ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_work_orders AS (
    SELECT 'work_order'::text, 'Work Orders'::text, 'work_orders'::text, wo.id,
           COALESCE(wo.work_order_name, wo.work_order_property_name), wo.work_order_customer_name, wo.work_order_record_number,
           CASE
             WHEN wo.work_order_record_number   ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN wo.work_order_external_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN wo.work_order_name            ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN wo.work_order_property_name   ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN wo.work_order_name            ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM work_orders wo, pat
    WHERE wo.work_order_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'work_order')
      AND ( wo.work_order_name ILIKE pat.like_pat OR wo.work_order_record_number ILIKE pat.prefix_pat
         OR wo.work_order_external_number ILIKE pat.prefix_pat OR wo.work_order_property_name ILIKE pat.like_pat
         OR wo.work_order_customer_name ILIKE pat.like_pat OR wo.work_order_contact_name ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_incentive_applications AS (
    SELECT 'incentive_application'::text, 'Incentive Applications'::text, 'incentive_applications'::text, ia.id,
           ia.ia_name, ia.ia_program_name, ia.ia_record_number,
           CASE
             WHEN ia.ia_record_number       ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN ia.ia_name                ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN ia.ia_applicant_name      ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN ia.ia_building_owner_name ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN ia.ia_name                ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM incentive_applications ia, pat
    WHERE ia.ia_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'incentive_application')
      AND ( ia.ia_name ILIKE pat.like_pat OR ia.ia_record_number ILIKE pat.prefix_pat
         OR ia.ia_program_name ILIKE pat.like_pat OR ia.ia_applicant_name ILIKE pat.like_pat
         OR ia.ia_building_owner_name ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_assessments AS (
    SELECT 'assessment'::text, 'Assessments'::text, 'assessments'::text, a2.id,
           a2.assessment_name, COALESCE(a2.assessment_applicant_name, a2.assessment_building_owner_name), a2.assessment_record_number,
           CASE
             WHEN a2.assessment_record_number   ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN a2.assessment_name            ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN a2.assessment_applicant_name  ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN a2.assessment_name            ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM assessments a2, pat
    WHERE a2.assessment_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'assessment')
      AND ( a2.assessment_name ILIKE pat.like_pat OR a2.assessment_record_number ILIKE pat.prefix_pat
         OR a2.assessment_applicant_name ILIKE pat.like_pat OR a2.assessment_building_owner_name ILIKE pat.like_pat
         OR a2.assessment_building_address ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_programs AS (
    SELECT 'program'::text, 'Programs'::text, 'programs'::text, pg.id,
           pg.name, pg.short_name, NULL::text,
           CASE
             WHEN pg.short_name ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN pg.name       ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN pg.name       ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM programs pg, pat
    WHERE pg.is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'program')
      AND ( pg.name ILIKE pat.like_pat OR pg.short_name ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_vehicles AS (
    SELECT 'vehicle'::text, 'Vehicles'::text, 'vehicles'::text, v.id,
           v.vehicle_name, v.vehicle_vin_last_3, v.vehicle_record_number,
           CASE
             WHEN v.vehicle_record_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN v.vehicle_vin_last_3    ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN v.vehicle_vin           ILIKE (SELECT like_pat   FROM pat) THEN 1
             WHEN v.vehicle_name          ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN v.vehicle_name          ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM vehicles v, pat
    WHERE v.vehicle_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'vehicle')
      AND ( v.vehicle_name ILIKE pat.like_pat OR v.vehicle_record_number ILIKE pat.prefix_pat
         OR v.vehicle_vin ILIKE pat.like_pat OR v.vehicle_vin_last_3 ILIKE pat.prefix_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_equipment AS (
    SELECT 'equipment'::text, 'Equipment'::text, 'equipment'::text, e.id,
           COALESCE(e.equipment_name, e.equipment_equipment_name_or_number), e.equipment_serial_number, e.equipment_record_number,
           CASE
             WHEN e.equipment_record_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN e.equipment_serial_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN e.equipment_name          ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN e.equipment_name          ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM equipment e, pat
    WHERE e.equipment_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'equipment')
      AND ( e.equipment_name ILIKE pat.like_pat OR e.equipment_equipment_name_or_number ILIKE pat.like_pat
         OR e.equipment_record_number ILIKE pat.prefix_pat OR e.equipment_serial_number ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_product_items AS (
    SELECT 'product_item'::text, 'Product Items'::text, 'product_items'::text, pi.id,
           pi.product_item_name, pi.product_item_serial_number, pi.product_item_record_number,
           CASE
             WHEN pi.product_item_record_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN pi.product_item_serial_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN pi.product_item_name          ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN pi.product_item_name          ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM product_items pi, pat
    WHERE pi.product_item_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'product_item')
      AND ( pi.product_item_name ILIKE pat.like_pat OR pi.product_item_record_number ILIKE pat.prefix_pat
         OR pi.product_item_serial_number ILIKE pat.like_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_users AS (
    SELECT 'user'::text, 'Users'::text, 'users'::text, u2.id,
           COALESCE(u2.user_name, NULLIF(TRIM(COALESCE(u2.user_first_name,'') || ' ' || COALESCE(u2.user_last_name,'')), '')),
           u2.user_email, u2.user_record_number,
           CASE
             WHEN u2.user_record_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN u2.user_last_name     ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN u2.user_first_name    ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN u2.user_name          ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN u2.user_email         ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN u2.user_name          ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM users u2, pat
    WHERE u2.user_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'user')
      AND ( u2.user_name ILIKE pat.like_pat OR u2.user_first_name ILIKE pat.like_pat
         OR u2.user_last_name ILIKE pat.like_pat OR u2.user_email ILIKE pat.like_pat
         OR u2.user_record_number ILIKE pat.prefix_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_envelopes AS (
    SELECT 'envelope'::text, 'Signature Envelopes'::text, 'envelopes'::text, ev.id,
           ev.env_name, NULL::text, ev.env_record_number,
           CASE
             WHEN ev.env_record_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN ev.env_name          ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN ev.env_name          ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM envelopes ev, pat
    WHERE ev.is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'envelope')
      AND ( ev.env_name ILIKE pat.like_pat OR ev.env_record_number ILIKE pat.prefix_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),
  q_service_appointments AS (
    SELECT 'service_appointment'::text, 'Service Appointments'::text, 'service_appointments'::text, sa.id,
           sa.sa_name, NULL::text, sa.sa_record_number,
           CASE
             WHEN sa.sa_record_number ILIKE (SELECT prefix_pat FROM pat) THEN 0
             WHEN sa.sa_name          ILIKE (SELECT prefix_pat FROM pat) THEN 1
             WHEN sa.sa_name          ILIKE (SELECT like_pat   FROM pat) THEN 2
             ELSE 3 END
    FROM service_appointments sa, pat
    WHERE sa.sa_is_deleted = false
      AND (p_object_type IS NULL OR p_object_type = 'service_appointment')
      AND ( sa.sa_name ILIKE pat.like_pat OR sa.sa_record_number ILIKE pat.prefix_pat )
    ORDER BY 8, 5 LIMIT p_limit_per_object
  ),

  exact AS (
    SELECT * FROM q_accounts               UNION ALL
    SELECT * FROM q_contacts               UNION ALL
    SELECT * FROM q_properties             UNION ALL
    SELECT * FROM q_buildings              UNION ALL
    SELECT * FROM q_units                  UNION ALL
    SELECT * FROM q_opportunities          UNION ALL
    SELECT * FROM q_projects               UNION ALL
    SELECT * FROM q_work_orders            UNION ALL
    SELECT * FROM q_incentive_applications UNION ALL
    SELECT * FROM q_assessments            UNION ALL
    SELECT * FROM q_programs               UNION ALL
    SELECT * FROM q_vehicles               UNION ALL
    SELECT * FROM q_equipment              UNION ALL
    SELECT * FROM q_product_items          UNION ALL
    SELECT * FROM q_users                  UNION ALL
    SELECT * FROM q_envelopes              UNION ALL
    SELECT * FROM q_service_appointments
  ),

  -- "Did you mean" suggestions. Fire ONLY on a true miss (no exact hits) for
  -- name-like queries (>= 3 chars). Keep only candidates whose VISIBLE label
  -- (primary_label) is itself a close match (word_similarity >= 0.3), so a user
  -- never sees a suggestion whose displayed name looks unrelated. Best-first.
  suggestions AS (
    SELECT f.object_type, f.object_label, f.table_name, f.id,
           f.primary_label, f.secondary_label, f.record_number,
           9 AS match_rank,
           word_similarity((SELECT q FROM p), f.primary_label) AS vis_score
    FROM fuzzy_match_records((SELECT q FROM p), p_object_type, 0.4, 12) f
    WHERE (SELECT q FROM p) IS NOT NULL
      AND length((SELECT q FROM p)) >= 3
      AND NOT EXISTS (SELECT 1 FROM exact)
      AND word_similarity((SELECT q FROM p), f.primary_label) >= 0.3
    ORDER BY vis_score DESC, f.primary_label ASC
    LIMIT 5
  ),

  combined AS (
    SELECT object_type, object_label, table_name, id, primary_label, secondary_label, record_number, match_rank,
           NULL::real AS vis_score
    FROM exact
    UNION ALL
    SELECT object_type, object_label, table_name, id, primary_label, secondary_label, record_number, match_rank,
           vis_score
    FROM suggestions
  )

  SELECT object_type, object_label, table_name, id, primary_label, secondary_label, record_number, match_rank
  FROM combined
  ORDER BY match_rank ASC, vis_score DESC NULLS LAST, primary_label ASC
$function$
;

CREATE OR REPLACE FUNCTION public.has_communications_view_all()
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select exists (
    select 1
    from public.users u
    join public.communications_view_all_grants g on g.cvag_role_id = u.role_id
    where u.auth_user_id = auth.uid()
      and not g.cvag_is_deleted
  );
$function$
;

CREATE OR REPLACE FUNCTION public.help_lookup_articles(p_anchors jsonb, p_audience text DEFAULT NULL::text)
 RETURNS TABLE(id uuid, ha_record_number text, ha_slug text, ha_title text, ha_summary text, ha_body_markdown text, ha_category text, ha_audience text, matched_anchor_type text, matched_anchor_value text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH spec AS (
    SELECT
      (elem->>'type')    AS atype,
      (elem->>'route')   AS aroute,
      (elem->>'object')  AS aobject,
      (elem->>'field')   AS afield,
      (elem->>'concept') AS aconcept
    FROM jsonb_array_elements(coalesce(p_anchors, '[]'::jsonb)) AS elem
  ),
  matched AS (
    SELECT DISTINCT ON (a.id, ha.haa_anchor_type)
      a.id, a.ha_record_number, a.ha_slug, a.ha_title, a.ha_summary,
      a.ha_body_markdown, a.ha_category, a.ha_audience,
      ha.haa_anchor_type AS m_type,
      CASE ha.haa_anchor_type
        WHEN 'route'   THEN ha.haa_route
        WHEN 'object'  THEN ha.haa_object
        WHEN 'field'   THEN ha.haa_object || '.' || ha.haa_field
        WHEN 'concept' THEN ha.haa_concept
      END AS m_value,
      ha.haa_sort_order AS m_sort
    FROM public.help_articles a
    JOIN public.help_article_anchors ha ON ha.haa_article_id = a.id
    JOIN spec s ON
      (s.atype = ha.haa_anchor_type)
      AND (
        (s.atype = 'route'   AND s.aroute   = ha.haa_route)
        OR (s.atype = 'object'  AND s.aobject  = ha.haa_object)
        OR (s.atype = 'field'   AND s.aobject  = ha.haa_object AND s.afield = ha.haa_field)
        OR (s.atype = 'concept' AND s.aconcept = ha.haa_concept)
      )
    WHERE a.ha_is_deleted = false
      AND a.ha_is_published = true
      AND (p_audience IS NULL OR a.ha_audience = 'all' OR a.ha_audience = p_audience)
  )
  SELECT
    matched.id,
    matched.ha_record_number,
    matched.ha_slug,
    matched.ha_title,
    matched.ha_summary,
    matched.ha_body_markdown,
    matched.ha_category,
    matched.ha_audience,
    matched.m_type  AS matched_anchor_type,
    matched.m_value AS matched_anchor_value
  FROM matched
  ORDER BY matched.m_sort, matched.ha_title;
$function$
;

CREATE OR REPLACE FUNCTION public.help_search_articles(p_query text, p_audience text DEFAULT NULL::text, p_limit integer DEFAULT 50)
 RETURNS TABLE(id uuid, ha_record_number text, ha_slug text, ha_title text, ha_summary text, ha_category text, ha_audience text, match_rank real)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_has_query boolean := (p_query IS NOT NULL AND length(trim(p_query)) > 0);
  v_tsquery   tsquery;
BEGIN
  IF v_has_query THEN
    v_tsquery := websearch_to_tsquery('english', p_query);
  END IF;

  RETURN QUERY
  SELECT
    a.id, a.ha_record_number, a.ha_slug, a.ha_title, a.ha_summary,
    a.ha_category, a.ha_audience,
    CASE WHEN v_has_query THEN ts_rank(a.ha_search, v_tsquery) ELSE 0::real END
  FROM public.help_articles a
  WHERE a.ha_is_deleted = false
    AND a.ha_is_published = true
    AND (p_audience IS NULL OR a.ha_audience = 'all' OR a.ha_audience = p_audience)
    AND (NOT v_has_query OR a.ha_search @@ v_tsquery)
  ORDER BY
    CASE WHEN v_has_query THEN ts_rank(a.ha_search, v_tsquery) ELSE 0::real END DESC,
    a.ha_title ASC
  LIMIT GREATEST(1, LEAST(coalesce(p_limit, 50), 200));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.import_property_batch(p_source_dataset text, p_records jsonb, p_owner_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_batch_id           uuid;
  v_batch_record_no    text;
  v_rec                jsonb;
  v_total              int := 0;
  v_created            int := 0;
  v_updated            int := 0;
  v_skipped            int := 0;
  v_errored            int := 0;
  v_accounts_created   int := 0;
  v_accounts_matched   int := 0;
  v_account_id         uuid;
  v_property_id        uuid;
  v_existing_property  uuid;
  v_property_rt_mf     uuid;
  v_account_rt_owner   uuid;
  v_error_msg          text;
  v_errors             jsonb := '[]'::jsonb;
BEGIN
  IF p_source_dataset IS NULL OR p_source_dataset = '' THEN
    RAISE EXCEPTION 'source_dataset is required';
  END IF;
  IF p_records IS NULL OR jsonb_typeof(p_records) <> 'array' THEN
    RAISE EXCEPTION 'records must be a JSON array';
  END IF;
  IF p_owner_user_id IS NULL THEN
    RAISE EXCEPTION 'owner_user_id is required';
  END IF;

  -- Resolve well-known picklist ids once
  SELECT id INTO v_property_rt_mf  FROM picklist_values
    WHERE picklist_object='properties' AND picklist_field='record_type' AND picklist_value='MultiFamily'  LIMIT 1;
  SELECT id INTO v_account_rt_owner FROM picklist_values
    WHERE picklist_object='accounts'   AND picklist_field='record_type' AND picklist_value='property_owner' LIMIT 1;

  -- Create the batch row
  INSERT INTO property_import_batches (
    pib_record_number, pib_source_dataset, pib_status,
    pib_started_at, pib_owner, pib_created_by, pib_updated_by
  ) VALUES (
    '', p_source_dataset, 'in_progress',
    now(), p_owner_user_id, p_owner_user_id, p_owner_user_id
  )
  RETURNING id, pib_record_number INTO v_batch_id, v_batch_record_no;

  -- Iterate
  FOR v_rec IN SELECT * FROM jsonb_array_elements(p_records)
  LOOP
    v_total := v_total + 1;
    BEGIN
      -- =============================================================
      -- 1. Account match-or-create (by HUD participant number)
      -- =============================================================
      v_account_id := NULL;
      IF v_rec->>'owner_hud_participant_number' IS NOT NULL
         AND v_rec->>'owner_hud_participant_number' <> '' THEN
        SELECT id INTO v_account_id
          FROM accounts
         WHERE account_hud_participant_number = v_rec->>'owner_hud_participant_number'
           AND COALESCE(account_is_deleted, false) = false
         LIMIT 1;

        IF v_account_id IS NULL THEN
          INSERT INTO accounts (
            account_record_number, account_name, account_record_type,
            account_hud_participant_number, account_owner,
            account_created_by, account_updated_by
          ) VALUES (
            '',
            COALESCE(NULLIF(v_rec->>'owner_name',''), 'HUD Owner ' || (v_rec->>'owner_hud_participant_number')),
            v_account_rt_owner,
            v_rec->>'owner_hud_participant_number',
            p_owner_user_id, p_owner_user_id, p_owner_user_id
          )
          RETURNING id INTO v_account_id;
          v_accounts_created := v_accounts_created + 1;
        ELSE
          v_accounts_matched := v_accounts_matched + 1;
        END IF;
      ELSE
        -- No participant number on the incoming record; try owner_name fallback
        IF v_rec->>'owner_name' IS NOT NULL AND v_rec->>'owner_name' <> '' THEN
          SELECT id INTO v_account_id
            FROM accounts
           WHERE LOWER(account_name) = LOWER(v_rec->>'owner_name')
             AND COALESCE(account_is_deleted, false) = false
           LIMIT 1;
          IF v_account_id IS NULL THEN
            INSERT INTO accounts (
              account_record_number, account_name, account_record_type,
              account_owner, account_created_by, account_updated_by
            ) VALUES (
              '', v_rec->>'owner_name', v_account_rt_owner,
              p_owner_user_id, p_owner_user_id, p_owner_user_id
            )
            RETURNING id INTO v_account_id;
            v_accounts_created := v_accounts_created + 1;
          ELSE
            v_accounts_matched := v_accounts_matched + 1;
          END IF;
        ELSE
          -- No identifying info at all; skip record
          v_skipped := v_skipped + 1;
          v_errors := v_errors || jsonb_build_object(
            'record', v_rec, 'reason', 'No owner_name or owner_hud_participant_number on record'
          );
          CONTINUE;
        END IF;
      END IF;

      -- =============================================================
      -- 2. Property match-or-create
      -- =============================================================
      v_existing_property := NULL;
      IF v_rec->>'hud_property_id' IS NOT NULL AND v_rec->>'hud_property_id' <> '' THEN
        SELECT id INTO v_existing_property
          FROM properties
         WHERE property_hud_property_id = v_rec->>'hud_property_id'
           AND COALESCE(property_is_deleted, false) = false
         LIMIT 1;
      END IF;
      IF v_existing_property IS NULL AND v_rec->>'lihtc_project_id' IS NOT NULL AND v_rec->>'lihtc_project_id' <> '' THEN
        SELECT id INTO v_existing_property
          FROM properties
         WHERE property_lihtc_project_id = v_rec->>'lihtc_project_id'
           AND COALESCE(property_is_deleted, false) = false
         LIMIT 1;
      END IF;

      IF v_existing_property IS NOT NULL THEN
        -- UPDATE existing — overlay non-null incoming fields only
        UPDATE properties SET
          property_name              = COALESCE(NULLIF(v_rec->>'property_name',''),       property_name),
          property_aka_name          = COALESCE(NULLIF(v_rec->>'property_aka_name',''),   property_aka_name),
          property_street            = COALESCE(NULLIF(v_rec->>'street',''),              property_street),
          property_city              = COALESCE(NULLIF(v_rec->>'city',''),                property_city),
          property_state             = COALESCE(NULLIF(v_rec->>'state',''),               property_state),
          property_zip               = COALESCE(NULLIF(v_rec->>'zip',''),                 property_zip),
          property_county            = COALESCE(NULLIF(v_rec->>'county',''),              property_county),
          property_latitude          = COALESCE((v_rec->>'latitude')::numeric,            property_latitude),
          property_longitude         = COALESCE((v_rec->>'longitude')::numeric,           property_longitude),
          property_total_units       = COALESCE((v_rec->>'total_units')::int,             property_total_units),
          property_total_buildings   = COALESCE((v_rec->>'total_buildings')::int,         property_total_buildings),
          property_year_built        = COALESCE((v_rec->>'year_built')::int,              property_year_built),
          property_lihtc_project_id  = COALESCE(NULLIF(v_rec->>'lihtc_project_id',''),    property_lihtc_project_id),
          property_account_id        = COALESCE(property_account_id, v_account_id),
          property_updated_by        = p_owner_user_id,
          property_updated_at        = now()
        WHERE id = v_existing_property;
        v_property_id := v_existing_property;
        v_updated := v_updated + 1;
      ELSE
        -- INSERT new
        INSERT INTO properties (
          property_record_number, property_name, property_aka_name,
          property_record_type, property_owner, property_account_id,
          property_street, property_city, property_state, property_zip, property_county,
          property_latitude, property_longitude,
          property_total_units, property_total_buildings, property_year_built,
          property_hud_property_id, property_lihtc_project_id,
          property_created_by, property_updated_by
        ) VALUES (
          '',
          COALESCE(NULLIF(v_rec->>'property_name',''), 'Unnamed HUD Property'),
          NULLIF(v_rec->>'property_aka_name',''),
          v_property_rt_mf, p_owner_user_id, v_account_id,
          COALESCE(NULLIF(v_rec->>'street',''), 'Unknown'),
          COALESCE(NULLIF(v_rec->>'city',''),   'Unknown'),
          COALESCE(NULLIF(v_rec->>'state',''),  'XX'),
          COALESCE(NULLIF(v_rec->>'zip',''),    '00000'),
          NULLIF(v_rec->>'county',''),
          (v_rec->>'latitude')::numeric,
          (v_rec->>'longitude')::numeric,
          (v_rec->>'total_units')::int,
          (v_rec->>'total_buildings')::int,
          (v_rec->>'year_built')::int,
          NULLIF(v_rec->>'hud_property_id',''),
          NULLIF(v_rec->>'lihtc_project_id',''),
          p_owner_user_id, p_owner_user_id
        )
        RETURNING id INTO v_property_id;
        v_created := v_created + 1;
      END IF;

      -- =============================================================
      -- 3. property_source_data — UPSERT on psd_property_id
      -- =============================================================
      INSERT INTO property_source_data (
        psd_record_number, psd_property_id,
        psd_source_dataset, psd_source_imported_at, psd_source_import_batch_id,
        psd_hud_contract_number, psd_hud_contract_type, psd_hud_subsidy_type,
        psd_hud_contract_expiration_date,
        psd_doe_lead_energy_burden_score, psd_doe_lead_average_energy_cost,
        psd_doe_lead_low_income_percentage,
        psd_raw_payload,
        psd_owner, psd_created_by, psd_updated_by
      ) VALUES (
        '', v_property_id,
        p_source_dataset, now(), v_batch_id,
        NULLIF(v_rec->>'hud_contract_number',''), NULLIF(v_rec->>'hud_contract_type',''),
        NULLIF(v_rec->>'hud_subsidy_type',''),
        NULLIF(v_rec->>'hud_contract_expiration_date','')::date,
        (v_rec->>'doe_lead_energy_burden_score')::numeric,
        (v_rec->>'doe_lead_average_energy_cost')::numeric,
        (v_rec->>'doe_lead_low_income_percentage')::numeric,
        v_rec,
        p_owner_user_id, p_owner_user_id, p_owner_user_id
      )
      ON CONFLICT (psd_property_id) DO UPDATE SET
        psd_source_dataset                = EXCLUDED.psd_source_dataset,
        psd_source_imported_at            = EXCLUDED.psd_source_imported_at,
        psd_source_import_batch_id        = EXCLUDED.psd_source_import_batch_id,
        psd_hud_contract_number           = COALESCE(EXCLUDED.psd_hud_contract_number,           property_source_data.psd_hud_contract_number),
        psd_hud_contract_type             = COALESCE(EXCLUDED.psd_hud_contract_type,             property_source_data.psd_hud_contract_type),
        psd_hud_subsidy_type              = COALESCE(EXCLUDED.psd_hud_subsidy_type,              property_source_data.psd_hud_subsidy_type),
        psd_hud_contract_expiration_date  = COALESCE(EXCLUDED.psd_hud_contract_expiration_date,  property_source_data.psd_hud_contract_expiration_date),
        psd_doe_lead_energy_burden_score  = COALESCE(EXCLUDED.psd_doe_lead_energy_burden_score,  property_source_data.psd_doe_lead_energy_burden_score),
        psd_doe_lead_average_energy_cost  = COALESCE(EXCLUDED.psd_doe_lead_average_energy_cost,  property_source_data.psd_doe_lead_average_energy_cost),
        psd_doe_lead_low_income_percentage= COALESCE(EXCLUDED.psd_doe_lead_low_income_percentage,property_source_data.psd_doe_lead_low_income_percentage),
        psd_raw_payload                   = EXCLUDED.psd_raw_payload,
        psd_updated_by                    = EXCLUDED.psd_updated_by,
        psd_updated_at                    = now();

      -- =============================================================
      -- 4. property_disaster_exposure — UPSERT when fema_* present
      -- =============================================================
      IF v_rec ? 'fema_county' OR v_rec ? 'fema_declaration_count' OR v_rec ? 'fema_declared_disasters' THEN
        INSERT INTO property_disaster_exposure (
          pde_record_number, pde_property_id,
          pde_fema_county, pde_fema_state,
          pde_fema_declaration_count, pde_fema_hurricane_declaration_count,
          pde_fema_most_recent_declaration_date, pde_fema_declared_disasters,
          pde_data_source, pde_data_last_refreshed_at,
          pde_owner, pde_created_by, pde_updated_by
        ) VALUES (
          '', v_property_id,
          NULLIF(v_rec->>'fema_county',''), NULLIF(v_rec->>'fema_state',''),
          COALESCE((v_rec->>'fema_declaration_count')::int, 0),
          COALESCE((v_rec->>'fema_hurricane_declaration_count')::int, 0),
          NULLIF(v_rec->>'fema_most_recent_declaration_date','')::date,
          v_rec->'fema_declared_disasters',
          'FEMA', now(),
          p_owner_user_id, p_owner_user_id, p_owner_user_id
        )
        ON CONFLICT (pde_property_id) DO UPDATE SET
          pde_fema_county                       = COALESCE(EXCLUDED.pde_fema_county,                       property_disaster_exposure.pde_fema_county),
          pde_fema_state                        = COALESCE(EXCLUDED.pde_fema_state,                        property_disaster_exposure.pde_fema_state),
          pde_fema_declaration_count            = EXCLUDED.pde_fema_declaration_count,
          pde_fema_hurricane_declaration_count  = EXCLUDED.pde_fema_hurricane_declaration_count,
          pde_fema_most_recent_declaration_date = COALESCE(EXCLUDED.pde_fema_most_recent_declaration_date, property_disaster_exposure.pde_fema_most_recent_declaration_date),
          pde_fema_declared_disasters           = COALESCE(EXCLUDED.pde_fema_declared_disasters,           property_disaster_exposure.pde_fema_declared_disasters),
          pde_data_last_refreshed_at            = EXCLUDED.pde_data_last_refreshed_at,
          pde_updated_by                        = EXCLUDED.pde_updated_by,
          pde_updated_at                        = now();
      END IF;

    EXCEPTION WHEN OTHERS THEN
      v_errored := v_errored + 1;
      GET STACKED DIAGNOSTICS v_error_msg = MESSAGE_TEXT;
      v_errors := v_errors || jsonb_build_object(
        'record', v_rec,
        'error',  v_error_msg
      );
    END;
  END LOOP;

  -- Finalize the batch row
  UPDATE property_import_batches SET
    pib_status            = CASE WHEN v_errored > 0 THEN 'completed_with_errors' ELSE 'completed' END,
    pib_records_total     = v_total,
    pib_records_created   = v_created,
    pib_records_updated   = v_updated,
    pib_records_skipped   = v_skipped,
    pib_records_errored   = v_errored,
    pib_accounts_created  = v_accounts_created,
    pib_accounts_matched  = v_accounts_matched,
    pib_completed_at      = now(),
    pib_updated_at        = now()
  WHERE id = v_batch_id;

  RETURN jsonb_build_object(
    'batch_id',          v_batch_id,
    'batch_record_no',   v_batch_record_no,
    'records_total',     v_total,
    'records_created',   v_created,
    'records_updated',   v_updated,
    'records_skipped',   v_skipped,
    'records_errored',   v_errored,
    'accounts_created',  v_accounts_created,
    'accounts_matched',  v_accounts_matched,
    'errors',            v_errors
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.import_property_hierarchy(p_rows jsonb, p_source_filename text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller_user_id      uuid;
  v_row                 jsonb;
  v_action              text;
  v_owner_name          text;
  v_owner_id            uuid;
  v_property_name       text;
  v_property_street     text;
  v_property_city       text;
  v_property_state      text;
  v_property_zip        text;
  v_property_subsidy    text;
  v_property_addr_norm  text;
  v_property_id         uuid;
  v_property_rt_id      uuid;
  v_account_rt_id       uuid;
  v_subsidy_pl_id       uuid;
  v_building_name       text;
  v_building_year       integer;
  v_building_count      integer;
  v_building_notes      text;
  v_building_id         uuid;
  v_unit_id             uuid;
  v_unit_i              integer;
  v_owners_created      integer := 0;
  v_properties_created  integer := 0;
  v_buildings_created   integer := 0;
  v_units_created       integer := 0;
  v_owner_ids           uuid[] := ARRAY[]::uuid[];
  v_property_ids        uuid[] := ARRAY[]::uuid[];
  v_building_ids        uuid[] := ARRAY[]::uuid[];
  v_unit_ids            uuid[] := ARRAY[]::uuid[];
  v_bir_id              uuid;
  v_bir_record_number   text;
  v_processed_rows      integer := 0;
BEGIN
  -- Resolve caller
  SELECT u.id INTO v_caller_user_id
    FROM public.users u
   WHERE u.auth_user_id = auth.uid()
   LIMIT 1;
  IF v_caller_user_id IS NULL THEN
    RAISE EXCEPTION 'import_property_hierarchy: caller has no public.users record (auth.uid()=%)', auth.uid();
  END IF;

  -- Resolve picklist UUIDs we'll stamp on every record (constants for v1)
  SELECT pv.id INTO v_account_rt_id
    FROM picklist_values pv
   WHERE pv.picklist_object='accounts' AND pv.picklist_field='record_type'
     AND pv.picklist_value='Property'
   LIMIT 1;

  SELECT pv.id INTO v_property_rt_id
    FROM picklist_values pv
   WHERE pv.picklist_object='properties' AND pv.picklist_field='record_type'
     AND pv.picklist_value='MultiFamily'
   LIMIT 1;

  -- Walk every row
  FOR v_row IN SELECT * FROM jsonb_array_elements(p_rows) LOOP
    v_action          := coalesce(v_row->>'row_action', 'create');
    IF v_action = 'skip' THEN CONTINUE; END IF;

    v_owner_name       := btrim(v_row->>'owner_name');
    v_property_name    := btrim(v_row->>'property_name');
    v_property_street  := btrim(v_row->>'property_street');
    v_property_city    := btrim(v_row->>'property_city');
    v_property_state   := upper(btrim(v_row->>'property_state'));
    v_property_zip     := btrim(v_row->>'property_zip');
    v_property_subsidy := nullif(btrim(v_row->>'property_subsidy_type'), '');
    v_building_name    := btrim(v_row->>'building_name');
    v_building_year    := nullif(v_row->>'building_year_built','')::integer;
    v_building_count   := nullif(v_row->>'building_unit_count','')::integer;
    v_building_notes   := nullif(btrim(v_row->>'building_notes'), '');

    -- Resolve / create Account (owner)
    SELECT a.id INTO v_owner_id
      FROM public.accounts a
     WHERE lower(btrim(a.account_name)) = lower(v_owner_name)
       AND NOT a.account_is_deleted
     LIMIT 1;

    IF v_owner_id IS NULL THEN
      INSERT INTO public.accounts (
        account_name, account_record_type, account_owner, account_created_by, account_updated_by
      ) VALUES (
        v_owner_name, v_account_rt_id, v_caller_user_id, v_caller_user_id, v_caller_user_id
      ) RETURNING id INTO v_owner_id;
      v_owners_created := v_owners_created + 1;
      v_owner_ids := array_append(v_owner_ids, v_owner_id);
    END IF;

    -- Resolve / create Property (dedup by normalized street+city+state)
    v_property_addr_norm := normalize_property_address(v_property_street, v_property_city, v_property_state);

    SELECT p.id INTO v_property_id
      FROM public.properties p
     WHERE normalize_property_address(p.property_street, p.property_city, p.property_state) = v_property_addr_norm
       AND NOT p.property_is_deleted
     LIMIT 1;

    IF v_property_id IS NULL THEN
      -- Resolve optional subsidy picklist
      v_subsidy_pl_id := NULL;
      IF v_property_subsidy IS NOT NULL THEN
        SELECT pv.id INTO v_subsidy_pl_id
          FROM picklist_values pv
         WHERE pv.picklist_object='properties'
           AND pv.picklist_field='property_subsidy_type'
           AND pv.picklist_value=v_property_subsidy
         LIMIT 1;
      END IF;

      INSERT INTO public.properties (
        property_name, property_account_id, property_street, property_city,
        property_state, property_zip, property_record_type, property_subsidy_type,
        property_owner, property_created_by, property_updated_by
      ) VALUES (
        v_property_name, v_owner_id, v_property_street, v_property_city,
        v_property_state, v_property_zip, v_property_rt_id, v_subsidy_pl_id,
        v_caller_user_id, v_caller_user_id, v_caller_user_id
      ) RETURNING id INTO v_property_id;
      v_properties_created := v_properties_created + 1;
      v_property_ids := array_append(v_property_ids, v_property_id);
    END IF;

    -- Building — dedup by (property_id, lower(name))
    IF v_building_name IS NOT NULL AND v_building_name <> '' THEN
      SELECT b.id INTO v_building_id
        FROM public.buildings b
       WHERE b.property_id = v_property_id
         AND lower(btrim(b.building_name)) = lower(v_building_name)
         AND NOT b.building_is_deleted
       LIMIT 1;

      IF v_building_id IS NULL THEN
        INSERT INTO public.buildings (
          building_name, building_number_or_name, property_id,
          building_year_built, building_notes,
          building_owner, building_created_by, building_updated_by
        ) VALUES (
          v_building_name, v_building_name, v_property_id,
          v_building_year, v_building_notes,
          v_caller_user_id, v_caller_user_id, v_caller_user_id
        ) RETURNING id INTO v_building_id;
        v_buildings_created := v_buildings_created + 1;
        v_building_ids := array_append(v_building_ids, v_building_id);

        -- Auto-create unit placeholders
        IF v_building_count IS NOT NULL AND v_building_count > 0 THEN
          FOR v_unit_i IN 1..v_building_count LOOP
            INSERT INTO public.units (
              unit_name, unit_number, building_id,
              unit_owner, unit_created_by, unit_updated_by
            ) VALUES (
              'Unit ' || v_unit_i, v_unit_i::text, v_building_id,
              v_caller_user_id, v_caller_user_id, v_caller_user_id
            ) RETURNING id INTO v_unit_id;
            v_units_created := v_units_created + 1;
            v_unit_ids := array_append(v_unit_ids, v_unit_id);
          END LOOP;
        END IF;
      END IF;
    END IF;

    v_processed_rows := v_processed_rows + 1;
  END LOOP;

  -- Audit row
  INSERT INTO public.bulk_import_runs (
    bir_import_type, bir_source_filename, bir_row_count,
    bir_accounts_created, bir_properties_created, bir_buildings_created, bir_units_created,
    bir_decisions_json, bir_created_record_ids,
    bir_owner, bir_created_by, bir_updated_by
  ) VALUES (
    'property_hierarchy', p_source_filename, v_processed_rows,
    v_owners_created, v_properties_created, v_buildings_created, v_units_created,
    p_rows,
    jsonb_build_object(
      'account_ids',  to_jsonb(v_owner_ids),
      'property_ids', to_jsonb(v_property_ids),
      'building_ids', to_jsonb(v_building_ids),
      'unit_ids',     to_jsonb(v_unit_ids)
    ),
    v_caller_user_id, v_caller_user_id, v_caller_user_id
  ) RETURNING id, bir_record_number INTO v_bir_id, v_bir_record_number;

  RETURN jsonb_build_object(
    'import_run_id',         v_bir_id,
    'import_run_record_number', v_bir_record_number,
    'processed_rows',        v_processed_rows,
    'accounts_created',      v_owners_created,
    'properties_created',    v_properties_created,
    'buildings_created',     v_buildings_created,
    'units_created',         v_units_created
  );
END
$function$
;

CREATE OR REPLACE FUNCTION public.import_sf_layout(p jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_layout_id uuid;
  v_rt_id uuid;
  v_sec_id uuid;
  v_sec jsonb;
  v_idx int := 0;
  v_owner uuid := (p->>'owner')::uuid;
  v_obj text := p->>'object';
  v_rt text := p->>'rt';
  v_label text := p->>'label';
BEGIN
  IF v_rt IS NOT NULL THEN
    SELECT id INTO v_rt_id FROM public.picklist_values
    WHERE picklist_object = v_obj AND picklist_field = 'record_type' AND picklist_value = v_rt LIMIT 1;
  END IF;
  INSERT INTO public.page_layouts (
    page_layout_record_number, page_layout_name, page_layout_object, page_layout_type,
    page_layout_is_default, page_layout_description, record_type_id,
    page_layout_owner, page_layout_created_by, is_deleted
  ) VALUES (
    '', v_label, v_obj, 'record_detail', true,
    'Imported from SF Layout: ' || v_obj || '/' || v_label, v_rt_id, v_owner, v_owner, false
  ) RETURNING id INTO v_layout_id;
  FOR v_sec IN SELECT * FROM jsonb_array_elements(COALESCE(p->'sections', '[]'::jsonb))
  LOOP
    v_idx := v_idx + 1;
    INSERT INTO public.page_layout_sections (
      page_layout_id, section_order, section_label, section_columns, section_tab,
      section_is_collapsible, section_is_collapsed_by_default, is_deleted
    ) VALUES (
      v_layout_id, v_idx, v_sec->>'label', 2, 'Details', true,
      (v_idx > 2), false
    ) RETURNING id INTO v_sec_id;
    INSERT INTO public.page_layout_widgets (
      page_layout_id, section_id, widget_type, widget_title, widget_column, widget_position, widget_size, widget_config, is_deleted
    ) VALUES (
      v_layout_id, v_sec_id, 'field_group', v_sec->>'label', 1, 1, 'medium',
      jsonb_build_object('fields', v_sec->'fields'), false
    );
  END LOOP;
  RETURN v_layout_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.instantiate_work_plan(p_work_order_id uuid)
 RETURNS TABLE(work_plan_id uuid, step_count integer, outcome text, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_actor       uuid := public.current_app_user_id();
  v_wo          public.work_orders;
  v_wpt_id      uuid;
  v_wpt_name    text;
  v_owner       uuid;
  v_new_plan_id uuid;
  v_status_new  uuid;
  v_count       integer := 0;
BEGIN
  SELECT * INTO v_wo FROM public.work_orders WHERE id = p_work_order_id AND work_order_is_deleted IS NOT TRUE;
  IF v_wo.id IS NULL THEN
    RETURN QUERY SELECT NULL::uuid, 0, 'error', format('Work order %s not found or deleted', p_work_order_id);
    RETURN;
  END IF;

  -- Actor: prefer the session app-user; fall back to the work order's owner/creator
  -- so the function never writes a NULL audit actor regardless of how it is invoked.
  v_actor := COALESCE(v_actor, v_wo.work_order_owner, v_wo.work_order_created_by);
  v_owner := COALESCE(v_wo.work_order_owner, v_actor);

  SELECT wp.id INTO v_new_plan_id
    FROM public.work_plans wp
   WHERE wp.work_order_id = p_work_order_id AND wp.work_plan_is_deleted IS NOT TRUE
   LIMIT 1;
  IF v_new_plan_id IS NOT NULL THEN
    SELECT count(*) INTO v_count FROM public.work_steps ws WHERE ws.work_plan_id = v_new_plan_id AND ws.work_step_is_deleted IS NOT TRUE;
    RETURN QUERY SELECT v_new_plan_id, v_count, 'exists', 'Work plan already instantiated for this work order';
    RETURN;
  END IF;

  SELECT wt.work_type_default_work_plan_template_id INTO v_wpt_id
    FROM public.work_types wt WHERE wt.id = v_wo.work_type_id;
  IF v_wpt_id IS NULL THEN
    RETURN QUERY SELECT NULL::uuid, 0, 'error',
      'Work type has no default work plan template — set work_type_default_work_plan_template_id first';
    RETURN;
  END IF;

  SELECT wpt.wpt_name INTO v_wpt_name FROM public.work_plan_templates wpt WHERE wpt.id = v_wpt_id AND wpt.wpt_is_deleted IS NOT TRUE;
  IF v_wpt_name IS NULL THEN
    RETURN QUERY SELECT NULL::uuid, 0, 'error', 'Default work plan template is missing or deleted';
    RETURN;
  END IF;

  SELECT id INTO v_status_new FROM public.picklist_values
   WHERE picklist_object='work_steps' AND picklist_field='work_step_status' AND picklist_value='New' AND picklist_is_active LIMIT 1;

  INSERT INTO public.work_plans (
    work_plan_record_number, work_plan_name, work_plan_owner, work_plan_created_by,
    work_order_id, work_plan_template_id, work_plan_description, work_plan_execution_order,
    is_seed_data, work_plan_is_deleted
  ) VALUES (
    '', v_wpt_name, v_owner, v_actor,
    p_work_order_id, v_wpt_id,
    (SELECT wpt_description FROM public.work_plan_templates WHERE id = v_wpt_id),
    1, false, false
  ) RETURNING id INTO v_new_plan_id;

  INSERT INTO public.work_steps (
    work_step_record_number, work_step_name, work_step_owner, work_step_created_by,
    work_plan_id, work_order_id, work_step_template_id,
    work_step_status, work_step_execution_order, work_step_plan_execution_order,
    work_step_description, work_step_action_type, work_step_action_definition,
    work_step_reference_photo_url,
    work_step_required_evidence_type_id, work_step_photos_required_count,
    work_step_photo_before_required, work_step_photo_after_required,
    work_step_estimated_duration_minutes,
    work_step_assigned_owner_role_id, work_step_verifier_role_id,
    is_seed_data, work_step_is_deleted
  )
  SELECT
    '', wst.wst_name, v_owner, v_actor,
    v_new_plan_id, p_work_order_id, wst.id,
    v_status_new, e.wpte_execution_order, e.wpte_execution_order,
    wst.wst_description, wst.wst_action_type, wst.wst_action_definition,
    wst.wst_reference_photo_url,
    wst.wst_required_evidence_type_id, COALESCE(wst.wst_photos_required_count, 0),
    COALESCE(wst.wst_photo_before_required, false), COALESCE(wst.wst_photo_after_required, false),
    wst.wst_estimated_duration_minutes,
    wst.wst_assigned_owner_role_id, wst.wst_verifier_role_id,
    false, false
  FROM public.work_plan_template_entries e
  JOIN public.work_step_templates wst ON wst.id = e.work_step_template_id AND wst.wst_is_deleted IS NOT TRUE
  WHERE e.work_plan_template_id = v_wpt_id AND e.wpte_is_deleted IS NOT TRUE
  ORDER BY e.wpte_execution_order;

  GET DIAGNOSTICS v_count = ROW_COUNT;

  RETURN QUERY SELECT v_new_plan_id, v_count, 'success',
    format('Instantiated work plan "%s" with %s steps on work order %s', v_wpt_name, v_count, v_wo.work_order_record_number);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.is_admin()
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select exists (
    select 1
    from public.users u
    join public.roles r on r.id = u.role_id
    where u.auth_user_id = auth.uid()
      and r.role_name = 'Admin'
      and r.role_is_active
  );
$function$
;

CREATE OR REPLACE FUNCTION public.is_on_anchor_opportunity_contact_roles(p_conversation_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select exists (
    select 1
    from public.users u
    join public.contacts c on c.contact_user_id = u.id
    join public.opportunity_contact_roles ocr on ocr.contact_id = c.id
    where u.auth_user_id = auth.uid()
      and ocr.ocr_includes_communications = true
      and not ocr.ocr_is_deleted
      and ocr.opportunity_id in (select * from resolve_anchor_opportunity(p_conversation_id))
  );
$function$
;

CREATE OR REPLACE FUNCTION public.is_recipient(p_conversation_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  select exists (
    select 1
    from public.users u
    join public.contacts c on c.contact_user_id = u.id
    join public.messages m on m.conversation_id = p_conversation_id
    where u.auth_user_id = auth.uid()
      and not m.msg_is_deleted
      and (
        m.msg_to_address    in (c.contact_email, c.contact_phone, c.contact_mobile_phone)
        or m.msg_from_address in (c.contact_email, c.contact_phone, c.contact_mobile_phone)
      )
  );
$function$
;

CREATE OR REPLACE FUNCTION public.is_record_owner_in_chain(p_conversation_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  with me as (
    select id as user_id from public.users where auth_user_id = auth.uid()
  ), conv as (
    select c.contact_id, c.account_id, c.project_id, c.service_appointment_id
    from public.conversations c
    where c.id = p_conversation_id and not c.conv_is_deleted
  )
  select exists (
    select 1 from conv c, me
    where (c.contact_id is not null
           and exists (select 1 from public.contacts x where x.id = c.contact_id and x.contact_owner = me.user_id))
       or (c.account_id is not null
           and exists (select 1 from public.accounts x where x.id = c.account_id and x.account_owner = me.user_id))
       or (c.project_id is not null
           and exists (select 1 from public.projects x where x.id = c.project_id and x.project_owner = me.user_id))
       or (c.service_appointment_id is not null
           and exists (select 1 from public.service_appointments x where x.id = c.service_appointment_id and x.sa_owner = me.user_id))
       or exists (
         select 1 from public.opportunities o
         where o.id in (select * from resolve_anchor_opportunity(p_conversation_id))
           and o.opportunity_owner = me.user_id
       )
  );
$function$
;

CREATE OR REPLACE FUNCTION public.jsonb_object_keys_count(p jsonb)
 RETURNS integer
 LANGUAGE sql
 IMMUTABLE STRICT
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT CASE WHEN jsonb_typeof(p) = 'object'
              THEN (SELECT count(*) FROM jsonb_object_keys(p))::int
              ELSE NULL END
$function$
;

CREATE OR REPLACE FUNCTION public.lifecycle_field_dispatcher()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_status_field text := TG_ARGV[0];
  v_current_status uuid;
  v_old_val text;
  v_new_val text;
  v_new_status text;
  v_t public.status_transitions%ROWTYPE;
  v_fire boolean;
  v_user_id uuid;
  v_event_id uuid;
BEGIN
  EXECUTE format('SELECT ($1).%I::uuid', v_status_field) INTO v_current_status USING OLD;

  -- If the status itself changed on this write, don't also auto-advance.
  EXECUTE format('SELECT ($1).%I::uuid', v_status_field) INTO v_new_status USING NEW;
  IF v_new_status IS DISTINCT FROM v_current_status::text THEN
    RETURN NEW;
  END IF;

  FOR v_t IN
    SELECT * FROM public.status_transitions
    WHERE st_object = TG_TABLE_NAME
      AND st_status_field = v_status_field
      AND st_is_active = true
      AND st_is_deleted = false
      AND st_trigger_type IN ('field_populated','field_equals')
      AND st_from_status_id IS NOT DISTINCT FROM v_current_status
    ORDER BY st_sort_order ASC
  LOOP
    EXECUTE format('SELECT ($1).%I::text', v_t.st_trigger_field) INTO v_old_val USING OLD;
    EXECUTE format('SELECT ($1).%I::text', v_t.st_trigger_field) INTO v_new_val USING NEW;

    v_fire := false;
    IF v_t.st_trigger_type = 'field_populated' THEN
      IF (v_old_val IS NULL OR v_old_val = '')
         AND v_new_val IS NOT NULL AND v_new_val <> '' THEN
        v_fire := true;
      END IF;
    ELSIF v_t.st_trigger_type = 'field_equals' THEN
      IF v_new_val IS NOT DISTINCT FROM v_t.st_trigger_value
         AND v_old_val IS DISTINCT FROM v_t.st_trigger_value THEN
        v_fire := true;
      END IF;
    END IF;

    IF v_fire THEN
      -- In-row advance via jsonb: overlay the status field onto NEW.
      NEW := jsonb_populate_record(
        NEW,
        jsonb_build_object(v_status_field, v_t.st_to_status_id::text)
      );

      v_user_id := (SELECT id FROM public.users WHERE auth_user_id = auth.uid());
      INSERT INTO public.status_change_events (
        sce_record_number, sce_object, sce_record_id, sce_transition_id,
        sce_from_status_id, sce_to_status_id, sce_note, sce_created_by
      ) VALUES (
        '', TG_TABLE_NAME, NEW.id, v_t.id,
        v_current_status, v_t.st_to_status_id,
        format('Auto-advanced: %s populated', v_t.st_trigger_field),
        v_user_id
      ) RETURNING id INTO v_event_id;

      EXIT;
    END IF;
  END LOOP;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.lifecycle_object_columns(p_object text)
 RETURNS TABLE(column_name text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT c.column_name::text
  FROM information_schema.columns c
  WHERE c.table_schema = 'public'
    AND c.table_name = p_object
  ORDER BY c.column_name;
$function$
;

CREATE OR REPLACE FUNCTION public.list_assistant_tasks(p_launch_object text DEFAULT NULL::text)
 RETURNS TABLE(flow_id uuid, name text, description text, launch_object text)
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT f.id, f.flow_name, f.flow_description, f.flow_launch_object
  FROM public.flows f
  WHERE f.is_deleted = false
    AND f.flow_type = 'screen'
    AND f.flow_status = 'active'
    AND f.flow_active_version_id IS NOT NULL
    AND f.flow_name <> 'AI Assistant — Ad-hoc'
    AND ( p_launch_object IS NULL
          OR f.flow_launch_object IS NULL
          OR f.flow_launch_object = p_launch_object )
  ORDER BY f.flow_name ASC;
$function$
;

CREATE OR REPLACE FUNCTION public.list_buildings_for_property(p_property_ids uuid[], p_include_building_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(id uuid, building_name text)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT b.id, b.building_name
  FROM buildings b
  WHERE b.building_is_deleted = false
    AND (
      b.property_id = ANY(p_property_ids)
      OR (p_include_building_id IS NOT NULL AND b.id = p_include_building_id)
    )
  ORDER BY b.building_name ASC, b.id ASC;
$function$
;

CREATE OR REPLACE FUNCTION public.list_contacts_for_accounts(p_account_ids uuid[], p_include_contact_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(id uuid, contact_name text)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT c.id, c.contact_name
    FROM contacts c
   WHERE NOT c.contact_is_deleted
     AND (
       (p_account_ids IS NOT NULL AND array_length(p_account_ids, 1) > 0
         AND c.contact_account_id = ANY(p_account_ids))
       OR EXISTS (
         SELECT 1
           FROM account_contact_relations acr
          WHERE acr.contact_id = c.id
            AND acr.account_id = ANY(p_account_ids)
            AND acr.acr_is_active = true
            AND NOT acr.acr_is_deleted
       )
       OR (p_include_contact_id IS NOT NULL AND c.id = p_include_contact_id)
     )
   ORDER BY c.contact_name;
$function$
;

CREATE OR REPLACE FUNCTION public.list_contacts_for_opportunity(p_opportunity_id uuid, p_include_contact_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(id uuid, contact_name text)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  WITH acct AS (
    SELECT ARRAY_REMOVE(ARRAY[
      o.opportunity_account_id,
      o.opportunity_managing_account_id
    ], NULL) AS account_ids
    FROM opportunities o
    WHERE o.id = p_opportunity_id
  )
  SELECT c.id, c.contact_name
    FROM contacts c, acct
   WHERE NOT c.contact_is_deleted
     AND (
       (array_length(acct.account_ids, 1) > 0
         AND c.contact_account_id = ANY(acct.account_ids))
       OR EXISTS (
         SELECT 1
           FROM account_contact_relations acr
          WHERE acr.contact_id = c.id
            AND acr.account_id = ANY(acct.account_ids)
            AND acr.acr_is_active = true
            AND NOT acr.acr_is_deleted
       )
       OR (p_include_contact_id IS NOT NULL AND c.id = p_include_contact_id)
     )
   ORDER BY c.contact_name;
$function$
;

CREATE OR REPLACE FUNCTION public.list_email_sends_for_record(p_parent_object text, p_parent_record_id uuid)
 RETURNS TABLE(id uuid, email_send_record_number text, subject text, recipients_to jsonb, sender_email text, sent_by_user_id uuid, sent_by_name text, status text, sent_at timestamp with time zone, body_html text, related_envelope_id uuid)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT
    es.id, es.email_send_record_number, es.subject, es.recipients_to,
    es.sender_email, es.sent_by_user_id,
    COALESCE(NULLIF(TRIM(COALESCE(u.user_first_name,'') || ' ' || COALESCE(u.user_last_name,'')), ''),
             u.user_name, es.sender_email) AS sent_by_name,
    es.status, es.sent_at, es.body_html, es.related_envelope_id
  FROM public.email_sends es
  LEFT JOIN public.users u ON u.id = es.sent_by_user_id
  WHERE es.parent_object = p_parent_object
    AND es.parent_record_id = p_parent_record_id
    AND NOT es.is_deleted
  ORDER BY es.sent_at DESC NULLS LAST, es.created_at DESC;
$function$
;

CREATE OR REPLACE FUNCTION public.list_envelope_events_for_record(p_parent_object text, p_parent_record_id uuid)
 RETURNS TABLE(id uuid, event_record_number text, event_type text, envelope_id uuid, envelope_record_number text, envelope_name text, recipient_id uuid, recipient_name text, recipient_email text, event_metadata jsonb, created_at timestamp with time zone)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  SELECT
    ev.id,
    ev.event_record_number,
    pv.picklist_value AS event_type,
    e.id              AS envelope_id,
    e.env_record_number,
    e.env_name,
    ev.recipient_id,
    r.recipient_name,
    r.recipient_email,
    ev.event_metadata,
    ev.created_at
  FROM public.envelope_events ev
  JOIN public.envelopes      e  ON e.id = ev.envelope_id
  LEFT JOIN public.envelope_recipients r ON r.id = ev.recipient_id
  LEFT JOIN public.picklist_values pv ON pv.id = ev.event_type
  WHERE e.env_parent_object    = p_parent_object
    AND e.env_parent_record_id = p_parent_record_id
    AND COALESCE(e.is_deleted, false) = false
  ORDER BY ev.created_at DESC;
$function$
;

CREATE OR REPLACE FUNCTION public.list_signer_contacts_for_opportunity(p_opportunity_id uuid, p_include_contact_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(id uuid, contact_name text)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT DISTINCT c.id, c.contact_name
    FROM contacts c
   WHERE NOT c.contact_is_deleted
     AND (
       EXISTS (
         SELECT 1
           FROM opportunity_contact_roles ocr
          WHERE ocr.opportunity_id = p_opportunity_id
            AND ocr.contact_id = c.id
            AND NOT COALESCE(ocr.ocr_is_deleted, false)
       )
       OR (p_include_contact_id IS NOT NULL AND c.id = p_include_contact_id)
     )
   ORDER BY c.contact_name;
$function$
;

CREATE OR REPLACE FUNCTION public.list_status_change_events_for_record(p_object text, p_record_id uuid)
 RETURNS TABLE(id uuid, sce_record_number text, sce_created_at timestamp with time zone, sce_note text, sce_status_field text, transition_id uuid, transition_record_number text, transition_label text, from_status_label text, to_status_label text, actor_user_id uuid, actor_name text)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT
    sce.id,
    sce.sce_record_number,
    sce.sce_created_at,
    sce.sce_note,
    st.st_status_field          AS sce_status_field,
    st.id                       AS transition_id,
    st.st_record_number         AS transition_record_number,
    st.st_transition_label      AS transition_label,
    pv_from.picklist_label      AS from_status_label,
    pv_to.picklist_label        AS to_status_label,
    sce.sce_created_by          AS actor_user_id,
    NULLIF(
      trim(COALESCE(u.user_first_name, '') || ' ' || COALESCE(u.user_last_name, '')),
      ''
    )                           AS actor_name
  FROM public.status_change_events sce
  LEFT JOIN public.status_transitions st
    ON st.id = sce.sce_transition_id
  LEFT JOIN public.picklist_values pv_from
    ON pv_from.id = sce.sce_from_status_id
  LEFT JOIN public.picklist_values pv_to
    ON pv_to.id = sce.sce_to_status_id
  LEFT JOIN public.users u
    ON u.id = sce.sce_created_by
  WHERE sce.sce_object    = p_object
    AND sce.sce_record_id = p_record_id
    AND sce.sce_is_deleted = false
  ORDER BY sce.sce_created_at DESC, sce.sce_record_number DESC;
$function$
;

CREATE OR REPLACE FUNCTION public.log_audit_and_field_history()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_table     text := TG_TABLE_NAME;
  v_record_id uuid;
  v_action    text;
  v_user_id   uuid;
  v_old       jsonb;
  v_new       jsonb;
  v_tracked   record;
  v_old_val   text;
  v_new_val   text;
  v_flag_col  text;
  v_snapshot  jsonb;
BEGIN
  v_user_id := public.current_app_user_id();

  IF TG_OP = 'DELETE' THEN
    v_action    := 'HARD_DELETE';
    v_record_id := OLD.id;
    v_old       := to_jsonb(OLD);
    v_snapshot  := v_old;
  ELSIF TG_OP = 'INSERT' THEN
    v_action    := 'INSERT';
    v_record_id := NEW.id;
    v_new       := to_jsonb(NEW);
    v_snapshot  := v_new;
  ELSIF TG_OP = 'UPDATE' THEN
    v_record_id := NEW.id;
    v_old       := to_jsonb(OLD);
    v_new       := to_jsonb(NEW);

    v_action := 'UPDATE';

    -- Soft-delete / restore detection: any column ending in 'is_deleted'
    SELECT k INTO v_flag_col
    FROM jsonb_object_keys(v_new) AS k
    WHERE k LIKE '%is\_deleted' ESCAPE '\'
    LIMIT 1;

    IF v_flag_col IS NOT NULL THEN
      IF (v_new ->> v_flag_col) = 'true' AND COALESCE((v_old ->> v_flag_col), 'false') = 'false' THEN
        v_action := 'SOFT_DELETE';
      ELSIF (v_new ->> v_flag_col) = 'false' AND (v_old ->> v_flag_col) = 'true' THEN
        v_action := 'RESTORE';
      END IF;
    END IF;

    -- Field-level history for tracked columns
    FOR v_tracked IN
      SELECT fhtf_column_name
      FROM public.field_history_tracked_fields
      WHERE fhtf_table_name = v_table AND fhtf_is_active = true
    LOOP
      v_old_val := v_old ->> v_tracked.fhtf_column_name;
      v_new_val := v_new ->> v_tracked.fhtf_column_name;

      IF v_old_val IS DISTINCT FROM v_new_val THEN
        INSERT INTO public.field_history (
          fh_object, fh_record_id, fh_field, fh_old_value, fh_new_value, fh_changed_by, fh_changed_at
        ) VALUES (
          v_table, v_record_id, v_tracked.fhtf_column_name, v_old_val, v_new_val, v_user_id, now()
        );
      END IF;
    END LOOP;

    v_snapshot := CASE
      WHEN v_action IN ('SOFT_DELETE', 'RESTORE') THEN v_new
      ELSE NULL
    END;
  ELSE
    RETURN NULL;
  END IF;

  INSERT INTO public.audit_log (
    al_action, al_object, al_record_id, al_record_snapshot, al_performed_by, al_performed_at
  ) VALUES (
    v_action, v_table, v_record_id, v_snapshot, v_user_id, now()
  );

  IF TG_OP = 'DELETE' THEN RETURN OLD; ELSE RETURN NEW; END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.lookup_service_appointment_by_token(p_token text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_sat                 service_appointment_tokens%rowtype;
  v_sa                  service_appointments%rowtype;
  v_wo_property_id      uuid;
  v_wo_opportunity_id   uuid;
  v_wo_work_type_id     uuid;
  v_wt_name             text;
  v_wt_slug             text;
  v_prop_street         text;
  v_prop_city           text;
  v_prop_state          text;
  v_prop_zip            text;
  v_opp_account_id      uuid;
  v_acc_name            text;
  v_acc_phone           text;
  v_acc_email           text;
  v_terr_name           text;
  v_aud_first           text;
  v_aud_last            text;
  v_aud_id              uuid;
  v_status_val          text;
BEGIN
  IF p_token IS NULL OR length(p_token) != 32 THEN
    RETURN jsonb_build_object('status', 'invalid_token');
  END IF;

  SELECT * INTO v_sat FROM service_appointment_tokens WHERE sat_token = p_token;
  IF v_sat.id IS NULL THEN
    RETURN jsonb_build_object('status', 'invalid_token');
  END IF;
  IF v_sat.sat_expires_at < now() THEN
    RETURN jsonb_build_object('status', 'expired_token');
  END IF;

  SELECT * INTO v_sa FROM service_appointments
   WHERE id = v_sat.service_appointment_id AND sa_is_deleted = false;
  IF v_sa.id IS NULL THEN
    RETURN jsonb_build_object('status', 'appointment_not_found');
  END IF;

  SELECT property_id, opportunity_id, work_type_id
    INTO v_wo_property_id, v_wo_opportunity_id, v_wo_work_type_id
    FROM work_orders WHERE id = v_sa.work_order_id;

  SELECT work_type_name, work_type_public_slug
    INTO v_wt_name, v_wt_slug
    FROM work_types WHERE id = v_wo_work_type_id;

  SELECT property_street, property_city, property_state, property_zip
    INTO v_prop_street, v_prop_city, v_prop_state, v_prop_zip
    FROM properties WHERE id = v_wo_property_id;

  SELECT opportunity_account_id INTO v_opp_account_id
    FROM opportunities WHERE id = v_wo_opportunity_id;

  SELECT account_name, account_phone, account_email
    INTO v_acc_name, v_acc_phone, v_acc_email
    FROM accounts WHERE id = v_opp_account_id;

  SELECT service_territory_name INTO v_terr_name
    FROM service_territories WHERE id = v_sa.service_territory_id;

  SELECT c.id, c.contact_first_name, c.contact_last_name
    INTO v_aud_id, v_aud_first, v_aud_last
    FROM service_appointment_assignments saa
    JOIN contacts c ON c.id = saa.contact_id
   WHERE saa.service_appointment_id = v_sa.id
     AND saa.saa_is_deleted = false
   LIMIT 1;

  SELECT picklist_value INTO v_status_val
    FROM picklist_values WHERE id = v_sa.sa_status;

  RETURN jsonb_build_object(
    'status', 'ok',
    'service_appointment_id', v_sa.id,
    'sa_record_number',       v_sa.sa_record_number,
    'sa_status',              v_status_val,
    'sa_scheduled_start_iso', v_sa.sa_scheduled_start_time,
    'sa_scheduled_end_iso',   v_sa.sa_scheduled_end_time,
    'duration_minutes',       v_sa.sa_duration_minutes,
    'work_type_name',         v_wt_name,
    'work_type_slug',         v_wt_slug,
    'address', jsonb_build_object(
      'street', v_prop_street, 'city', v_prop_city,
      'state',  v_prop_state,  'zip',  v_prop_zip
    ),
    'customer', jsonb_build_object(
      'name',  v_acc_name, 'phone', v_acc_phone, 'email', v_acc_email
    ),
    'territory_name', v_terr_name,
    'auditor_id',     v_aud_id,
    'auditor_name',   trim(coalesce(v_aud_first,'') || ' ' || coalesce(v_aud_last,'')),
    'token_expires_at', v_sat.sat_expires_at,
    'token_consumed',   v_sat.sat_consumed_at IS NOT NULL
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.mark_conversation_read(p_conversation_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
begin
  update public.conversations
  set conv_inbound_unread_count = 0, conv_updated_at = now()
  where id = p_conversation_id and conv_is_deleted = false;
end $function$
;

CREATE OR REPLACE FUNCTION public.mark_seed_data(p_table_name text, p_record_id uuid, p_batch_name text DEFAULT 'initial-training-set'::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_id     uuid;
  v_actor  uuid;
BEGIN
  v_actor := current_app_user_id();
  INSERT INTO seed_data_records (sdr_table_name, sdr_record_id, sdr_batch_name, sdr_seeded_by)
  VALUES (p_table_name, p_record_id, p_batch_name, v_actor)
  ON CONFLICT (sdr_table_name, sdr_record_id) DO UPDATE SET
    sdr_batch_name = EXCLUDED.sdr_batch_name,
    sdr_seeded_at  = now(),
    sdr_seeded_by  = EXCLUDED.sdr_seeded_by
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.mark_work_order_unable_to_complete(p_wo_id uuid, p_reason text, p_note text DEFAULT NULL::text)
 RETURNS TABLE(wo_id uuid, status text, outcome text, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_uid   uuid := public.current_app_user_id();
  v_wo    public.work_orders;
  v_cur   text;
  v_target uuid;
  v_res   jsonb;
BEGIN
  IF v_uid IS NULL THEN
    RETURN QUERY SELECT p_wo_id, NULL::text, 'error', 'Not authenticated.'; RETURN;
  END IF;
  IF coalesce(btrim(p_reason),'') = '' THEN
    RETURN QUERY SELECT p_wo_id, NULL::text, 'error', 'A reason is required.'; RETURN;
  END IF;

  SELECT * INTO v_wo FROM public.work_orders WHERE id=p_wo_id AND work_order_is_deleted IS NOT TRUE;
  IF v_wo.id IS NULL THEN
    RETURN QUERY SELECT p_wo_id, NULL::text, 'error', 'Work order not found.'; RETURN;
  END IF;

  SELECT picklist_value INTO v_cur FROM public.picklist_values WHERE id=v_wo.work_order_status;
  IF v_cur = 'Unable to Complete' THEN
    RETURN QUERY SELECT p_wo_id, v_cur, 'noop', 'Work order is already marked Unable to Complete.'; RETURN;
  END IF;
  IF v_cur <> 'In Progress' THEN
    RETURN QUERY SELECT p_wo_id, v_cur, 'blocked',
      format('Work order is "%s". Only an In Progress work order can be marked Unable to Complete.', COALESCE(v_cur,'(no status)')); RETURN;
  END IF;

  -- Record the reason/note on the work order.
  UPDATE public.work_orders
  SET work_order_incomplete_reason =
        btrim(p_reason) || CASE WHEN coalesce(btrim(p_note),'')<>'' THEN E'\n\nNotes: ' || btrim(p_note) ELSE '' END,
      work_order_updated_by = v_uid,
      work_order_updated_at = now()
  WHERE id = p_wo_id;

  SELECT id INTO v_target FROM public.picklist_values
   WHERE picklist_object='work_orders' AND picklist_field='work_order_status'
     AND picklist_value='Unable to Complete' AND picklist_is_active LIMIT 1;

  v_res := public.change_record_status('work_orders', p_wo_id, 'work_order_status', v_target,
            'Marked Unable to Complete from the field');

  RETURN QUERY SELECT p_wo_id, 'Unable to Complete', 'success',
    format('Work order %s marked Unable to Complete', v_wo.work_order_record_number);
END; $function$
;

CREATE OR REPLACE FUNCTION public.module_access_for_role(p_role_id uuid)
 RETURNS text[]
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_result text[]; v_role_name text;
BEGIN
  IF NOT can_use_view_as() THEN
    RAISE EXCEPTION 'Not permitted to use View As';
  END IF;
  SELECT role_name INTO v_role_name FROM public.roles WHERE id = p_role_id;
  IF v_role_name IS NULL THEN RETURN ARRAY[]::text[]; END IF;
  IF v_role_name = 'Admin' THEN RETURN ARRAY['*']; END IF;
  SELECT array_agg(rma_module_id ORDER BY rma_module_id) INTO v_result
  FROM public.role_module_access
  WHERE rma_role_id = p_role_id AND rma_can_access = true AND is_deleted = false;
  RETURN COALESCE(v_result, ARRAY[]::text[]);
END; $function$
;

CREATE OR REPLACE FUNCTION public.my_accessible_modules()
 RETURNS text[]
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user_id uuid;
  v_role_id uuid;
  v_result  text[];
BEGIN
  IF app_is_admin() THEN
    RETURN ARRAY['*'];
  END IF;

  v_user_id := current_app_user_id();
  IF v_user_id IS NULL THEN
    RETURN ARRAY[]::text[];
  END IF;

  SELECT role_id INTO v_role_id FROM public.users WHERE id = v_user_id;
  IF v_role_id IS NULL THEN
    RETURN ARRAY[]::text[];
  END IF;

  SELECT array_agg(rma_module_id ORDER BY rma_module_id)
    INTO v_result
  FROM public.role_module_access
  WHERE rma_role_id = v_role_id
    AND rma_can_access = true
    AND is_deleted = false;

  RETURN COALESCE(v_result, ARRAY[]::text[]);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.my_outlook_connection_status()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_user_id uuid := public.current_app_user_id();
  v_row record;
BEGIN
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('connected', false, 'reason', 'not authenticated');
  END IF;

  SELECT account_email, account_display_name, microsoft_tenant_id,
         connected_at, last_used_at, is_active,
         (token_expires_at > now()) AS token_currently_valid,
         token_expires_at
    INTO v_row
  FROM public.user_outlook_connections
  WHERE user_id = v_user_id AND is_active = true;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('connected', false);
  END IF;

  RETURN jsonb_build_object(
    'connected', true,
    'account_email', v_row.account_email,
    'account_display_name', v_row.account_display_name,
    'microsoft_tenant_id', v_row.microsoft_tenant_id,
    'connected_at', v_row.connected_at,
    'last_used_at', v_row.last_used_at,
    'token_currently_valid', v_row.token_currently_valid,
    'token_expires_at', v_row.token_expires_at
  );
END $function$
;

CREATE OR REPLACE FUNCTION public.my_service_appointments(p_date date DEFAULT ((now() AT TIME ZONE 'America/Chicago'::text))::date)
 RETURNS TABLE(sa_id uuid, sa_record_number text, sa_status text, sa_scheduled_start_time timestamp with time zone, sa_scheduled_end_time timestamp with time zone, sa_duration_minutes numeric, work_order_id uuid, work_order_record_number text, work_order_name text, work_order_status text, work_type_name text, property_name text, property_address text, building text, unit text, customer_name text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT
    sa.id, sa.sa_record_number, sast.picklist_value,
    sa.sa_scheduled_start_time, sa.sa_scheduled_end_time, sa.sa_duration_minutes,
    wo.id, wo.work_order_record_number, wo.work_order_name, wost.picklist_value,
    wt.work_type_name,
    COALESCE(NULLIF(wo.work_order_property_name,''), p.property_name),
    NULLIF(trim(BOTH ', ' FROM concat_ws(', ',
      COALESCE(NULLIF(wo.work_order_building_address,''), b.building_address, p.property_street),
      COALESCE(b.building_city, p.property_city),
      COALESCE(b.building_state, p.property_state),
      COALESCE(b.building_zip, p.property_zip)
    )), ''),
    COALESCE(NULLIF(wo.work_order_building,''), b.building_number_or_name, b.building_name),
    COALESCE(NULLIF(wo.work_order_unit,''), u.unit_number, u.unit_name),
    wo.work_order_customer_name
  FROM public.service_appointment_assignments saa
  JOIN public.service_appointments sa
    ON sa.id = saa.service_appointment_id AND sa.sa_is_deleted IS NOT TRUE
  LEFT JOIN public.work_orders wo
    ON wo.id = sa.work_order_id AND wo.work_order_is_deleted IS NOT TRUE
  LEFT JOIN public.work_types wt ON wt.id = sa.work_type_id
  LEFT JOIN public.picklist_values sast ON sast.id = sa.sa_status
  LEFT JOIN public.picklist_values wost ON wost.id = wo.work_order_status
  LEFT JOIN public.properties p ON p.id = wo.property_id
  LEFT JOIN public.buildings  b ON b.id = wo.building_id
  LEFT JOIN public.units      u ON u.id = wo.unit_id
  WHERE saa.saa_is_deleted IS NOT TRUE
    AND saa.saa_user_id = public.current_app_user_id()
    AND (sa.sa_scheduled_start_time AT TIME ZONE 'America/Chicago')::date = p_date
  ORDER BY sa.sa_scheduled_start_time NULLS LAST;
$function$
;

CREATE OR REPLACE FUNCTION public.normalize_addr_key(p_addr text, p_zip text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE s text;
BEGIN
  IF p_addr IS NULL OR btrim(p_addr)='' THEN RETURN NULL; END IF;
  s := upper(btrim(p_addr));
  s := regexp_replace(s, '[.,#]', ' ', 'g');
  s := ' ' || regexp_replace(s, '\s+', ' ', 'g') || ' ';
  s := replace(s, ' STREET ', ' ST ');
  s := replace(s, ' AVENUE ', ' AVE ');
  s := replace(s, ' BOULEVARD ', ' BLVD ');
  s := replace(s, ' DRIVE ', ' DR ');
  s := replace(s, ' ROAD ', ' RD ');
  s := replace(s, ' LANE ', ' LN ');
  s := replace(s, ' COURT ', ' CT ');
  s := replace(s, ' PLACE ', ' PL ');
  s := replace(s, ' CIRCLE ', ' CIR ');
  s := replace(s, ' TERRACE ', ' TER ');
  s := replace(s, ' PARKWAY ', ' PKWY ');
  s := replace(s, ' HIGHWAY ', ' HWY ');
  s := replace(s, ' NORTH ', ' N ');
  s := replace(s, ' SOUTH ', ' S ');
  s := replace(s, ' EAST ', ' E ');
  s := replace(s, ' WEST ', ' W ');
  s := btrim(regexp_replace(s, '\s+', ' ', 'g'));
  RETURN s || '|' || COALESCE(left(btrim(p_zip),5),'');
END $function$
;

CREATE OR REPLACE FUNCTION public.normalize_owner_key(p_owner text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE s text;
BEGIN
  IF p_owner IS NULL OR btrim(p_owner)='' THEN RETURN NULL; END IF;
  s := upper(btrim(p_owner));
  s := regexp_replace(s, '[.,#''&-]', ' ', 'g');
  s := ' ' || regexp_replace(s, '\s+', ' ', 'g') || ' ';
  s := replace(s, ' LIMITED PARTNERSHIP ', ' LP ');
  s := replace(s, ' LLC ', ' ');
  s := replace(s, ' L L C ', ' ');
  s := replace(s, ' INC ', ' ');
  s := replace(s, ' CORPORATION ', ' ');
  s := replace(s, ' CORP ', ' ');
  s := replace(s, ' COMPANY ', ' ');
  s := replace(s, ' ASSOCIATES ', ' ');
  s := replace(s, ' HOUSING AUTHORITY ', ' HA ');
  s := btrim(regexp_replace(s, '\s+', ' ', 'g'));
  RETURN NULLIF(s,'');
END $function$
;

CREATE OR REPLACE FUNCTION public.normalize_phone_e164(p_phone text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  digits text;
begin
  if p_phone is null or p_phone = '' then return null; end if;
  if p_phone like '+%' then
    return '+' || regexp_replace(p_phone, '[^0-9]', '', 'g');
  end if;
  digits := regexp_replace(p_phone, '[^0-9]', '', 'g');
  if length(digits) = 10 then return '+1' || digits; end if;
  if length(digits) = 11 and left(digits, 1) = '1' then return '+' || digits; end if;
  return '+' || digits;
end $function$
;

CREATE OR REPLACE FUNCTION public.normalize_property_address(p_street text, p_city text, p_state text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT lower(
    regexp_replace(
      regexp_replace(
        regexp_replace(
          regexp_replace(
            regexp_replace(
              regexp_replace(
                regexp_replace(
                  regexp_replace(
                    regexp_replace(
                      regexp_replace(
                        regexp_replace(
                          coalesce(p_street, '') || '|' || coalesce(p_city, '') || '|' || coalesce(p_state, ''),
                          '[.,#]', '', 'g'),
                        '\s+', ' ', 'g'),
                      '\m(street)\M', 'street', 'gi'),       -- already canonical
                    '\m(st)\M', 'street', 'gi'),
                  '\m(ave|av)\M', 'avenue', 'gi'),
                '\m(rd)\M', 'road', 'gi'),
              '\m(blvd|bl)\M', 'boulevard', 'gi'),
            '\m(dr)\M', 'drive', 'gi'),
          '\m(ln)\M', 'lane', 'gi'),
        '\m(ct)\M', 'court', 'gi'),
      '\m(n|no)\M', 'north', 'gi')
  );
$function$
;

CREATE OR REPLACE FUNCTION public.notifications_list_recent(p_limit integer DEFAULT 30)
 RETURNS TABLE(id uuid, notification_type text, title text, body text, related_object text, related_id uuid, is_read boolean, read_at timestamp with time zone, is_automated boolean, triggered_by uuid, created_at timestamp with time zone)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_uid uuid; v_lim int;
BEGIN
  v_uid := public._current_app_user_id();
  IF v_uid IS NULL THEN RETURN; END IF;
  v_lim := LEAST(GREATEST(coalesce(p_limit, 30), 1), 100);
  RETURN QUERY
    SELECT n.id, n.notification_type, n.title, n.body,
           n.related_object, n.related_id,
           n.is_read, n.read_at,
           n.is_automated, n.triggered_by,
           n.created_at
      FROM notifications n
     WHERE n.recipient_id = v_uid
     ORDER BY n.created_at DESC
     LIMIT v_lim;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.notifications_mark_all_read()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_uid uuid; v_n int;
BEGIN
  v_uid := public._current_app_user_id();
  IF v_uid IS NULL THEN RETURN 0; END IF;
  UPDATE notifications
     SET is_read = true,
         read_at = COALESCE(read_at, now())
   WHERE recipient_id = v_uid AND NOT is_read;
  GET DIAGNOSTICS v_n = ROW_COUNT;
  RETURN v_n;
END;
$function$
;

