CREATE OR REPLACE FUNCTION public.notifications_unread_count()
 RETURNS integer
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_uid uuid; v_cnt int;
BEGIN
  v_uid := public._current_app_user_id();
