CREATE OR REPLACE FUNCTION public.parse_hud_date(p text)
 RETURNS date
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF p IS NULL OR btrim(p)='' THEN RETURN NULL; END IF;
  BEGIN RETURN to_date(p, 'DD-MON-YY'); EXCEPTION WHEN OTHERS THEN
    BEGIN RETURN to_date(p, 'YYYY-MM-DD'); EXCEPTION WHEN OTHERS THEN RETURN NULL; END;
  END;
END $function$
;

CREATE OR REPLACE FUNCTION public.picklist_values_for_record_type(p_object text, p_field text, p_record_type uuid)
 RETURNS TABLE(id uuid, picklist_value text, picklist_label text, picklist_sort_order integer, picklist_description text, scope_mode text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT
    pv.id,
    pv.picklist_value,
    pv.picklist_label,
    -- Effective order: per-record-type position when set, else global.
    COALESCE(a.pvrta_sort_order, pv.picklist_sort_order) AS picklist_sort_order,
    pv.picklist_description,
    CASE WHEN EXISTS (
      SELECT 1 FROM public.picklist_value_record_type_assignments x
       WHERE x.pvrta_picklist_value_id = pv.id
         AND x.pvrta_is_deleted = false
    ) THEN 'scoped' ELSE 'universal' END AS scope_mode
  FROM public.picklist_values pv
  LEFT JOIN public.picklist_value_record_type_assignments a
    ON a.pvrta_picklist_value_id = pv.id
   AND a.pvrta_record_type_id    = p_record_type
   AND a.pvrta_is_deleted        = false
  WHERE pv.picklist_object = p_object
    AND pv.picklist_field  = p_field
    AND pv.picklist_is_active = true
    AND (
      NOT EXISTS (
        SELECT 1 FROM public.picklist_value_record_type_assignments x
         WHERE x.pvrta_picklist_value_id = pv.id
           AND x.pvrta_is_deleted = false
      )
      OR (
        p_record_type IS NOT NULL AND EXISTS (
          SELECT 1 FROM public.picklist_value_record_type_assignments x
           WHERE x.pvrta_picklist_value_id = pv.id
             AND x.pvrta_record_type_id    = p_record_type
             AND x.pvrta_is_deleted = false
        )
      )
    )
  ORDER BY COALESCE(a.pvrta_sort_order, pv.picklist_sort_order) NULLS LAST, pv.picklist_value;
$function$
;

CREATE OR REPLACE FUNCTION public.prevent_active_document_template_edits()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_old_status text := public._dt_status_value(OLD.status);
  v_new_status text := public._dt_status_value(NEW.status);
BEGIN
  IF v_old_status IS DISTINCT FROM 'Active' THEN
    RETURN NEW;
  END IF;
  IF v_old_status = 'Active' AND v_new_status IS DISTINCT FROM 'Active' THEN
    RETURN NEW;
  END IF;
  IF NEW.is_deleted IS DISTINCT FROM OLD.is_deleted THEN
    RETURN NEW;
  END IF;

  IF NEW.name                   IS DISTINCT FROM OLD.name                   OR
     NEW.description            IS DISTINCT FROM OLD.description            OR
     NEW.template_type          IS DISTINCT FROM OLD.template_type          OR
     NEW.body_html              IS DISTINCT FROM OLD.body_html              OR
     NEW.program_id             IS DISTINCT FROM OLD.program_id             OR
     NEW.state                  IS DISTINCT FROM OLD.state                  OR
     NEW.related_object         IS DISTINCT FROM OLD.related_object         OR
     NEW.record_type            IS DISTINCT FROM OLD.record_type            OR
     NEW.requires_signature     IS DISTINCT FROM OLD.requires_signature     OR
     NEW.signer_role            IS DISTINCT FROM OLD.signer_role            OR
     NEW.trigger_status         IS DISTINCT FROM OLD.trigger_status         OR
     NEW.is_manual              IS DISTINCT FROM OLD.is_manual              OR
     NEW.is_automated           IS DISTINCT FROM OLD.is_automated           OR
     NEW.owner_id               IS DISTINCT FROM OLD.owner_id               OR
     NEW.dt_authoring_mode      IS DISTINCT FROM OLD.dt_authoring_mode      OR
     NEW.dt_template_asset_path IS DISTINCT FROM OLD.dt_template_asset_path
  THEN
    RAISE EXCEPTION 'Document template % is Active and locked. Unpublish to Draft, or use Clone Template, before editing.',
      OLD.dt_record_number USING ERRCODE = '42501';
  END IF;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.prevent_active_email_template_edits()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_old_status text := public._et_status_value(OLD.status);
  v_new_status text := public._et_status_value(NEW.status);
BEGIN
  IF v_old_status IS DISTINCT FROM 'Active' THEN
    RETURN NEW;
  END IF;
  IF v_old_status = 'Active' AND v_new_status IS DISTINCT FROM 'Active' THEN
    RETURN NEW;
  END IF;

  -- soft-delete / restore is allowed
  IF NEW.is_deleted IS DISTINCT FROM OLD.is_deleted THEN
    RETURN NEW;
  END IF;

  IF NEW.name           IS DISTINCT FROM OLD.name           OR
     NEW.description    IS DISTINCT FROM OLD.description    OR
     NEW.subject        IS DISTINCT FROM OLD.subject        OR
     NEW.body_html      IS DISTINCT FROM OLD.body_html      OR
     NEW.program_id     IS DISTINCT FROM OLD.program_id     OR
     NEW.state          IS DISTINCT FROM OLD.state          OR
     NEW.related_object IS DISTINCT FROM OLD.related_object OR
     NEW.record_type    IS DISTINCT FROM OLD.record_type    OR
     NEW.trigger_status IS DISTINCT FROM OLD.trigger_status OR
     NEW.is_manual      IS DISTINCT FROM OLD.is_manual      OR
     NEW.is_automated   IS DISTINCT FROM OLD.is_automated   OR
     NEW.owner_id       IS DISTINCT FROM OLD.owner_id
  THEN
    RAISE EXCEPTION 'Email template % is Active and locked. Unpublish to Draft, or use Clone Template, before editing.',
      OLD.et_record_number USING ERRCODE = '42501';
  END IF;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.prevent_active_prt_edits()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_old_status text;
  v_new_status text;
BEGIN
  v_old_status := _prt_status_value(OLD.prt_status);
  v_new_status := _prt_status_value(NEW.prt_status);

  -- If we're transitioning OUT of Active (or staying non-Active), allow.
  IF v_old_status IS DISTINCT FROM 'Active' THEN
    RETURN NEW;
  END IF;
  IF v_old_status = 'Active' AND v_new_status IS DISTINCT FROM 'Active' THEN
    RETURN NEW;  -- unpublish or archive
  END IF;

  -- OLD = Active AND NEW = Active. Allow only soft-delete flips and
  -- the metadata bookkeeping that always accompanies any save.
  IF NEW.prt_is_deleted IS DISTINCT FROM OLD.prt_is_deleted THEN
    RETURN NEW;  -- soft delete / restore
  END IF;

  -- Compare every business field. If anything substantive changed, reject.
  IF NEW.prt_name              IS DISTINCT FROM OLD.prt_name              OR
     NEW.prt_description       IS DISTINCT FROM OLD.prt_description       OR
     NEW.prt_record_type       IS DISTINCT FROM OLD.prt_record_type       OR
     NEW.prt_orientation       IS DISTINCT FROM OLD.prt_orientation       OR
     NEW.prt_paper_size        IS DISTINCT FROM OLD.prt_paper_size        OR
     NEW.prt_version           IS DISTINCT FROM OLD.prt_version           OR
     NEW.prt_is_default_for_unmapped IS DISTINCT FROM OLD.prt_is_default_for_unmapped OR
     NEW.prt_owner             IS DISTINCT FROM OLD.prt_owner
  THEN
    RAISE EXCEPTION 'Template % is Active and locked. Unpublish to Draft, or use Clone Template, before editing.',
      OLD.prt_record_number
      USING ERRCODE = '42501';
  END IF;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.prevent_active_prts_edits()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_parent_id uuid;
  v_parent_status text;
BEGIN
  v_parent_id := COALESCE(NEW.prt_id, OLD.prt_id);
  SELECT _prt_status_value(prt_status) INTO v_parent_status
  FROM project_report_templates
  WHERE id = v_parent_id;

  IF v_parent_status IS DISTINCT FROM 'Active' THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  -- Parent is Active — allow only soft-delete / restore (prts_is_deleted flip).
  IF TG_OP = 'UPDATE'
     AND NEW.prts_is_deleted IS DISTINCT FROM OLD.prts_is_deleted
     AND NEW.prts_section_order = OLD.prts_section_order
     AND NEW.prts_section_type = OLD.prts_section_type
     AND NEW.prts_section_title IS NOT DISTINCT FROM OLD.prts_section_title
     AND NEW.prts_body_template IS NOT DISTINCT FROM OLD.prts_body_template
     AND NEW.prts_config = OLD.prts_config
     AND NEW.prts_filter_config = OLD.prts_filter_config
  THEN
    RETURN NEW;
  END IF;

  RAISE EXCEPTION 'Parent template is Active and locked. Sections cannot be added, edited, or reordered without unpublishing first.'
    USING ERRCODE = '42501';
END;
$function$
;

