CREATE OR REPLACE FUNCTION public.preview_property_hierarchy_import(p_rows jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller_user_id  uuid;
  v_row             jsonb;
  v_idx             integer := 0;
  v_addr_norm       text;
  v_existing_prop   record;
  v_existing_bldg   record;
  v_result          jsonb := '[]'::jsonb;
  v_row_result      jsonb;
BEGIN
  SELECT u.id INTO v_caller_user_id
    FROM public.users u WHERE u.auth_user_id = auth.uid() LIMIT 1;
  IF v_caller_user_id IS NULL THEN
    RAISE EXCEPTION 'preview_property_hierarchy_import: caller has no public.users record';
  END IF;

  FOR v_row IN SELECT * FROM jsonb_array_elements(p_rows) LOOP
    v_addr_norm := normalize_property_address(
      v_row->>'property_street', v_row->>'property_city', v_row->>'property_state'
    );

    v_existing_prop := NULL;
    v_existing_bldg := NULL;

    SELECT p.id, p.property_name, p.property_record_number,
           p.property_street, p.property_city, p.property_state,
           p.property_account_id, a.account_name
      INTO v_existing_prop
      FROM public.properties p
      LEFT JOIN public.accounts a ON a.id = p.property_account_id
     WHERE normalize_property_address(p.property_street, p.property_city, p.property_state) = v_addr_norm
       AND NOT p.property_is_deleted
     LIMIT 1;

    IF v_existing_prop.id IS NOT NULL
       AND coalesce(btrim(v_row->>'building_name'),'') <> '' THEN
      SELECT b.id, b.building_name, b.building_record_number
        INTO v_existing_bldg
        FROM public.buildings b
       WHERE b.property_id = v_existing_prop.id
         AND lower(btrim(b.building_name)) = lower(btrim(v_row->>'building_name'))
         AND NOT b.building_is_deleted
       LIMIT 1;
    END IF;

    v_row_result := jsonb_build_object(
      'row_index', v_idx,
      'existing_property', CASE WHEN v_existing_prop.id IS NULL THEN NULL ELSE
        jsonb_build_object(
          'id',            v_existing_prop.id,
          'name',          v_existing_prop.property_name,
          'record_number', v_existing_prop.property_record_number,
          'street',        v_existing_prop.property_street,
          'city',          v_existing_prop.property_city,
          'state',         v_existing_prop.property_state,
          'account_name',  v_existing_prop.account_name
        )
      END,
      'existing_building', CASE WHEN v_existing_bldg.id IS NULL THEN NULL ELSE
        jsonb_build_object(
          'id',            v_existing_bldg.id,
          'name',          v_existing_bldg.building_name,
          'record_number', v_existing_bldg.building_record_number
        )
      END,
      'suggested_action',
        CASE
          WHEN v_existing_bldg.id IS NOT NULL THEN 'error_building_exists'
          WHEN v_existing_prop.id IS NOT NULL THEN 'skip'
          ELSE 'create'
        END
    );

    v_result := v_result || v_row_result;
    v_idx := v_idx + 1;
  END LOOP;

  RETURN v_result;
END
$function$
;

CREATE OR REPLACE FUNCTION public.project_scheduled_work_orders(p_project_id uuid)
 RETURNS TABLE(work_order_id uuid, work_order_record_number text, work_order_name text, service_appointment_id uuid, sa_scheduled_start_time timestamp with time zone, sa_scheduled_end_time timestamp with time zone, team_lead_contact_id uuid, team_lead_full_name text)
 LANGUAGE sql
 SET search_path TO 'public', 'pg_temp'
AS $function$
  WITH sched_pid AS (
    SELECT id FROM picklist_values
     WHERE picklist_object='service_appointments'
       AND picklist_field='sa_status'
       AND picklist_value='Scheduled'
       AND picklist_is_active=true
     LIMIT 1
  ),
  sched_sa AS (
    SELECT sa.id, sa.work_order_id,
           sa.sa_scheduled_start_time, sa.sa_scheduled_end_time
      FROM service_appointments sa
     WHERE sa.project_id = p_project_id
       AND coalesce(sa.sa_is_deleted,false) = false
       AND sa.sa_status = (SELECT id FROM sched_pid)
  ),
  sa_lead AS (
    SELECT s.id AS sa_id,
           c.id AS lead_id,
           trim(coalesce(c.contact_first_name,'') || ' ' || coalesce(c.contact_last_name,'')) AS lead_name
      FROM sched_sa s
      JOIN service_appointment_assignments saa ON saa.service_appointment_id = s.id
       AND coalesce(saa.saa_is_deleted,false) = false
      JOIN contacts c ON c.id = saa.contact_id
       AND coalesce(c.contact_is_deleted,false) = false
       AND coalesce(c.contact_title,'') ILIKE '%team lead%'
  )
  SELECT wo.id, wo.work_order_record_number, wo.work_order_name,
         s.id, s.sa_scheduled_start_time, s.sa_scheduled_end_time,
         sl.lead_id, sl.lead_name
    FROM sched_sa s
    JOIN work_orders wo ON wo.id = s.work_order_id
     AND coalesce(wo.work_order_is_deleted,false) = false
    LEFT JOIN sa_lead sl ON sl.sa_id = s.id
   ORDER BY s.sa_scheduled_start_time ASC;
$function$
;

CREATE OR REPLACE FUNCTION public.provision_field_technician(p_user_id uuid, p_program_ids uuid[] DEFAULT '{}'::uuid[], p_permission_set_ids uuid[] DEFAULT '{}'::uuid[], p_service_territory_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_admin        uuid := current_app_user_id();
  v_prog         uuid;
  v_ps           uuid;
  v_stm_id       uuid;
  v_programs_added int := 0;
  v_psets_added    int := 0;
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Only Admin users can provision technicians';
  END IF;

  IF p_user_id IS NULL OR NOT EXISTS (
    SELECT 1 FROM users WHERE id = p_user_id AND user_is_deleted = false
  ) THEN
    RAISE EXCEPTION 'Target user does not exist or is deleted';
  END IF;

  -- Program scopes (skip dupes)
  IF p_program_ids IS NOT NULL THEN
    FOREACH v_prog IN ARRAY p_program_ids LOOP
      IF NOT EXISTS (
        SELECT 1 FROM user_program_scopes
        WHERE ups_user_id = p_user_id AND ups_program_id = v_prog AND is_deleted = false
      ) THEN
        INSERT INTO user_program_scopes (ups_user_id, ups_program_id, created_by, updated_by)
        VALUES (p_user_id, v_prog, v_admin, v_admin);
        v_programs_added := v_programs_added + 1;
      END IF;
    END LOOP;
  END IF;

  -- Permission sets (skip dupes)
  IF p_permission_set_ids IS NOT NULL THEN
    FOREACH v_ps IN ARRAY p_permission_set_ids LOOP
      IF NOT EXISTS (
        SELECT 1 FROM user_permission_sets
        WHERE ups_user_id = p_user_id AND ups_permission_set_id = v_ps
      ) THEN
        INSERT INTO user_permission_sets (ups_user_id, ups_permission_set_id, ups_created_by)
        VALUES (p_user_id, v_ps, v_admin);
        v_psets_added := v_psets_added + 1;
      END IF;
    END LOOP;
  END IF;

  -- Service resource (user-linked), one active per (territory,user)
  IF p_service_territory_id IS NOT NULL THEN
    SELECT id INTO v_stm_id FROM service_territory_members
    WHERE service_territory_id = p_service_territory_id
      AND stm_user_id = p_user_id AND stm_is_deleted = false
    LIMIT 1;
    IF v_stm_id IS NULL THEN
      INSERT INTO service_territory_members
        (stm_record_number, service_territory_id, contact_id, stm_user_id,
         stm_owner, stm_created_by, stm_effective_start_date)
      VALUES ('', p_service_territory_id, NULL, p_user_id,
         v_admin, v_admin, CURRENT_DATE)
      RETURNING id INTO v_stm_id;
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'ok', true,
    'user_id', p_user_id,
    'programs_added', v_programs_added,
    'permission_sets_added', v_psets_added,
    'service_resource_id', v_stm_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.publish_document_template(p_document_template_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller       uuid := public.current_app_user_id();
  v_current      text;
  v_published_at timestamptz;
  v_version      int;
  v_active_id    uuid;
  v_template_row public.document_templates%ROWTYPE;
  v_snapshot_id  uuid;
  v_authoring_mode_value text;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'publish_document_template: must be authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT public._dt_status_value(status), published_at, version
    INTO v_current, v_published_at, v_version
  FROM public.document_templates
  WHERE id = p_document_template_id AND NOT is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'publish_document_template: template not found';
  END IF;

  IF v_current = 'Active' THEN
    RAISE EXCEPTION 'publish_document_template: template is already Active';
  END IF;
  IF v_current = 'Archived' THEN
    RAISE EXCEPTION 'publish_document_template: cannot publish an Archived template — restore to Draft first';
  END IF;

  SELECT pv_mode.picklist_value
    INTO v_authoring_mode_value
  FROM public.document_templates dt
  LEFT JOIN public.picklist_values pv_mode ON pv_mode.id = dt.dt_authoring_mode
  WHERE dt.id = p_document_template_id;

  IF v_authoring_mode_value = 'docx' THEN
    PERFORM 1 FROM public.document_templates
    WHERE id = p_document_template_id
      AND dt_template_asset_path IS NOT NULL
      AND dt_template_asset_path <> '';
    IF NOT FOUND THEN
      RAISE EXCEPTION 'publish_document_template: docx-mode template has no asset uploaded — upload a .docx file before publishing';
    END IF;
  END IF;

  SELECT id INTO v_active_id FROM public.picklist_values
  WHERE picklist_object='document_templates' AND picklist_field='status'
    AND picklist_value='Active' AND picklist_is_active=true LIMIT 1;

  IF v_published_at IS NOT NULL THEN
    v_version := v_version + 1;
  END IF;

  UPDATE public.document_templates SET
    status       = v_active_id,
    version      = v_version,
    published_at = COALESCE(published_at, now()),
    updated_by   = v_caller,
    updated_at   = now()
  WHERE id = p_document_template_id
  RETURNING * INTO v_template_row;

  INSERT INTO public.document_template_snapshots (
    dtsn_record_number, document_template_id, dtsn_version,
    dtsn_template_json,
    dtsn_template_asset_path, dtsn_authoring_mode,
    dtsn_published_at, dtsn_published_by,
    dtsn_owner, dtsn_created_by, dtsn_updated_by
  ) VALUES (
    '', p_document_template_id, v_version,
    to_jsonb(v_template_row),
    v_template_row.dt_template_asset_path,
    v_template_row.dt_authoring_mode,
    now(), v_caller,
    v_caller, v_caller, v_caller
  )
  RETURNING id INTO v_snapshot_id;

  RETURN jsonb_build_object(
    'ok', true,
    'document_template_id', p_document_template_id,
    'new_status', 'Active',
    'new_version', v_version,
    'first_publish', v_published_at IS NULL,
    'snapshot_id', v_snapshot_id,
    'authoring_mode', v_authoring_mode_value
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.publish_email_template(p_email_template_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller        uuid := public.current_app_user_id();
  v_current       text;
  v_published_at  timestamptz;
  v_version       int;
  v_active_id     uuid;
  v_template_row  public.email_templates%ROWTYPE;
  v_snapshot_id   uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'publish_email_template: must be authenticated as a registered user' USING ERRCODE = '42501';
  END IF;

  SELECT public._et_status_value(status), published_at, version
    INTO v_current, v_published_at, v_version
  FROM public.email_templates
  WHERE id = p_email_template_id AND NOT is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'publish_email_template: template not found';
  END IF;

  IF v_current = 'Active' THEN
    RAISE EXCEPTION 'publish_email_template: template is already Active';
  END IF;
  IF v_current = 'Archived' THEN
    RAISE EXCEPTION 'publish_email_template: cannot publish an Archived template — restore to Draft first';
  END IF;

  SELECT id INTO v_active_id FROM public.picklist_values
  WHERE picklist_object='email_templates' AND picklist_field='status'
    AND picklist_value='Active' AND picklist_is_active=true LIMIT 1;
  IF v_active_id IS NULL THEN
    RAISE EXCEPTION 'publish_email_template: Active status not configured';
  END IF;

  IF v_published_at IS NOT NULL THEN
    v_version := v_version + 1;
  END IF;

  UPDATE public.email_templates SET
    status         = v_active_id,
    version        = v_version,
    published_at   = COALESCE(published_at, now()),
    updated_by     = v_caller,
    updated_at     = now()
  WHERE id = p_email_template_id
  RETURNING * INTO v_template_row;

  INSERT INTO public.email_template_snapshots (
    etsn_record_number, email_template_id, etsn_version,
    etsn_template_json,
    etsn_published_at, etsn_published_by,
    etsn_owner, etsn_created_by, etsn_updated_by
  ) VALUES (
    '', p_email_template_id, v_version,
    to_jsonb(v_template_row),
    now(), v_caller,
    v_caller, v_caller, v_caller
  )
  RETURNING id INTO v_snapshot_id;

  RETURN jsonb_build_object(
    'ok', true,
    'email_template_id', p_email_template_id,
    'new_status', 'Active',
    'new_version', v_version,
    'first_publish', v_published_at IS NULL,
    'snapshot_id', v_snapshot_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.publish_flow(p_flow_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user uuid; v_flow public.flows%ROWTYPE; v_ver integer; v_snapshot jsonb; v_version_id uuid;
BEGIN
  v_user := current_app_user_id();
  IF NOT app_user_can('flows','update') THEN RAISE EXCEPTION 'No update permission on flows'; END IF;
  SELECT * INTO v_flow FROM public.flows WHERE id=p_flow_id AND is_deleted=false;
  IF NOT FOUND THEN RAISE EXCEPTION 'Flow not found'; END IF;

  v_ver := v_flow.flow_current_version;
  SELECT jsonb_agg(to_jsonb(e) ORDER BY e.fe_order)
    INTO v_snapshot FROM public.flow_elements e
   WHERE e.fe_flow_id=p_flow_id AND e.is_deleted=false;

  UPDATE public.flow_versions SET fv_status='superseded', updated_by=v_user
   WHERE fv_flow_id=p_flow_id AND fv_status='published';

  INSERT INTO public.flow_versions
    (fv_record_number, fv_flow_id, fv_version_number, fv_status, fv_snapshot,
     fv_published_at, fv_published_by, owner_id, created_by)
  VALUES
    ('', p_flow_id, v_ver, 'published', COALESCE(v_snapshot,'[]'::jsonb),
     now(), v_user, v_flow.owner_id, v_user)
  RETURNING id INTO v_version_id;

  UPDATE public.flows
     SET flow_status='active', flow_active_version_id=v_version_id,
         flow_current_version=v_ver+1, updated_by=v_user
   WHERE id=p_flow_id;

  RETURN jsonb_build_object('ok',true,'version_id',v_version_id,'version_number',v_ver);
END; $function$
;

CREATE OR REPLACE FUNCTION public.publish_project_report_template(p_prt_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller uuid := public.current_app_user_id();
  v_current text;
  v_published_at timestamptz;
  v_version int;
  v_active_id uuid;
  v_section_count int;
  v_template_row project_report_templates%ROWTYPE;
  v_sections_json jsonb;
  v_snapshot_id uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'publish: must be authenticated as a registered user' USING ERRCODE = '42501';
  END IF;

  SELECT _prt_status_value(prt_status), prt_published_at, prt_version
    INTO v_current, v_published_at, v_version
  FROM project_report_templates
  WHERE id = p_prt_id AND NOT prt_is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'publish: template not found';
  END IF;

  IF v_current = 'Active' THEN
    RAISE EXCEPTION 'publish: template is already Active';
  END IF;
  IF v_current = 'Archived' THEN
    RAISE EXCEPTION 'publish: cannot publish an Archived template — restore to Draft first';
  END IF;

  SELECT id INTO v_active_id
  FROM picklist_values
  WHERE picklist_object='project_report_templates'
    AND picklist_field='prt_status'
    AND picklist_value='Active'
    AND picklist_is_active=true
  LIMIT 1;
  IF v_active_id IS NULL THEN
    RAISE EXCEPTION 'publish: Active status not configured';
  END IF;

  SELECT COUNT(*) INTO v_section_count
  FROM project_report_template_sections
  WHERE prt_id = p_prt_id AND NOT prts_is_deleted;
  IF v_section_count = 0 THEN
    RAISE EXCEPTION 'publish: template has no sections — add at least one before publishing';
  END IF;

  -- Increment version on re-publish (already had a published_at).
  IF v_published_at IS NOT NULL THEN
    v_version := v_version + 1;
  END IF;

  -- Flip the status + bump version. Capture the post-update PRT row for
  -- the snapshot — that way prtsn_template_json reflects the true state
  -- of the row at the moment Active took effect, including the bumped
  -- version and freshly stamped prt_updated_at.
  UPDATE project_report_templates SET
    prt_status = v_active_id,
    prt_version = v_version,
    prt_published_at = COALESCE(prt_published_at, now()),
    prt_updated_by = v_caller,
    prt_updated_at = now()
  WHERE id = p_prt_id
  RETURNING * INTO v_template_row;

  -- Build the sections JSON: every non-deleted section in section_order,
  -- as an array of full row objects. Using jsonb_agg + ORDER BY in the
  -- aggregate guarantees stable ordering inside the array.
  SELECT COALESCE(jsonb_agg(to_jsonb(s) ORDER BY s.prts_section_order ASC), '[]'::jsonb)
    INTO v_sections_json
  FROM project_report_template_sections s
  WHERE s.prt_id = p_prt_id AND NOT s.prts_is_deleted;

  INSERT INTO project_report_template_snapshots (
    prtsn_record_number, prt_id, prtsn_version,
    prtsn_template_json, prtsn_sections_json,
    prtsn_published_at, prtsn_published_by,
    prtsn_owner, prtsn_created_by, prtsn_updated_by
  ) VALUES (
    '', p_prt_id, v_version,
    to_jsonb(v_template_row), v_sections_json,
    now(), v_caller,
    v_caller, v_caller, v_caller
  )
  RETURNING id INTO v_snapshot_id;

  RETURN jsonb_build_object(
    'ok', true,
    'prt_id', p_prt_id,
    'new_status', 'Active',
    'new_version', v_version,
    'first_publish', v_published_at IS NULL,
    'snapshot_id', v_snapshot_id
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.purge_deleted_properties(p_age interval DEFAULT '30 days'::interval)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE n integer;
BEGIN
  ALTER TABLE public.properties DISABLE TRIGGER trg_properties_no_hard_delete;
  DELETE FROM public.properties
  WHERE property_is_deleted = true
    AND property_updated_at < now() - p_age;
  GET DIAGNOSTICS n = ROW_COUNT;
  ALTER TABLE public.properties ENABLE TRIGGER trg_properties_no_hard_delete;
  RETURN n;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.purge_record(p_table text, p_record_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller       uuid    := public.current_app_user_id();
  v_is_admin     boolean := public.app_is_admin();
  v_meta         jsonb;
  v_deleted_col  text;
  v_sql          text;
  v_check_sql    text;
  v_is_deleted   boolean;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'purge_record: must be authenticated' USING ERRCODE = '42501';
  END IF;
  IF NOT v_is_admin THEN
    RAISE EXCEPTION 'purge_record: admin role required' USING ERRCODE = '42501';
  END IF;
  IF p_table IS NULL OR p_record_id IS NULL THEN
    RAISE EXCEPTION 'purge_record: table and record_id are required';
  END IF;

  v_meta := public.ees_table_metadata(p_table);
  IF v_meta IS NULL OR v_meta->>'is_deleted_column' IS NULL THEN
    RAISE EXCEPTION 'purge_record: table % is not soft-deletable; refusing to purge', p_table
      USING ERRCODE = '22023';
  END IF;
  v_deleted_col := v_meta->>'is_deleted_column';

  -- Refuse to purge a live record. Two-step delete \u2192 purge is the only
  -- legitimate path. If the admin wants this gone permanently, they
  -- should soft-delete it first (reversible) and only then purge
  -- (irreversible).
  v_check_sql := format(
    'SELECT %I FROM public.%I WHERE id = $1',
    v_deleted_col, p_table
  );
  EXECUTE v_check_sql INTO v_is_deleted USING p_record_id;
  IF v_is_deleted IS NULL THEN
    RAISE EXCEPTION 'purge_record: record % not found in %', p_record_id, p_table
      USING ERRCODE = '02000';
  END IF;
  IF NOT v_is_deleted THEN
    RAISE EXCEPTION 'purge_record: record % in % is not soft-deleted; soft-delete first', p_record_id, p_table
      USING ERRCODE = '22023';
  END IF;

  v_sql := format('DELETE FROM public.%I WHERE id = $1 RETURNING id', p_table);
  EXECUTE v_sql INTO v_caller USING p_record_id;
  -- (Reusing v_caller as the return-capture scratch variable. If the
  -- delete didn't return a row, the trigger never fired either, so we
  -- raise a not-found.)
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'purge_record: record % in % could not be deleted', p_record_id, p_table
      USING ERRCODE = '02000';
  END IF;

  RETURN v_caller;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.purge_seed_data()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_table         text;
  v_total_deleted int := 0;
  v_tables        int := 0;
  v_per_table     int;
  v_errors        jsonb := '[]'::jsonb;
  v_error_msg     text;
  v_sql           text;
BEGIN
  -- Walk each distinct table that appears in seed_data_records and
  -- hard-delete the rows. We have to do this through a session flag
  -- because block_hard_delete() refuses ordinary DELETEs platform-wide.
  PERFORM set_config('leap.allow_hard_delete', 'seed_purge', true);

  -- Delete in reverse-dependency order: leaf tables first to avoid
  -- foreign-key cascade issues. We group by table for the per-table
  -- count summary.
  FOR v_table IN
    -- Tables that point at others go first. The ordering below mirrors
    -- the typical parent->child dependency chain in LEAP. Any table
    -- not in this explicit list still gets purged at the end via the
    -- final pass.
    SELECT unnest(ARRAY[
      'message_ai_transcripts','message_attachments','messages','conversations',
      'help_article_anchors','help_articles',
      'envelope_signers','envelopes',
      'document_templates','email_templates','templates',
      'service_appointment_assignments','service_appointments',
      'resource_absences','service_territory_members',
      'work_orders','tasks','documents',
      'project_payment_requests','project_reports',
      'projects','incentive_applications','assessments',
      'equipment_activities','vehicle_activities','diagnostic_tests',
      'mechanical_equipment','products','efr_reports',
      'opportunity_contact_roles','opportunities',
      'property_programs','property_disaster_exposure','property_source_data',
      'units','buildings','properties',
      'contacts','accounts',
      'vehicles','equipment',
      'crew_phones'
    ])
  LOOP
    BEGIN
      v_sql := format(
        'WITH targets AS (SELECT sdr_record_id FROM seed_data_records WHERE sdr_table_name = %L) ' ||
        'DELETE FROM %I WHERE id IN (SELECT sdr_record_id FROM targets)',
        v_table, v_table
      );
      EXECUTE v_sql;
      GET DIAGNOSTICS v_per_table = ROW_COUNT;
      IF v_per_table > 0 THEN
        v_tables := v_tables + 1;
        v_total_deleted := v_total_deleted + v_per_table;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      GET STACKED DIAGNOSTICS v_error_msg = MESSAGE_TEXT;
      v_errors := v_errors || jsonb_build_object(
        'table', v_table,
        'error', v_error_msg
      );
    END;
  END LOOP;

  -- Catch any tables in seed_data_records that we didn't enumerate
  -- above. Same delete logic.
  FOR v_table IN
    SELECT DISTINCT sdr_table_name FROM seed_data_records
     WHERE sdr_table_name NOT IN (
       'message_ai_transcripts','message_attachments','messages','conversations',
       'help_article_anchors','help_articles',
       'envelope_signers','envelopes',
       'document_templates','email_templates','templates',
       'service_appointment_assignments','service_appointments',
       'resource_absences','service_territory_members',
       'work_orders','tasks','documents',
       'project_payment_requests','project_reports',
       'projects','incentive_applications','assessments',
       'equipment_activities','vehicle_activities','diagnostic_tests',
       'mechanical_equipment','products','efr_reports',
       'opportunity_contact_roles','opportunities',
       'property_programs','property_disaster_exposure','property_source_data',
       'units','buildings','properties',
       'contacts','accounts',
       'vehicles','equipment',
       'crew_phones'
     )
  LOOP
    BEGIN
      v_sql := format(
        'WITH targets AS (SELECT sdr_record_id FROM seed_data_records WHERE sdr_table_name = %L) ' ||
        'DELETE FROM %I WHERE id IN (SELECT sdr_record_id FROM targets)',
        v_table, v_table
      );
      EXECUTE v_sql;
      GET DIAGNOSTICS v_per_table = ROW_COUNT;
      IF v_per_table > 0 THEN
        v_tables := v_tables + 1;
        v_total_deleted := v_total_deleted + v_per_table;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      GET STACKED DIAGNOSTICS v_error_msg = MESSAGE_TEXT;
      v_errors := v_errors || jsonb_build_object('table', v_table, 'error', v_error_msg);
    END;
  END LOOP;

  -- Finally clear the seed_data_records ledger.
  DELETE FROM seed_data_records;

  -- Drop the bypass flag.
  PERFORM set_config('leap.allow_hard_delete', '', true);

  RETURN jsonb_build_object(
    'tables_touched',  v_tables,
    'records_deleted', v_total_deleted,
    'errors',          v_errors
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recompute_account_rollups(p_account_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_open_id uuid;
  v_won_id  uuid;
BEGIN
  IF p_account_id IS NULL THEN RETURN; END IF;

  SELECT id INTO v_open_id FROM picklist_values
   WHERE picklist_object='opportunities' AND picklist_field='opportunity_status'
     AND picklist_value='Open' LIMIT 1;
  SELECT id INTO v_won_id FROM picklist_values
   WHERE picklist_object='opportunities' AND picklist_field='opportunity_status'
     AND picklist_value='Won' LIMIT 1;

  UPDATE accounts a
     SET account_total_number_of_properties = COALESCE((
           SELECT count(*)::int FROM properties p
            WHERE p.property_account_id = p_account_id AND NOT p.property_is_deleted), 0),
         account_total_number_of_buildings = COALESCE((
           SELECT count(*)::int FROM buildings b
             JOIN properties p ON p.id = b.property_id AND NOT p.property_is_deleted
            WHERE p.property_account_id = p_account_id AND NOT b.building_is_deleted), 0),
         account_total_number_of_units = COALESCE((
           SELECT count(*)::int FROM units u
             JOIN buildings b  ON b.id = u.building_id        AND NOT b.building_is_deleted
             JOIN properties p ON p.id = b.property_id        AND NOT p.property_is_deleted
            WHERE p.property_account_id = p_account_id AND NOT u.unit_is_deleted), 0),
         account_number_of_opportunities = COALESCE((
           SELECT count(*)::int FROM opportunities o
            WHERE o.opportunity_account_id = p_account_id AND NOT o.opportunity_is_deleted), 0),
         account_number_of_open_opportunities = COALESCE((
           SELECT count(*)::int FROM opportunities o
            WHERE o.opportunity_account_id = p_account_id AND NOT o.opportunity_is_deleted
              AND o.opportunity_status = v_open_id), 0),
         account_number_of_won_opportunities = COALESCE((
           SELECT count(*)::int FROM opportunities o
            WHERE o.opportunity_account_id = p_account_id AND NOT o.opportunity_is_deleted
              AND o.opportunity_status = v_won_id), 0),
         account_amount_of_open_opportunities = COALESCE((
           SELECT sum(o.opportunity_amount) FROM opportunities o
            WHERE o.opportunity_account_id = p_account_id AND NOT o.opportunity_is_deleted
              AND o.opportunity_status = v_open_id), 0)
   WHERE a.id = p_account_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recompute_building_rollups(p_building_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_property_id uuid;
  v_units       int;
BEGIN
  IF p_building_id IS NULL THEN RETURN; END IF;

  SELECT count(*)::int INTO v_units FROM units u
   WHERE u.building_id = p_building_id AND NOT u.unit_is_deleted;

  UPDATE buildings b
     SET building_number_of_units = v_units::numeric,
         building_total_units     = v_units
   WHERE b.id = p_building_id
   RETURNING b.property_id INTO v_property_id;

  PERFORM recompute_property_rollups(v_property_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recompute_opportunity_rollups(p_opportunity_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_account_id uuid;
  v_projects   int;
BEGIN
  IF p_opportunity_id IS NULL THEN RETURN; END IF;

  SELECT count(*)::int INTO v_projects FROM projects pr
   WHERE pr.opportunity_id = p_opportunity_id AND NOT pr.project_is_deleted;

  UPDATE opportunities o
     SET opportunity_number_of_projects = v_projects
   WHERE o.id = p_opportunity_id
   RETURNING o.opportunity_account_id INTO v_account_id;

  PERFORM recompute_account_rollups(v_account_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recompute_property_rollups(p_property_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_account_id uuid;
  v_buildings  int;
  v_units      int;
BEGIN
  IF p_property_id IS NULL THEN RETURN; END IF;

  SELECT count(*)::int INTO v_buildings FROM buildings b
   WHERE b.property_id = p_property_id AND NOT b.building_is_deleted;

  SELECT count(*)::int INTO v_units FROM units u
    JOIN buildings b ON b.id = u.building_id AND NOT b.building_is_deleted
   WHERE b.property_id = p_property_id AND NOT u.unit_is_deleted;

  UPDATE properties p
     SET property_number_of_buildings   = v_buildings::numeric,
         property_total_buildings       = v_buildings,
         property_total_number_of_units = v_units::numeric,
         property_total_units           = v_units
   WHERE p.id = p_property_id
   RETURNING p.property_account_id INTO v_account_id;

  PERFORM recompute_account_rollups(v_account_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reorder_junction_rows(p_table text, p_order_field text, p_ids uuid[])
 RETURNS integer
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_allowed_tables text[] := ARRAY[
    'work_plan_template_entries',
    'page_layout_sections',
    'page_layout_widgets'
  ];
  v_allowed_fields text[] := ARRAY[
    'wpte_execution_order',
    'section_order',
    'widget_position'
  ];
  v_count          integer;
BEGIN
  IF p_table IS NULL OR p_order_field IS NULL OR p_ids IS NULL THEN
    RAISE EXCEPTION 'reorder_junction_rows: table, order field, and ids are required';
  END IF;

  IF NOT (p_table = ANY(v_allowed_tables)) THEN
    RAISE EXCEPTION 'reorder_junction_rows: table % is not in the allowed list', p_table;
  END IF;
  IF NOT (p_order_field = ANY(v_allowed_fields)) THEN
    RAISE EXCEPTION 'reorder_junction_rows: field % is not in the allowed list', p_order_field;
  END IF;

  IF array_length(p_ids, 1) IS NULL THEN
    RETURN 0;
  END IF;

  -- Phase 1: park rows at negative staging indexes so the unique constraint
  -- holds while we swap them in place.
  EXECUTE format(
    'UPDATE %I AS t
        SET %I = -s.new_order
       FROM (SELECT unnest($1::uuid[]) AS id,
                    generate_subscripts($1::uuid[], 1) AS new_order) s
      WHERE t.id = s.id',
    p_table, p_order_field
  ) USING p_ids;

  -- Phase 2: settle at final positive order.
  EXECUTE format(
    'UPDATE %I AS t
        SET %I = s.new_order
       FROM (SELECT unnest($1::uuid[]) AS id,
                    generate_subscripts($1::uuid[], 1) AS new_order) s
      WHERE t.id = s.id',
    p_table, p_order_field
  ) USING p_ids;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.report_aggregate(p_primary_object text, p_group_col text, p_measure_type text DEFAULT 'count'::text, p_measure_field text DEFAULT NULL::text, p_filters jsonb DEFAULT '[]'::jsonb, p_sort text DEFAULT 'value_desc'::text, p_limit integer DEFAULT 100)
 RETURNS TABLE(label text, value numeric, raw_value text)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_soft_col   text;
  v_ref_table  text;
  v_name_col   text;
  v_group_expr text;
  v_raw_expr   text := format('%I::text', p_group_col);
  v_measure_expr text;
  v_where      text := ' WHERE true';
  v_join       text := '';
  v_order      text;
  v_sql        text;
  v_filter     jsonb;
  v_col        text;
  v_op         text;
  v_val        jsonb;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM information_schema.tables
                 WHERE table_schema='public' AND table_name=p_primary_object) THEN
    RAISE EXCEPTION 'Unknown object: %', p_primary_object;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                 WHERE table_schema='public' AND table_name=p_primary_object
                   AND column_name=p_group_col) THEN
    RAISE EXCEPTION 'Unknown column %.%', p_primary_object, p_group_col;
  END IF;

  SELECT (ees_table_metadata(p_primary_object)->>'is_deleted_column') INTO v_soft_col;
  IF v_soft_col IS NOT NULL THEN
    v_where := v_where || format(' AND t.%I = false', v_soft_col);
  END IF;

  SELECT cl2.relname INTO v_ref_table
  FROM pg_constraint con
  JOIN pg_class cl  ON cl.oid = con.conrelid
  JOIN pg_attribute att ON att.attrelid = con.conrelid AND att.attnum = ANY(con.conkey)
  JOIN pg_class cl2 ON cl2.oid = con.confrelid
  WHERE con.contype='f' AND cl.relname=p_primary_object AND att.attname=p_group_col
  LIMIT 1;

  IF v_ref_table = 'picklist_values' THEN
    v_join := ' LEFT JOIN picklist_values pv ON pv.id = t.' || quote_ident(p_group_col);
    v_group_expr := 'COALESCE(pv.picklist_label, pv.picklist_value, ''—'')';
  ELSIF v_ref_table IS NOT NULL THEN
    SELECT column_name INTO v_name_col
    FROM information_schema.columns
    WHERE table_schema='public' AND table_name=v_ref_table
      AND column_name LIKE '%\_name' ESCAPE '\'
    ORDER BY (column_name = v_ref_table || '_name') DESC, column_name
    LIMIT 1;
    IF v_name_col IS NOT NULL THEN
      v_join := format(' LEFT JOIN %I fk ON fk.id = t.%I', v_ref_table, p_group_col);
      v_group_expr := format('COALESCE(fk.%I, ''—'')', v_name_col);
    ELSE
      v_group_expr := format('COALESCE(t.%I::text, ''—'')', p_group_col);
    END IF;
  ELSE
    v_group_expr := format('COALESCE(t.%I::text, ''—'')', p_group_col);
  END IF;

  IF p_measure_type = 'count' OR p_measure_field IS NULL THEN
    v_measure_expr := 'COUNT(*)::numeric';
  ELSE
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                   WHERE table_schema='public' AND table_name=p_primary_object
                     AND column_name=p_measure_field) THEN
      RAISE EXCEPTION 'Unknown measure column %.%', p_primary_object, p_measure_field;
    END IF;
    v_measure_expr := CASE lower(p_measure_type)
      WHEN 'sum' THEN format('COALESCE(SUM(t.%I),0)::numeric', p_measure_field)
      WHEN 'avg' THEN format('COALESCE(AVG(t.%I),0)::numeric', p_measure_field)
      WHEN 'min' THEN format('MIN(t.%I)::numeric', p_measure_field)
      WHEN 'max' THEN format('MAX(t.%I)::numeric', p_measure_field)
      ELSE 'COUNT(*)::numeric'
    END;
  END IF;

  FOR v_filter IN SELECT * FROM jsonb_array_elements(COALESCE(p_filters,'[]'::jsonb))
  LOOP
    v_col := v_filter->>'col';
    v_op  := COALESCE(v_filter->>'op','equals');
    v_val := v_filter->'val';
    IF v_col IS NULL OR NOT EXISTS (
      SELECT 1 FROM information_schema.columns
      WHERE table_schema='public' AND table_name=p_primary_object AND column_name=v_col
    ) THEN
      CONTINUE;
    END IF;
    v_where := v_where || CASE v_op
      WHEN 'equals'      THEN format(' AND t.%I = %L', v_col, v_val#>>'{}')
      WHEN 'not_equals'  THEN format(' AND t.%I <> %L', v_col, v_val#>>'{}')
      WHEN 'gt'          THEN format(' AND t.%I > %L', v_col, v_val#>>'{}')
      WHEN 'lt'          THEN format(' AND t.%I < %L', v_col, v_val#>>'{}')
      WHEN 'gte'         THEN format(' AND t.%I >= %L', v_col, v_val#>>'{}')
      WHEN 'lte'         THEN format(' AND t.%I <= %L', v_col, v_val#>>'{}')
      WHEN 'is_null'     THEN format(' AND t.%I IS NULL', v_col)
      WHEN 'is_not_null' THEN format(' AND t.%I IS NOT NULL', v_col)
      WHEN 'in'          THEN format(' AND t.%I = ANY(%L)', v_col,
                              (SELECT array_agg(x#>>'{}') FROM jsonb_array_elements(v_val) x))
      ELSE ''
    END;
  END LOOP;

  -- SELECT order is label(1), value(2), raw_value(3).
  v_order := CASE p_sort
    WHEN 'name'      THEN '1 ASC'
    WHEN 'value_asc' THEN '2 ASC'
    ELSE '2 DESC'
  END;

  v_sql := format(
    'SELECT %s AS label, %s AS value, %s AS raw_value FROM %I t%s%s GROUP BY %s, %s ORDER BY %s LIMIT %s',
    v_group_expr, v_measure_expr, v_raw_expr,
    p_primary_object, v_join, v_where,
    v_group_expr, v_raw_expr, v_order, GREATEST(p_limit,1)
  );

  RETURN QUERY EXECUTE v_sql;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.require_deletion_reason()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
    IF NEW.is_deleted = true AND OLD.is_deleted = false THEN
        IF NEW.deletion_reason IS NULL OR trim(NEW.deletion_reason) = '' THEN
            RAISE EXCEPTION 'A deletion_reason is required when soft-deleting a record. Table: %, Record: %', TG_TABLE_NAME, OLD.id;
        END IF;
        IF NEW.deleted_at IS NULL THEN
            NEW.deleted_at = now();
        END IF;
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reschedule_appointment(p_token text, p_new_start_iso timestamp with time zone, p_new_end_iso timestamp with time zone, p_new_resource_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_sat             service_appointment_tokens%rowtype;
  v_sa              service_appointments%rowtype;
  v_sa_day_chi      date;
  v_lock_key        bigint;
  v_conflict_count  integer;
  v_resource_exists boolean;
  v_admin_id        uuid := 'c5a01ec8-960f-42ab-8a9e-a49822de89af';
BEGIN
  IF p_token IS NULL OR length(p_token) != 32 THEN
    RETURN jsonb_build_object('status', 'invalid_token');
  END IF;

  SELECT * INTO v_sat FROM service_appointment_tokens WHERE sat_token = p_token;
  IF v_sat.id IS NULL THEN RETURN jsonb_build_object('status', 'invalid_token'); END IF;
  IF v_sat.sat_expires_at < now() THEN RETURN jsonb_build_object('status', 'expired_token'); END IF;
  IF v_sat.sat_consumed_at IS NOT NULL THEN
    RETURN jsonb_build_object('status', 'already_consumed', 'message', 'This appointment has already been canceled.');
  END IF;

  SELECT * INTO v_sa FROM service_appointments
   WHERE id = v_sat.service_appointment_id AND sa_is_deleted = false;
  IF v_sa.id IS NULL THEN RETURN jsonb_build_object('status', 'appointment_not_found'); END IF;

  IF v_sa.sa_scheduled_start_time < now() THEN
    RETURN jsonb_build_object('status', 'too_late',
                              'message', 'Cannot reschedule an appointment that has already started or passed.');
  END IF;

  IF p_new_start_iso IS NULL OR p_new_end_iso IS NULL OR p_new_start_iso >= p_new_end_iso THEN
    RETURN jsonb_build_object('status', 'invalid_slot');
  END IF;
  IF p_new_start_iso < now() THEN
    RETURN jsonb_build_object('status', 'past_slot');
  END IF;
  IF p_new_resource_id IS NULL THEN
    RETURN jsonb_build_object('status', 'invalid_resource');
  END IF;

  SELECT true INTO v_resource_exists
    FROM contacts
   WHERE id = p_new_resource_id
     AND coalesce(contact_is_deleted, false) = false;
  IF v_resource_exists IS NULL THEN
    RETURN jsonb_build_object('status', 'invalid_resource');
  END IF;

  v_sa_day_chi := (p_new_start_iso AT TIME ZONE 'America/Chicago')::date;
  v_lock_key   := hashtextextended(p_new_resource_id::text || ':' || v_sa_day_chi::text, 0);
  PERFORM pg_advisory_xact_lock(v_lock_key);

  SELECT count(*) INTO v_conflict_count
    FROM service_appointment_assignments saa
    JOIN service_appointments sa2 ON sa2.id = saa.service_appointment_id
   WHERE saa.contact_id = p_new_resource_id
     AND coalesce(saa.saa_is_deleted, false) = false
     AND coalesce(sa2.sa_is_deleted, false)  = false
     AND sa2.id != v_sa.id
     AND sa2.sa_scheduled_start_time < p_new_end_iso
     AND sa2.sa_scheduled_end_time   > p_new_start_iso;

  IF v_conflict_count > 0 THEN
    RETURN jsonb_build_object('status', 'slot_taken',
                              'message', 'That time slot was just taken. Please pick another.');
  END IF;

  UPDATE service_appointments
     SET sa_scheduled_start_time = p_new_start_iso,
         sa_scheduled_end_time   = p_new_end_iso,
         sa_updated_at           = now(),
         sa_updated_by           = v_admin_id
   WHERE id = v_sa.id;

  UPDATE service_appointment_assignments
     SET saa_is_deleted      = true,
         saa_deleted_at      = now(),
         saa_deleted_by      = v_admin_id,
         saa_deletion_reason = 'rescheduled by customer'
   WHERE service_appointment_id = v_sa.id
     AND coalesce(saa_is_deleted, false) = false;

  INSERT INTO service_appointment_assignments (
    saa_record_number, saa_name,
    service_appointment_id, contact_id,
    saa_created_at, saa_created_by,
    saa_updated_at, saa_updated_by,
    saa_is_deleted
  ) VALUES (
    '', '',
    v_sa.id, p_new_resource_id,
    now(), v_admin_id,
    now(), v_admin_id,
    false
  );

  RETURN jsonb_build_object(
    'status', 'ok',
    'service_appointment_id', v_sa.id,
    'sa_record_number',       v_sa.sa_record_number,
    'sa_scheduled_start_iso', p_new_start_iso,
    'sa_scheduled_end_iso',   p_new_end_iso
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reset_sf_layouts(p_object text)
 RETURNS integer
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE n int;
BEGIN
  UPDATE public.page_layouts SET is_deleted = true, updated_at = now()
  WHERE page_layout_object = p_object AND is_deleted = false;
  GET DIAGNOSTICS n = ROW_COUNT;
  RETURN n;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.resolve_adhoc_assistant_flow()
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user uuid;
  v_flow_id uuid;
BEGIN
  v_user := current_app_user_id();
  IF v_user IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;

  SELECT id INTO v_flow_id
    FROM public.flows
   WHERE flow_name = 'AI Assistant — Ad-hoc'
     AND is_deleted = false
   LIMIT 1;
  IF v_flow_id IS NOT NULL THEN RETURN v_flow_id; END IF;

  INSERT INTO public.flows
    (flow_record_number, flow_name, flow_description, flow_type, flow_status, owner_id, created_by, updated_by)
  VALUES
    ('', 'AI Assistant — Ad-hoc',
     'System flow anchoring ad-hoc AI assistant actions not saved as a named task.',
     'screen', 'active', v_user, v_user, v_user)
  RETURNING id INTO v_flow_id;

  RETURN v_flow_id;
END; $function$
;

CREATE OR REPLACE FUNCTION public.resolve_anchor_opportunity(p_conversation_id uuid)
 RETURNS SETOF uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  with conv as (
    select contact_id, account_id, project_id, service_appointment_id
    from public.conversations
    where id = p_conversation_id and not conv_is_deleted
  )
  select distinct opp_id from (
    -- contact_id → opportunity_contact_roles
    select ocr.opportunity_id as opp_id
    from conv c
    join public.opportunity_contact_roles ocr on ocr.contact_id = c.contact_id
    where c.contact_id is not null and not ocr.ocr_is_deleted

    union

    -- account_id → opportunities.opportunity_account_id
    select o.id as opp_id
    from conv c
    join public.opportunities o on o.opportunity_account_id = c.account_id
    where c.account_id is not null and not o.opportunity_is_deleted

    union

    -- project_id → projects.property_id → opportunities.property_id
    select o.id as opp_id
    from conv c
    join public.projects p on p.id = c.project_id
    join public.opportunities o on o.property_id = p.property_id
    where c.project_id is not null and not p.project_is_deleted and not o.opportunity_is_deleted

    union

    -- service_appointment_id → SA''s own opportunity_id (preferred) else
    -- walk via project → property → opportunity.
    select coalesce(sa.opportunity_id, o.id) as opp_id
    from conv c
    join public.service_appointments sa on sa.id = c.service_appointment_id
    left join public.projects p on p.id = sa.project_id
    left join public.opportunities o on o.property_id = p.property_id and not o.opportunity_is_deleted
    where c.service_appointment_id is not null and not sa.sa_is_deleted
  ) anchors
  where opp_id is not null;
$function$
;

CREATE OR REPLACE FUNCTION public.resolve_contact_from_phone(p_phone_e164 text)
 RETURNS TABLE(contact_id uuid, account_id uuid, project_id uuid, service_appointment_id uuid)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_contact_id uuid;
  v_account_id uuid;
  v_project_id uuid;
  v_sa_id      uuid;
begin
  if p_phone_e164 is null or p_phone_e164 = '' then
    return query select null::uuid, null::uuid, null::uuid, null::uuid;
    return;
  end if;

  -- Try mobile first, then primary phone. Match on normalized form.
  select c.id, c.contact_account_id
  into v_contact_id, v_account_id
  from public.contacts c
  where c.contact_is_deleted = false
    and (
      public.normalize_phone_e164(c.contact_mobile_phone) = p_phone_e164
      or public.normalize_phone_e164(c.contact_phone) = p_phone_e164
    )
  order by c.contact_updated_at desc nulls last
  limit 1;

  if v_contact_id is null then
    return query select null::uuid, null::uuid, null::uuid, null::uuid;
    return;
  end if;

  -- Most recent project associated with this contact's account (best-effort).
  select p.id
  into v_project_id
  from public.projects p
  where p.project_is_deleted = false
    and p.account_id = v_account_id
  order by p.project_updated_at desc nulls last
  limit 1;

  -- Most recent service appointment linked to this contact via the
  -- service_appointment_assignments junction (best-effort).
  select sa.id
  into v_sa_id
  from public.service_appointments sa
  join public.service_appointment_assignments saa
    on saa.service_appointment_id = sa.id
   and saa.saa_is_deleted = false
  where sa.sa_is_deleted = false
    and saa.contact_id = v_contact_id
  order by sa.sa_scheduled_start_time desc nulls last
  limit 1;

  return query select v_contact_id, v_account_id, v_project_id, v_sa_id;
end $function$
;

CREATE OR REPLACE FUNCTION public.resolve_home_page_for_current_user()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_role uuid;
  v_page public.home_pages%ROWTYPE;
  v_components jsonb;
BEGIN
  SELECT role_id INTO v_role FROM public.users WHERE auth_user_id = auth.uid();

  SELECT * INTO v_page FROM public.home_pages
   WHERE hp_is_deleted = false AND hp_is_active = true AND hp_role_id = v_role
   ORDER BY hp_updated_at DESC LIMIT 1;

  IF v_page.id IS NULL THEN
    SELECT * INTO v_page FROM public.home_pages
     WHERE hp_is_deleted = false AND hp_is_active = true AND hp_is_default = true
     ORDER BY hp_updated_at DESC LIMIT 1;
  END IF;

  IF v_page.id IS NULL THEN
    RETURN NULL;  -- no configured page; caller falls back to the built-in home
  END IF;

  SELECT jsonb_agg(jsonb_build_object(
            'id', hpc.id, 'region', hpc.hpc_region, 'type', hpc.hpc_type,
            'source_id', hpc.hpc_source_id, 'title', hpc.hpc_title,
            'config', hpc.hpc_config, 'sort_order', hpc.hpc_sort_order
          ) ORDER BY hpc.hpc_region, hpc.hpc_sort_order)
    INTO v_components
    FROM public.home_page_components hpc
   WHERE hpc.hpc_page_id = v_page.id AND hpc.hpc_is_deleted = false;

  RETURN jsonb_build_object(
    'id', v_page.id, 'name', v_page.hp_name, 'template', v_page.hp_template,
    'role_id', v_page.hp_role_id, 'is_default', v_page.hp_is_default,
    'components', COALESCE(v_components, '[]'::jsonb)
  );
END; $function$
;

CREATE OR REPLACE FUNCTION public.resolve_home_page_for_module(p_module text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_role uuid;
  v_page public.home_pages%ROWTYPE;
  v_components jsonb;
BEGIN
  SELECT role_id INTO v_role FROM public.users WHERE auth_user_id = auth.uid();

  -- 1. module + role
  SELECT * INTO v_page FROM public.home_pages
   WHERE hp_is_deleted = false AND hp_is_active = true
     AND hp_module_id IS NOT DISTINCT FROM p_module
     AND hp_role_id = v_role
   ORDER BY hp_updated_at DESC LIMIT 1;

  -- 2. module default
  IF v_page.id IS NULL THEN
    SELECT * INTO v_page FROM public.home_pages
     WHERE hp_is_deleted = false AND hp_is_active = true
       AND hp_module_id IS NOT DISTINCT FROM p_module
       AND hp_is_default = true
     ORDER BY hp_updated_at DESC LIMIT 1;
  END IF;

  -- 3. global-only fallback to legacy role/default (module-agnostic) pages
  IF v_page.id IS NULL AND p_module IS NULL THEN
    SELECT * INTO v_page FROM public.home_pages
     WHERE hp_is_deleted = false AND hp_is_active = true AND hp_role_id = v_role
     ORDER BY hp_updated_at DESC LIMIT 1;
    IF v_page.id IS NULL THEN
      SELECT * INTO v_page FROM public.home_pages
       WHERE hp_is_deleted = false AND hp_is_active = true AND hp_is_default = true
       ORDER BY hp_updated_at DESC LIMIT 1;
    END IF;
  END IF;

  IF v_page.id IS NULL THEN
    RETURN NULL;
  END IF;

  SELECT jsonb_agg(jsonb_build_object(
            'id', hpc.id, 'region', hpc.hpc_region, 'type', hpc.hpc_type,
            'source_id', hpc.hpc_source_id, 'title', hpc.hpc_title,
            'config', hpc.hpc_config, 'sort_order', hpc.hpc_sort_order
          ) ORDER BY hpc.hpc_region, hpc.hpc_sort_order)
    INTO v_components
    FROM public.home_page_components hpc
   WHERE hpc.hpc_page_id = v_page.id AND hpc.hpc_is_deleted = false;

  RETURN jsonb_build_object(
    'id', v_page.id, 'name', v_page.hp_name, 'template', v_page.hp_template,
    'role_id', v_page.hp_role_id, 'module_id', v_page.hp_module_id,
    'is_default', v_page.hp_is_default,
    'components', COALESCE(v_components, '[]'::jsonb)
  );
END; $function$
;

CREATE OR REPLACE FUNCTION public.resolve_outbound_mailbox_for_anchor(p_anchor_object text, p_anchor_record_id uuid)
 RETURNS TABLE(outbound_mailbox_id uuid, obm_address text, obm_display_name text, obm_state text, resolution_path text)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_state text;
  v_path  text;
  v_match_count int;
begin
  -- Walk anchor → state. Each branch sets v_state and v_path on success.
  if p_anchor_object = 'projects' then
    select pr.property_state, 'projects → properties.property_state'
      into v_state, v_path
      from projects p
      join properties pr on pr.id = p.property_id
     where p.id = p_anchor_record_id;

  elsif p_anchor_object = 'work_orders' then
    select pr.property_state, 'work_orders.property_id → properties.property_state'
      into v_state, v_path
      from work_orders w
      join properties pr on pr.id = w.property_id
     where w.id = p_anchor_record_id;
    if v_state is null then
      select pr.property_state, 'work_orders.project_id → projects.property_id → properties.property_state'
        into v_state, v_path
        from work_orders w
        join projects p    on p.id = w.project_id
        join properties pr on pr.id = p.property_id
       where w.id = p_anchor_record_id;
    end if;

  elsif p_anchor_object = 'service_appointments' then
    select pr.property_state,
           'service_appointments.work_order_id → work_orders → properties.property_state'
      into v_state, v_path
      from service_appointments sa
      join work_orders w on w.id = sa.work_order_id
      join properties pr on pr.id = coalesce(w.property_id,
                                             (select property_id from projects where id = w.project_id))
     where sa.id = p_anchor_record_id;

  elsif p_anchor_object = 'accounts' then
    select coalesce(a.billing_state, a.mailing_state),
           'accounts → billing_state (or mailing_state)'
      into v_state, v_path
      from accounts a
     where a.id = p_anchor_record_id;

  elsif p_anchor_object = 'contacts' then
    select c.contact_mailing_state, 'contacts.contact_mailing_state'
      into v_state, v_path
      from contacts c
     where c.id = p_anchor_record_id;
    if v_state is null then
      select coalesce(a.billing_state, a.mailing_state),
             'contacts.account_id → accounts.billing_state'
        into v_state, v_path
        from contacts c
        join accounts a on a.id = c.account_id
       where c.id = p_anchor_record_id;
    end if;

  elsif p_anchor_object = 'opportunities' then
    select o.opportunity_state, 'opportunities.opportunity_state'
      into v_state, v_path
      from opportunities o
     where o.id = p_anchor_record_id;
    if v_state is null then
      select pr.property_state, 'opportunities.property_id → properties.property_state'
        into v_state, v_path
        from opportunities o
        join properties pr on pr.id = o.property_id
       where o.id = p_anchor_record_id;
    end if;

  elsif p_anchor_object = 'incentive_applications' then
    select ia.ia_installation_address_state, 'incentive_applications.ia_installation_address_state'
      into v_state, v_path
      from incentive_applications ia
     where ia.id = p_anchor_record_id;
    if v_state is null then
      select pr.property_state, 'incentive_applications.property_id → properties.property_state'
        into v_state, v_path
        from incentive_applications ia
        join properties pr on pr.id = ia.property_id
       where ia.id = p_anchor_record_id;
    end if;
    if v_state is null then
      select pr.property_state, 'incentive_applications.project_id → projects.property_id → properties.property_state'
        into v_state, v_path
        from incentive_applications ia
        join projects p    on p.id = ia.project_id
        join properties pr on pr.id = p.property_id
       where ia.id = p_anchor_record_id;
    end if;

  elsif p_anchor_object = 'assessments' then
    select pr.property_state, 'assessments.property_id → properties.property_state'
      into v_state, v_path
      from assessments a
      join properties pr on pr.id = a.property_id
     where a.id = p_anchor_record_id;
    if v_state is null then
      select pr.property_state, 'assessments.project_id → projects.property_id → properties.property_state'
        into v_state, v_path
        from assessments a
        join projects p    on p.id = a.project_id
        join properties pr on pr.id = p.property_id
       where a.id = p_anchor_record_id;
    end if;
    if v_state is null then
      select b.building_state, 'assessments.building_id → buildings.building_state'
        into v_state, v_path
        from assessments a
        join buildings b on b.id = a.building_id
       where a.id = p_anchor_record_id;
    end if;

  elsif p_anchor_object = 'buildings' then
    select b.building_state, 'buildings.building_state'
      into v_state, v_path
      from buildings b
     where b.id = p_anchor_record_id;
    if v_state is null then
      select pr.property_state, 'buildings.property_id → properties.property_state'
        into v_state, v_path
        from buildings b
        join properties pr on pr.id = b.property_id
       where b.id = p_anchor_record_id;
    end if;

  elsif p_anchor_object = 'properties' then
    select pr.property_state, 'properties.property_state'
      into v_state, v_path
      from properties pr
     where pr.id = p_anchor_record_id;

  end if;

  if v_state is null then
    return;  -- empty result; caller surfaces "no state resolvable for anchor"
  end if;

  -- Count active mailboxes for this state. Return only when exactly one
  -- matches. Zero or multiple -> empty result so the caller surfaces
  -- the configuration problem rather than picking arbitrarily.
  select count(*) into v_match_count
    from outbound_mailboxes m
   where m.obm_state = v_state
     and m.obm_is_active = true
     and m.obm_is_deleted = false;

  if v_match_count <> 1 then
    return;  -- empty; caller's error path tells the user to fix mailbox config
  end if;

  return query
    select m.id, m.obm_address, m.obm_display_name, m.obm_state, v_path
      from outbound_mailboxes m
     where m.obm_state = v_state
       and m.obm_is_active = true
       and m.obm_is_deleted = false;
end$function$
;

CREATE OR REPLACE FUNCTION public.resolve_territory_by_point(p_lat double precision, p_lng double precision)
 RETURNS TABLE(id uuid, service_territory_name text, service_territory_state text)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT st.id, st.service_territory_name, st.service_territory_state
  FROM service_territories st
  WHERE st.service_territory_is_deleted = false
    AND st.service_territory_is_active  = true
    AND st.service_territory_polygon IS NOT NULL
    AND ST_Contains(
      st.service_territory_polygon::geometry,
      ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geometry
    )
  -- Deepest match wins: prefer rows with a parent_territory_id (i.e. sub-territories).
  ORDER BY (st.parent_territory_id IS NOT NULL) DESC,
           ST_Area(st.service_territory_polygon::geometry) ASC
  LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.restore_document_template(p_document_template_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller   uuid := public.current_app_user_id();
  v_current  text;
  v_draft_id uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'restore_document_template: must be authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT public._dt_status_value(status) INTO v_current
  FROM public.document_templates WHERE id = p_document_template_id AND NOT is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'restore_document_template: template not found';
  END IF;
  IF v_current IS DISTINCT FROM 'Archived' THEN
    RAISE EXCEPTION 'restore_document_template: only Archived templates can be restored (current: %)', v_current;
  END IF;

  SELECT id INTO v_draft_id FROM public.picklist_values
  WHERE picklist_object='document_templates' AND picklist_field='status'
    AND picklist_value='Draft' AND picklist_is_active=true LIMIT 1;

  UPDATE public.document_templates
  SET status = v_draft_id, updated_by = v_caller, updated_at = now()
  WHERE id = p_document_template_id;

  RETURN jsonb_build_object('ok', true, 'document_template_id', p_document_template_id, 'new_status', 'Draft');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.restore_email_template(p_email_template_id uuid)
 RETURNS jsonb
