CREATE OR REPLACE FUNCTION public.restore_project_report_template(p_prt_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller uuid := public.current_app_user_id();
  v_current text;
  v_draft_id uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'restore: must be authenticated as a registered user' USING ERRCODE = '42501';
  END IF;

  SELECT _prt_status_value(prt_status) INTO v_current
  FROM project_report_templates
  WHERE id = p_prt_id AND NOT prt_is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'restore: template not found';
  END IF;
  IF v_current IS DISTINCT FROM 'Archived' THEN
    RAISE EXCEPTION 'restore: only Archived templates can be restored (current: %)', v_current;
  END IF;

  SELECT id INTO v_draft_id
  FROM picklist_values
  WHERE picklist_object='project_report_templates'
    AND picklist_field='prt_status'
    AND picklist_value='Draft'
    AND picklist_is_active=true
  LIMIT 1;
  IF v_draft_id IS NULL THEN
    RAISE EXCEPTION 'restore: Draft status not configured';
  END IF;

  UPDATE project_report_templates SET
    prt_status = v_draft_id,
    prt_updated_by = v_caller,
    prt_updated_at = now()
  WHERE id = p_prt_id;

  RETURN jsonb_build_object('ok', true, 'prt_id', p_prt_id, 'new_status', 'Draft');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.restore_record(p_table text, p_record_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller       uuid := public.current_app_user_id();
  v_meta         jsonb;
  v_deleted_col  text;
  v_prefix       text;
  v_reason_col   text;
  v_at_col       text;
  v_by_col       text;
  v_has_reason   boolean;
  v_has_at       boolean;
  v_has_by       boolean;
  v_set_clauses  text[];
  v_sql          text;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'restore_record: must be authenticated' USING ERRCODE = '42501';
  END IF;
  IF p_table IS NULL OR p_record_id IS NULL THEN
    RAISE EXCEPTION 'restore_record: table and record_id are required';
  END IF;

  -- Validate the table is known. ees_table_metadata returns NULL for
  -- unknown tables; pulling is_deleted_column gives us both validation
  -- and the actual column name in one call.
  v_meta := public.ees_table_metadata(p_table);
  IF v_meta IS NULL OR v_meta->>'is_deleted_column' IS NULL THEN
    RAISE EXCEPTION 'restore_record: table % is not soft-deletable', p_table
      USING ERRCODE = '22023';
  END IF;
  v_deleted_col := v_meta->>'is_deleted_column';

  -- Derive the prefix from the is_deleted column name.
  --   'is_deleted'         → prefix ''           → deletion_reason / deleted_at / deleted_by
  --   'project_is_deleted' → prefix 'project_'   → project_deletion_reason / ...
  --   'ps_is_deleted'      → prefix 'ps_'        → ps_deletion_reason
  v_prefix     := regexp_replace(v_deleted_col, 'is_deleted$', '');
  v_reason_col := v_prefix || 'deletion_reason';
  v_at_col     := v_prefix || 'deleted_at';
  v_by_col     := v_prefix || 'deleted_by';

  -- Probe which audit columns actually exist
  SELECT EXISTS (
    SELECT 1 FROM pg_attribute a
    JOIN pg_class c ON a.attrelid = c.oid
    JOIN pg_namespace n ON c.relnamespace = n.oid
    WHERE n.nspname='public' AND c.relname=p_table
      AND a.attname=v_reason_col AND a.attnum > 0
  ) INTO v_has_reason;
  SELECT EXISTS (
    SELECT 1 FROM pg_attribute a
    JOIN pg_class c ON a.attrelid = c.oid
    JOIN pg_namespace n ON c.relnamespace = n.oid
    WHERE n.nspname='public' AND c.relname=p_table
      AND a.attname=v_at_col AND a.attnum > 0
  ) INTO v_has_at;
  SELECT EXISTS (
    SELECT 1 FROM pg_attribute a
    JOIN pg_class c ON a.attrelid = c.oid
    JOIN pg_namespace n ON c.relnamespace = n.oid
    WHERE n.nspname='public' AND c.relname=p_table
      AND a.attname=v_by_col AND a.attnum > 0
  ) INTO v_has_by;

  v_set_clauses := ARRAY[quote_ident(v_deleted_col) || ' = false'];
  IF v_has_reason THEN
    v_set_clauses := v_set_clauses || (quote_ident(v_reason_col) || ' = NULL');
  END IF;
  IF v_has_at THEN
    v_set_clauses := v_set_clauses || (quote_ident(v_at_col) || ' = NULL');
  END IF;
  IF v_has_by THEN
    v_set_clauses := v_set_clauses || (quote_ident(v_by_col) || ' = NULL');
  END IF;

  v_sql := format(
    'UPDATE public.%I SET %s WHERE id = $1 AND %I = true RETURNING id',
    p_table,
    array_to_string(v_set_clauses, ', '),
    v_deleted_col
  );

  EXECUTE v_sql INTO v_caller USING p_record_id;
  -- (Reusing v_caller as a scratch return capture — restore returns the
  -- record id we just restored, or NULL if no row matched.)

  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'restore_record: record % not found in % or already not deleted',
      p_record_id, p_table USING ERRCODE = '02000';
  END IF;

  RETURN v_caller;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rls_auto_enable()
 RETURNS event_trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'pg_catalog'
AS $function$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rollup_work_plan_status()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_plan uuid := COALESCE(NEW.work_plan_id, OLD.work_plan_id);
  -- step status ids
  s_new        uuid := 'e83b77fa-9902-4329-bd2c-a0b73df782ba';
  s_inprog     uuid := 'ccb51848-2251-42f2-97b2-e0f604a672a1';
  s_unable     uuid := '16174ac6-6ec9-44a0-b722-78074e117d5f';
  s_completed  uuid := '101e1e86-2f49-4999-9fbb-fc5451df5fdc';
  s_verified   uuid := 'f25dc618-6416-480d-8a09-b31ba5205329';
  -- plan status ids
  p_new        uuid := 'b895cdea-5af9-455f-8517-f4b7f031665e';
  p_inprog     uuid := '93a2faa6-5eab-44b7-aebf-4bd22b14a05f';
  p_unable     uuid := '85203617-8ebe-48af-8cb0-d0ac31e9fbb2';
  p_completed  uuid := 'fca72be9-c550-4809-b165-10c7c8e40d47';
  p_verified   uuid := 'eb7c0e0b-1bb1-4c20-b575-66b4a876b236';
  n_total int; n_unable int; n_verified int; n_done int; n_started int;
  v_new_status uuid;
BEGIN
  SELECT count(*),
         count(*) FILTER (WHERE work_step_status = s_unable),
         count(*) FILTER (WHERE work_step_status = s_verified),
         count(*) FILTER (WHERE work_step_status IN (s_completed, s_verified)),
         count(*) FILTER (WHERE work_step_status <> s_new)
    INTO n_total, n_unable, n_verified, n_done, n_started
  FROM public.work_steps
  WHERE work_plan_id = v_plan AND COALESCE(work_step_is_deleted,false) = false;

  IF n_total = 0 THEN
    v_new_status := p_new;
  ELSIF n_unable > 0 THEN
    v_new_status := p_unable;              -- any blocked step forces plan Unable to Complete
  ELSIF n_verified = n_total THEN
    v_new_status := p_verified;            -- all verified
  ELSIF n_done = n_total THEN
    v_new_status := p_completed;           -- all completed or verified
  ELSIF n_started > 0 THEN
    v_new_status := p_inprog;
  ELSE
    v_new_status := p_new;
  END IF;

  UPDATE public.work_plans
     SET work_plan_status = v_new_status, work_plan_updated_at = now()
   WHERE id = v_plan AND work_plan_status IS DISTINCT FROM v_new_status;

  RETURN NULL;
END; $function$
;

CREATE OR REPLACE FUNCTION public.save_assistant_task(p_task jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user uuid;
  v_flow_id uuid;
  v_version_id uuid;
  v_name text;
  v_launch_object text;
  v_questions jsonb;
  v_actions jsonb;
  v_q jsonb;
  v_ord integer := 0;
  v_qtype text;
  v_elements jsonb := '[]'::jsonb;
  v_el_id uuid;
  v_snapshot jsonb;
BEGIN
  v_user := current_app_user_id();
  IF v_user IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;

  v_name := NULLIF(trim(p_task->>'name'), '');
  IF v_name IS NULL THEN RAISE EXCEPTION 'Task name is required'; END IF;
  v_launch_object := NULLIF(p_task->>'launch_object','');
  v_questions := COALESCE(p_task->'questions','[]'::jsonb);
  v_actions   := COALESCE(p_task->'actions','[]'::jsonb);

  -- Flow row (active, screen-type, launch-scoped).
  INSERT INTO public.flows
    (flow_record_number, flow_name, flow_description, flow_type, flow_status,
     flow_launch_object, flow_launch_contexts, owner_id, created_by, updated_by)
  VALUES
    ('', v_name, NULLIF(p_task->>'description',''), 'screen', 'active',
     v_launch_object,
     CASE WHEN v_launch_object IS NULL THEN '[]'::jsonb
          ELSE jsonb_build_array(jsonb_build_object('object', v_launch_object)) END,
     v_user, v_user, v_user)
  RETURNING id INTO v_flow_id;

  -- Start element.
  INSERT INTO public.flow_elements
    (fe_record_number, fe_flow_id, fe_element_type, fe_order, fe_label, owner_id, created_by, updated_by)
  VALUES ('', v_flow_id, 'start', v_ord, 'Start', v_user, v_user, v_user)
  RETURNING id INTO v_el_id;
  v_elements := v_elements || jsonb_build_object('id', v_el_id, 'type','start','order',v_ord);

  -- One element per guided question. yes_no/single_select -> decision; text -> screen.
  FOR v_q IN SELECT * FROM jsonb_array_elements(v_questions) LOOP
    v_ord := v_ord + 1;
    v_qtype := COALESCE(v_q->>'type','text');
    INSERT INTO public.flow_elements
      (fe_record_number, fe_flow_id, fe_element_type, fe_order, fe_label, fe_api_name,
       fe_config, fe_decision_branches, owner_id, created_by, updated_by)
    VALUES
      ('', v_flow_id,
       CASE WHEN v_qtype IN ('yes_no','single_select') THEN 'decision' ELSE 'screen' END,
       v_ord,
       v_q->>'label',
       v_q->>'key',
       jsonb_build_object('question_type', v_qtype, 'options', COALESCE(v_q->'options','[]'::jsonb)),
       CASE WHEN v_qtype='yes_no'
            THEN '[{"value":"yes","label":"Yes"},{"value":"no","label":"No"}]'::jsonb
            WHEN v_qtype='single_select'
            THEN COALESCE(v_q->'options','[]'::jsonb)
            ELSE '[]'::jsonb END,
       v_user, v_user, v_user)
    RETURNING id INTO v_el_id;
    v_elements := v_elements || jsonb_build_object(
      'id', v_el_id, 'type', CASE WHEN v_qtype IN ('yes_no','single_select') THEN 'decision' ELSE 'screen' END,
      'order', v_ord, 'key', v_q->>'key', 'label', v_q->>'label',
      'question_type', v_qtype, 'options', COALESCE(v_q->'options','[]'::jsonb));
  END LOOP;

  -- Action element holding the action template(s).
  v_ord := v_ord + 1;
  INSERT INTO public.flow_elements
    (fe_record_number, fe_flow_id, fe_element_type, fe_order, fe_label, fe_config, owner_id, created_by, updated_by)
  VALUES
    ('', v_flow_id, 'action', v_ord, 'Run actions',
     jsonb_build_object('actions', v_actions), v_user, v_user, v_user)
  RETURNING id INTO v_el_id;
  v_elements := v_elements || jsonb_build_object('id', v_el_id, 'type','action','order',v_ord,'actions',v_actions);

  -- Finish element.
  v_ord := v_ord + 1;
  INSERT INTO public.flow_elements
    (fe_record_number, fe_flow_id, fe_element_type, fe_order, fe_label, owner_id, created_by, updated_by)
  VALUES ('', v_flow_id, 'finish', v_ord, 'Finish', v_user, v_user, v_user)
  RETURNING id INTO v_el_id;
  v_elements := v_elements || jsonb_build_object('id', v_el_id, 'type','finish','order',v_ord);

  -- Snapshot for the runner: one read gives the whole guided task.
  v_snapshot := jsonb_build_object(
    'name', v_name,
    'launch_object', v_launch_object,
    'questions', v_questions,
    'actions', v_actions,
    'elements', v_elements);

  INSERT INTO public.flow_versions
    (fv_record_number, fv_flow_id, fv_version_number, fv_status, fv_snapshot,
     fv_published_at, fv_published_by, owner_id, created_by, updated_by)
  VALUES
    ('', v_flow_id, 1, 'published', v_snapshot, now(), v_user, v_user, v_user, v_user)
  RETURNING id INTO v_version_id;

  UPDATE public.flows
     SET flow_active_version_id = v_version_id, flow_current_version = 1, updated_by = v_user
   WHERE id = v_flow_id;

  RETURN v_flow_id;
END; $function$
;

CREATE OR REPLACE FUNCTION public.save_home_page(p_page jsonb, p_components jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user uuid; v_page_id uuid; v_elem jsonb; v_is_default boolean; v_module text;
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Editing home pages is admin-only' USING ERRCODE='insufficient_privilege';
  END IF;
  SELECT id INTO v_user FROM public.users WHERE auth_user_id = auth.uid();
  v_page_id := NULLIF(p_page->>'id','')::uuid;
  v_is_default := COALESCE((p_page->>'is_default')::boolean, false);
  v_module := NULLIF(p_page->>'module_id','');

  -- One default per module: clear others in the SAME module bucket only.
  IF v_is_default THEN
    UPDATE public.home_pages SET hp_is_default = false, hp_updated_by = v_user
      WHERE hp_is_default = true AND hp_is_deleted = false
        AND COALESCE(hp_module_id,'__global__') = COALESCE(v_module,'__global__')
        AND (v_page_id IS NULL OR id <> v_page_id);
  END IF;

  IF v_page_id IS NULL THEN
    INSERT INTO public.home_pages (hp_record_number, hp_name, hp_template, hp_role_id, hp_module_id, hp_is_active, hp_is_default, hp_created_by, hp_updated_by)
    VALUES ('', p_page->>'name', COALESCE(p_page->>'template','two_thirds_one_third'),
            NULLIF(p_page->>'role_id','')::uuid, v_module, COALESCE((p_page->>'is_active')::boolean,false), v_is_default, v_user, v_user)
    RETURNING id INTO v_page_id;
  ELSE
    UPDATE public.home_pages SET
      hp_name = p_page->>'name',
      hp_template = COALESCE(p_page->>'template', hp_template),
      hp_role_id = NULLIF(p_page->>'role_id','')::uuid,
      hp_module_id = v_module,
      hp_is_active = COALESCE((p_page->>'is_active')::boolean, hp_is_active),
      hp_is_default = v_is_default,
      hp_updated_by = v_user
    WHERE id = v_page_id;
  END IF;

  UPDATE public.home_page_components SET hpc_is_deleted = true, hpc_updated_by = v_user
    WHERE hpc_page_id = v_page_id AND hpc_is_deleted = false;

  FOR v_elem IN SELECT * FROM jsonb_array_elements(COALESCE(p_components,'[]'::jsonb))
  LOOP
    INSERT INTO public.home_page_components (hpc_record_number, hpc_page_id, hpc_region, hpc_type, hpc_source_id, hpc_title, hpc_config, hpc_sort_order, hpc_created_by, hpc_updated_by)
    VALUES ('', v_page_id, v_elem->>'region', v_elem->>'type', NULLIF(v_elem->>'source_id','')::uuid,
            v_elem->>'title', COALESCE(v_elem->'config','{}'::jsonb), COALESCE((v_elem->>'sort_order')::int,0), v_user, v_user);
  END LOOP;

  RETURN jsonb_build_object('ok', true, 'page_id', v_page_id);
END; $function$
;

CREATE OR REPLACE FUNCTION public.seed_purge_tenant_data(confirm_token text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller_user_id uuid;
  v_caller_role    text;
  v_table          text;
  v_count          bigint;
  v_dry_run        boolean := (confirm_token IS NULL OR confirm_token <> 'PURGE_ALL_SEED_DATA');
  v_result         jsonb := '{}'::jsonb;
  v_total          bigint := 0;
  v_tenant_tables  text[] := ARRAY[
    'message_ai_transcripts','message_attachments',
    'unmatched_inbox','messages','conversations',
    'envelope_events','envelope_tabs','envelope_recipients','envelopes','email_sends',
    'occurrence_participants','occurrences',
    'notification_logs','notifications',
    'comments','tasks','activities',
    'chat_messages','chat_threads',
    'gps_points','vehicle_activities','equipment_activities','asset_assignments',
    'time_sheet_entries','time_sheets',
    'job_kit_line_items','job_kits',
    'materials_request_line_items','materials_requests',
    'product_transfers','product_items',
    'work_steps','work_plans',
    'service_appointment_assignments','service_appointment_tokens','service_appointments',
    'dispatcher_followup_requests',
    'work_orders',
    'diagnostic_tests','efr_reports','assessments',
    'payment_receipts','project_payment_requests','project_reservations',
    'incentives','incentive_applications',
    'income_qualifications',
    'cfp_scenarios','cfp_projects',
    'mechanical_equipment','equipment_information',
    'opportunity_line_items','opportunity_contact_roles','opportunities',
    'property_programs','property_distances','units','buildings','properties',
    'projects',
    'documents','photos','status_change_events',
    'account_contact_relations','contacts','portal_users','accounts'
  ];
BEGIN
  SELECT u.id INTO v_caller_user_id
    FROM public.users u
   WHERE u.auth_user_id = auth.uid()
   LIMIT 1;

  IF v_caller_user_id IS NULL THEN
    RAISE EXCEPTION 'seed_purge_tenant_data: caller has no public.users record (auth.uid()=%)', auth.uid();
  END IF;

  SELECT r.role_name INTO v_caller_role
    FROM public.users u
    JOIN public.roles r ON r.id = u.role_id
   WHERE u.id = v_caller_user_id;

  IF v_caller_role IS DISTINCT FROM 'Admin' THEN
    RAISE EXCEPTION 'seed_purge_tenant_data: only Admin users can execute (caller role: %)', coalesce(v_caller_role, 'unknown');
  END IF;

  IF NOT v_dry_run THEN
    SET CONSTRAINTS ALL DEFERRED;
  END IF;

  FOREACH v_table IN ARRAY v_tenant_tables LOOP
    IF v_dry_run THEN
      EXECUTE format('SELECT count(*) FROM public.%I WHERE is_seed_data', v_table) INTO v_count;
    ELSE
      EXECUTE format('WITH d AS (DELETE FROM public.%I WHERE is_seed_data RETURNING 1) SELECT count(*) FROM d', v_table) INTO v_count;
    END IF;
    v_result := v_result || jsonb_build_object(v_table, v_count);
    v_total  := v_total + v_count;
  END LOOP;

  RETURN jsonb_build_object(
    'mode',          CASE WHEN v_dry_run THEN 'dry_run' ELSE 'purged' END,
    'total_rows',    v_total,
    'per_table',     v_result,
    'caller_user',   v_caller_user_id,
    'executed_at',   now()
  );
END
$function$
;

