CREATE OR REPLACE FUNCTION public.set_flow_active(p_flow_id uuid, p_active boolean)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF NOT app_user_can('flows','update') THEN RAISE EXCEPTION 'No update permission on flows'; END IF;
  UPDATE public.flows
     SET flow_status = CASE WHEN p_active THEN 'active' ELSE 'inactive' END,
         updated_by = current_app_user_id()
   WHERE id=p_flow_id AND is_deleted=false;
  RETURN jsonb_build_object('ok',true);
END; $function$
;

