CREATE OR REPLACE FUNCTION public.set_module_sections(p_module_id text, p_sections jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user uuid;
  v_elem jsonb;
  v_updated int := 0;
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Editing module sections is admin-only' USING ERRCODE='insufficient_privilege';
  END IF;
  SELECT id INTO v_user FROM public.users WHERE auth_user_id = auth.uid();

  FOR v_elem IN SELECT * FROM jsonb_array_elements(p_sections)
  LOOP
    UPDATE public.module_sections m
       SET ms_label      = COALESCE(v_elem->>'label', m.ms_label),
           ms_sort_order = COALESCE((v_elem->>'sort_order')::int, m.ms_sort_order),
           ms_is_visible = COALESCE((v_elem->>'is_visible')::boolean, m.ms_is_visible),
           ms_updated_by = v_user
     WHERE m.ms_module_id = p_module_id
       AND m.ms_section_id = v_elem->>'section_id'
       AND m.ms_is_deleted = false;
    IF FOUND THEN v_updated := v_updated + 1; END IF;
  END LOOP;

  RETURN jsonb_build_object('ok', true, 'updated', v_updated);
END; $function$
;

