CREATE OR REPLACE FUNCTION public.set_ocr_name()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_role_label text;
  v_contact_name text;
  v_generated text;
BEGIN
  SELECT pv.picklist_label INTO v_role_label
  FROM public.picklist_values pv
  WHERE pv.id = NEW.ocr_role;

  SELECT c.contact_name INTO v_contact_name
  FROM public.contacts c
  WHERE c.id = NEW.contact_id;

  v_generated := trim(both ' ' FROM
    concat_ws(' — ', NULLIF(v_role_label,''), NULLIF(v_contact_name,'')));

  IF v_generated IS NULL OR v_generated = '' THEN
    v_generated := COALESCE(NULLIF(NEW.ocr_record_number,''), 'Contact Role');
  END IF;

  -- Set on insert always; on update only refresh if the stored name was blank
  -- or itself a generated value (contains the em-dash separator or equals the
  -- record number), so we never clobber a deliberate manual override.
  IF TG_OP = 'INSERT' THEN
    IF NEW.ocr_name IS NULL OR NEW.ocr_name = '' THEN
      NEW.ocr_name := v_generated;
    END IF;
  ELSE
    IF NEW.ocr_name IS NULL OR NEW.ocr_name = ''
       OR NEW.ocr_name = OLD.ocr_name THEN
      NEW.ocr_name := v_generated;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

