CREATE OR REPLACE FUNCTION public.set_record_type_picklist_values(p_record_type_id uuid, p_object text, p_field text, p_value_ids uuid[])
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user uuid;
  v_keep uuid[] := COALESCE(p_value_ids, ARRAY[]::uuid[]);
  v_added int := 0; v_removed int := 0;
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Managing record-type picklist availability is admin-only'
      USING ERRCODE='insufficient_privilege';
  END IF;
  SELECT id INTO v_user FROM public.users WHERE auth_user_id = auth.uid();

  -- Soft-delete assignments for this RT+field whose value is no longer in the set.
  UPDATE public.picklist_value_record_type_assignments a
     SET pvrta_is_deleted = true, pvrta_deleted_at = now(), pvrta_deleted_by = v_user,
         pvrta_deletion_reason = 'removed via record-type picklist editor'
   WHERE a.pvrta_record_type_id = p_record_type_id
     AND a.pvrta_is_deleted = false
     AND a.pvrta_picklist_value_id IN (
        SELECT pv.id FROM public.picklist_values pv
         WHERE pv.picklist_object = p_object AND pv.picklist_field = p_field
     )
     AND NOT (a.pvrta_picklist_value_id = ANY(v_keep));
  GET DIAGNOSTICS v_removed = ROW_COUNT;

  -- Revive any soft-deleted rows that are back in the set.
  UPDATE public.picklist_value_record_type_assignments a
     SET pvrta_is_deleted = false, pvrta_deleted_at = NULL, pvrta_deleted_by = NULL,
         pvrta_deletion_reason = NULL, pvrta_updated_by = v_user
   WHERE a.pvrta_record_type_id = p_record_type_id
     AND a.pvrta_is_deleted = true
     AND a.pvrta_picklist_value_id = ANY(v_keep);

  -- Insert assignments that don't exist at all yet.
  INSERT INTO public.picklist_value_record_type_assignments
    (pvrta_record_number, pvrta_picklist_value_id, pvrta_record_type_id, pvrta_owner, pvrta_created_by, pvrta_updated_by)
  SELECT '', vid, p_record_type_id, v_user, v_user, v_user
    FROM unnest(v_keep) AS vid
   WHERE NOT EXISTS (
     SELECT 1 FROM public.picklist_value_record_type_assignments a
      WHERE a.pvrta_record_type_id = p_record_type_id
        AND a.pvrta_picklist_value_id = vid
   );
  GET DIAGNOSTICS v_added = ROW_COUNT;

  RETURN jsonb_build_object('ok', true, 'added', v_added, 'removed', v_removed,
                            'available_count', array_length(v_keep,1));
END; $function$
;

