CREATE OR REPLACE FUNCTION public.set_work_step_approval(p_step_id uuid, p_tier text, p_approved boolean, p_comment text DEFAULT NULL::text)
 RETURNS TABLE(step_id uuid, tier text, verdict text, outcome text, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_actor   uuid := public.current_app_user_id();
  v_step    public.work_steps;
  v_field   text;
  v_cfield  text;
  v_pv      uuid;
  v_verdict text := CASE WHEN p_approved THEN 'Approved' ELSE 'Rejected' END;
BEGIN
  IF lower(p_tier) NOT IN ('pc','psl') THEN
    RETURN QUERY SELECT p_step_id, p_tier, NULL::text, 'error', 'p_tier must be ''pc'' or ''psl'''; RETURN;
  END IF;

  SELECT * INTO v_step FROM public.work_steps WHERE id = p_step_id AND work_step_is_deleted IS NOT TRUE;
  IF v_step.id IS NULL THEN
    RETURN QUERY SELECT p_step_id, p_tier, NULL::text, 'error', 'Work step not found or deleted'; RETURN;
  END IF;

  v_actor := COALESCE(v_actor, v_step.work_step_owner, v_step.work_step_created_by);
  v_field  := format('work_step_%s_approval_status', lower(p_tier));
  v_cfield := format('work_step_%s_comment', lower(p_tier));

  SELECT id INTO v_pv FROM public.picklist_values
   WHERE picklist_object='work_steps' AND picklist_field=v_field
     AND picklist_value=v_verdict AND picklist_is_active LIMIT 1;
  IF v_pv IS NULL THEN
    RETURN QUERY SELECT p_step_id, p_tier, v_verdict, 'error',
      format('No picklist value "%s" on %s', v_verdict, v_field); RETURN;
  END IF;

  EXECUTE format(
    'UPDATE public.work_steps SET %I=$1, %I=$2, work_step_updated_by=$3, work_step_updated_at=now() WHERE id=$4',
    v_field, v_cfield)
  USING v_pv, NULLIF(btrim(p_comment),''), v_actor, p_step_id;

  RETURN QUERY SELECT p_step_id, lower(p_tier), v_verdict, 'success',
    format('Step "%s" %s by %s', v_step.work_step_name, v_verdict, upper(p_tier));
END;
$function$
;

