CREATE OR REPLACE FUNCTION public.submit_work_order_for_verification(p_wo_id uuid)
 RETURNS TABLE(wo_id uuid, status text, outcome text, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_wo            public.work_orders;
  v_cur           text;
  v_to_verify     uuid;
  v_open_count    integer := 0;
  v_first_gap     text;
  v_res           jsonb;
BEGIN
  SELECT * INTO v_wo FROM public.work_orders WHERE id = p_wo_id AND work_order_is_deleted IS NOT TRUE;
  IF v_wo.id IS NULL THEN
    RETURN QUERY SELECT p_wo_id, NULL::text, 'error', 'Work order not found or deleted'; RETURN;
  END IF;

  SELECT picklist_value INTO v_cur FROM public.picklist_values WHERE id = v_wo.work_order_status;
  IF v_cur <> 'In Progress' THEN
    RETURN QUERY SELECT p_wo_id, v_cur, 'blocked',
      format('Work order is "%s". Only a work order In Progress can be submitted for verification. Begin work on the work order first.', COALESCE(v_cur,'(no status)'));
    RETURN;
  END IF;

  -- Any step not Completed/Verified/Not Applicable blocks submission.
  SELECT count(*) INTO v_open_count
  FROM public.work_steps ws
  JOIN public.picklist_values pv ON pv.id = ws.work_step_status
  WHERE ws.work_order_id = p_wo_id AND ws.work_step_is_deleted IS NOT TRUE
    AND pv.picklist_value NOT IN ('Completed','Verified','Not Applicable');

  IF v_open_count > 0 THEN
    -- Surface the first concrete evidence gap if one exists; else the count.
    SELECT public._work_step_evidence_gap(ws) INTO v_first_gap
    FROM public.work_steps ws
    JOIN public.picklist_values pv ON pv.id = ws.work_step_status
    WHERE ws.work_order_id = p_wo_id AND ws.work_step_is_deleted IS NOT TRUE
      AND pv.picklist_value NOT IN ('Completed','Verified','Not Applicable')
      AND public._work_step_evidence_gap(ws) IS NOT NULL
    ORDER BY ws.work_step_execution_order LIMIT 1;

    RETURN QUERY SELECT p_wo_id, v_cur, 'blocked',
      COALESCE(v_first_gap,
        format('%s work step(s) are not yet complete. Complete all required steps before submitting for verification.', v_open_count));
    RETURN;
  END IF;

  SELECT id INTO v_to_verify FROM public.picklist_values
   WHERE picklist_object='work_orders' AND picklist_field='work_order_status'
     AND picklist_value='To Be Verified' AND picklist_is_active LIMIT 1;

  v_res := public.change_record_status('work_orders', p_wo_id, 'work_order_status', v_to_verify,
            'Submitted for verification');

  RETURN QUERY SELECT p_wo_id, 'To Be Verified', 'success',
    format('Work order %s submitted for verification', v_wo.work_order_record_number);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.team_leads_qualified_for_work_orders(p_work_order_ids uuid[], p_start_date date)
 RETURNS TABLE(contact_id uuid, full_name text, contact_title text, crew_label text, qualified boolean, missing_certs text, resource_source text, user_id uuid)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF public.current_app_user_id() IS NULL THEN
    RAISE EXCEPTION 'team_leads_qualified_for_work_orders: caller not authenticated' USING ERRCODE='28000';
  END IF;

  RETURN QUERY
  WITH leads AS (
    SELECT c.id, c.contact_first_name, c.contact_last_name, c.contact_title
      FROM contacts c
     WHERE c.contact_is_deleted = false
       AND c.contact_title ILIKE '%team lead%'
  ),
  required AS (
    SELECT DISTINCT cert.id AS cert_id, cert.certification_name
      FROM unnest(COALESCE(p_work_order_ids, ARRAY[]::uuid[])) AS uw(wo_id)
      JOIN work_orders wo ON wo.id = uw.wo_id
      JOIN work_type_required_certifications wtrc
        ON wtrc.work_type_id = wo.work_type_id AND wtrc.wtrc_is_deleted = false
      JOIN certifications cert
        ON cert.id = wtrc.certification_id
       AND COALESCE(cert.certification_is_active, true) = true
       AND COALESCE(cert.certification_is_deleted, false) = false
  ),
  per_lead_missing AS (
    SELECT l.id AS contact_id,
           r.cert_id, r.certification_name,
           EXISTS (
             SELECT 1 FROM contact_certifications cc
              WHERE cc.contact_id = l.id
                AND cc.certification_id = r.cert_id
                AND COALESCE(cc.cc_is_deleted, false) = false
                AND (cc.cc_expires_date IS NULL OR cc.cc_expires_date >= p_start_date)
           ) AS held
      FROM leads l CROSS JOIN required r
  ),
  per_lead_summary AS (
    SELECT pm.contact_id,
           string_agg(pm.certification_name, ', ' ORDER BY pm.certification_name)
             FILTER (WHERE NOT pm.held) AS missing_certs
      FROM per_lead_missing pm
     GROUP BY pm.contact_id
  ),
  contact_leads AS (
    SELECT l.id AS contact_id,
           TRIM(BOTH ' ' FROM COALESCE(l.contact_first_name,'') || ' ' || COALESCE(l.contact_last_name,'')) AS full_name,
           l.contact_title,
           CASE
             WHEN l.contact_title ILIKE '%—%'
               THEN TRIM(BOTH ' ' FROM SPLIT_PART(l.contact_title, '—', 2))
             WHEN l.contact_title ILIKE '%-%'
               THEN TRIM(BOTH ' ' FROM SPLIT_PART(l.contact_title, '-', 2))
             ELSE NULL
           END AS crew_label,
           COALESCE(s.missing_certs, '') = '' AS qualified,
           s.missing_certs,
           'contact'::text AS resource_source,
           NULL::uuid AS user_id,
           l.contact_last_name AS sort_last,
           l.contact_first_name AS sort_first
      FROM leads l
      LEFT JOIN per_lead_summary s ON s.contact_id = l.id
  ),
  user_leads AS (
    SELECT NULL::uuid AS contact_id,
           u.user_name AS full_name,
           u.user_title AS contact_title,
           CASE
             WHEN u.user_title ILIKE '%—%' THEN TRIM(BOTH ' ' FROM SPLIT_PART(u.user_title, '—', 2))
             WHEN u.user_title ILIKE '%-%' THEN TRIM(BOTH ' ' FROM SPLIT_PART(u.user_title, '-', 2))
             ELSE NULL
           END AS crew_label,
           true AS qualified,           -- user certs not gated yet (later phase)
           NULL::text AS missing_certs,
           'user'::text AS resource_source,
           u.id AS user_id,
           u.user_last_name AS sort_last,
           u.user_first_name AS sort_first
      FROM users u
      JOIN roles r ON r.id = u.role_id
     WHERE u.user_is_deleted = false
       AND u.user_is_active = true
       AND r.role_name = 'Team Lead'
  ),
  combined AS (
    SELECT * FROM contact_leads
    UNION ALL
    SELECT * FROM user_leads
  )
  SELECT combined.contact_id, combined.full_name, combined.contact_title,
         combined.crew_label, combined.qualified, combined.missing_certs,
         combined.resource_source, combined.user_id
    FROM combined
   ORDER BY combined.qualified DESC, combined.sort_last, combined.sort_first;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.technicians_in_territory(p_territory_id uuid)
 RETURNS TABLE(contact_id uuid)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT DISTINCT c.id AS contact_id
  FROM contacts c
  JOIN picklist_values pv ON pv.id = c.contact_record_type
                          AND pv.picklist_object = 'contacts'
                          AND pv.picklist_field  = 'record_type'
                          AND pv.picklist_value  = 'Technician'
  WHERE c.contact_is_deleted = false
    AND COALESCE(c.contact_inactive, false) = false
    AND (
      c.contact_service_territory_id = p_territory_id
      OR EXISTS (
        SELECT 1 FROM service_territory_members stm
        WHERE stm.contact_id = c.id
          AND stm.service_territory_id = p_territory_id
          AND stm.stm_is_deleted = false
      )
    );
$function$
;

