CREATE OR REPLACE FUNCTION public.trg_buildings_recompute_rollups()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_property_ids uuid[] := ARRAY[]::uuid[];
  v_account_ids uuid[] := ARRAY[]::uuid[];
  v_pid uuid;
BEGIN
  IF TG_OP = 'INSERT' THEN
    v_property_ids := ARRAY[NEW.property_id];
  ELSIF TG_OP = 'UPDATE' THEN
    IF NEW.property_id IS DISTINCT FROM OLD.property_id THEN
      v_property_ids := ARRAY[OLD.property_id, NEW.property_id];
    ELSE
      v_property_ids := ARRAY[NEW.property_id];
    END IF;
  ELSIF TG_OP = 'DELETE' THEN
    v_property_ids := ARRAY[OLD.property_id];
  END IF;

  FOREACH v_pid IN ARRAY v_property_ids LOOP
    IF v_pid IS NOT NULL THEN
      PERFORM recompute_property_rollups(v_pid);
      v_account_ids := v_account_ids || (
        SELECT property_account_id FROM properties WHERE id = v_pid
      );
    END IF;
  END LOOP;

  FOREACH v_pid IN ARRAY v_account_ids LOOP
    IF v_pid IS NOT NULL THEN
      PERFORM recompute_account_rollups(v_pid);
    END IF;
  END LOOP;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

