CREATE OR REPLACE FUNCTION public.trg_opportunities_recompute_rollups()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_account_ids uuid[] := ARRAY[]::uuid[];
  v_aid uuid;
BEGIN
  IF TG_OP = 'INSERT' THEN
    v_account_ids := ARRAY[NEW.opportunity_account_id];
  ELSIF TG_OP = 'UPDATE' THEN
    IF NEW.opportunity_account_id IS DISTINCT FROM OLD.opportunity_account_id THEN
      v_account_ids := ARRAY[OLD.opportunity_account_id, NEW.opportunity_account_id];
    ELSE
      v_account_ids := ARRAY[NEW.opportunity_account_id];
    END IF;
  ELSIF TG_OP = 'DELETE' THEN
    v_account_ids := ARRAY[OLD.opportunity_account_id];
  END IF;

  FOREACH v_aid IN ARRAY v_account_ids LOOP
    IF v_aid IS NOT NULL THEN
      PERFORM recompute_account_rollups(v_aid);
    END IF;
  END LOOP;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

