CREATE OR REPLACE FUNCTION public.trg_sa_fire_booking_confirmation()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  -- Skip soft-deleted inserts (shouldn't happen normally; defensive).
  if NEW.sa_is_deleted then return null; end if;
  -- Skip when no customer is attached — synthetic seed SAs (bulk-schedule
  -- output, dispatcher-created internal-only SAs) won't have a contact
  -- to notify. The orchestrator would also no-op in this case, but
  -- short-circuiting at the trigger avoids an unnecessary HTTP call.
  if NEW.contact_id is null then return null; end if;

  perform public.enqueue_notification(NEW.id, 'booking_confirmation', null);
  return null;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.trg_sa_fire_status_or_reschedule()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_old_status text;
  v_new_status text;
  v_event      text;
begin
  -- Don't fire on soft-delete; that's an admin action, not a lifecycle event.
  if NEW.sa_is_deleted then return null; end if;
  -- No customer = no notification (same logic as INSERT path).
  if NEW.contact_id is null then return null; end if;

  -- Status change? Look up labels for both sides; only fire when the
  -- new status is one of the mapped values.
  if NEW.sa_status is distinct from OLD.sa_status then
    select picklist_value into v_old_status from picklist_values where id = OLD.sa_status;
    select picklist_value into v_new_status from picklist_values where id = NEW.sa_status;

    v_event := case v_new_status
      when 'En Route'  then 'on_my_way'
      when 'Arrived'   then 'arrived'
      when 'Completed' then 'completed'
      when 'Canceled'  then 'canceled'
      else null
    end;

    if v_event is not null then
      perform public.enqueue_notification(NEW.id, v_event, null);
    end if;
    -- Status change always supersedes — don't also fire reschedule.
    return null;
  end if;

  -- No status change but the schedule time moved → reschedule.
  if NEW.sa_scheduled_start_time is distinct from OLD.sa_scheduled_start_time then
    perform public.enqueue_notification(NEW.id, 'rescheduled', null);
  end if;

  return null;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.trg_task_create_notification()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_creator_user uuid;
  v_owner_user   uuid;
  v_title        text;
  v_body         text;
  v_rel_object   text;
  v_rel_id       uuid;
BEGIN
  -- Pick up the right owner / creator depending on trigger type
  v_owner_user := NEW.owner_id;
  v_creator_user := NEW.created_by_id;

  -- Don't notify on self-assignments (creator == owner) or unassigned tasks
  IF v_owner_user IS NULL THEN RETURN NEW; END IF;
  IF v_owner_user = v_creator_user THEN RETURN NEW; END IF;

  -- On UPDATE, only fire if the owner actually changed to a new person
  IF TG_OP = 'UPDATE' AND OLD.owner_id IS NOT DISTINCT FROM NEW.owner_id THEN
    RETURN NEW;
  END IF;

  -- Title / body composition. The task may or may not have a related record.
  IF NEW.is_automated THEN
    v_title := 'Task assigned by automation: ' || coalesce(NEW.subject, 'Untitled task');
  ELSE
    v_title := 'New task assigned: ' || coalesce(NEW.subject, 'Untitled task');
  END IF;
  v_body := coalesce(NEW.description, '');
  IF NEW.due_date IS NOT NULL THEN
    v_body := trim(both E'\n' from v_body || E'\nDue: ' || to_char(NEW.due_date, 'YYYY-MM-DD'));
  END IF;

  -- Prefer to link back to the source record (e.g. the work order) so the
  -- user lands where the work actually happens. Fall back to the task itself.
  IF NEW.related_object IS NOT NULL AND NEW.related_id IS NOT NULL THEN
    v_rel_object := NEW.related_object;
    v_rel_id     := NEW.related_id;
  ELSE
    v_rel_object := 'tasks';
    v_rel_id     := NEW.id;
  END IF;

  INSERT INTO notifications (
    recipient_id, notification_type, title, body,
    related_object, related_id, channel,
    is_read, is_sent, triggered_by, is_automated, is_seed_data
  ) VALUES (
    v_owner_user,
    CASE WHEN TG_OP = 'INSERT' THEN 'task_assigned' ELSE 'task_reassigned' END,
    v_title, NULLIF(v_body, ''),
    v_rel_object, v_rel_id,
    'in_app',
    false, true, v_creator_user, NEW.is_automated, false
  );

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trg_units_recompute_rollups()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_building_ids uuid[] := ARRAY[]::uuid[];
  v_property_ids uuid[] := ARRAY[]::uuid[];
  v_account_ids uuid[] := ARRAY[]::uuid[];
  v_bid uuid;
BEGIN
  IF TG_OP = 'INSERT' THEN
    v_building_ids := ARRAY[NEW.building_id];
  ELSIF TG_OP = 'UPDATE' THEN
    IF NEW.building_id IS DISTINCT FROM OLD.building_id THEN
      v_building_ids := ARRAY[OLD.building_id, NEW.building_id];
    ELSE
      v_building_ids := ARRAY[NEW.building_id];
    END IF;
  ELSIF TG_OP = 'DELETE' THEN
    v_building_ids := ARRAY[OLD.building_id];
  END IF;

  -- Walk chain: building → property → account
  FOREACH v_bid IN ARRAY v_building_ids LOOP
    IF v_bid IS NOT NULL THEN
      PERFORM recompute_building_rollups(v_bid);
      v_property_ids := v_property_ids || (
        SELECT property_id FROM buildings WHERE id = v_bid
      );
    END IF;
  END LOOP;

  FOREACH v_bid IN ARRAY v_property_ids LOOP
    IF v_bid IS NOT NULL THEN
      PERFORM recompute_property_rollups(v_bid);
      v_account_ids := v_account_ids || (
        SELECT property_account_id FROM properties WHERE id = v_bid
      );
    END IF;
  END LOOP;

  FOREACH v_bid IN ARRAY v_account_ids LOOP
    IF v_bid IS NOT NULL THEN
      PERFORM recompute_account_rollups(v_bid);
    END IF;
  END LOOP;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trg_units_rollup()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF TG_OP = 'INSERT' THEN
    PERFORM recompute_building_rollups(NEW.building_id);
  ELSIF TG_OP = 'DELETE' THEN
    PERFORM recompute_building_rollups(OLD.building_id);
  ELSE
    PERFORM recompute_building_rollups(NEW.building_id);
    IF OLD.building_id IS DISTINCT FROM NEW.building_id THEN
      PERFORM recompute_building_rollups(OLD.building_id);
    END IF;
  END IF;
  RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.unpublish_document_template(p_document_template_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller   uuid := public.current_app_user_id();
  v_current  text;
  v_draft_id uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'unpublish_document_template: must be authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT public._dt_status_value(status) INTO v_current
  FROM public.document_templates WHERE id = p_document_template_id AND NOT is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'unpublish_document_template: template not found';
  END IF;
  IF v_current IS DISTINCT FROM 'Active' THEN
    RAISE EXCEPTION 'unpublish_document_template: template is not Active (status: %)', v_current;
  END IF;

  SELECT id INTO v_draft_id FROM public.picklist_values
  WHERE picklist_object='document_templates' AND picklist_field='status'
    AND picklist_value='Draft' AND picklist_is_active=true LIMIT 1;

  UPDATE public.document_templates
  SET status = v_draft_id, updated_by = v_caller, updated_at = now()
  WHERE id = p_document_template_id;

  RETURN jsonb_build_object('ok', true, 'document_template_id', p_document_template_id, 'new_status', 'Draft');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.unpublish_email_template(p_email_template_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller   uuid := public.current_app_user_id();
  v_current  text;
  v_draft_id uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'unpublish_email_template: must be authenticated' USING ERRCODE = '42501';
  END IF;

  SELECT public._et_status_value(status) INTO v_current
  FROM public.email_templates WHERE id = p_email_template_id AND NOT is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'unpublish_email_template: template not found';
  END IF;
  IF v_current IS DISTINCT FROM 'Active' THEN
    RAISE EXCEPTION 'unpublish_email_template: template is not Active (status: %)', v_current;
  END IF;

  SELECT id INTO v_draft_id FROM public.picklist_values
  WHERE picklist_object='email_templates' AND picklist_field='status'
    AND picklist_value='Draft' AND picklist_is_active=true LIMIT 1;

  UPDATE public.email_templates
  SET status = v_draft_id, updated_by = v_caller, updated_at = now()
  WHERE id = p_email_template_id;

  RETURN jsonb_build_object('ok', true, 'email_template_id', p_email_template_id, 'new_status', 'Draft');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.unpublish_project_report_template(p_prt_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_caller uuid := public.current_app_user_id();
  v_current text;
  v_draft_id uuid;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'unpublish: must be authenticated as a registered user' USING ERRCODE = '42501';
  END IF;

  SELECT _prt_status_value(prt_status) INTO v_current
  FROM project_report_templates
  WHERE id = p_prt_id AND NOT prt_is_deleted;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'unpublish: template not found';
  END IF;
  IF v_current IS DISTINCT FROM 'Active' THEN
    RAISE EXCEPTION 'unpublish: template is not Active (status: %)', v_current;
  END IF;

  SELECT id INTO v_draft_id
  FROM picklist_values
  WHERE picklist_object='project_report_templates'
    AND picklist_field='prt_status'
    AND picklist_value='Draft'
    AND picklist_is_active=true
  LIMIT 1;
  IF v_draft_id IS NULL THEN
    RAISE EXCEPTION 'unpublish: Draft status not configured';
  END IF;

  UPDATE project_report_templates SET
    prt_status = v_draft_id,
    prt_updated_by = v_caller,
    prt_updated_at = now()
  WHERE id = p_prt_id;

  RETURN jsonb_build_object('ok', true, 'prt_id', p_prt_id, 'new_status', 'Draft');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_conversation_on_message_insert()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
begin
  update public.conversations
  set
    conv_last_message_at         = new.msg_created_at,
    conv_last_message_direction  = new.msg_direction,
    conv_last_message_preview    = left(coalesce(new.msg_body, ''), 200),
    conv_inbound_unread_count    = case
                                     when new.msg_direction = 'inbound'
                                       then conv_inbound_unread_count + 1
                                     else conv_inbound_unread_count
                                   end,
    conv_updated_at              = now()
  where id = new.conversation_id;
  return new;
end $function$
;

CREATE OR REPLACE FUNCTION public.update_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_page_layout_widget_config()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
declare
  v_parent_table text;
  v_field_name   text;
  v_child_table  text;
  v_fk_column    text;
  v_col_name     text;
begin
  -- Skip validation on soft-delete updates -- we don't want a layout
  -- author to be unable to delete a widget that was already broken.
  if tg_op = 'UPDATE' and new.is_deleted = true and old.is_deleted = false then
    return new;
  end if;

  -- The parent table is on the layout, not the widget. We must look it up.
  select pl.page_layout_object into v_parent_table
  from public.page_layouts pl
  where pl.id = new.page_layout_id;

  if v_parent_table is null then
    -- Layout doesn't exist or was deleted -- defer to FK constraint
    return new;
  end if;

  -- ─── field_group: validate every fields[].name exists on parent ──────
  if new.widget_type = 'field_group' and new.widget_config ? 'fields' then
    for v_field_name in
      select jsonb_extract_path_text(f, 'name')
      from jsonb_array_elements(new.widget_config->'fields') f
      where jsonb_extract_path_text(f, 'name') is not null
        and jsonb_extract_path_text(f, 'name') <> ''
    loop
      if not exists (
        select 1
        from information_schema.columns
        where table_schema = 'public'
          and table_name   = v_parent_table
          and column_name  = v_field_name
      ) then
        raise exception
          'page layout widget %.%: field_group references column "%" which does not exist on table "%"',
          new.page_layout_id, coalesce(new.widget_title, '(untitled)'),
          v_field_name, v_parent_table
        using errcode = '22023';  -- invalid_parameter_value
      end if;
    end loop;
  end if;

  -- ─── related_list: validate table, fk, and every columns[].name ──────
  if new.widget_type = 'related_list' then
    v_child_table := new.widget_config->>'table';
    v_fk_column   := new.widget_config->>'fk';

    if v_child_table is null or v_child_table = '' then
      raise exception
        'page layout widget %.%: related_list missing widget_config.table',
        new.page_layout_id, coalesce(new.widget_title, '(untitled)')
      using errcode = '22023';
    end if;

    if not exists (
      select 1 from information_schema.tables
      where table_schema = 'public' and table_name = v_child_table
    ) then
      raise exception
        'page layout widget %.%: related_list references child table "%" which does not exist',
        new.page_layout_id, coalesce(new.widget_title, '(untitled)'), v_child_table
      using errcode = '22023';
    end if;

    if v_fk_column is null or v_fk_column = '' then
      raise exception
        'page layout widget %.%: related_list missing widget_config.fk',
        new.page_layout_id, coalesce(new.widget_title, '(untitled)')
      using errcode = '22023';
    end if;

    if not exists (
      select 1 from information_schema.columns
      where table_schema = 'public'
        and table_name   = v_child_table
        and column_name  = v_fk_column
    ) then
      raise exception
        'page layout widget %.%: related_list FK column "%" does not exist on child table "%"',
        new.page_layout_id, coalesce(new.widget_title, '(untitled)'),
        v_fk_column, v_child_table
      using errcode = '22023';
    end if;

    -- Validate each columns[].name
    if new.widget_config ? 'columns' then
      for v_col_name in
        select jsonb_extract_path_text(c, 'name')
        from jsonb_array_elements(new.widget_config->'columns') c
        where jsonb_extract_path_text(c, 'name') is not null
          and jsonb_extract_path_text(c, 'name') <> ''
      loop
        if not exists (
          select 1 from information_schema.columns
          where table_schema = 'public'
            and table_name   = v_child_table
            and column_name  = v_col_name
        ) then
          raise exception
            'page layout widget %.%: related_list column "%" does not exist on child table "%"',
            new.page_layout_id, coalesce(new.widget_title, '(untitled)'),
            v_col_name, v_child_table
          using errcode = '22023';
        end if;
      end loop;
    end if;
  end if;

  return new;
end$function$
;

CREATE OR REPLACE FUNCTION public.validate_status_transition_endpoints()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_to_object   text;
  v_to_field    text;
  v_from_object text;
  v_from_field  text;
BEGIN
  -- to-status is required and must match
  SELECT picklist_object, picklist_field INTO v_to_object, v_to_field
  FROM public.picklist_values WHERE id = NEW.st_to_status_id;
  IF v_to_object IS NULL THEN
    RAISE EXCEPTION 'st_to_status_id does not reference an existing picklist value';
  END IF;
  IF v_to_object <> NEW.st_object OR v_to_field <> NEW.st_status_field THEN
    RAISE EXCEPTION 'st_to_status_id picklist is on (%, %) but transition is on (%, %)',
      v_to_object, v_to_field, NEW.st_object, NEW.st_status_field;
  END IF;
  -- from-status is optional; if set must match
  IF NEW.st_from_status_id IS NOT NULL THEN
    SELECT picklist_object, picklist_field INTO v_from_object, v_from_field
    FROM public.picklist_values WHERE id = NEW.st_from_status_id;
    IF v_from_object IS NULL THEN
      RAISE EXCEPTION 'st_from_status_id does not reference an existing picklist value';
    END IF;
    IF v_from_object <> NEW.st_object OR v_from_field <> NEW.st_status_field THEN
      RAISE EXCEPTION 'st_from_status_id picklist is on (%, %) but transition is on (%, %)',
        v_from_object, v_from_field, NEW.st_object, NEW.st_status_field;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.verify_work_order(p_wo_id uuid, p_tier text, p_note text DEFAULT NULL::text)
 RETURNS TABLE(wo_id uuid, status text, outcome text, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_wo          public.work_orders;
  v_cur         text;
  v_field       text;
  v_total       integer := 0;
  v_approved    integer := 0;
  v_rejected    integer := 0;
  v_target      uuid;
  v_cn_step     uuid;
  v_res         jsonb;
BEGIN
  IF lower(p_tier) NOT IN ('pc','psl') THEN
    RETURN QUERY SELECT p_wo_id, NULL::text, 'error', 'p_tier must be ''pc'' or ''psl'''; RETURN;
  END IF;

  SELECT * INTO v_wo FROM public.work_orders WHERE id = p_wo_id AND work_order_is_deleted IS NOT TRUE;
  IF v_wo.id IS NULL THEN
    RETURN QUERY SELECT p_wo_id, NULL::text, 'error', 'Work order not found or deleted'; RETURN;
  END IF;

  SELECT picklist_value INTO v_cur FROM public.picklist_values WHERE id = v_wo.work_order_status;
  IF v_cur <> 'To Be Verified' THEN
    RETURN QUERY SELECT p_wo_id, v_cur, 'blocked',
      format('Work order is "%s". Only a work order To Be Verified can be verified.', COALESCE(v_cur,'(no status)'));
    RETURN;
  END IF;

  v_field := format('work_step_%s_approval_status', lower(p_tier));

  EXECUTE format($q$
    SELECT
      count(*) FILTER (WHERE pv.picklist_value IS DISTINCT FROM 'Not Applicable'),
      count(*) FILTER (WHERE av.picklist_value = 'Approved'),
      count(*) FILTER (WHERE av.picklist_value = 'Rejected')
    FROM public.work_steps ws
    JOIN public.picklist_values pv ON pv.id = ws.work_step_status
    LEFT JOIN public.picklist_values av ON av.id = ws.%I
    WHERE ws.work_order_id = $1 AND ws.work_step_is_deleted IS NOT TRUE
      AND pv.picklist_value IS DISTINCT FROM 'Not Applicable'
  $q$, v_field)
  INTO v_total, v_approved, v_rejected USING p_wo_id;

  IF v_total = 0 THEN
    RETURN QUERY SELECT p_wo_id, v_cur, 'blocked', 'No verifiable work steps on this work order.'; RETURN;
  END IF;

  IF v_rejected > 0 THEN
    -- Flag rejected steps back to the crew, then move WO to Corrections Needed.
    SELECT id INTO v_cn_step FROM public.picklist_values
     WHERE picklist_object='work_steps' AND picklist_field='work_step_status'
       AND picklist_value='Corrections Needed' AND picklist_is_active LIMIT 1;

    EXECUTE format(
      'UPDATE public.work_steps SET work_step_status=$1, work_step_updated_at=now() '
      || 'WHERE work_order_id=$2 AND work_step_is_deleted IS NOT TRUE AND %I = '
      || '(SELECT id FROM public.picklist_values WHERE picklist_object=''work_steps'' AND picklist_field=$3 AND picklist_value=''Rejected'' LIMIT 1)',
      v_field)
    USING v_cn_step, p_wo_id, v_field;

    SELECT id INTO v_target FROM public.picklist_values
     WHERE picklist_object='work_orders' AND picklist_field='work_order_status'
       AND picklist_value='Corrections Needed' AND picklist_is_active LIMIT 1;

    v_res := public.change_record_status('work_orders', p_wo_id, 'work_order_status', v_target,
              COALESCE(p_note, format('%s rejected %s step(s); sent back for corrections', upper(p_tier), v_rejected)));

    RETURN QUERY SELECT p_wo_id, 'Corrections Needed', 'corrections',
      format('Work order %s sent back: %s of %s step(s) rejected by %s', v_wo.work_order_record_number, v_rejected, v_total, upper(p_tier));
    RETURN;
  END IF;

  IF v_approved < v_total THEN
    RETURN QUERY SELECT p_wo_id, v_cur, 'blocked',
      format('%s of %s step(s) approved by %s. Approve every step before verifying the work order.', v_approved, v_total, upper(p_tier));
    RETURN;
  END IF;

  -- All approved -> Verified.
  SELECT id INTO v_target FROM public.picklist_values
   WHERE picklist_object='work_orders' AND picklist_field='work_order_status'
     AND picklist_value='Verified' AND picklist_is_active LIMIT 1;

  v_res := public.change_record_status('work_orders', p_wo_id, 'work_order_status', v_target,
            COALESCE(p_note, format('All %s step(s) approved by %s', v_total, upper(p_tier))));

  RETURN QUERY SELECT p_wo_id, 'Verified', 'success',
    format('Work order %s verified (%s step(s) approved by %s)', v_wo.work_order_record_number, v_total, upper(p_tier));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.void_envelope(p_envelope_id uuid, p_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller_user_id uuid;
  v_env            record;
  v_status_value   text;
  v_voided_id      uuid;
  v_event_rt_id    uuid;
  v_event_type_id  uuid;
  v_now            timestamptz := now();
  v_reason         text := NULLIF(BTRIM(COALESCE(p_reason, '')), '');
  v_is_office_side boolean;
BEGIN
  IF p_envelope_id IS NULL THEN
    RAISE EXCEPTION 'p_envelope_id required' USING ERRCODE = '22023';
  END IF;
  IF v_reason IS NULL THEN
    RAISE EXCEPTION 'p_reason required (a void reason must be supplied)' USING ERRCODE = '22023';
  END IF;

  v_caller_user_id := public.current_app_user_id();
  IF v_caller_user_id IS NULL THEN
    RAISE EXCEPTION 'Caller is not authenticated' USING ERRCODE = '28000';
  END IF;
  v_is_office_side := COALESCE(public.app_is_office_side(), false);

  SELECT e.id, e.env_owner, e.env_status, ps.picklist_value AS status_value
    INTO v_env
  FROM public.envelopes e
  JOIN public.picklist_values ps ON ps.id = e.env_status
  WHERE e.id = p_envelope_id
    AND COALESCE(e.is_deleted, false) = false;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Envelope not found or deleted: %', p_envelope_id USING ERRCODE = '02000';
  END IF;

  IF NOT v_is_office_side AND v_env.env_owner <> v_caller_user_id THEN
    RAISE EXCEPTION 'Only the envelope owner or an office-side user may void this envelope'
      USING ERRCODE = '42501';
  END IF;

  v_status_value := v_env.status_value;
  IF v_status_value NOT IN ('Draft','Sent','Delivered','Failed') THEN
    RAISE EXCEPTION 'Cannot void envelope in status %: only Draft / Sent / Delivered / Failed are voidable',
      v_status_value USING ERRCODE = '22023';
  END IF;

  SELECT id INTO v_voided_id
  FROM public.picklist_values
  WHERE picklist_object='envelopes' AND picklist_field='env_status'
    AND picklist_value='Voided' AND picklist_is_active=true;
  IF v_voided_id IS NULL THEN
    RAISE EXCEPTION 'Picklist value envelopes.env_status=Voided not found';
  END IF;

  SELECT id INTO v_event_type_id
  FROM public.picklist_values
  WHERE picklist_object='envelope_events' AND picklist_field='event_type'
    AND picklist_value='Voided' AND picklist_is_active=true;

  SELECT id INTO v_event_rt_id
  FROM public.picklist_values
  WHERE picklist_object='envelope_events' AND picklist_field='record_type'
    AND picklist_value='Standard' AND picklist_is_active=true;

  -- ── change ──: also write env_void_reason so the column reflects truth.
  UPDATE public.envelopes
     SET env_status        = v_voided_id,
         env_voided_at     = v_now,
         env_void_reason   = v_reason,
         updated_by        = v_caller_user_id,
         updated_at        = v_now
   WHERE id = p_envelope_id;

  UPDATE public.envelope_recipients
     SET recipient_token_expires_at = v_now,
         updated_by                 = v_caller_user_id,
         updated_at                 = v_now
   WHERE envelope_id = p_envelope_id
     AND recipient_signed_at   IS NULL
     AND recipient_declined_at IS NULL
     AND COALESCE(is_deleted, false) = false
     AND (recipient_token_expires_at IS NULL OR recipient_token_expires_at > v_now);

  IF v_event_type_id IS NOT NULL THEN
    INSERT INTO public.envelope_events (
      event_record_number, envelope_id, recipient_id,
      event_record_type, event_type, event_metadata,
      created_by
    ) VALUES (
      '', p_envelope_id, NULL,
      v_event_rt_id, v_event_type_id,
      jsonb_build_object(
        'reason', v_reason,
        'voided_by_user_id', v_caller_user_id::text,
        'prior_status', v_status_value
      ),
      v_caller_user_id
    );
  END IF;

  RETURN (
    SELECT jsonb_build_object(
      'id',                e.id,
      'env_record_number', e.env_record_number,
      'env_status',        ps.picklist_value,
      'env_voided_at',     e.env_voided_at,
      'env_void_reason',   e.env_void_reason,
      'reason',            v_reason
    )
    FROM public.envelopes e
    JOIN public.picklist_values ps ON ps.id = e.env_status
    WHERE e.id = p_envelope_id
  );
END
$function$
;

CREATE OR REPLACE FUNCTION public.work_order_detail_for_technician(p_wo_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_uid uuid := public.current_app_user_id();
  v_header jsonb;
  v_steps  jsonb;
  v_first  timestamptz;
  v_last   timestamptz;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('outcome','error','message','Not authenticated.');
  END IF;

  SELECT jsonb_build_object(
    'work_order_id',          wo.id,
    'work_order_record_number', wo.work_order_record_number,
    'work_order_name',        wo.work_order_name,
    'work_order_status',      wost.picklist_value,
    'work_order_status_id',   wo.work_order_status,
    'property_name',          COALESCE(NULLIF(wo.work_order_property_name,''), p.property_name),
    'property_address',       NULLIF(trim(BOTH ', ' FROM
                                concat_ws(', ',
                                  COALESCE(NULLIF(wo.work_order_building_address,''), b.building_address, p.property_street),
                                  COALESCE(b.building_city, p.property_city),
                                  COALESCE(b.building_state, p.property_state),
                                  COALESCE(b.building_zip, p.property_zip)
                                )), ''),
    'building',               COALESCE(NULLIF(wo.work_order_building,''), b.building_number_or_name, b.building_name),
    'unit',                   COALESCE(NULLIF(wo.work_order_unit,''), u.unit_number, u.unit_name),
    'customer_name',          wo.work_order_customer_name,
    'work_type_name',         wt.work_type_name,
    'updated_at',             wo.work_order_updated_at,
    'scheduled_start',        (SELECT sa.sa_scheduled_start_time FROM service_appointments sa
                                 WHERE sa.work_order_id = wo.id AND sa.sa_is_deleted IS NOT TRUE
                                 ORDER BY sa.sa_scheduled_start_time DESC NULLS LAST LIMIT 1)
  )
  INTO v_header
  FROM public.work_orders wo
  LEFT JOIN public.picklist_values wost ON wost.id = wo.work_order_status
  LEFT JOIN public.work_types wt ON wt.id = wo.work_type_id
  LEFT JOIN public.properties p ON p.id = wo.property_id
  LEFT JOIN public.buildings  b ON b.id = wo.building_id
  LEFT JOIN public.units      u ON u.id = wo.unit_id
  WHERE wo.id = p_wo_id AND wo.work_order_is_deleted IS NOT TRUE;

  IF v_header IS NULL THEN
    RETURN jsonb_build_object('outcome','error','message','Work order not found.');
  END IF;

  -- Evidence-bracketed duration: first and last photo across all steps on this WO.
  SELECT min(ph.taken_at), max(ph.taken_at)
  INTO v_first, v_last
  FROM public.photos ph
  JOIN public.work_steps ws ON ws.id = ph.work_step_id
  WHERE ws.work_order_id = p_wo_id AND ph.is_deleted = false AND ph.taken_at IS NOT NULL;

  SELECT coalesce(jsonb_agg(step ORDER BY (step->>'execution_order')::int NULLS LAST), '[]'::jsonb)
  INTO v_steps
  FROM (
    SELECT jsonb_build_object(
      'work_step_id',            ws.id,
      'work_step_record_number', ws.work_step_record_number,
      'name',                    ws.work_step_name,
      'description',             ws.work_step_description,
      'execution_order',         ws.work_step_execution_order,
      'status',                  wsst.picklist_value,
      'status_id',               ws.work_step_status,
      'photos_required_count',   coalesce(ws.work_step_photos_required_count,0),
      'photo_before_required',   coalesce(ws.work_step_photo_before_required,false),
      'photo_after_required',    coalesce(ws.work_step_photo_after_required,false),
      'evidence_type',           et.picklist_value,
      'reference_photo_url',     ws.work_step_reference_photo_url,
      'photo_count',             (SELECT count(*) FROM public.photos p2 WHERE p2.work_step_id = ws.id AND p2.is_deleted = false),
      'before_count',            (SELECT count(*) FROM public.photos p2 WHERE p2.work_step_id = ws.id AND p2.is_deleted = false AND lower(coalesce(p2.photo_type,''))='before'),
      'after_count',             (SELECT count(*) FROM public.photos p2 WHERE p2.work_step_id = ws.id AND p2.is_deleted = false AND lower(coalesce(p2.photo_type,''))='after'),
      'photos',                  (SELECT coalesce(jsonb_agg(jsonb_build_object(
                                     'id', p2.id, 'photo_type', p2.photo_type,
                                     'bucket', p2.storage_bucket, 'path', p2.storage_path_original,
                                     'taken_at', p2.taken_at
                                   ) ORDER BY p2.taken_at), '[]'::jsonb)
                                   FROM public.photos p2 WHERE p2.work_step_id = ws.id AND p2.is_deleted = false),
      'evidence_gap',            public._work_step_evidence_gap(ws.*),
      'pc_comment',              ws.work_step_pc_comment,
      'psl_comment',             ws.work_step_psl_comment
    ) AS step
    FROM public.work_steps ws
    LEFT JOIN public.picklist_values wsst ON wsst.id = ws.work_step_status
    LEFT JOIN public.picklist_values et   ON et.id   = ws.work_step_required_evidence_type_id
    WHERE ws.work_order_id = p_wo_id AND ws.work_step_is_deleted IS NOT TRUE
  ) s;

  RETURN jsonb_build_object(
    'outcome','ok',
    'header', v_header,
    'steps',  v_steps,
    'first_photo_at', v_first,
    'last_photo_at',  v_last,
    'duration_minutes', CASE WHEN v_first IS NOT NULL AND v_last IS NOT NULL AND v_last > v_first
                             THEN round(EXTRACT(EPOCH FROM (v_last - v_first))/60.0, 1) ELSE NULL END
  );
END; $function$
;

CREATE OR REPLACE FUNCTION public.work_order_inherit_parent_fields()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_project_name   text;
  v_proj_opp       uuid;
  v_proj_property  uuid;
  v_proj_building  uuid;
  v_unit_number    text;
  v_unit_name      text;
  v_work_type_name text;
  v_record_type_lbl text;
  v_property_name  text;
  v_building_name  text;
  v_name_parts     text[] := ARRAY[]::text[];
BEGIN
  -- Pull project parent context
  SELECT p.project_name, p.opportunity_id, p.property_id, p.building_id
    INTO v_project_name, v_proj_opp, v_proj_property, v_proj_building
  FROM public.projects p
  WHERE p.id = NEW.project_id;

  -- Inherit parent FKs only when caller left them NULL
  IF NEW.opportunity_id IS NULL THEN NEW.opportunity_id := v_proj_opp; END IF;
  IF NEW.property_id   IS NULL THEN NEW.property_id   := v_proj_property; END IF;
  IF NEW.building_id   IS NULL THEN NEW.building_id   := v_proj_building; END IF;

  -- Resolve unit
  IF NEW.unit_id IS NOT NULL THEN
    SELECT u.unit_number, u.unit_name
      INTO v_unit_number, v_unit_name
    FROM public.units u WHERE u.id = NEW.unit_id;
  END IF;

  -- Resolve work type
  IF NEW.work_type_id IS NOT NULL THEN
    SELECT wt.work_type_name INTO v_work_type_name
    FROM public.work_types wt WHERE wt.id = NEW.work_type_id;
  END IF;

  -- Resolve record type label (fallback for name only)
  IF NEW.work_order_record_type IS NOT NULL THEN
    SELECT pv.picklist_label INTO v_record_type_lbl
    FROM public.picklist_values pv WHERE pv.id = NEW.work_order_record_type;
  END IF;

  -- Resolve property / building names for denormalized mirrors
  IF NEW.property_id IS NOT NULL THEN
    SELECT pr.property_name INTO v_property_name
    FROM public.properties pr WHERE pr.id = NEW.property_id;
  END IF;
  IF NEW.building_id IS NOT NULL THEN
    SELECT b.building_name INTO v_building_name
    FROM public.buildings b WHERE b.id = NEW.building_id;
  END IF;

  -- Compose work_order_name only when not explicitly supplied
  IF NEW.work_order_name IS NULL OR btrim(NEW.work_order_name) = '' THEN
    IF v_project_name IS NOT NULL AND btrim(v_project_name) <> '' THEN
      v_name_parts := v_name_parts || v_project_name;
    END IF;
    IF v_unit_number IS NOT NULL AND btrim(v_unit_number) <> '' THEN
      v_name_parts := v_name_parts || v_unit_number;
    ELSIF v_unit_name IS NOT NULL AND btrim(v_unit_name) <> '' THEN
      v_name_parts := v_name_parts || v_unit_name;
    END IF;
    IF v_work_type_name IS NOT NULL AND btrim(v_work_type_name) <> '' THEN
      v_name_parts := v_name_parts || v_work_type_name;
    ELSIF v_record_type_lbl IS NOT NULL AND btrim(v_record_type_lbl) <> '' THEN
      v_name_parts := v_name_parts || v_record_type_lbl;
    END IF;

    IF array_length(v_name_parts, 1) IS NOT NULL THEN
      NEW.work_order_name := array_to_string(v_name_parts, ' - ');
    END IF;
  END IF;

  -- Denormalized text mirrors (only when caller left NULL)
  IF NEW.work_order_project IS NULL THEN NEW.work_order_project := v_project_name; END IF;
  IF NEW.work_order_unit IS NULL THEN NEW.work_order_unit := COALESCE(v_unit_number, v_unit_name); END IF;
  IF NEW.work_order_property_name IS NULL THEN NEW.work_order_property_name := v_property_name; END IF;
  IF NEW.work_order_property IS NULL THEN NEW.work_order_property := v_property_name; END IF;
  IF NEW.work_order_building IS NULL THEN NEW.work_order_building := v_building_name; END IF;

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.yn(p text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT CASE WHEN upper(btrim(coalesce(p,'')))='Y' THEN true
              WHEN upper(btrim(coalesce(p,'')))='N' THEN false ELSE NULL END
$function$
;


